/// Host callback invoked by `console.*` methods.
///
/// The sink receives the raw JS argument list. Embeddings that want browser-like formatting
/// (including `%` substitutions) should format via
/// [`crate::js::vm_error_format::format_console_arguments_limited`], which is:
/// - bounded (safe to enable for untrusted pages)
/// - deterministic (avoids invoking user-defined `toString` hooks)
///
/// Note: Some console methods (e.g. `console.trace`, `console.assert`, `console.timeLog`) pass a
/// preformatted string as the first argument.
pub type ConsoleSink =
  Arc<dyn Fn(ConsoleMessageLevel, &mut vm_js::Heap, &[vm_js::Value]) + Send + Sync + 'static>;

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum DomBindingsBackend {
  /// Install handcrafted `vm-js` shims and allocate per-realm DOM prototypes via [`DomPlatform`].
  Handwritten,
  /// Install WebIDL-generated constructors/prototypes for core DOM interfaces and reuse those
  /// global prototype objects for native wrapper creation.
  WebIdl,
}

/// Lightweight `VmHost` context used by `WindowRealm` helpers that need a stable downcast target.
///
/// `vm-js` passes a `&mut dyn VmHost` into every native call/construct handler. In full browser
/// embeddings this is typically a document/tab host type (e.g. [`DocumentHostState`]), but some
/// `WindowRealm` entrypoints create an internal host context instead.
///
/// We keep a dedicated type so helpers like `current_script_state_handle_from_vm_host` can reliably
/// recover shared host-side state (currently: `Document.currentScript` bookkeeping) even when the
/// embedder passes a unit `()` host or other opaque type.
#[derive(Clone, Debug, Default)]
struct VmJsHostContext {
  current_script_state: Option<CurrentScriptStateHandle>,
}

impl VmJsHostContext {
  fn current_script_state(&self) -> Option<&CurrentScriptStateHandle> {
    self.current_script_state.as_ref()
  }
}
// Compile-time guard: `vm-js` must keep exposing the borrow-splitting accessor used by FastRender
// embeddings (see `WindowRealm::new`).
#[allow(dead_code)]
const _VM_JS_RUNTIME_VM_REALM_AND_HEAP_MUT_GUARD: fn(
  &mut VmJsRuntime,
) -> (&mut Vm, &Realm, &mut Heap) = VmJsRuntime::vm_realm_and_heap_mut;

#[derive(Clone)]
pub struct WindowRealmConfig {
  pub document_url: String,
  /// Identifier of the session storage namespace that this realm's `sessionStorage` should bind to.
  ///
  /// When set, `sessionStorage` is backed by the thread-local Web Storage hub and shared across
  /// realms that use the same namespace (e.g. navigations within a single browser tab).
  ///
  /// When unset, `sessionStorage` is **ephemeral** and scoped to this `WindowRealm` instance.
  pub session_storage_namespace_id: Option<u64>,
  /// Media context used for `window.devicePixelRatio`, viewport geometry, and `matchMedia()`.
  ///
  /// This should generally match the renderer's layout/styling media context for the document so
  /// JS and CSS agree on viewport/resolution queries.
  pub media: MediaContext,
  /// Host-owned `Document.currentScript` state handle to expose via `document.currentScript`.
  pub current_script_state: Option<CurrentScriptStateHandle>,
  pub console_sink: Option<ConsoleSink>,
  /// Memory limits for the embedded `vm-js` heap.
  ///
  /// FastRender treats JavaScript as hostile input; keeping a hard heap limit is a foundational
  /// safety invariant even before full script execution is wired up.
  pub heap_limits: HeapLimits,
  /// Construction-time VM options for the embedded `vm-js` VM.
  ///
  /// Notably, this includes stack depth limits (`VmOptions::max_stack_depth`).
  pub vm_options: VmOptions,
  /// Host clock backing web time APIs like `Date.now()` and `performance.now()`.
  pub clock: Arc<dyn Clock>,
  /// Deterministic web time model (`performance.timeOrigin`, and the epoch offset for `Date.now()`).
  pub web_time: WebTime,
  /// Optional override for the per-realm deterministic PRNG seed used by `window.crypto`.
  ///
  /// When unset, the seed defaults to a deterministic value derived from `document_url` so render
  /// output and tests remain reproducible across runs. Callers that prefer per-process randomness
  /// (e.g. a production browser embedding) can provide a random seed here.
  pub crypto_rng_seed: Option<u64>,
  /// Maximum size of a single Web Storage area (`localStorage` / `sessionStorage`), in UTF-16 bytes.
  pub web_storage_quota_utf16_bytes: usize,
  /// Selects how DOM interface constructors/prototypes are installed for this realm.
  pub dom_bindings_backend: DomBindingsBackend,
}

static NEXT_WINDOW_ID: AtomicU64 = AtomicU64::new(1);

fn alloc_window_id() -> u64 {
  NEXT_WINDOW_ID.fetch_add(1, Ordering::Relaxed)
}

/// Navigation request emitted by `window.location` APIs (`href`, `assign`, `replace`).
///
/// WindowRealm itself does not perform document loading/navigation; it records a pending request and
/// interrupts the currently running script so the embedding can commit the navigation.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct LocationNavigationRequest {
  pub url: String,
  pub replace: bool,
}

impl WindowRealmConfig {
  pub fn new(document_url: impl Into<String>) -> Self {
    Self {
      document_url: document_url.into(),
      session_storage_namespace_id: None,
      media: MediaContext::screen(800.0, 600.0),
      current_script_state: None,
      console_sink: None,
      heap_limits: super::vm_limits::default_heap_limits(),
      vm_options: VmOptions::default(),
      clock: Arc::new(RealClock::default()),
      web_time: WebTime::default(),
      crypto_rng_seed: None,
      web_storage_quota_utf16_bytes: 5 * 1024 * 1024,
      dom_bindings_backend: DomBindingsBackend::Handwritten,
    }
  }

  pub fn with_media_context(mut self, media: MediaContext) -> Self {
    self.media = media;
    self
  }

  pub fn with_session_storage_namespace_id(mut self, id: u64) -> Self {
    self.session_storage_namespace_id = Some(id);
    self
  }

  pub fn with_current_script_state(mut self, state: CurrentScriptStateHandle) -> Self {
    self.current_script_state = Some(state);
    self
  }

  pub fn with_js_execution_options(mut self, options: JsExecutionOptions) -> Self {
    self.heap_limits = super::vm_limits::heap_limits_from_js_options(&options);
    if let Some(max_stack_depth) = options.max_stack_depth {
      self.vm_options.max_stack_depth = max_stack_depth;
    }
    self
  }

  pub fn with_heap_limits(mut self, heap_limits: HeapLimits) -> Self {
    self.heap_limits = heap_limits;
    self
  }

  pub fn with_vm_options(mut self, options: VmOptions) -> Self {
    self.vm_options = options;
    self
  }

  pub fn with_clock(mut self, clock: Arc<dyn Clock>) -> Self {
    self.clock = clock;
    self
  }

  pub fn with_web_time(mut self, web_time: WebTime) -> Self {
    self.web_time = web_time;
    self
  }

  pub fn with_crypto_rng_seed(mut self, seed: u64) -> Self {
    self.crypto_rng_seed = Some(seed);
    self
  }

  pub fn with_web_storage_quota_utf16_bytes(mut self, quota_bytes: usize) -> Self {
    self.web_storage_quota_utf16_bytes = quota_bytes;
    self
  }

  pub fn with_dom_bindings_backend(mut self, backend: DomBindingsBackend) -> Self {
    self.dom_bindings_backend = backend;
    self
  }
}

pub struct WindowRealm {
  runtime: Box<VmJsRuntime>,
  realm_id: RealmId,
  console_obj: GcObject,
  console_sink_id_key_s: GcString,
  console_sink_id: Option<u64>,
  match_media_env_id: Option<u64>,
  time_bindings: Option<TimeBindings>,
  text_encoding_bindings: Option<crate::js::window_text_encoding::TextEncodingBindings>,
  interrupt_flag: Arc<AtomicBool>,
  /// Tracks whether `runtime.heap` is still alive.
  ///
  /// `vm-js` promise jobs can be queued onto the host event loop. When execution is aborted (due to
  /// budgets/cancellation), those queued jobs may be dropped without being run. Dropping a job
  /// without calling `Job::discard(..)` triggers debug assertions in `vm-js` because it would leak
  /// persistent roots.
  ///
  /// We use this flag to safely discard any abandoned jobs while the heap is still live, and fall
  /// back to leaking the job (only possible during teardown) once the heap is gone.
  heap_alive: Arc<AtomicBool>,
  js_execution_options: JsExecutionOptions,
  module_loader: ModuleLoaderHandle,
  /// Optional WebIDL bindings dispatch host for WindowRealm-owned hook shims.
  ///
  /// This is only used by `WindowRealm` convenience entry points that fabricate their own
  /// `VmHostHooks` implementations (e.g. `exec_script_with_name`, `perform_microtask_checkpoint`).
  ///
  /// The pointer is installed via `WindowRealm::with_webidl_bindings_host` and must not outlive the
  /// dynamic extent of that call.
  webidl_bindings_host: Option<NonNull<dyn WebIdlBindingsHost>>,
  next_script_id_raw: u64,
}

#[derive(Debug, Clone)]
struct SessionHistoryEntry {
  url: String,
  state_root: RootId,
}

#[derive(Debug, Default)]
struct SessionHistory {
  entries: Vec<SessionHistoryEntry>,
  index: usize,
}

pub(crate) struct WindowRealmUserData {
  pub(crate) window_id: u64,
  pub(crate) local_storage_area: Arc<Mutex<web_storage::StorageArea>>,
  pub(crate) session_storage_area: Arc<Mutex<web_storage::StorageArea>>,
  document_url: String,
  pub(crate) base_url: Option<String>,
  /// Host-controlled flag that indicates this realm is a privileged `chrome://` realm.
  ///
  /// When set, `window.location` navigations are restricted to internal schemes to prevent
  /// privileged chrome pages (where `window.chrome` bindings may be installed) from navigating to
  /// untrusted network content via `location.assign` / `location.href = ...` / etc.
  privileged_chrome_realm: bool,
  session_history: SessionHistory,
  fallback_scroll_x: f64,
  fallback_scroll_y: f64,
  pending_navigation: Option<LocationNavigationRequest>,
  /// Pending `hashchange` events queued when the realm is running without an HTML [`EventLoop`].
  ///
  /// In full browser-style embeddings, fragment navigations queue a DOM manipulation task on the
  /// event loop. When embedders use `WindowRealm` directly (no event loop installed in
  /// `VmHostHooks`), we still need to deliver `hashchange` asynchronously; these entries are
  /// dispatched during `WindowRealm::perform_microtask_checkpoint`.
  pending_hashchange_events: VecDeque<QueuedHashChangeEvent>,
  cookie_fetcher: Option<Arc<dyn ResourceFetcher>>,
  cookie_jar: CookieJar,
  pub(crate) module_loader: ModuleLoaderHandle,
  /// Optional module graph backing module scripts and dynamic `import()`.
  ///
  /// When present, `Vm::module_graph_ptr()` points into this boxed allocation.
  pub(crate) module_graph: Option<Box<ModuleGraph>>,
  /// Cached native call handler id for `import.meta.resolve`.
  pub(crate) import_meta_resolve_call_id: Option<NativeFunctionId>,
  pub(crate) worker_registry: crate::js::window_worker::WorkerRegistry,
  media_element_state_registry: MediaElementStateRegistry,
  dom_platform: Option<DomPlatform>,
  /// Registry of realm-owned (non-host) `dom2::Document` instances keyed by their document ID.
  ///
  /// This is used for DOMs created from JS (e.g. `document.implementation.createHTMLDocument()`)
  /// which are not backed by the embedder/renderer.
  owned_dom2_documents: Rc<RefCell<HashMap<DocumentId, Box<dom2::Document>>>>,
  /// Documents that had `dataset` mutations while running without direct access to `&mut Vm`.
  ///
  /// `Element.dataset` is implemented via `VmHostHooks::{host_exotic_get,host_exotic_set,host_exotic_delete}`.
  /// Those hooks cannot safely borrow `&mut Vm` (the VM is already mutably borrowed by the engine),
  /// so we record which documents need mutation-observer microtask queueing and drain this set at a
  /// safe execution boundary.
  pub(crate) pending_dataset_mutation_observer_microtasks: Rc<RefCell<HashSet<WeakGcObject>>>,
  /// Deterministic per-realm PRNG state used by `window.crypto` RNG APIs.
  pub(crate) crypto_rng_state: u64,
  /// Fallback `dom2::Document` used for events when the realm is not backed by a host DOM.
  ///
  /// This enables `window`/`document` (and `new EventTarget()`) event listeners in minimal realms
  /// created without a host DOM.
  events_dom_fallback: dom2::Document,
  realm_document_registry: RealmDocumentRegistry,
  /// Cached JS `window` global object for mapping `EventTargetId::Window` back into JS when the
  /// target is not a DOM-backed node/document.
  window_obj: Option<GcObject>,
  /// Cached JS `window.history` object for updating `history.state`/`history.length` during
  /// same-document navigations (fragment navigations and session history traversal).
  history_obj: Option<GcObject>,
  /// Cached JS `document` object for rooting event listener callbacks and mapping
  /// `EventTargetId::Document` back into JS.
  document_obj: Option<GcObject>,
  /// Cached JS `location` object so embedders can repair `location.href` when a navigation is
  /// canceled (for example by a `beforeunload` handler).
  location_obj: Option<GcObject>,
  console_counts: HashMap<String, u64>,
  console_timers: HashMap<String, Duration>,
  console_group_depth: u8,
}

#[derive(Default)]
struct RealmDocumentRegistry {
  last_gc_runs: u64,
  documents: HashMap<vm_js::WeakGcObject, Box<dom2::Document>>,
}

impl RealmDocumentRegistry {
  fn sweep_if_needed(&mut self, heap: &Heap) -> bool {
    let gc_runs = heap.gc_runs();
    if gc_runs == self.last_gc_runs {
      return false;
    }
    self
      .documents
      .retain(|doc_obj, _dom| doc_obj.upgrade(heap).is_some());
    self.last_gc_runs = gc_runs;
    true
  }

  fn register(&mut self, document_obj: GcObject, dom: dom2::Document) {
    self
      .documents
      .insert(vm_js::WeakGcObject::new(document_obj), Box::new(dom));
  }

  fn get_dom_ptr_for_events(
    &mut self,
    heap: &Heap,
    document_obj: GcObject,
  ) -> Option<NonNull<dom2::Document>> {
    self.sweep_if_needed(heap);
    self
      .documents
      .get_mut(&vm_js::WeakGcObject::new(document_obj))
      .map(|dom| NonNull::from(dom.as_mut()))
  }
}

impl std::fmt::Debug for WindowRealmUserData {
  fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
    f.debug_struct("WindowRealmUserData")
      .field("window_id", &self.window_id)
      .field("document_url", &self.document_url)
      .field("base_url", &self.base_url)
      .field("session_history_len", &self.session_history.entries.len())
      .field("session_history_index", &self.session_history.index)
      .field(
        "fallback_scroll",
        &(self.fallback_scroll_x, self.fallback_scroll_y),
      )
      .field("has_cookie_fetcher", &self.cookie_fetcher.is_some())
      .field("cookie_jar", &self.cookie_jar)
      .field("has_module_graph", &self.module_graph.is_some())
      .field(
        "has_import_meta_resolve_call_id",
        &self.import_meta_resolve_call_id.is_some(),
      )
      .field("worker_count", &self.worker_registry.len())
      .field(
        "media_element_state_registry_len",
        &self.media_element_state_registry.len(),
      )
      .field("has_dom_platform", &self.dom_platform.is_some())
      .field("crypto_rng_state", &self.crypto_rng_state)
      .field("has_window_obj", &self.window_obj.is_some())
      .field("has_history_obj", &self.history_obj.is_some())
      .field("has_document_obj", &self.document_obj.is_some())
      .field("has_location_obj", &self.location_obj.is_some())
      .field(
        "pending_dataset_mutation_observer_microtasks_len",
        &self.pending_dataset_mutation_observer_microtasks.borrow().len(),
      )
      .field(
        "pending_hashchange_events_len",
        &self.pending_hashchange_events.len(),
      )
      .field(
        "owned_dom2_documents_len",
        &self.owned_dom2_documents.borrow().len(),
      )
      .finish()
  }
}

impl WindowRealmUserData {
  pub(crate) fn new(
    document_url: String,
    module_loader: ModuleLoaderHandle,
    session_storage_namespace_id: Option<u64>,
    crypto_rng_seed: Option<u64>,
    web_storage_quota_utf16_bytes: usize,
  ) -> Self {
    let crypto_rng_state = crypto_rng_seed
      .map(crate::js::window_crypto::crypto_rng_seed_from_u64)
      .unwrap_or_else(|| crate::js::window_crypto::crypto_rng_seed_from_document_url(&document_url));
    let window_id = alloc_window_id();
    let storage_origin_key = web_storage::origin_key_from_document_url(&document_url);
    let local_storage_area = web_storage::get_local_area(storage_origin_key.as_deref());
    let session_storage_area = match session_storage_namespace_id {
      Some(id) => web_storage::get_session_area(
        web_storage::SessionNamespaceId(id),
        storage_origin_key.as_deref(),
      ),
      // When the caller does not provide an explicit namespace, `sessionStorage` is ephemeral (per
      // realm) and must not be stored in the shared hub.
      None => Arc::new(Mutex::new(web_storage::StorageArea::new_with_quota(
        web_storage_quota_utf16_bytes,
      ))),
    };
    local_storage_area
      .lock()
      .set_quota_bytes(web_storage_quota_utf16_bytes);
    session_storage_area
      .lock()
      .set_quota_bytes(web_storage_quota_utf16_bytes);
    Self {
      window_id,
      local_storage_area,
      session_storage_area,
      base_url: Some(document_url.clone()),
      session_history: SessionHistory::default(),
      fallback_scroll_x: 0.0,
      fallback_scroll_y: 0.0,
      pending_navigation: None,
      pending_hashchange_events: VecDeque::new(),
      document_url,
      privileged_chrome_realm: false,
      cookie_fetcher: None,
      cookie_jar: CookieJar::new(),
      module_loader,
      module_graph: None,
      import_meta_resolve_call_id: None,
      worker_registry: crate::js::window_worker::WorkerRegistry::default(),
      media_element_state_registry: MediaElementStateRegistry::default(),
      dom_platform: None,
      owned_dom2_documents: Rc::new(RefCell::new(HashMap::new())),
      pending_dataset_mutation_observer_microtasks: Rc::new(RefCell::new(HashSet::new())),
      crypto_rng_state,
      events_dom_fallback: dom2::Document::new(QuirksMode::NoQuirks),
      realm_document_registry: RealmDocumentRegistry::default(),
      window_obj: None,
      history_obj: None,
      document_obj: None,
      location_obj: None,
      console_counts: HashMap::new(),
      console_timers: HashMap::new(),
      console_group_depth: 0,
    }
  }

  pub(crate) fn register_realm_document(&mut self, document_obj: GcObject, dom: dom2::Document) {
    self.realm_document_registry.register(document_obj, dom);
  }

  pub(crate) fn document_url(&self) -> &str {
    &self.document_url
  }

  pub(crate) fn window_obj(&self) -> Option<GcObject> {
    self.window_obj
  }

  pub(crate) fn document_obj(&self) -> Option<GcObject> {
    self.document_obj
  }

  pub(crate) fn media_element_state_registry_len(&self) -> usize {
    self.media_element_state_registry.len()
  }

  pub(crate) fn media_element_state_registry_mut(&mut self) -> &mut MediaElementStateRegistry {
    &mut self.media_element_state_registry
  }

  pub(crate) fn sweep_media_element_state_registry_if_needed(
    &mut self,
    heap: &Heap,
    host: &mut dyn VmHost,
  ) -> bool {
    let host_dom = dom_from_vm_host(host);
    let owned_dom2_documents = self.owned_dom2_documents.borrow();
    let dom_platform = self.dom_platform.as_mut();
    self.media_element_state_registry.sweep_if_needed(
      heap,
      dom_platform,
      host_dom,
      Some(&*owned_dom2_documents),
    )
  }

  pub(crate) fn dom_platform_mut(&mut self) -> Option<&mut DomPlatform> {
    self.dom_platform.as_mut()
  }

  #[cfg(test)]
  pub(crate) fn set_dom_platform(&mut self, platform: DomPlatform) {
    self.dom_platform = Some(platform);
  }

  pub(crate) fn events_dom_fallback(&self) -> &dom2::Document {
    &self.events_dom_fallback
  }
}

impl WindowRealm {
  pub fn new(config: WindowRealmConfig) -> Result<Self, VmError> {
    let mut vm_options = config.vm_options.clone();
    let heap_limits = config.heap_limits;
    let enforced_heap_max_bytes = heap_limits.max_bytes;
    let enforced_stack_depth = vm_options.max_stack_depth;

    // `WindowRealm` stores the JS execution options that drive per-run budgets. Realms created
    // directly via `WindowRealm::new` use default execution limits, but we still record the
    // enforced heap/stack bounds from the construction config for consistency/debugging.
    let mut js_execution_options = JsExecutionOptions::default();
    js_execution_options.max_vm_heap_bytes = Some(enforced_heap_max_bytes);
    js_execution_options.max_stack_depth = Some(enforced_stack_depth);

    // Window realms should be interruptible even before full script execution is wired up.
    // This is separate from the renderer-level interrupt flag: it's resettable per realm.
    let interrupt_flag = Arc::new(AtomicBool::new(false));
    let heap_alive = Arc::new(AtomicBool::new(true));
    vm_options.interrupt_flag = Some(Arc::clone(&interrupt_flag));
    // Also observe the render-wide interrupt flag so host cancellation interrupts JS at the next
    // `Vm::tick()`.
    vm_options.external_interrupt_flag = Some(render_control::interrupt_flag());
    let vm = Vm::new(vm_options);
    let heap = Heap::new(heap_limits);

    let module_loader: ModuleLoaderHandle = Rc::new(RefCell::new({
      let mut loader = ModuleLoader::new(Some(config.document_url.clone()));
      loader.set_js_execution_options(js_execution_options);
      loader
    }));

    let mut runtime = Box::new(VmJsRuntime::new(vm, heap)?);
    runtime.vm.set_user_data(WindowRealmUserData::new(
      config.document_url.clone(),
      Rc::clone(&module_loader),
      config.session_storage_namespace_id,
      config.crypto_rng_seed,
      config.web_storage_quota_utf16_bytes,
    ));
    let realm_id = runtime.realm().id();

    let (vm, realm, heap) = runtime.vm_realm_and_heap_mut();

    let (console_sink_id, match_media_env_id, text_encoding_bindings, console_obj, console_sink_id_key_s) =
      init_window_globals(vm, heap, realm, &config)?;
    let time_bindings = match crate::js::time::install_time_bindings(
      vm,
      realm,
      heap,
      Arc::clone(&config.clock),
      config.web_time,
    ) {
      Ok(bindings) => bindings,
      Err(err) => {
        // `init_window_globals` registers host-owned resources (console sink IDs, matchMedia envs,
        // and URL binding state) that must not leak when WindowRealm initialization fails midway
        // through.
        if let Some(id) = console_sink_id {
          unregister_console_sink(id);
        }
        if let Some(id) = match_media_env_id {
          unregister_match_media_env(id);
        }
        crate::js::window_url::teardown_window_url_bindings_for_realm(realm_id, heap);
        crate::js::window_streams::teardown_window_streams_bindings_for_realm(realm_id);
        crate::js::window_blob::teardown_window_blob_bindings_for_realm(realm_id);
        crate::js::window_file::teardown_window_file_bindings_for_realm(realm_id);
        crate::js::window_file_reader::teardown_window_file_reader_bindings_for_realm(realm_id);
        crate::js::window_form_data::teardown_window_form_data_bindings_for_realm(realm_id);
        crate::js::window_message_channel::teardown_window_message_channel_bindings_for_realm(realm_id);
        crate::js::window_broadcast_channel::teardown_window_broadcast_channel_bindings_for_realm(realm_id);
        return Err(err);
      }
    };
    Ok(Self {
      runtime,
      realm_id,
      console_obj,
      console_sink_id_key_s,
      console_sink_id,
      match_media_env_id,
      time_bindings: Some(time_bindings),
      text_encoding_bindings: Some(text_encoding_bindings),
      interrupt_flag,
      heap_alive,
      js_execution_options,
      module_loader,
      webidl_bindings_host: None,
      next_script_id_raw: 0,
    })
  }

  pub fn new_with_js_execution_options(
    mut config: WindowRealmConfig,
    js_execution_options: JsExecutionOptions,
  ) -> Result<Self, VmError> {
    if js_execution_options.max_vm_heap_bytes.is_some() {
      // When explicitly configured, override any heap limits provided by the config. The chosen
      // limit is still clamped by the OS address-space ceiling (`RLIMIT_AS`) when tighter.
      config.heap_limits = super::vm_limits::heap_limits_from_js_options(&js_execution_options);
    }

    if let Some(max_stack_depth) = js_execution_options.max_stack_depth {
      config.vm_options.max_stack_depth = max_stack_depth;
    }
    // Also propagate per-run budgets into VM construction-time defaults. We still reset the budget
    // before each JS "turn" so the deadline is relative to the current turn and incorporates the
    // root render deadline.
    config.vm_options.default_fuel = js_execution_options.max_instruction_count;
    config.vm_options.default_deadline = js_execution_options.event_loop_run_limits.max_wall_time;
    let enforced_heap_max_bytes = config.heap_limits.max_bytes;
    let enforced_stack_depth = config.vm_options.max_stack_depth;

    let mut realm = Self::new(config)?;
    realm.js_execution_options = js_execution_options;
    // Keep stored options consistent with the realm's actual limits. Even when the caller leaves
    // these as `None`, the realm still applies a concrete heap cap + stack depth.
    realm.js_execution_options.max_vm_heap_bytes = Some(enforced_heap_max_bytes);
    realm.js_execution_options.max_stack_depth = Some(enforced_stack_depth);
    realm
      .module_loader
      .borrow_mut()
      .set_js_execution_options(realm.js_execution_options);
    Ok(realm)
  }

  /// Temporarily installs a [`WebIdlBindingsHost`] for WindowRealm-owned `VmHostHooks` shims.
  ///
  /// This is used by `WindowRealm` convenience entrypoints (like `exec_script_with_name` and
  /// `perform_microtask_checkpoint`) that fabricate their own `VmHostHooks` objects and therefore
  /// cannot receive a WebIDL host through the embedding's event-loop hook adapters.
  pub(crate) fn with_webidl_bindings_host<R>(
    &mut self,
    host: &mut dyn WebIdlBindingsHost,
    f: impl FnOnce(&mut Self) -> R,
  ) -> R {
    struct Guard<'a> {
      realm: &'a mut WindowRealm,
      prev: Option<NonNull<dyn WebIdlBindingsHost>>,
    }

    impl Drop for Guard<'_> {
      fn drop(&mut self) {
        self.realm.webidl_bindings_host = self.prev;
      }
    }

    let prev = self.webidl_bindings_host;
    self.webidl_bindings_host = Some(NonNull::from(host));
    let mut guard = Guard { realm: self, prev };
    f(&mut *guard.realm)
  }

  pub fn reset_interrupt(&self) {
    self.interrupt_flag.store(false, Ordering::Relaxed);
    self.runtime.vm.reset_interrupt();
  }

  pub(crate) fn vm_budget_now(&self) -> vm_js::Budget {
    self.js_execution_options.vm_js_budget_now()
  }

  pub fn js_execution_options(&self) -> JsExecutionOptions {
    self.js_execution_options
  }

  pub fn heap(&self) -> &Heap {
    &self.runtime.heap
  }

  pub fn heap_mut(&mut self) -> &mut Heap {
    &mut self.runtime.heap
  }

  pub(crate) fn heap_alive_flag(&self) -> &Arc<AtomicBool> {
    &self.heap_alive
  }

  pub fn vm(&self) -> &Vm {
    &self.runtime.vm
  }

  pub fn vm_mut(&mut self) -> &mut Vm {
    &mut self.runtime.vm
  }

  pub(crate) fn dataset_exotic_context(&self) -> DatasetExoticContext {
    DatasetExoticContext::for_vm(&self.runtime.vm)
  }

  pub fn vm_and_heap_mut(&mut self) -> (&mut Vm, &mut Heap) {
    let runtime = &mut *self.runtime;
    (&mut runtime.vm, &mut runtime.heap)
  }

  pub fn vm_realm_and_heap_mut(&mut self) -> (&mut Vm, &Realm, &mut Heap) {
    self.runtime.vm_realm_and_heap_mut()
  }

  pub fn realm(&self) -> &Realm {
    self.runtime.realm()
  }

  pub fn window_id(&self) -> u64 {
    self
      .runtime
      .vm
      .user_data::<WindowRealmUserData>()
      .expect("WindowRealm missing WindowRealmUserData") // fastrender-allow-unwrap
      .window_id
  }

  pub fn global_object(&self) -> GcObject {
    self.runtime.realm().global_object()
  }

  pub fn teardown(&mut self) {
    // Discard any queued Promise jobs so their persistent roots are unregistered before we tear down
    // the realm/module graph. This is especially important on early-abort paths where the embedding
    // drops the realm without running a microtask checkpoint.
    self.runtime.teardown_microtasks();

    // If the embedding tears down the realm while module loading is in flight (for example, a page
    // triggers `import()` or starts loading a module graph, but the event loop is dropped before the
    // queued networking tasks run), the host-side `ModuleLoader` can still hold `ModuleLoadPayload`s
    // with persistent roots (promise capabilities).
    //
    // Tear down those payload roots here so dropping the loader cannot leak roots or trip `vm-js`
    // leaked-root debug assertions.
    {
      let heap = &mut self.runtime.heap;
      if let Ok(mut loader) = self.module_loader.try_borrow_mut() {
        for (_key, waiters) in loader.inflight.drain() {
          for waiter in waiters {
            waiter.payload.teardown_roots(heap);
          }
        }
      } else if let Ok(loader) = self.module_loader.try_borrow() {
        // Best-effort fallback when a mutable borrow isn't available: release roots even if we
        // cannot drain the inflight map.
        for waiters in loader.inflight.values() {
          for waiter in waiters {
            waiter.payload.teardown_roots(heap);
          }
        }
      }
    }

    // If module support was enabled for this realm, `Vm::module_graph_ptr` points into the
    // realm-owned module graph allocation.
    //
    // `vm-js` module graphs store persistent GC roots (module environments/namespaces, cached
    // `import.meta`, async evaluation state, etc). Dropping a graph without tearing it down leaks
    // those roots when the heap is reused and can trigger `vm-js` debug assertions.
    let module_graph = self
      .runtime
      .vm
      .user_data_mut::<WindowRealmUserData>()
      .and_then(|data| data.module_graph.take());
    if let Some(mut module_graph) = module_graph {
      module_graph.teardown(&mut self.runtime.vm, &mut self.runtime.heap);
    }
    self.runtime.vm.clear_module_graph();
    self.time_bindings.take();
    self.text_encoding_bindings.take();
    if let Some(id) = self.console_sink_id.take() {
      unregister_console_sink(id);
    }
    if let Some(id) = self.match_media_env_id.take() {
      unregister_match_media_env(id);
    }
    if let Some(data) = self.runtime.vm.user_data_mut::<WindowRealmUserData>() {
      data.worker_registry.terminate_all(&mut self.runtime.heap);
      // `history.pushState` stores entry state values as persistent roots; clear them before the heap
      // is dropped to avoid leaking root slots.
      for entry in data.session_history.entries.drain(..) {
        self.runtime.heap.remove_root(entry.state_root);
      }
      data.session_history.index = 0;
      if let Some(platform) = data.dom_platform.as_mut() {
        platform.teardown(&mut self.runtime.heap);
      }
    }
    let realm_id = self.runtime.realm().id();
    crate::js::window_streams::teardown_window_streams_bindings_for_realm(realm_id);
    crate::js::window_blob::teardown_window_blob_bindings_for_realm(realm_id);
    crate::js::window_file::teardown_window_file_bindings_for_realm(realm_id);
    crate::js::window_file_reader::teardown_window_file_reader_bindings_for_realm(realm_id);
    crate::js::window_form_data::teardown_window_form_data_bindings_for_realm(realm_id);
    crate::js::window_url::teardown_window_url_bindings_for_realm(realm_id, &mut self.runtime.heap);
    crate::js::window_message_channel::teardown_window_message_channel_bindings_for_realm(realm_id);
    crate::js::window_broadcast_channel::teardown_window_broadcast_channel_bindings_for_realm(realm_id);
  }

  pub fn enable_module_loader(
    &mut self,
    fetcher: Arc<dyn ResourceFetcher>,
    document_origin: Option<crate::resource::DocumentOrigin>,
  ) -> Result<(), VmError> {
    // Configure the per-realm module loader to use the provided fetcher and limits. Callers can
    // still override per-request defaults (e.g. CORS mode) before executing scripts.
    {
      let mut loader = self.module_loader.borrow_mut();
      loader.set_fetcher(Arc::clone(&fetcher));
      loader.set_js_execution_options(self.js_execution_options);
      if document_origin.is_some() {
        loader.set_document_origin(document_origin);
      }
    }

    let vm = self.vm_mut();
    let graph_ptr: *mut ModuleGraph = {
      let Some(data) = vm.user_data_mut::<WindowRealmUserData>() else {
        return Err(VmError::InvariantViolation(
          "window realm missing user data",
        ));
      };
      if data.module_graph.is_none() {
        data.module_graph = Some(Box::new(ModuleGraph::new()));
      }
      let Some(graph) = data.module_graph.as_deref_mut() else {
        return Err(VmError::InvariantViolation("window realm missing module graph"));
      };
      graph as *mut ModuleGraph
    };
    // SAFETY: the `ModuleGraph` is stored in a `Box` owned by the VM's `WindowRealmUserData` and is
    // cleared in `WindowRealm::teardown` before the user data is dropped.
    unsafe {
      vm.set_module_graph(&mut *graph_ptr);
    }
    Ok(())
  }

  pub fn set_cookie_fetcher(&mut self, fetcher: Arc<dyn ResourceFetcher>) {
    if let Some(data) = self.runtime.vm.user_data_mut::<WindowRealmUserData>() {
      data.cookie_fetcher = Some(fetcher);
    }
  }

  pub fn set_module_fetcher(&mut self, fetcher: Arc<dyn ResourceFetcher>) {
    self.module_loader.borrow_mut().set_fetcher(fetcher);
  }

  /// Update the document base URL used for resolving relative URLs in JS (e.g. `fetch("rel")` and
  /// `document.baseURI`).
  pub fn set_base_url(&mut self, base_url: Option<String>) {
    let effective_for_module_loader = if let Some(data) = self.runtime.vm.user_data_mut::<WindowRealmUserData>() {
      data.base_url = base_url;
      // When the embedder hasn't installed a base URL (or clears it), browsers still use the
      // document URL as the base URL. Keep module resolution consistent with `document.baseURI` and
      // `fetch("rel")` by falling back to `document_url` here as well.
      Some(
        data
          .base_url
          .clone()
          .unwrap_or_else(|| data.document_url.clone()),
      )
    } else {
      base_url
    };
    self
      .module_loader
      .borrow_mut()
      .set_document_url(effective_for_module_loader);
  }

  pub fn set_console_sink(&mut self, sink: Option<ConsoleSink>) -> Result<(), VmError> {
    let old_id = self.console_sink_id;

    match sink {
      Some(sink) => {
        let new_id = register_console_sink(sink);
        if let Err(err) = self.set_console_sink_id_on_console_obj(Some(new_id)) {
          unregister_console_sink(new_id);
          return Err(err);
        }

        if let Some(old_id) = old_id {
          unregister_console_sink(old_id);
        }
        self.console_sink_id = Some(new_id);
        Ok(())
      }
      None => {
        self.set_console_sink_id_on_console_obj(None)?;

        if let Some(old_id) = old_id {
          unregister_console_sink(old_id);
        }
        self.console_sink_id = None;
        Ok(())
      }
    }
  }

  fn set_console_sink_id_on_console_obj(&mut self, sink_id: Option<u64>) -> Result<(), VmError> {
    let console_obj = self.console_obj;
    let sink_key_s = self.console_sink_id_key_s;

    let (_vm, _realm, heap) = self.vm_realm_and_heap_mut();
    let mut scope = heap.scope();
    if !scope.heap().is_valid_object(console_obj) || !scope.heap().is_valid_string(sink_key_s) {
      return Ok(());
    }

    // Ensure the console object + sink key survive any allocation/GC triggered by `define_property`.
    scope.push_root(Value::Object(console_obj))?;
    scope.push_root(Value::String(sink_key_s))?;

    let sink_key = PropertyKey::from_string(sink_key_s);
    match sink_id {
      Some(id) => scope.define_property(
        console_obj,
        sink_key,
        data_desc(Value::Number(id as f64)),
      ),
      None => {
        let _ = scope.ordinary_delete(console_obj, sink_key)?;
        Ok(())
      }
    }
  }

  /// Updates the realm's [`MediaContext`], backing `matchMedia()` and other environment shims.
  ///
  /// Returns the internal `match_media_env_id` used by the `window_env` registry when present (real
  /// window realms), or `None` for minimal realms without `matchMedia` shims.
  pub fn set_media_context(&mut self, media: MediaContext) -> Option<u64> {
    let id = self.match_media_env_id?;
    set_match_media_env_media(id, media);
    Some(id)
  }

  pub fn module_loader_handle(&self) -> ModuleLoaderHandle {
    Rc::clone(&self.module_loader)
  }

  /// Mark this realm as a privileged chrome realm.
  ///
  /// When enabled, `window.location` navigations are restricted to internal schemes (`chrome:` and
  /// `about:`) as a defense-in-depth measure: privileged chrome pages must not be able to navigate
  /// themselves to untrusted network content via `window.location`.
  pub fn set_privileged_chrome_realm(&mut self, privileged: bool) {
    if let Some(data) = self.runtime.vm.user_data_mut::<WindowRealmUserData>() {
      data.privileged_chrome_realm = privileged;
    }
  }

  /// Returns and clears any `window.location` navigation request emitted by scripts.
  pub fn take_pending_navigation_request(&mut self) -> Option<LocationNavigationRequest> {
    self
      .runtime
      .vm
      .user_data_mut::<WindowRealmUserData>()
      .and_then(|data| data.pending_navigation.take())
  }

  /// Restore `location.href` to the current document URL.
  ///
  /// `window.location` APIs update the location object's internal href slot before the embedding
  /// commits navigation. When a navigation is canceled (for example by a `beforeunload` handler),
  /// embeddings should call this to keep `location.href` consistent with the still-active document.
  pub fn restore_location_url_to_document_url(&mut self) -> Result<(), VmError> {
    let (document_url, location_obj) = {
      let Some(data) = self.runtime.vm.user_data_mut::<WindowRealmUserData>() else {
        return Ok(());
      };
      (data.document_url.clone(), data.location_obj)
    };
    let Some(location_obj) = location_obj else {
      return Ok(());
    };

    let (_vm, _realm, heap) = self.runtime.vm_realm_and_heap_mut();
    let mut scope = heap.scope();
    scope.push_root(Value::Object(location_obj))?;

    let url_s = scope.alloc_string(&document_url)?;
    scope.push_root(Value::String(url_s))?;

    let location_url_key = alloc_key(&mut scope, LOCATION_URL_KEY)?;
    scope.define_property(location_obj, location_url_key, data_desc(Value::String(url_s)))?;
    Ok(())
  }

  /// Dispatch a DOM `Event` with the given type at a specific DOM node.
  ///
  /// This is intended for host-side engines (e.g. a media playback engine) to surface events like
  /// `timeupdate`, `ended`, and `error` into the JS realm, targeting a particular
  /// `HTMLMediaElement`.
  ///
  /// Best-effort: if the node is no longer present in the backing DOM (stale `NodeId`), the event
  /// is ignored and `Ok(())` is returned.
  pub fn dispatch_media_event(
    &mut self,
    host: &mut dyn VmHost,
    hooks: &mut dyn VmHostHooks,
    document_obj: GcObject,
    node_id: NodeId,
    type_: &str,
  ) -> Result<(), VmError> {
    let realm_id = self.realm_id;
    self.with_vm_budget(|rt| {
      let (vm, _realm, heap) = rt.vm_realm_and_heap_mut();
      let mut scope = heap.scope();
      let mut vm = vm.execution_context_guard(vm_js::ExecutionContext {
        realm: realm_id,
        script_or_module: None,
      })?;

      let document_id = gc_object_id(document_obj);
      let Some(dom_ptr) = dom_ptr_for_document_id_read(&mut vm, host, document_id) else {
        return Ok(());
      };
      // SAFETY: `dom_ptr` is derived from the caller-provided `VmHost` and remains valid for the
      // duration of this call.
      let dom = unsafe { dom_ptr.as_ref() };
      if dom.node_id_from_index(node_id.index()).is_err() {
        return Ok(());
      }

      // Obtain the JS wrapper for the target node.
      let target_value =
        get_or_create_node_wrapper(&mut vm, &mut scope, document_obj, Some(dom), node_id)?;
      let Value::Object(target_obj) = target_value else {
        return Ok(());
      };
      scope.push_root(Value::Object(target_obj))?;

      // Construct a branded `Event` instance with the requested type.
      let event_obj = scope.alloc_object()?;
      scope.push_root(Value::Object(event_obj))?;

      // Inherit from the internal `Event.prototype` stored on the document wrapper so
      // `instanceof Event` and prototype methods behave as expected even when the global `Event`
      // constructor is overwritten.
      scope.push_root(Value::Object(document_obj))?;
      let event_proto_key = alloc_key(&mut scope, EVENT_PROTOTYPE_KEY)?;
      if let Some(Value::Object(proto_obj)) =
        scope
          .heap()
          .object_get_own_data_property_value(document_obj, &event_proto_key)?
      {
        scope.heap_mut().object_set_prototype(event_obj, Some(proto_obj))?;
      }

      let type_s = scope.alloc_string(type_)?;
      scope.push_root(Value::String(type_s))?;
      let type_key = alloc_key(&mut scope, "type")?;
      scope.define_property(event_obj, type_key, read_only_data_desc(Value::String(type_s)))?;
      let bubbles_key = alloc_key(&mut scope, "bubbles")?;
      scope.define_property(event_obj, bubbles_key, read_only_data_desc(Value::Bool(false)))?;
      let cancelable_key = alloc_key(&mut scope, "cancelable")?;
      scope.define_property(
        event_obj,
        cancelable_key,
        read_only_data_desc(Value::Bool(false)),
      )?;
      let composed_key = alloc_key(&mut scope, "composed")?;
      scope.define_property(event_obj, composed_key, read_only_data_desc(Value::Bool(false)))?;

      define_event_default_properties(&mut scope, event_obj)?;
      let initialized_key = alloc_key(&mut scope, EVENT_INITIALIZED_KEY)?;
      scope.define_property(event_obj, initialized_key, data_desc(Value::Bool(true)))?;
      brand_event_object(&mut scope, event_obj, BrandedEventKind::Event)?;

      let _ = event_target_dispatch_event_dom2(
        &mut vm,
        &mut scope,
        host,
        hooks,
        target_obj,
        &[Value::Object(event_obj)],
      )?;

      Ok(())
    })
  }

  /// Execute a classic script in this window realm.
  pub fn exec_script(&mut self, source: &str) -> Result<Value, VmError> {
    self.exec_script_with_name("<inline>", source)
  }

  /// Execute a classic script in this window realm with an explicit embedder host context and host
  /// hook implementation.
  ///
  /// This routes Promise jobs through `VmHostHooks::host_enqueue_promise_job` instead of the
  /// VM-owned microtask queue used by [`WindowRealm::exec_script`].
  pub fn exec_script_with_host_and_hooks(
    &mut self,
    host: &mut dyn VmHost,
    hooks: &mut dyn VmHostHooks,
    source: &str,
  ) -> Result<Value, VmError> {
    let source = {
      let (_vm, _realm, heap) = self.runtime.vm_realm_and_heap_mut();
      SourceText::new_charged_arc(heap, "<inline>", source)?
    };
    self.exec_script_source_with_host_and_hooks(host, hooks, source)
  }

  /// Execute a classic script in this window realm with an explicit source name, embedder host
  /// context, and host hook implementation.
  ///
  /// This is the named counterpart to [`WindowRealm::exec_script_with_host_and_hooks`]. Embeddings
  /// should prefer this when they have a URL-like source name so dynamic `import()` expressions can
  /// resolve relative to the active script rather than the document base URL.
  pub fn exec_script_with_name_and_host_and_hooks<'a>(
    &mut self,
    host: &mut dyn VmHost,
    hooks: &mut dyn VmHostHooks,
    source_name: impl Into<SourceTextInput<'a>>,
    source_text: impl Into<SourceTextInput<'a>>,
  ) -> Result<Value, VmError> {
    let source = {
      let (_vm, _realm, heap) = self.runtime.vm_realm_and_heap_mut();
      SourceText::new_charged_arc(heap, source_name, source_text)?
    };
    self.exec_script_source_with_host_and_hooks(host, hooks, source)
  }

  /// Execute a classic script in this window realm using a custom host hook implementation.
  ///
  /// This routes Promise jobs through `VmHostHooks::host_enqueue_promise_job` instead of the
  /// VM-owned microtask queue used by [`WindowRealm::exec_script`]. Embeddings can use this to
  /// integrate ECMAScript jobs into an HTML-shaped microtask queue.
  pub fn exec_script_with_hooks(
    &mut self,
    hooks: &mut dyn VmHostHooks,
    source: &str,
  ) -> Result<Value, VmError> {
    let source = {
      let (_vm, _realm, heap) = self.runtime.vm_realm_and_heap_mut();
      SourceText::new_charged_arc(heap, "<inline>", source)?
    };
    self.exec_script_source_with_hooks(hooks, source)
  }

  /// Ensure the `window` global object participates in the DOM `EventTarget` prototype chain.
  ///
  /// FastRender models `window` as the realm global object. While the realm global object is
  /// spec-shaped in `vm-js` (`[[Prototype]]` is `%Object.prototype%`), browser `window` objects are
  /// `EventTarget`s. Some curated WPT tests rely on `window instanceof EventTarget`.
  fn ensure_window_inherits_event_target(rt: &mut VmJsRuntime) -> Result<(), VmError> {
    let (_vm, realm, heap) = rt.vm_realm_and_heap_mut();
    let global = realm.global_object();
    let mut scope = heap.scope();
    scope.push_root(Value::Object(global))?;

    let event_target_key = alloc_key(&mut scope, "EventTarget")?;
    let event_target_ctor = scope
      .heap()
      .object_get_own_data_property_value(global, &event_target_key)?
      .unwrap_or(Value::Undefined);
    let Value::Object(event_target_ctor) = event_target_ctor else {
      // Best effort: some test-only realms may not install `EventTarget`.
      return Ok(());
    };
    scope.push_root(Value::Object(event_target_ctor))?;

    let prototype_key = alloc_key(&mut scope, "prototype")?;
    let event_target_proto = scope
      .heap()
      .object_get_own_data_property_value(event_target_ctor, &prototype_key)?
      .unwrap_or(Value::Undefined);
    let Value::Object(event_target_proto) = event_target_proto else {
      return Ok(());
    };
    scope.push_root(Value::Object(event_target_proto))?;

    // `WindowRealm` initialization already wires up `Window.prototype -> EventTarget.prototype`;
    // do not rewrite the global object's immediate prototype when `EventTarget.prototype` is
    // already present in the prototype chain.
    let mut cursor = Some(global);
    while let Some(obj) = cursor {
      if obj == event_target_proto {
        return Ok(());
      }
      cursor = scope.object_get_prototype(obj)?;
    }

    scope
      .heap_mut()
      .object_set_prototype(global, Some(event_target_proto))?;

    Ok(())
  }

  pub(crate) fn exec_script_source_with_host_and_hooks(
    &mut self,
    host: &mut dyn VmHost,
    hooks: &mut dyn VmHostHooks,
    source: Arc<SourceText>,
  ) -> Result<Value, VmError> {
    // Route Promise jobs through host hooks so embeddings can integrate with a host-owned microtask
    // queue (HTML event loop).

    // Keep a stable ScriptId->URL mapping in the realm module loader so dynamic `import()` calls
    // originating from this script (including from Promise jobs and future callbacks created by
    // this script) can resolve relative module specifiers against the script URL.
    //
    // `vm-js` assigns a fresh ScriptId at the start of each `exec_script_*` entrypoint, so we mirror
    // that allocation here to obtain the ScriptId that will be used as the `ModuleReferrer::Script`
    // identity for this run.
    let script_id = vm_js::ScriptId::from_raw(self.next_script_id_raw);

    // Use the script's own URL as the referrer base for dynamic `import()` when the source name is
    // URL-like (external scripts). Otherwise fall back to the document base URL (inline scripts).
    let script_url = if Url::parse(source.name.as_ref()).is_ok() {
      source.name.to_string()
    } else {
      let Some(data) = self.runtime.vm.user_data_mut::<WindowRealmUserData>() else {
        return Err(VmError::InvariantViolation(
          "window realm missing user data",
        ));
      };
      data
        .base_url
        .clone()
        .unwrap_or_else(|| data.document_url.clone())
    };

    let module_loader = Rc::clone(&self.module_loader);
    let did_consume_script_id = std::cell::Cell::new(false);
    let did_consume_script_id = &did_consume_script_id;

    let result = self.with_vm_budget(move |rt| {
      Self::ensure_window_inherits_event_target(rt)?;

      {
        let mut loader = module_loader
          .try_borrow_mut()
          .map_err(|_| VmError::InvariantViolation("module loader already borrowed"))?;
        loader.register_script_url(script_id, script_url)?;
      }

      did_consume_script_id.set(true);
      let result = rt.exec_script_source_with_host_and_hooks(host, hooks, source);

      let drain_result = {
        let mut scope = rt.heap.scope();
        drain_pending_dataset_mutation_observer_microtasks(&mut rt.vm, &mut scope, host, hooks)
      };
      if result.is_ok() {
        drain_result?;
      }

      result
    });

    if did_consume_script_id.get() {
      self.next_script_id_raw = self.next_script_id_raw.wrapping_add(1);
    }

    result
  }

  pub(crate) fn exec_script_source_with_hooks(
    &mut self,
    hooks: &mut dyn VmHostHooks,
    source: Arc<SourceText>,
  ) -> Result<Value, VmError> {
    // When the embedder doesn't provide a real host context, execute against a lightweight host
    // value.
    //
    // IMPORTANT: we intentionally do not use `DocumentHostState` here. A per-call `DocumentHostState`
    // would carry a fresh `dom2::Document`, which would:
    // - lose `addEventListener` registrations across turns, and
    // - incorrectly drop any asynchronously-dispatched events (e.g. `hashchange` fallback delivery).
    //
    // Instead, event listeners fall back to the realm-owned `events_dom_fallback` document stored in
    // `WindowRealmUserData`, which persists for the lifetime of the realm.
    let mut host_ctx = VmJsHostContext::default();
    self.exec_script_source_with_host_and_hooks(&mut host_ctx, hooks, source)
  }

  /// Execute a classic script with an explicit source name for stack traces.
  pub fn exec_script_with_name<'a>(
    &mut self,
    source_name: impl Into<SourceTextInput<'a>>,
    source_text: impl Into<SourceTextInput<'a>>,
  ) -> Result<Value, VmError> {
    let webidl_bindings_host = self.webidl_bindings_host;
    let webidl_limits = self.js_execution_options.webidl_limits;

    let script_id = vm_js::ScriptId::from_raw(self.next_script_id_raw);
    let module_loader = Rc::clone(&self.module_loader);
    let did_consume_script_id = std::cell::Cell::new(false);
    let did_consume_script_id = &did_consume_script_id;

    // The `vm-js` default `exec_script` path uses the VM-owned microtask queue as the active
    // `VmHostHooks` implementation. That queue does not provide FastRender's DOM shims (like
    // `Element.dataset`), which rely on `VmHostHooks::{host_exotic_get,host_exotic_set,host_exotic_delete}`.
    //
    // Install a lightweight host hook wrapper for the duration of the run, while still preserving
    // the VM-owned microtask queue for Promise jobs.

    struct MicrotaskQueueRestoreGuard {
      vm: *mut Vm,
      queue: vm_js::MicrotaskQueue,
    }

    impl MicrotaskQueueRestoreGuard {
      fn new(vm: &mut Vm) -> Self {
        let queue = std::mem::take(vm.microtask_queue_mut());
        Self {
          vm: vm as *mut Vm,
          queue,
        }
      }
    }

    impl Drop for MicrotaskQueueRestoreGuard {
      fn drop(&mut self) {
        // SAFETY: the guard is only constructed from a live `&mut Vm` owned by the current realm.
        // It is dropped before the realm (and its VM) can be dropped.
        let vm = unsafe { &mut *self.vm };
        *vm.microtask_queue_mut() = std::mem::take(&mut self.queue);
      }
    }

    struct WindowRealmDomShimHooks<'a> {
      microtasks: &'a mut vm_js::MicrotaskQueue,
      any: VmJsHostHooksPayload,
      dataset_ctx: DatasetExoticContext,
    }

    impl vm_js::VmHostHooks for WindowRealmDomShimHooks<'_> {
      fn host_enqueue_promise_job(&mut self, job: vm_js::Job, realm: Option<vm_js::RealmId>) {
        self.microtasks.enqueue_promise_job(job, realm);
      }

      fn host_exotic_get(
        &mut self,
        scope: &mut Scope<'_>,
        obj: GcObject,
        key: PropertyKey,
        receiver: Value,
      ) -> Result<Option<Value>, VmError> {
        dispatch_host_exotic_get(scope, &mut self.any, &self.dataset_ctx, obj, key, receiver)
      }

      fn host_exotic_set(
        &mut self,
        scope: &mut Scope<'_>,
        obj: GcObject,
        key: PropertyKey,
        value: Value,
        receiver: Value,
      ) -> Result<Option<bool>, VmError> {
        Ok(
          dispatch_host_exotic_set(
            scope,
            &mut self.any,
            &self.dataset_ctx,
            obj,
            key,
            value,
            receiver,
          )?
          .handled,
        )
      }

      fn host_exotic_delete(
        &mut self,
        scope: &mut Scope<'_>,
        obj: GcObject,
        key: PropertyKey,
      ) -> Result<Option<bool>, VmError> {
        Ok(
          dispatch_host_exotic_delete(scope, &mut self.any, &self.dataset_ctx, obj, key)?.handled,
        )
      }

      fn host_call_job_callback(
        &mut self,
        ctx: &mut dyn vm_js::VmJobContext,
        callback: &vm_js::JobCallback,
        this_argument: Value,
        arguments: &[Value],
      ) -> Result<Value, VmError> {
        // Mirror `vm-js`'s built-in `MicrotaskQueue` implementation, but pass `self` so queued jobs
        // see the same DOM shim host hooks as the originating script.
        ctx.call(
          self,
          Value::Object(callback.callback_object()),
          this_argument,
          arguments,
        )
      }

      fn as_any_mut(&mut self) -> Option<&mut dyn std::any::Any> {
        Some(&mut self.any)
      }
    }

    let result = self.with_vm_budget(move |rt| {
      let source = SourceText::new_charged_arc(&mut rt.heap, source_name, source_text)?;

      // Use the script's own URL as the referrer base for dynamic `import()` when the source name
      // is URL-like (external scripts). Otherwise fall back to the document base URL (inline
      // scripts).
      let script_url = if Url::parse(source.name.as_ref()).is_ok() {
        source.name.to_string()
      } else {
        let Some(data) = rt.vm.user_data_mut::<WindowRealmUserData>() else {
          return Err(VmError::InvariantViolation(
            "window realm missing user data",
          ));
        };
        data
          .base_url
          .clone()
          .unwrap_or_else(|| data.document_url.clone())
      };

      {
        let mut loader = module_loader
          .try_borrow_mut()
          .map_err(|_| VmError::InvariantViolation("module loader already borrowed"))?;
        loader.register_script_url(script_id, script_url)?;
      }

      // Temporarily move the VM-owned microtask queue out so we can both:
      // - expose DOM shim exotic hooks to the evaluator, and
      // - keep Promise jobs enqueued onto the VM-owned queue (restored on drop).
      let mut guard = MicrotaskQueueRestoreGuard::new(&mut rt.vm);
      let mut host_ctx = VmJsHostContext::default();
      let mut any = VmJsHostHooksPayload::default();
      any.set_vm_host(&mut host_ctx);
      any.set_webidl_limits(webidl_limits);
      let mut fallback_webidl_bindings_host = WindowRealmWebIdlBindingsHost::default();
      if let Some(mut host_ptr) = webidl_bindings_host {
        // SAFETY: The pointer is only installed via `WindowRealm::with_webidl_bindings_host` for the
        // dynamic extent of that call.
        let bindings_host: &mut dyn WebIdlBindingsHost = unsafe { host_ptr.as_mut() };
        any.webidl_bindings_host_slot_mut().set(bindings_host);
      } else {
        any
          .webidl_bindings_host_slot_mut()
          .set(&mut fallback_webidl_bindings_host);
      }
      let dataset_ctx = DatasetExoticContext::for_vm(&rt.vm);
      let mut hooks = WindowRealmDomShimHooks {
        microtasks: &mut guard.queue,
        any,
        dataset_ctx,
      };
      did_consume_script_id.set(true);
      let result = rt.exec_script_source_with_host_and_hooks(&mut host_ctx, &mut hooks, source);
      let drain_result = {
        let mut scope = rt.heap.scope();
        drain_pending_dataset_mutation_observer_microtasks(&mut rt.vm, &mut scope, &mut host_ctx, &mut hooks)
      };
      if result.is_ok() {
        drain_result?;
      }
      // Ensure the locally-created fallback bindings host outlives the JS execution boundary: the
      // hooks payload stores a raw pointer to it.
      let _ = &mut fallback_webidl_bindings_host;
      result
    });

    if did_consume_script_id.get() {
      self.next_script_id_raw = self.next_script_id_raw.wrapping_add(1);
    }

    result
  }

  fn with_vm_budget<T>(
    &mut self,
    f: impl FnOnce(&mut VmJsRuntime) -> Result<T, VmError>,
  ) -> Result<T, VmError> {
    let budget = self.vm_budget_now();
    let prev_budget = self.runtime.vm.swap_budget_state(budget);
    let result = (|| {
      // Ensure immediate termination when no budget remains (deadline exceeded, interrupted, etc).
      self.runtime.vm.tick()?;
      f(&mut self.runtime)
    })();
    self.runtime.vm.restore_budget_state(prev_budget);
    result
  }

  pub fn perform_microtask_checkpoint(&mut self) -> Result<(), VmError> {
    let webidl_bindings_host = self.webidl_bindings_host;
    let webidl_limits = self.js_execution_options.webidl_limits;
    let realm_id = self.realm_id;
    self.with_vm_budget(|rt| {
      // `vm-js`'s built-in `Vm::perform_microtask_checkpoint` runs queued jobs using a lightweight
      // internal `VmHostHooks` implementation that only supports Promise job chaining. FastRender's
      // DOM shims (notably `Element.dataset`) rely on `VmHostHooks::{host_exotic_get,host_exotic_set,host_exotic_delete}`.
      //
      // When embedders use `WindowRealm` directly (without the higher-level `EventLoop`/`WindowHost`
      // pipeline), we still want Promise callbacks to behave like script execution and see the same
      // DOM shim host hooks.

      if !rt.vm.microtask_queue_mut().begin_checkpoint() {
        return Ok(());
      }

      struct DomShimMicrotaskHooks {
        any: VmJsHostHooksPayload,
        pending: Vec<(Option<RealmId>, vm_js::Job)>,
        dataset_ctx: DatasetExoticContext,
      }

      impl DomShimMicrotaskHooks {
        fn new(
          host_ctx: &mut dyn VmHost,
          dataset_ctx: DatasetExoticContext,
          webidl_limits: webidl::WebIdlLimits,
        ) -> Self {
          let mut any = VmJsHostHooksPayload::default();
          any.set_vm_host(host_ctx);
          any.set_webidl_limits(webidl_limits);
          Self {
            any,
            pending: Vec::new(),
            dataset_ctx,
          }
        }

        fn drain_into(&mut self, queue: &mut vm_js::MicrotaskQueue) {
          for (realm, job) in self.pending.drain(..) {
            queue.enqueue_promise_job(job, realm);
          }
        }
      }

      impl VmHostHooks for DomShimMicrotaskHooks {
        fn host_enqueue_promise_job(&mut self, job: vm_js::Job, realm: Option<RealmId>) {
          self.pending.push((realm, job));
        }

        fn host_exotic_get(
          &mut self,
          scope: &mut Scope<'_>,
          obj: GcObject,
          key: PropertyKey,
          receiver: Value,
        ) -> Result<Option<Value>, VmError> {
          dispatch_host_exotic_get(scope, &mut self.any, &self.dataset_ctx, obj, key, receiver)
        }

        fn host_exotic_set(
          &mut self,
          scope: &mut Scope<'_>,
          obj: GcObject,
          key: PropertyKey,
          value: Value,
          receiver: Value,
        ) -> Result<Option<bool>, VmError> {
          Ok(
            dispatch_host_exotic_set(
              scope,
              &mut self.any,
              &self.dataset_ctx,
              obj,
              key,
              value,
              receiver,
            )?
            .handled,
          )
        }

        fn host_exotic_delete(
          &mut self,
          scope: &mut Scope<'_>,
          obj: GcObject,
          key: PropertyKey,
        ) -> Result<Option<bool>, VmError> {
          Ok(dispatch_host_exotic_delete(scope, &mut self.any, &self.dataset_ctx, obj, key)?.handled)
        }

        fn host_call_job_callback(
          &mut self,
          ctx: &mut dyn vm_js::VmJobContext,
          callback: &vm_js::JobCallback,
          this_argument: Value,
          arguments: &[Value],
        ) -> Result<Value, VmError> {
          ctx.call(
            self,
            Value::Object(callback.callback_object()),
            this_argument,
            arguments,
          )
        }

        fn as_any_mut(&mut self) -> Option<&mut dyn std::any::Any> {
          Some(&mut self.any)
        }
      }

      struct Ctx<'a> {
        vm: &'a mut Vm,
        heap: &'a mut Heap,
        host: &'a mut dyn VmHost,
        realm: Option<RealmId>,
      }

      impl vm_js::VmJobContext for Ctx<'_> {
        fn call(
          &mut self,
          hooks: &mut dyn VmHostHooks,
          callee: Value,
          this: Value,
          args: &[Value],
        ) -> Result<Value, VmError> {
          let mut scope = self.heap.scope();
          if let Some(realm) = self.realm {
            let mut vm = self
              .vm
              .execution_context_guard(vm_js::ExecutionContext {
                realm,
                script_or_module: None,
              })?;
            vm.call_with_host_and_hooks(&mut *self.host, &mut scope, hooks, callee, this, args)
          } else {
            self
              .vm
              .call_with_host_and_hooks(&mut *self.host, &mut scope, hooks, callee, this, args)
          }
        }

        fn construct(
          &mut self,
          hooks: &mut dyn VmHostHooks,
          callee: Value,
          args: &[Value],
          new_target: Value,
        ) -> Result<Value, VmError> {
          let mut scope = self.heap.scope();
          if let Some(realm) = self.realm {
            let mut vm = self
              .vm
              .execution_context_guard(vm_js::ExecutionContext {
                realm,
                script_or_module: None,
              })?;
            vm.construct_with_host_and_hooks(
              &mut *self.host,
              &mut scope,
              hooks,
              callee,
              args,
              new_target,
            )
          } else {
            self.vm.construct_with_host_and_hooks(
              &mut *self.host,
              &mut scope,
              hooks,
              callee,
              args,
              new_target,
            )
          }
        }

        fn add_root(&mut self, value: Value) -> Result<vm_js::RootId, VmError> {
          self.heap.add_root(value)
        }

        fn remove_root(&mut self, id: vm_js::RootId) {
          self.heap.remove_root(id);
        }
      }

      struct TeardownCtx<'a> {
        heap: &'a mut Heap,
      }

      impl vm_js::VmJobContext for TeardownCtx<'_> {
        fn call(
          &mut self,
          _hooks: &mut dyn VmHostHooks,
          _callee: Value,
          _this: Value,
          _args: &[Value],
        ) -> Result<Value, VmError> {
          Err(VmError::Unimplemented("TeardownCtx::call"))
        }

        fn construct(
          &mut self,
          _hooks: &mut dyn VmHostHooks,
          _callee: Value,
          _args: &[Value],
          _new_target: Value,
        ) -> Result<Value, VmError> {
          Err(VmError::Unimplemented("TeardownCtx::construct"))
        }

        fn add_root(&mut self, value: Value) -> Result<vm_js::RootId, VmError> {
          self.heap.add_root(value)
        }

        fn remove_root(&mut self, id: vm_js::RootId) {
          self.heap.remove_root(id);
        }
      }

      // Use a lightweight `VmHost` context for Promise job execution when the higher-level
      // `WindowHost`/event-loop pipeline is not in use.
      //
      // `VmJsHostContext` is a stable downcast target for host-side state needed by some DOM
      // algorithms (currently: `Document.currentScript` bookkeeping).
      let mut host_ctx = VmJsHostContext::default();
      let dataset_ctx = DatasetExoticContext::for_vm(&rt.vm);
      let mut hooks = DomShimMicrotaskHooks::new(&mut host_ctx, dataset_ctx, webidl_limits);
      let mut fallback_webidl_bindings_host = WindowRealmWebIdlBindingsHost::default();
      if let Some(mut host_ptr) = webidl_bindings_host {
        // SAFETY: The pointer is only installed via `WindowRealm::with_webidl_bindings_host` around
        // this call boundary.
        let bindings_host: &mut dyn WebIdlBindingsHost = unsafe { host_ptr.as_mut() };
        hooks
          .any
          .webidl_bindings_host_slot_mut()
          .set(bindings_host);
      } else {
        hooks
          .any
          .webidl_bindings_host_slot_mut()
          .set(&mut fallback_webidl_bindings_host);
      }

      let mut first_err: Option<VmError> = None;
      let mut hard_stop_err: Option<VmError> = None;

      loop {
        let Some((realm, job)) = rt.vm.microtask_queue_mut().pop_front() else {
          break;
        };

        let job_result = {
          let mut ctx = Ctx {
            vm: &mut rt.vm,
            heap: &mut rt.heap,
            host: &mut host_ctx,
            realm,
          };
          job.run(&mut ctx, &mut hooks)
        };

        // Some job types may schedule new Promise jobs via `VmHostHooks`; enqueue them into the VM's
        // microtask queue before proceeding (or before discarding the remaining queue on
        // termination).
        hooks.drain_into(rt.vm.microtask_queue_mut());

        match job_result {
          Ok(()) => {}
          Err(e @ (VmError::Termination(_) | VmError::OutOfMemory)) => {
            hard_stop_err = Some(e);
            break;
          }
          Err(e) => {
            if first_err.is_none() {
              first_err = Some(e);
            }
          }
        }
      }

      if let Some(err) = hard_stop_err {
        // Hard stop: discard any remaining queued jobs (and any jobs enqueued by the failing job)
        // so we don't leak persistent roots.
        let mut ctx = TeardownCtx { heap: &mut rt.heap };
        rt.vm.microtask_queue_mut().teardown(&mut ctx);
        rt.vm.microtask_queue_mut().end_checkpoint();
        // Ensure the locally-created fallback bindings host outlives the microtask checkpoint: the
        // hooks payload stores a raw pointer to it.
        let _ = &mut fallback_webidl_bindings_host;
        return Err(err);
      }

      let mut termination_err: Option<VmError> = None;

      // Drain and dispatch any pending fallback `hashchange` events queued while running without an
      // HTML `EventLoop` (for example when embedders use `WindowRealm` directly).
      //
      // We take a snapshot of the queue so `hashchange` listeners that trigger further fragment
      // navigations still see asynchronous delivery: events queued during dispatch will remain
      // pending until the next explicit checkpoint.
      let mut pending_hashchange_events: VecDeque<QueuedHashChangeEvent> = rt
        .vm
        .user_data_mut::<WindowRealmUserData>()
        .map(|data| std::mem::take(&mut data.pending_hashchange_events))
        .unwrap_or_default();

      while let Some(event) = pending_hashchange_events.pop_front() {
        let dispatch_result: Result<(), VmError> = (|| {
          let (vm, realm, heap) = rt.vm_realm_and_heap_mut();
          let mut scope = heap.scope();
          let mut vm = vm.execution_context_guard(vm_js::ExecutionContext {
            realm: realm_id,
            script_or_module: None,
          })?;
          dispatch_hashchange_event(
            &mut vm,
            &mut scope,
            &mut host_ctx,
            &mut hooks,
            realm.global_object(),
            &event.old_url,
            &event.new_url,
          )
        })();

        // Ensure any Promise jobs scheduled during dispatch are enqueued before continuing (or
        // before teardown on termination).
        hooks.drain_into(rt.vm.microtask_queue_mut());

        match dispatch_result {
          Ok(()) => {}
          Err(e @ (VmError::Termination(_) | VmError::OutOfMemory)) => {
            termination_err = Some(e);
            // Re-queue the current + remaining events so a future checkpoint can retry delivery.
            pending_hashchange_events.push_front(event);
            break;
          }
          Err(e) => {
            if first_err.is_none() {
              first_err = Some(e);
            }
          }
        }
      }

      if !pending_hashchange_events.is_empty() {
        if let Some(data) = rt.vm.user_data_mut::<WindowRealmUserData>() {
          let mut queued_during_dispatch = std::mem::take(&mut data.pending_hashchange_events);
          data.pending_hashchange_events = pending_hashchange_events;
          data
            .pending_hashchange_events
            .append(&mut queued_during_dispatch);
          while data.pending_hashchange_events.len() > MAX_PENDING_HASHCHANGE_EVENTS {
            data.pending_hashchange_events.pop_front();
          }
        }
      }

      if let Some(err) = termination_err {
        // Termination during `hashchange` dispatch is also a hard stop: discard any queued microtasks
        // to avoid leaking persistent roots.
        let mut ctx = TeardownCtx { heap: &mut rt.heap };
        rt.vm.microtask_queue_mut().teardown(&mut ctx);
        rt.vm.microtask_queue_mut().end_checkpoint();
        // Ensure the locally-created fallback bindings host outlives the microtask checkpoint: the
        // hooks payload stores a raw pointer to it.
        let _ = &mut fallback_webidl_bindings_host;
        return Err(err);
      }

      // Drain any Promise jobs queued during fallback event dispatch so callers see a fully-drained
      // microtask queue after the checkpoint.
      loop {
        let Some((realm, job)) = rt.vm.microtask_queue_mut().pop_front() else {
          break;
        };

        let job_result = {
          let mut ctx = Ctx {
            vm: &mut rt.vm,
            heap: &mut rt.heap,
            host: &mut host_ctx,
            realm,
          };
          job.run(&mut ctx, &mut hooks)
        };

        hooks.drain_into(rt.vm.microtask_queue_mut());

        match job_result {
          Ok(()) => {}
          Err(e @ (VmError::Termination(_) | VmError::OutOfMemory)) => {
            termination_err = Some(e);
            break;
          }
          Err(e) => {
            if first_err.is_none() {
              first_err = Some(e);
            }
          }
        }
      }

      if let Some(err) = termination_err {
        let mut ctx = TeardownCtx { heap: &mut rt.heap };
        rt.vm.microtask_queue_mut().teardown(&mut ctx);
        rt.vm.microtask_queue_mut().end_checkpoint();
        // Ensure the locally-created fallback bindings host outlives the microtask checkpoint: the
        // hooks payload stores a raw pointer to it.
        let _ = &mut fallback_webidl_bindings_host;
        return Err(err);
      }

      rt.vm.microtask_queue_mut().end_checkpoint();
      // Ensure the locally-created fallback bindings host outlives the microtask checkpoint: the
      // hooks payload stores a raw pointer to it.
      let _ = &mut fallback_webidl_bindings_host;
      match first_err {
        Some(err) => Err(err),
        None => Ok(()),
      }
    })
  }
}

pub trait WindowRealmHost {
  /// Borrow-splits the host into:
  /// - a mutable `VmHost` context for native calls, and
  /// - a mutable `WindowRealm` for script/job execution.
  ///
  /// Implementations must ensure these borrows do not alias.
  fn vm_host_and_window_realm(
    &mut self,
  ) -> crate::error::Result<(&mut dyn VmHost, &mut WindowRealm)>;

  fn webidl_bindings_host(&mut self) -> Option<&mut dyn WebIdlBindingsHost> {
    None
  }

  fn window_realm(&mut self) -> crate::error::Result<&mut WindowRealm> {
    let (_, realm) = self.vm_host_and_window_realm()?;
    Ok(realm)
  }

  fn vm_host(&mut self) -> crate::error::Result<&mut dyn VmHost> {
    let (host, _) = self.vm_host_and_window_realm()?;
    Ok(host)
  }
}

impl Drop for WindowRealm {
  fn drop(&mut self) {
    self.heap_alive.store(false, Ordering::Relaxed);
    self.teardown();
  }
}

fn data_desc(value: Value) -> PropertyDescriptor {
  PropertyDescriptor {
    enumerable: false,
    configurable: true,
    kind: PropertyKind::Data {
      value,
      writable: true,
    },
  }
}

fn enumerable_data_desc(value: Value) -> PropertyDescriptor {
  PropertyDescriptor {
    enumerable: true,
    configurable: true,
    kind: PropertyKind::Data {
      value,
      writable: true,
    },
  }
}

fn read_only_data_desc(value: Value) -> PropertyDescriptor {
  PropertyDescriptor {
    enumerable: false,
    configurable: true,
    kind: PropertyKind::Data {
      value,
      writable: false,
    },
  }
}

fn non_configurable_read_only_data_desc(value: Value) -> PropertyDescriptor {
  PropertyDescriptor {
    enumerable: false,
    configurable: false,
    kind: PropertyKind::Data {
      value,
      writable: false,
    },
  }
}

fn ctor_link_desc(value: Value) -> PropertyDescriptor {
  non_configurable_read_only_data_desc(value)
}

fn const_desc(value: Value) -> PropertyDescriptor {
  PropertyDescriptor {
    enumerable: true,
    configurable: false,
    kind: PropertyKind::Data {
      value,
      writable: false,
    },
  }
}

fn idl_attribute_desc(get: Value, set: Value) -> PropertyDescriptor {
  PropertyDescriptor {
    // Keep handcrafted DOM attributes aligned with the WebIDL vm-js runtime defaults
    // (`AccessorPropertyAttributes::ATTRIBUTE`).
    enumerable: true,
    configurable: true,
    kind: PropertyKind::Accessor { get, set },
  }
}
fn create_error(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  ctor: GcObject,
  message: &str,
) -> Result<Value, VmError> {
  let msg = scope.alloc_string(message)?;
  scope.push_root(Value::String(msg))?;
  vm.construct_with_host_and_hooks(
    host,
    scope,
    hooks,
    Value::Object(ctor),
    &[Value::String(msg)],
    Value::Object(ctor),
  )
}

#[cfg(test)]
pub(crate) fn test_only_create_error(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  ctor: GcObject,
  message: &str,
) -> Result<Value, VmError> {
  create_error(vm, scope, host, hooks, ctor, message)
}

fn throw_type_error(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  message: &str,
) -> VmError {
  let intr = match vm.intrinsics() {
    Some(intr) => intr,
    None => return VmError::TypeError("TypeError requires intrinsics (create a Realm first)"),
  };
  match create_error(vm, scope, host, hooks, intr.type_error(), message) {
    Ok(err) => VmError::Throw(err),
    Err(_) => VmError::Throw(Value::Undefined),
  }
}

fn alloc_key(scope: &mut Scope<'_>, name: &str) -> Result<PropertyKey, VmError> {
  let s = scope.alloc_string(name)?;
  scope.push_root(Value::String(s))?;
  Ok(PropertyKey::from_string(s))
}

fn illegal_dom_constructor_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  _this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  Err(throw_type_error(
    vm,
    scope,
    host,
    hooks,
    "Illegal constructor",
  ))
}

fn illegal_dom_constructor_construct_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  callee: GcObject,
  args: &[Value],
  new_target: Value,
) -> Result<Value, VmError> {
  let ctor = match new_target {
    Value::Object(obj) => obj,
    _ => callee,
  };
  illegal_dom_constructor_native(vm, scope, host, hooks, ctor, Value::Undefined, args)
}

// WebIDL legacy callback interface object call handler.
//
// NodeFilter is a callback interface with constants, so WebIDL exposes it as a *function object*
// (not a plain object) whose call path throws TypeError.
fn node_filter_legacy_callback_interface_object_native(
  _vm: &mut Vm,
  _scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  _this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  Err(VmError::TypeError(""))
}

fn document_constructor_native(
  _vm: &mut Vm,
  _scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  _this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  Err(VmError::TypeError(
    "Document constructor cannot be invoked without 'new'",
  ))
}

fn document_constructor_construct_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  _args: &[Value],
  _new_target: Value,
) -> Result<Value, VmError> {
  // Implement `new Document()` by delegating to the realm's existing
  // `document.implementation.createDocument(null, "", null)` machinery so the created document:
  // - is backed by a realm-owned `dom2::Document`,
  // - inherits the same Document surface as the host document, and
  // - behaves like an XML document (needed by curated WPT helpers).
  let document_obj = vm
    .user_data_mut::<WindowRealmUserData>()
    .and_then(|data| data.document_obj)
    .ok_or(VmError::TypeError(
      "Document constructor requires a host-backed WindowRealm",
    ))?;

  let mut scope = scope.reborrow();
  scope.push_root(Value::Object(document_obj))?;
  let implementation_key = alloc_key(&mut scope, "implementation")?;
  let impl_value = scope
    .heap()
    .object_get_own_data_property_value(document_obj, &implementation_key)?
    .unwrap_or(Value::Undefined);
  let Value::Object(impl_obj) = impl_value else {
    return Err(VmError::TypeError(
      "Document constructor requires document.implementation",
    ));
  };

  let args = [Value::Null, Value::Null, Value::Null];
  dom_implementation_create_document_native(
    vm,
    &mut scope,
    host,
    hooks,
    impl_obj,
    Value::Object(impl_obj),
    &args,
  )
}

fn storage_require_this(
  scope: &mut Scope<'_>,
  this: Value,
) -> Result<web_storage::StorageKind, VmError> {
  let Value::Object(obj) = this else {
    return Err(VmError::TypeError(ILLEGAL_INVOCATION_ERROR));
  };

  // `Heap::object_host_slots` only supports ordinary objects/functions. When `this` is another kind
  // (like a Proxy), treat it as unbranded.
  let slots = match scope.heap().object_host_slots(obj) {
    Ok(slots) => slots,
    Err(VmError::InvalidHandle { .. }) if scope.heap().is_valid_object(obj) => None,
    Err(err) => return Err(err),
  };
  let Some(slots) = slots else {
    return Err(VmError::TypeError(ILLEGAL_INVOCATION_ERROR));
  };

  if slots.b != HOST_EXOTIC_STORAGE {
    return Err(VmError::TypeError(ILLEGAL_INVOCATION_ERROR));
  }

  match slots.a {
    0 => Ok(web_storage::StorageKind::Local),
    1 => Ok(web_storage::StorageKind::Session),
    _ => Err(VmError::TypeError(ILLEGAL_INVOCATION_ERROR)),
  }
}

fn history_require_this(this: Value, history_obj: GcObject) -> Result<(), VmError> {
  match this {
    Value::Object(obj) if obj == history_obj => Ok(()),
    _ => Err(VmError::TypeError(ILLEGAL_INVOCATION_ERROR)),
  }
}

fn location_require_this(scope: &Scope<'_>, this: Value) -> Result<GcObject, VmError> {
  let Value::Object(obj) = this else {
    return Err(VmError::TypeError(ILLEGAL_INVOCATION_ERROR));
  };

  // `Heap::object_host_slots` only supports ordinary objects/functions. When `this` is another kind
  // (like a Proxy), treat it as unbranded.
  let slots = match scope.heap().object_host_slots(obj) {
    Ok(slots) => slots,
    Err(VmError::InvalidHandle { .. }) if scope.heap().is_valid_object(obj) => None,
    Err(err) => return Err(err),
  };
  if !matches!(slots, Some(HostSlots { a, .. }) if a == WINDOW_REALM_LOCATION_HOST_TAG) {
    return Err(VmError::TypeError(ILLEGAL_INVOCATION_ERROR));
  }
  Ok(obj)
}

fn storage_to_string(scope: &mut Scope<'_>, value: Value) -> Result<GcString, VmError> {
  let s = match value {
    Value::String(s) => s,
    other => scope.heap_mut().to_string(other)?,
  };
  scope.push_root(Value::String(s))?;
  Ok(s)
}

fn storage_to_index(scope: &mut Scope<'_>, value: Value) -> Result<Option<usize>, VmError> {
  let mut n = scope.heap_mut().to_number(value)?;
  if !n.is_finite() || n.is_nan() {
    n = 0.0;
  }
  let n = n.trunc();
  if n < 0.0 {
    return Ok(None);
  }
  if n >= usize::MAX as f64 {
    return Ok(Some(usize::MAX));
  }
  Ok(Some(n as usize))
}

fn storage_area_from_kind(
  vm: &Vm,
  kind: web_storage::StorageKind,
) -> Result<Arc<Mutex<web_storage::StorageArea>>, VmError> {
  let Some(user_data) = vm.user_data::<WindowRealmUserData>() else {
    return Err(VmError::InvariantViolation(
      "window realm missing user data",
    ));
  };
  Ok(match kind {
    web_storage::StorageKind::Local => Arc::clone(&user_data.local_storage_area),
    web_storage::StorageKind::Session => Arc::clone(&user_data.session_storage_area),
  })
}

#[derive(Clone)]
struct WindowHostStorageEventListener {
  window_id: u64,
  local_storage_area_ptr: usize,
  session_storage_area_ptr: usize,
  task_queue: crate::js::ExternalTaskQueueHandle<WindowHostState>,
}

static WINDOW_HOST_STORAGE_EVENT_LISTENERS: OnceLock<Mutex<Vec<WindowHostStorageEventListener>>> =
  OnceLock::new();

fn window_host_storage_event_listeners() -> &'static Mutex<Vec<WindowHostStorageEventListener>> {
  WINDOW_HOST_STORAGE_EVENT_LISTENERS.get_or_init(|| Mutex::new(Vec::new()))
}

#[derive(Debug)]
pub(crate) struct WindowHostStorageEventListenerGuard {
  window_id: u64,
  active: bool,
}

impl Drop for WindowHostStorageEventListenerGuard {
  fn drop(&mut self) {
    if !self.active {
      return;
    }
    window_host_storage_event_listeners()
      .lock()
      .retain(|entry| entry.window_id != self.window_id);
  }
}

pub(crate) fn register_window_host_storage_event_listener(
  window_id: u64,
  local_storage_area_ptr: usize,
  session_storage_area_ptr: usize,
  task_queue: crate::js::ExternalTaskQueueHandle<WindowHostState>,
) -> WindowHostStorageEventListenerGuard {
  window_host_storage_event_listeners()
    .lock()
    .push(WindowHostStorageEventListener {
      window_id,
      local_storage_area_ptr,
      session_storage_area_ptr,
      task_queue,
    });
  WindowHostStorageEventListenerGuard {
    window_id,
    active: true,
  }
}

#[derive(Clone, Debug)]
struct QueuedStorageEvent {
  key: Option<String>,
  old_value: Option<String>,
  new_value: Option<String>,
  url: String,
  storage_kind: web_storage::StorageKind,
}

fn queue_storage_event_to_other_window_hosts(
  source_window_id: u64,
  storage_area_ptr: usize,
  event: QueuedStorageEvent,
) {
  let queues: Vec<crate::js::ExternalTaskQueueHandle<WindowHostState>> = {
    let lock = window_host_storage_event_listeners().lock();
    lock
      .iter()
      .filter(|entry| entry.window_id != source_window_id)
      .filter(|entry| match event.storage_kind {
        web_storage::StorageKind::Local => entry.local_storage_area_ptr == storage_area_ptr,
        web_storage::StorageKind::Session => entry.session_storage_area_ptr == storage_area_ptr,
      })
      .map(|entry| entry.task_queue.clone())
      .collect()
  };

  for queue in queues {
    let event = event.clone();
    // Best-effort: failing to enqueue should not break the initiating storage mutation.
    let _ = queue.queue_task(TaskSource::DOMManipulation, move |host, event_loop| {
      dispatch_storage_event_task(host, event_loop, event)
    });
  }
}

fn dispatch_storage_event_task<Host: WindowRealmHost + 'static>(
  host: &mut Host,
  event_loop: &mut EventLoop<Host>,
  event: QueuedStorageEvent,
) -> crate::error::Result<()> {
  let mut hooks = VmJsEventLoopHooks::<Host>::new_with_host(host)?;
  hooks.set_event_loop(event_loop);

  let (vm_host, window_realm) = host.vm_host_and_window_realm()?;
  let realm_id = window_realm.realm_id;
  let result = window_realm.with_vm_budget(|rt| {
    let (vm, realm, heap) = rt.vm_realm_and_heap_mut();
    let mut scope = heap.scope();
    let mut vm = vm
      .execution_context_guard(vm_js::ExecutionContext {
        realm: realm_id,
        script_or_module: None,
      })?;
    let window_obj = realm.global_object();

    // Root the window global while allocating keys: `alloc_key` can GC.
    scope.push_root(Value::Object(window_obj))?;

    let dispatch_key = alloc_key(&mut scope, "dispatchEvent")?;
    let dispatch_event =
      vm.get_with_host_and_hooks(vm_host, &mut scope, &mut hooks, window_obj, dispatch_key)?;
    scope.push_root(dispatch_event)?;
    if !scope.heap().is_callable(dispatch_event).unwrap_or(false) {
      return Ok(());
    }

    let init_obj = scope.alloc_object()?;
    scope.push_root(Value::Object(init_obj))?;

    let bubbles_key = alloc_key(&mut scope, "bubbles")?;
    scope.define_property(init_obj, bubbles_key, data_desc(Value::Bool(false)))?;
    let cancelable_key = alloc_key(&mut scope, "cancelable")?;
    scope.define_property(init_obj, cancelable_key, data_desc(Value::Bool(false)))?;
    let composed_key = alloc_key(&mut scope, "composed")?;
    scope.define_property(init_obj, composed_key, data_desc(Value::Bool(false)))?;

    let key_v = match event.key.as_deref() {
      Some(s) => {
        let s = scope.alloc_string(s)?;
        scope.push_root(Value::String(s))?;
        Value::String(s)
      }
      None => Value::Null,
    };
    let key_key = alloc_key(&mut scope, "key")?;
    scope.define_property(init_obj, key_key, data_desc(key_v))?;

    let old_value_v = match event.old_value.as_deref() {
      Some(s) => {
        let s = scope.alloc_string(s)?;
        scope.push_root(Value::String(s))?;
        Value::String(s)
      }
      None => Value::Null,
    };
    let old_value_key = alloc_key(&mut scope, "oldValue")?;
    scope.define_property(init_obj, old_value_key, data_desc(old_value_v))?;

    let new_value_v = match event.new_value.as_deref() {
      Some(s) => {
        let s = scope.alloc_string(s)?;
        scope.push_root(Value::String(s))?;
        Value::String(s)
      }
      None => Value::Null,
    };
    let new_value_key = alloc_key(&mut scope, "newValue")?;
    scope.define_property(init_obj, new_value_key, data_desc(new_value_v))?;

    let url_key = alloc_key(&mut scope, "url")?;
    let url_s = scope.alloc_string(&event.url)?;
    scope.push_root(Value::String(url_s))?;
    scope.define_property(init_obj, url_key, data_desc(Value::String(url_s)))?;

    let storage_obj_key = match event.storage_kind {
      web_storage::StorageKind::Local => alloc_key(&mut scope, "localStorage")?,
      web_storage::StorageKind::Session => alloc_key(&mut scope, "sessionStorage")?,
    };
    let storage_obj =
      vm.get_with_host_and_hooks(vm_host, &mut scope, &mut hooks, window_obj, storage_obj_key)?;
    scope.push_root(storage_obj)?;
    // Keep the storage object properties in sync with the underlying `StorageArea` so enumeration
    // (`Object.keys`, `for...in`, etc.) in other window hosts reflects mutations.
    if let Value::Object(storage_obj) = storage_obj {
      // If user script deletes/replaces `window.localStorage`/`sessionStorage`, be defensive and
      // only sync properties on the real Storage object.
      let slots = match scope.heap().object_host_slots(storage_obj) {
        Ok(slots) => slots,
        Err(VmError::InvalidHandle { .. }) if scope.heap().is_valid_object(storage_obj) => None,
        Err(err) => return Err(err),
      };
      let is_storage = matches!(slots, Some(HostSlots { b, .. }) if b == HOST_EXOTIC_STORAGE);
      if is_storage {
        match (event.key.as_deref(), event.new_value.as_deref()) {
          (Some(key), Some(new_value)) => {
            let key_s = scope.alloc_string(key)?;
            scope.push_root(Value::String(key_s))?;
            let value_s = scope.alloc_string(new_value)?;
            scope.push_root(Value::String(value_s))?;
            storage_sync_key_property(
              &mut scope,
              storage_obj,
              PropertyKey::from_string(key_s),
              Value::String(value_s),
            )?;
          }
          (Some(key), None) => {
            let key_s = scope.alloc_string(key)?;
            scope.push_root(Value::String(key_s))?;
            storage_delete_key_property(&mut scope, storage_obj, PropertyKey::from_string(key_s))?;
          }
          (None, _) => {
            storage_clear_key_properties(&mut scope, storage_obj)?;
          }
        }
      }
    }
    let storage_area_key = alloc_key(&mut scope, "storageArea")?;
    scope.define_property(init_obj, storage_area_key, data_desc(storage_obj))?;

    let (event_obj, needs_payload_define) = make_history_event_object(
      &mut vm,
      &mut scope,
      vm_host,
      &mut hooks,
      window_obj,
      "StorageEvent",
      "storage",
      init_obj,
    )?;
    scope.push_root(Value::Object(event_obj))?;

    if needs_payload_define {
      // `Event` does not expose storage-specific fields; populate them so listeners can observe the
      // mutation even if `StorageEvent` was removed/overridden by user script.
      let key_key = alloc_key(&mut scope, "key")?;
      scope.define_property(event_obj, key_key, read_only_data_desc(key_v))?;
      let old_value_key = alloc_key(&mut scope, "oldValue")?;
      scope.define_property(event_obj, old_value_key, read_only_data_desc(old_value_v))?;
      let new_value_key = alloc_key(&mut scope, "newValue")?;
      scope.define_property(event_obj, new_value_key, read_only_data_desc(new_value_v))?;
      let url_key = alloc_key(&mut scope, "url")?;
      scope.define_property(event_obj, url_key, read_only_data_desc(Value::String(url_s)))?;
      let storage_area_key = alloc_key(&mut scope, "storageArea")?;
      scope.define_property(event_obj, storage_area_key, read_only_data_desc(storage_obj))?;
    }

    vm.call_with_host_and_hooks(
      vm_host,
      &mut scope,
      &mut hooks,
      dispatch_event,
      Value::Object(window_obj),
      &[Value::Object(event_obj)],
    )?;

    Ok(())
  });

  if let Some(err) = hooks.finish(window_realm.heap_mut()) {
    return Err(err);
  }

  match result {
    Ok(()) => Ok(()),
    Err(err) => Err(crate::js::vm_error_format::vm_error_to_error(
      window_realm.heap_mut(),
      err,
    )),
  }
}

fn maybe_queue_storage_event_from_change(
  vm: &Vm,
  kind: web_storage::StorageKind,
  change: web_storage::StorageChange,
) {
  if !change.did_mutate {
    return;
  }
  let Some(user_data) = vm.user_data::<WindowRealmUserData>() else {
    return;
  };
  let storage_area_ptr = match kind {
    web_storage::StorageKind::Local => Arc::as_ptr(&user_data.local_storage_area) as usize,
    web_storage::StorageKind::Session => Arc::as_ptr(&user_data.session_storage_area) as usize,
  };
  queue_storage_event_to_other_window_hosts(
    user_data.window_id,
    storage_area_ptr,
    QueuedStorageEvent {
      key: change.key,
      old_value: change.old_value,
      new_value: change.new_value,
      url: user_data.document_url.clone(),
      storage_kind: kind,
    },
  );
}

fn storage_length_get_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  let kind = storage_require_this(scope, this)?;
  let area = storage_area_from_kind(vm, kind)?;
  let len = area.lock().len();
  Ok(Value::Number(len as f64))
}

fn storage_get_item_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let kind = storage_require_this(scope, this)?;
  let area = storage_area_from_kind(vm, kind)?;
  let key_v = args.get(0).copied().unwrap_or(Value::Undefined);
  let key_s = storage_to_string(scope, key_v)?;
  let key = scope.heap().get_string(key_s)?.to_utf8_lossy();
  let Some(value) = area.lock().get_item(&key) else {
    return Ok(Value::Null);
  };
  let value_s = scope.alloc_string(&value)?;
  scope.push_root(Value::String(value_s))?;
  Ok(Value::String(value_s))
}

fn storage_set_item_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let kind = storage_require_this(scope, this)?;
  let Value::Object(storage_obj) = this else {
    return Err(VmError::TypeError(ILLEGAL_INVOCATION_ERROR));
  };
  let area = storage_area_from_kind(vm, kind)?;
  let key_v = args.get(0).copied().unwrap_or(Value::Undefined);
  let value_v = args.get(1).copied().unwrap_or(Value::Undefined);
  let key_s = storage_to_string(scope, key_v)?;
  let value_s = storage_to_string(scope, value_v)?;
  let key = scope.heap().get_string(key_s)?.to_utf8_lossy();
  let value = scope.heap().get_string(value_s)?.to_utf8_lossy();

  let change = match area.lock().set_item(&key, &value) {
    Ok(change) => change,
    Err(web_storage::StorageError::QuotaExceeded) => {
      return Err(VmError::Throw(make_dom_exception(vm, scope,
        "QuotaExceededError",
        "The quota has been exceeded.",
      )?));
    }
  };

  storage_sync_key_property(
    scope,
    storage_obj,
    PropertyKey::from_string(key_s),
    Value::String(value_s),
  )?;
  maybe_queue_storage_event_from_change(vm, kind, change);
  Ok(Value::Undefined)
}

fn storage_remove_item_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let kind = storage_require_this(scope, this)?;
  let Value::Object(storage_obj) = this else {
    return Err(VmError::TypeError(ILLEGAL_INVOCATION_ERROR));
  };
  let area = storage_area_from_kind(vm, kind)?;
  let key_v = args.get(0).copied().unwrap_or(Value::Undefined);
  let key_s = storage_to_string(scope, key_v)?;
  let key = scope.heap().get_string(key_s)?.to_utf8_lossy();
  let change = area.lock().remove_item(&key);
  if change.did_mutate {
    storage_delete_key_property(scope, storage_obj, PropertyKey::from_string(key_s))?;
  }
  maybe_queue_storage_event_from_change(vm, kind, change);
  Ok(Value::Undefined)
}

fn storage_clear_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  let kind = storage_require_this(scope, this)?;
  let Value::Object(storage_obj) = this else {
    return Err(VmError::TypeError(ILLEGAL_INVOCATION_ERROR));
  };
  let area = storage_area_from_kind(vm, kind)?;
  let change = area.lock().clear();
  if change.did_mutate {
    storage_clear_key_properties(scope, storage_obj)?;
  }
  maybe_queue_storage_event_from_change(vm, kind, change);
  Ok(Value::Undefined)
}

fn storage_key_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let kind = storage_require_this(scope, this)?;
  let area = storage_area_from_kind(vm, kind)?;
  let idx_v = args.get(0).copied().unwrap_or(Value::Undefined);
  let Some(idx) = storage_to_index(scope, idx_v)? else {
    return Ok(Value::Null);
  };
  let Some(key) = area.lock().key(idx) else {
    return Ok(Value::Null);
  };
  let key_s = scope.alloc_string(&key)?;
  scope.push_root(Value::String(key_s))?;
  Ok(Value::String(key_s))
}

fn storage_key_data_desc(value: Value) -> PropertyDescriptor {
  PropertyDescriptor {
    enumerable: true,
    configurable: true,
    kind: PropertyKind::Data {
      value,
      writable: true,
    },
  }
}

fn storage_key_is_visible(
  heap: &Heap,
  storage_obj: GcObject,
  key: &PropertyKey,
) -> Result<bool, VmError> {
  Ok(!proto_chain_has_own_property(heap, storage_obj, key)?)
}

fn storage_sync_key_property(
  scope: &mut Scope<'_>,
  storage_obj: GcObject,
  key: PropertyKey,
  value: Value,
) -> Result<(), VmError> {
  if !storage_key_is_visible(scope.heap(), storage_obj, &key)? {
    return Ok(());
  }
  // Root the receiver while defining properties: `define_property` can allocate.
  scope.push_root(Value::Object(storage_obj))?;
  scope.define_property(storage_obj, key, storage_key_data_desc(value))?;
  Ok(())
}

fn storage_delete_key_property(
  scope: &mut Scope<'_>,
  storage_obj: GcObject,
  key: PropertyKey,
) -> Result<(), VmError> {
  if !storage_key_is_visible(scope.heap(), storage_obj, &key)? {
    return Ok(());
  }
  scope.push_root(Value::Object(storage_obj))?;
  let _ = scope.ordinary_delete(storage_obj, key)?;
  Ok(())
}

fn storage_clear_key_properties(scope: &mut Scope<'_>, storage_obj: GcObject) -> Result<(), VmError> {
  // Delete all enumerable own string-keyed properties, which correspond to visible storage keys.
  // Keep non-enumerable branding/internal state intact.
  let keys = scope.heap().own_property_keys(storage_obj)?;
  for key in keys {
    let PropertyKey::String(_) = key else {
      continue;
    };
    let Some(desc) = scope.heap().object_get_own_property(storage_obj, &key)? else {
      continue;
    };
    if !desc.enumerable {
      continue;
    }
    // Root the receiver while deleting: `ordinary_delete` can allocate.
    scope.push_root(Value::Object(storage_obj))?;
    let _ = scope.ordinary_delete(storage_obj, key)?;
  }
  Ok(())
}

fn storage_sync_all_key_properties_from_area(
  scope: &mut Scope<'_>,
  storage_obj: GcObject,
  area: &web_storage::StorageArea,
) -> Result<(), VmError> {
  for idx in 0..area.len() {
    let Some(key) = area.key(idx) else {
      continue;
    };
    let Some(value) = area.get_item(&key) else {
      continue;
    };
    let key_s = scope.alloc_string(&key)?;
    scope.push_root(Value::String(key_s))?;
    let value_s = scope.alloc_string(&value)?;
    scope.push_root(Value::String(value_s))?;
    storage_sync_key_property(
      scope,
      storage_obj,
      PropertyKey::from_string(key_s),
      Value::String(value_s),
    )?;
  }
  Ok(())
}

fn install_storage_object(
  scope: &mut Scope<'_>,
  global: GcObject,
  global_key: PropertyKey,
  storage_proto: GcObject,
  kind: web_storage::StorageKind,
) -> Result<GcObject, VmError> {
  let storage_obj = scope.alloc_object()?;
  scope.push_root(Value::Object(storage_obj))?;
  scope
    .heap_mut()
    .object_set_prototype(storage_obj, Some(storage_proto))?;

  // FastRender-only branding to ensure `Storage.prototype.*` methods throw when borrowed onto other
  // receivers. Use host slots so `Object.getOwnPropertyNames(localStorage)` matches browsers (no
  // internal `__fastrender_*` keys).
  let kind_slot = match kind {
    web_storage::StorageKind::Local => 0,
    web_storage::StorageKind::Session => 1,
  };
  scope.heap_mut().object_set_host_slots(
    storage_obj,
    HostSlots {
      a: kind_slot,
      b: HOST_EXOTIC_STORAGE,
    },
  )?;

  // Install the storage object on the global as a read-only data property.
  scope.define_property(global, global_key, read_only_data_desc(Value::Object(storage_obj)))?;

  Ok(storage_obj)
}

static NEXT_CONSOLE_SINK_ID: AtomicU64 = AtomicU64::new(1);
static CONSOLE_SINKS: OnceLock<Mutex<HashMap<u64, ConsoleSink>>> = OnceLock::new();

fn console_sinks() -> &'static Mutex<HashMap<u64, ConsoleSink>> {
  CONSOLE_SINKS.get_or_init(|| Mutex::new(HashMap::new()))
}

fn register_console_sink(sink: ConsoleSink) -> u64 {
  let id = NEXT_CONSOLE_SINK_ID.fetch_add(1, Ordering::Relaxed);
  console_sinks().lock().insert(id, sink);
  id
}

fn unregister_console_sink(id: u64) {
  console_sinks().lock().remove(&id);
}

struct ConsoleSinkGuard {
  id: u64,
  active: bool,
}

impl ConsoleSinkGuard {
  fn new(sink: ConsoleSink) -> Self {
    Self {
      id: register_console_sink(sink),
      active: true,
    }
  }

  fn id(&self) -> u64 {
    self.id
  }

  fn disarm(mut self) -> u64 {
    self.active = false;
    self.id
  }
}

impl Drop for ConsoleSinkGuard {
  fn drop(&mut self) {
    if self.active {
      unregister_console_sink(self.id);
    }
  }
}

