// --- DOM Traversal (NodeIterator / TreeWalker / NodeFilter) -------------------
//
// These are minimal handwritten shims for the curated WPT traversal tests. They are intentionally
// implemented as plain JS wrapper objects (not `DomPlatform` node wrappers).
//
// Spec: https://dom.spec.whatwg.org/#traversal
const TRAVERSAL_IS_ACTIVE_KEY: &str = "__fastrender_traversal_is_active";
const TREE_WALKER_BRAND_KEY: &str = "__fastrender_tree_walker";
const TREE_WALKER_ROOT_KEY: &str = "__fastrender_tree_walker_root";
const TREE_WALKER_CURRENT_NODE_KEY: &str = "__fastrender_tree_walker_current_node";
const TREE_WALKER_WHAT_TO_SHOW_KEY: &str = "__fastrender_tree_walker_what_to_show";
const TREE_WALKER_FILTER_KEY: &str = "__fastrender_tree_walker_filter";
const TREE_WALKER_PROTOTYPE_KEY: &str = "__fastrender_tree_walker_prototype";
const NODE_FILTER_FILTER_ACCEPT: u16 = 1;
const NODE_FILTER_FILTER_REJECT: u16 = 2;
const NODE_FILTER_FILTER_SKIP: u16 = 3;
const NODE_FILTER_SHOW_ALL: u32 = 0xFFFF_FFFF;

static NEXT_CURRENT_SCRIPT_SOURCE_ID: AtomicU64 = AtomicU64::new(1);
static NEXT_ACTIVE_EVENT_ID: AtomicU64 = AtomicU64::new(1);

static NEXT_MUTATION_OBSERVER_ID: AtomicU64 = AtomicU64::new(1);
static NEXT_INTERSECTION_OBSERVER_ID: AtomicU64 = AtomicU64::new(1);
static NEXT_RESIZE_OBSERVER_ID: AtomicU64 = AtomicU64::new(1);

thread_local! {
  static CURRENT_SCRIPT_SOURCES: RefCell<HashMap<u64, CurrentScriptStateHandle>> =
    RefCell::new(HashMap::new());
}

fn register_current_script_source(state: CurrentScriptStateHandle) -> u64 {
  let id = NEXT_CURRENT_SCRIPT_SOURCE_ID.fetch_add(1, Ordering::Relaxed);
  CURRENT_SCRIPT_SOURCES.with(|sources| sources.borrow_mut().insert(id, state));
  id
}

fn unregister_current_script_source(id: u64) {
  CURRENT_SCRIPT_SOURCES.with(|sources| {
    sources.borrow_mut().remove(&id);
  });
}

fn event_active_event_id(
  scope: &mut Scope<'_>,
  event_obj: GcObject,
) -> Result<Option<u64>, VmError> {
  let key = alloc_key(scope, EVENT_ID_KEY)?;
  Ok(
    match scope
      .heap()
      .object_get_own_data_property_value(event_obj, &key)?
    {
      Some(Value::Number(n)) if n.is_finite() && n >= 0.0 => Some(n as u64),
      _ => None,
    },
  )
}

fn push_active_event_for_host(
  host: &mut dyn VmHost,
  event_id: u64,
  event: &mut web_events::Event,
) -> Option<ActiveEventGuard> {
  let any = host.as_any_mut();
  if let Some(host) = any.downcast_mut::<DocumentHostState>() {
    return Some(host.push_active_event(event_id, event));
  }
  if let Some(host) = any.downcast_mut::<BrowserDocumentDom2>() {
    return Some(host.push_active_event(event_id, event));
  }
  None
}

fn with_active_event_for_host<R>(
  host: &mut dyn VmHost,
  event_id: u64,
  f: impl FnOnce(&mut web_events::Event) -> R,
) -> Option<R> {
  let any = host.as_any_mut();
  if let Some(host) = any.downcast_mut::<DocumentHostState>() {
    return host.with_active_event(event_id, f);
  }
  if let Some(host) = any.downcast_mut::<BrowserDocumentDom2>() {
    return host.with_active_event(event_id, f);
  }
  None
}

/// Per-call execution context for `Element.dataset` exotic hooks.
///
/// `vm-js` `VmHostHooks::{host_exotic_get,host_exotic_set,host_exotic_delete}` are invoked while the
/// engine already holds a mutable borrow of the VM. This means the exotic hook implementation cannot
/// safely borrow `&mut Vm` to access per-realm state (like extra-document registries) or queue DOM
/// mutation observer microtasks.
///
/// To support multi-document realms, hook adapters capture this context at a safe boundary (before
/// entering the VM) and pass it into `dataset_exotic_*`.
#[derive(Clone, Debug)]
pub(crate) struct DatasetExoticContext {
  primary_document_id: Option<DocumentId>,
  owned_dom2_documents: Rc<RefCell<HashMap<DocumentId, Box<dom2::Document>>>>,
  pending_dataset_mutation_observer_microtasks: Rc<RefCell<HashSet<WeakGcObject>>>,
}

impl DatasetExoticContext {
  fn empty() -> Self {
    Self {
      primary_document_id: None,
      owned_dom2_documents: Rc::new(RefCell::new(HashMap::new())),
      pending_dataset_mutation_observer_microtasks: Rc::new(RefCell::new(HashSet::new())),
    }
  }

  pub(crate) fn for_vm(vm: &Vm) -> Self {
    let Some(data) = vm.user_data::<WindowRealmUserData>() else {
      return Self::empty();
    };
    Self {
      primary_document_id: data.document_obj.map(gc_object_id),
      owned_dom2_documents: Rc::clone(&data.owned_dom2_documents),
      pending_dataset_mutation_observer_microtasks: Rc::clone(
        &data.pending_dataset_mutation_observer_microtasks,
      ),
    }
  }

  fn record_dataset_mutation(&self, document_obj: GcObject) {
    self
      .pending_dataset_mutation_observer_microtasks
      .borrow_mut()
      .insert(WeakGcObject::new(document_obj));
  }
}

impl Default for DatasetExoticContext {
  fn default() -> Self {
    Self::empty()
  }
}

fn dataset_prop_is_valid(prop: &str) -> bool {
  if prop.is_empty() {
    return false;
  }
  let bytes = prop.as_bytes();
  if bytes[0].is_ascii_uppercase() {
    // Real DOMStringMap only exposes lower-camel-case properties.
    return false;
  }
  if bytes.iter().any(|b| *b == b'-') {
    // Hyphens are represented via camelCase in JS (`fooBar` <-> `data-foo-bar`).
    return false;
  }
  prop.chars().all(|ch| ch.is_ascii_alphanumeric() || ch == '_')
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub(crate) enum ExoticDispatchHandledBy {
  Dataset,
  DomTokenList,
  WebIdl,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub(crate) struct ExoticDispatchOutcome<T> {
  pub(crate) handled: Option<T>,
  pub(crate) handled_by: Option<ExoticDispatchHandledBy>,
}

impl<T> ExoticDispatchOutcome<T> {
  #[inline]
  fn not_handled() -> Self {
    Self {
      handled: None,
      handled_by: None,
    }
  }

  #[inline]
  fn handled(value: T, handled_by: ExoticDispatchHandledBy) -> Self {
    Self {
      handled: Some(value),
      handled_by: Some(handled_by),
    }
  }
}

pub(crate) fn dispatch_host_exotic_get(
  scope: &mut Scope<'_>,
  payload: &mut VmJsHostHooksPayload,
  dataset_ctx: &DatasetExoticContext,
  obj: GcObject,
  key: PropertyKey,
  receiver: Value,
) -> Result<Option<Value>, VmError> {
  if let Some(value) = dataset_exotic_get(scope, payload.vm_host_mut(), dataset_ctx, obj, key)? {
    return Ok(Some(value));
  }

  if let Some(value) = dom_token_list_exotic_get(scope, payload.vm_host_mut(), obj, key)? {
    return Ok(Some(value));
  }

  if let Some(value) =
    named_node_map_exotic_get(scope, payload.vm_host_mut(), dataset_ctx, obj, key)?
  {
    return Ok(Some(value));
  }

  if let Some(value) = computed_style_exotic_get(scope, payload.vm_host_mut(), obj, key)? {
    return Ok(Some(value));
  }

  let Some(host) = payload.webidl_bindings_host_mut() else {
    return Ok(None);
  };
  host.exotic_get(scope, obj, key, receiver)
}

pub(crate) fn dispatch_host_exotic_set(
  scope: &mut Scope<'_>,
  payload: &mut VmJsHostHooksPayload,
  dataset_ctx: &DatasetExoticContext,
  obj: GcObject,
  key: PropertyKey,
  value: Value,
  receiver: Value,
) -> Result<ExoticDispatchOutcome<bool>, VmError> {
  if let Some(ok) = dataset_exotic_set(scope, payload.vm_host_mut(), dataset_ctx, obj, key, value)? {
    return Ok(ExoticDispatchOutcome::handled(
      ok,
      ExoticDispatchHandledBy::Dataset,
    ));
  }

  if let Some(ok) = dom_token_list_exotic_set(scope, payload.vm_host_mut(), obj, key, value)? {
    return Ok(ExoticDispatchOutcome::handled(
      ok,
      ExoticDispatchHandledBy::DomTokenList,
    ));
  }

  let Some(host) = payload.webidl_bindings_host_mut() else {
    return Ok(ExoticDispatchOutcome::not_handled());
  };
  match host.exotic_set(scope, obj, key, value, receiver)? {
    Some(ok) => Ok(ExoticDispatchOutcome::handled(
      ok,
      ExoticDispatchHandledBy::WebIdl,
    )),
    None => Ok(ExoticDispatchOutcome::not_handled()),
  }
}

pub(crate) fn dispatch_host_exotic_delete(
  scope: &mut Scope<'_>,
  payload: &mut VmJsHostHooksPayload,
  dataset_ctx: &DatasetExoticContext,
  obj: GcObject,
  key: PropertyKey,
) -> Result<ExoticDispatchOutcome<bool>, VmError> {
  if let Some(ok) = dataset_exotic_delete(scope, payload.vm_host_mut(), dataset_ctx, obj, key)? {
    return Ok(ExoticDispatchOutcome::handled(
      ok,
      ExoticDispatchHandledBy::Dataset,
    ));
  }

  if let Some(ok) = dom_token_list_exotic_delete(scope, payload.vm_host_mut(), obj, key)? {
    return Ok(ExoticDispatchOutcome::handled(
      ok,
      ExoticDispatchHandledBy::DomTokenList,
    ));
  }

  let Some(host) = payload.webidl_bindings_host_mut() else {
    return Ok(ExoticDispatchOutcome::not_handled());
  };
  match host.exotic_delete(scope, obj, key)? {
    Some(ok) => Ok(ExoticDispatchOutcome::handled(
      ok,
      ExoticDispatchHandledBy::WebIdl,
    )),
    None => Ok(ExoticDispatchOutcome::not_handled()),
  }
}

pub(crate) fn dataset_exotic_get(
  scope: &mut Scope<'_>,
  mut host: Option<&mut dyn VmHost>,
  ctx: &DatasetExoticContext,
  obj: GcObject,
  key: PropertyKey,
) -> Result<Option<Value>, VmError> {
  // `host_exotic_get` is called for *all* objects, including VM-internal kinds like Promises and
  // typed arrays. `Heap::object_host_slots` only supports ordinary objects/functions; for other
  // object kinds, treat this as "no host slots" rather than failing the property access.
  let slots = match scope.heap().object_host_slots(obj) {
    Ok(slots) => slots,
    Err(VmError::InvalidHandle { .. }) if scope.heap().is_valid_object(obj) => None,
    Err(err) => return Err(err),
  };
  let Some(slots) = slots else {
    return Ok(None);
  };
  if slots.b != HOST_EXOTIC_DOM_STRING_MAP {
    return Ok(None);
  }

  let PropertyKey::String(prop_s) = key else {
    return Ok(None);
  };

  let node_index = match usize::try_from(slots.a) {
    Ok(v) => v,
    Err(_) => return Ok(None),
  };
  let prop = scope.heap().get_string(prop_s)?.to_utf8_lossy();

  // Resolve the owning document for this dataset object.
  scope.push_root(Value::Object(obj))?;
  let wrapper_document_key = alloc_key(scope, WRAPPER_DOCUMENT_KEY)?;
  let document_obj = match scope
    .heap()
    .object_get_own_data_property_value(obj, &wrapper_document_key)?
  {
    Some(Value::Object(obj)) => obj,
    _ => return Ok(None),
  };

  let document_id = gc_object_id(document_obj);

  // Active host document.
  if ctx
    .primary_document_id
    .is_some_and(|primary| primary == document_id)
  {
    let Some(host) = host.as_deref_mut() else {
      return Ok(None);
    };
    let Some(host) = crate::js::dom_host::dom_host_vmjs(host) else {
      return Ok(None);
    };
    let node_id = match host.node_id_from_index(node_index) {
      Ok(id) => id,
      Err(_) => return Ok(None),
    };
    let Some(value) = host.dataset_get(node_id, &prop) else {
      return Ok(None);
    };
    return Ok(Some(Value::String(scope.alloc_string(&value)?)));
  }

  // Realm-owned (non-host) document.
  let owned_dom2_documents = ctx.owned_dom2_documents.borrow();
  let Some(dom) = owned_dom2_documents.get(&document_id) else {
    return Ok(None);
  };
  let node_id = match dom.node_id_from_index(node_index) {
    Ok(id) => id,
    Err(_) => return Ok(None),
  };
  let Some(value) = dom.dataset_get(node_id, &prop) else {
    return Ok(None);
  };
  Ok(Some(Value::String(scope.alloc_string(value)?)))
}

pub(crate) fn dataset_exotic_set(
  scope: &mut Scope<'_>,
  mut host: Option<&mut dyn VmHost>,
  ctx: &DatasetExoticContext,
  obj: GcObject,
  key: PropertyKey,
  value: Value,
) -> Result<Option<bool>, VmError> {
  let slots = match scope.heap().object_host_slots(obj) {
    Ok(slots) => slots,
    Err(VmError::InvalidHandle { .. }) if scope.heap().is_valid_object(obj) => None,
    Err(err) => return Err(err),
  };
  let Some(slots) = slots else {
    return Ok(None);
  };
  if slots.b != HOST_EXOTIC_DOM_STRING_MAP {
    return Ok(None);
  }

  let PropertyKey::String(prop_s) = key else {
    return Ok(None);
  };

  let node_index = match usize::try_from(slots.a) {
    Ok(v) => v,
    Err(_) => return Ok(None),
  };

  let prop = scope.heap().get_string(prop_s)?.to_utf8_lossy();
  if !dataset_prop_is_valid(&prop) {
    // Invalid dataset property names behave like ordinary expando properties.
    return Ok(None);
  }

  let value_value = scope.heap_mut().to_string(value)?;
  let value = scope
    .heap()
    .get_string(value_value)
    .map(|s| s.to_utf8_lossy())
    .unwrap_or_default();

  scope.push_root(Value::Object(obj))?;
  let wrapper_document_key = alloc_key(scope, WRAPPER_DOCUMENT_KEY)?;
  let document_obj = match scope
    .heap()
    .object_get_own_data_property_value(obj, &wrapper_document_key)?
  {
    Some(Value::Object(obj)) => obj,
    _ => return Ok(None),
  };

  let document_id = gc_object_id(document_obj);

  // Active host document.
  if ctx
    .primary_document_id
    .is_some_and(|primary| primary == document_id)
  {
    let Some(host) = host.as_deref_mut() else {
      return Ok(None);
    };
    let Some(host_dom) = crate::js::dom_host::dom_host_vmjs(host) else {
      return Ok(None);
    };
    let node_id = match host_dom.node_id_from_index(node_index) {
      Ok(id) => id,
      Err(_) => return Ok(None),
    };
    if let Err(err) = host_dom.dataset_set(node_id, &prop, &value) {
      let document_window_key = alloc_key(scope, DOCUMENT_WINDOW_KEY)?;
      let window_obj = match scope
        .heap()
        .object_get_own_data_property_value(document_obj, &document_window_key)?
      {
        Some(Value::Object(obj)) => obj,
        _ => return Err(VmError::Throw(make_dom_exception_fallback_object(scope, err.code(), "")?)),
      };
      return Err(VmError::Throw(make_dom_exception_for_global(
        scope,
        window_obj,
        err.code(),
        "",
      )?));
    }
    ctx.record_dataset_mutation(document_obj);
    return Ok(Some(true));
  }

  // Realm-owned (non-host) document.
  let mut owned_dom2_documents = ctx.owned_dom2_documents.borrow_mut();
  let Some(dom) = owned_dom2_documents.get_mut(&document_id) else {
    return Ok(None);
  };
  let node_id = match dom.node_id_from_index(node_index) {
    Ok(id) => id,
    Err(_) => return Ok(None),
  };
  if let Err(err) = dom.dataset_set(node_id, &prop, &value) {
    let document_window_key = alloc_key(scope, DOCUMENT_WINDOW_KEY)?;
    let window_obj = match scope
      .heap()
      .object_get_own_data_property_value(document_obj, &document_window_key)?
    {
      Some(Value::Object(obj)) => obj,
      _ => return Err(VmError::Throw(make_dom_exception_fallback_object(scope, err.code(), "")?)),
    };
    return Err(VmError::Throw(make_dom_exception_for_global(
      scope,
      window_obj,
      err.code(),
      "",
    )?));
  }
  ctx.record_dataset_mutation(document_obj);

  Ok(Some(true))
}

