pub(crate) fn named_node_map_exotic_get(
  scope: &mut Scope<'_>,
  mut host: Option<&mut dyn VmHost>,
  ctx: &DatasetExoticContext,
  obj: GcObject,
  key: PropertyKey,
) -> Result<Option<Value>, VmError> {
  // `host_exotic_get` is called for *all* objects, including VM-internal kinds like Promises and
  // typed arrays. `Heap::object_host_slots` only supports ordinary objects/functions; for other
  // object kinds, treat this as "no host slots" rather than failing the property access.
  let slots = match scope.heap().object_host_slots(obj) {
    Ok(slots) => slots,
    Err(VmError::InvalidHandle { .. }) if scope.heap().is_valid_object(obj) => None,
    Err(err) => return Err(err),
  };
  let Some(slots) = slots else {
    return Ok(None);
  };
  if slots.b != HOST_EXOTIC_NAMED_NODE_MAP {
    return Ok(None);
  }

  let Some(idx) = canonical_array_index(scope, key)? else {
    return Ok(None);
  };

  let node_index = match usize::try_from(slots.a) {
    Ok(v) => v,
    Err(_) => return Ok(None),
  };
  let idx = idx as usize;

  scope.push_root(Value::Object(obj))?;

  // Resolve the owning document for this NamedNodeMap.
  let wrapper_document_key = alloc_key(scope, WRAPPER_DOCUMENT_KEY)?;
  let document_obj = match scope
    .heap()
    .object_get_own_data_property_value(obj, &wrapper_document_key)?
  {
    Some(Value::Object(obj)) => obj,
    _ => return Ok(None),
  };
  let document_id = gc_object_id(document_obj);

  // Resolve the owner element wrapper + Attr prototype to construct Attr objects.
  let owner_element_key = alloc_key(scope, NAMED_NODE_MAP_OWNER_ELEMENT_KEY)?;
  let owner_element = match scope
    .heap()
    .object_get_own_data_property_value(obj, &owner_element_key)?
  {
    Some(Value::Object(obj)) => obj,
    _ => return Ok(None),
  };
  scope.push_root(Value::Object(owner_element))?;

  let attr_proto_key = alloc_key(scope, NAMED_NODE_MAP_ATTR_PROTO_KEY)?;
  let attr_proto = match scope
    .heap()
    .object_get_own_data_property_value(obj, &attr_proto_key)?
  {
    Some(Value::Object(obj)) => obj,
    _ => return Ok(None),
  };
  scope.push_root(Value::Object(attr_proto))?;

  let resolve_attr = |dom: &dom2::Document| -> Option<(String, String, bool)> {
    let node_id = dom.node_id_from_index(node_index).ok()?;
    let (namespace, attrs) = match &dom.node(node_id).kind {
      NodeKind::Element {
        namespace,
        attributes,
        ..
      }
      | NodeKind::Slot {
        namespace,
        attributes,
        ..
    } => (namespace.as_str(), attributes.as_slice()),
      _ => return None,
    };
    let attr = attrs.get(idx)?;
    let is_html = dom.is_html_case_insensitive_namespace(namespace);
    let name = attr.qualified_name();
    let name = if is_html {
      name.as_ref().to_ascii_lowercase()
    } else {
      name.into_owned()
    };
    Some((name, attr.value.clone(), is_html))
  };

  let (name, value, _is_html) = if let Some(dom) = ctx.owned_dom2_documents.borrow().get(&document_id) {
    let dom = dom.as_ref();
    let Some(tuple) = resolve_attr(dom) else {
      return Ok(None);
    };
    tuple
  } else if let Some(host) = host.as_deref_mut() {
    let Some(dom) = dom_from_vm_host(host) else {
      return Ok(None);
    };
    let Some(tuple) = resolve_attr(dom) else {
      return Ok(None);
    };
    tuple
  } else {
    return Ok(None);
  };

  // Construct an Attr object that reflects the current attribute value.
  let attr_obj = scope.alloc_object_with_prototype(Some(attr_proto))?;
  scope.push_root(Value::Object(attr_obj))?;
  scope.heap_mut().object_set_host_slots(
    attr_obj,
    HostSlots {
      a: node_index as u64,
      b: HOST_OBJECT_ATTR,
    },
  )?;

  let name_key = alloc_key(scope, "name")?;
  let local_name_key = alloc_key(scope, "localName")?;
  let prefix_key = alloc_key(scope, "prefix")?;
  let namespace_uri_key = alloc_key(scope, "namespaceURI")?;
  let value_key = alloc_key(scope, "value")?;
  let owner_element_key = alloc_key(scope, "ownerElement")?;
  let specified_key = alloc_key(scope, "specified")?;

  let name_s = scope.alloc_string(&name)?;
  scope.push_root(Value::String(name_s))?;
  let local_name_s = scope.alloc_string(&name)?;
  scope.push_root(Value::String(local_name_s))?;
  let value_s = scope.alloc_string(&value)?;
  scope.push_root(Value::String(value_s))?;

  scope.define_property(attr_obj, name_key, read_only_data_desc(Value::String(name_s)))?;
  scope.define_property(
    attr_obj,
    local_name_key,
    read_only_data_desc(Value::String(local_name_s)),
  )?;
  scope.define_property(attr_obj, prefix_key, read_only_data_desc(Value::Null))?;
  scope.define_property(attr_obj, namespace_uri_key, read_only_data_desc(Value::Null))?;
  scope.define_property(attr_obj, value_key, data_desc(Value::String(value_s)))?;
  scope.define_property(
    attr_obj,
    owner_element_key,
    read_only_data_desc(Value::Object(owner_element)),
  )?;
  scope.define_property(
    attr_obj,
    specified_key,
    read_only_data_desc(Value::Bool(true)),
  )?;

  Ok(Some(Value::Object(attr_obj)))
}

fn computed_style_is_reserved_property_name(prop: &str) -> bool {
  // `host_exotic_get` may be invoked for arbitrary property reads (including those that would
  // normally be resolved on `Object.prototype`). Avoid breaking ordinary object semantics by
  // letting those fall back to the normal property lookup path.
  matches!(
    prop,
    "__proto__"
      | "prototype"
      | "constructor"
      | "toString"
      | "toLocaleString"
      | "valueOf"
      | "hasOwnProperty"
      | "isPrototypeOf"
      | "propertyIsEnumerable"
      | "getPropertyValue"
      | "setProperty"
      | "removeProperty"
  )
}

fn css_px_string(value: f32) -> String {
  if !value.is_finite() {
    return "0px".to_string();
  }
  // Snap near-integers so sizes like `10.000001` don't leak float noise into JS-visible values.
  let snapped = if (value - value.round()).abs() <= 1e-3 {
    value.round()
  } else {
    (value * 1000.0).round() / 1000.0
  };
  if (snapped - snapped.round()).abs() <= f32::EPSILON {
    format!("{}px", snapped.round() as i64)
  } else {
    format!("{snapped}px")
  }
}

pub(crate) fn computed_style_exotic_get(
  scope: &mut Scope<'_>,
  mut host: Option<&mut dyn VmHost>,
  obj: GcObject,
  key: PropertyKey,
) -> Result<Option<Value>, VmError> {
  // `host_exotic_get` is called for *all* objects, including VM-internal kinds like Promises and
  // typed arrays. `Heap::object_host_slots` only supports ordinary objects/functions; for other
  // object kinds, treat this as "no host slots" rather than failing the property access.
  let slots = match scope.heap().object_host_slots(obj) {
    Ok(slots) => slots,
    Err(VmError::InvalidHandle { .. }) if scope.heap().is_valid_object(obj) => None,
    Err(err) => return Err(err),
  };
  let Some(slots) = slots else {
    return Ok(None);
  };
  if slots.b != HOST_EXOTIC_COMPUTED_STYLE {
    return Ok(None);
  }

  let PropertyKey::String(prop_s) = key else {
    return Ok(None);
  };
  let prop_raw = scope.heap().get_string(prop_s)?.to_utf8_lossy();
  if computed_style_is_reserved_property_name(&prop_raw) {
    return Ok(None);
  }

  let node_index = match usize::try_from(slots.a) {
    Ok(v) => v,
    Err(_) => {
      let empty = scope.alloc_string("")?;
      return Ok(Some(Value::String(empty)));
    }
  };

  let Some(document) = host
    .as_deref_mut()
    .and_then(|host| host.as_any_mut().downcast_mut::<BrowserDocumentDom2>())
  else {
    let empty = scope.alloc_string("")?;
    return Ok(Some(Value::String(empty)));
  };

  let node_id = match document.dom().node_id_from_index(node_index) {
    Ok(id) => id,
    Err(_) => {
      let empty = scope.alloc_string("")?;
      return Ok(Some(Value::String(empty)));
    }
  };

  // Ensure style/layout caches are current, but avoid paint.
  if document.ensure_layout_for_dom_queries().is_err() {
    let empty = scope.alloc_string("")?;
    return Ok(Some(Value::String(empty)));
  }

  let Some(style) = document.computed_style_for_dom_node(node_id) else {
    let empty = scope.alloc_string("")?;
    return Ok(Some(Value::String(empty)));
  };

  // Normalize common camelCase property names used by JS property access.
  let lower = prop_raw.to_ascii_lowercase();
  let normalized = match lower.as_str() {
    "backgroundcolor" => "background-color",
    other => other,
  };

  let value = match normalized {
    // Prefer the used/layout size when available.
    "width" => match document.border_box_rect_viewport(node_id) {
      Ok(Some(rect)) => css_px_string(rect.width()),
      _ => "0px".to_string(),
    },
    "height" => match document.border_box_rect_viewport(node_id) {
      Ok(Some(rect)) => css_px_string(rect.height()),
      _ => "0px".to_string(),
    },
    // `gap` is a shorthand for row/column gaps. FastRender stores a single resolved length used for
    // the common one-value form, so expose that for now.
    "gap" => style.grid_gap.to_css(),
    _ => computed_style_property_value(&style, normalized).unwrap_or_default(),
  };

  Ok(Some(Value::String(scope.alloc_string(&value)?)))
}

const MAX_BASE64_INPUT_LEN: usize = 32 * 1024 * 1024;
const MAX_BASE64_OUTPUT_LEN: usize = 32 * 1024 * 1024;

fn console_call_native(
  _vm: &mut Vm,
  scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let slots = scope.heap().get_function_native_slots(callee)?;
  let level = match slots
    .get(CONSOLE_LEVEL_SLOT)
    .copied()
    .unwrap_or(Value::Undefined)
  {
    Value::Number(n) => match n as u8 {
      1 => ConsoleMessageLevel::Info,
      2 => ConsoleMessageLevel::Warn,
      3 => ConsoleMessageLevel::Error,
      4 => ConsoleMessageLevel::Debug,
      _ => ConsoleMessageLevel::Log,
    },
    _ => ConsoleMessageLevel::Log,
  };
  let console_obj = match this {
    Value::Object(obj) => obj,
    _ => match slots
      .get(CONSOLE_THIS_SLOT)
      .copied()
      .unwrap_or(Value::Undefined)
    {
      Value::Object(obj) => obj,
      _ => return Ok(Value::Undefined),
    },
  };
  let sink_key_s = match slots
    .get(CONSOLE_SINK_KEY_SLOT)
    .copied()
    .unwrap_or(Value::Undefined)
  {
    Value::String(s) => s,
    _ => return Ok(Value::Undefined),
  };

  let sink_id_key = PropertyKey::from_string(sink_key_s);
  let id = match scope
    .heap()
    .object_get_own_data_property_value(console_obj, &sink_id_key)?
  {
    Some(Value::Number(n)) => n as u64,
    _ => return Ok(Value::Undefined),
  };

  let sink = console_sinks().lock().get(&id).cloned();
  if let Some(sink) = sink {
    sink(level, scope.heap_mut(), args);
  }

  Ok(Value::Undefined)
}

fn console_truncate_trace_message(mut msg: String) -> String {
  if msg.len() <= MAX_CONSOLE_TRACE_BYTES {
    return msg;
  }
  if MAX_CONSOLE_TRACE_BYTES == 0 {
    msg.clear();
    return msg;
  }
  if MAX_CONSOLE_TRACE_BYTES <= 3 {
    let mut end = MAX_CONSOLE_TRACE_BYTES;
    while end > 0 && !msg.is_char_boundary(end) {
      end -= 1;
    }
    msg.truncate(end);
    return msg;
  }
  let max_prefix = MAX_CONSOLE_TRACE_BYTES - 3;
  let mut end = max_prefix;
  while end > 0 && !msg.is_char_boundary(end) {
    end -= 1;
  }
  msg.truncate(end);
  msg.push_str("...");
  msg
}

fn console_trace_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let Some(sink) = console_sink_from_callee_and_this(scope, callee, this)? else {
    return Ok(Value::Undefined);
  };

  let formatted = crate::js::vm_error_format::format_console_arguments_limited(scope.heap_mut(), args);
  let mut message = if formatted.is_empty() {
    "Trace".to_string()
  } else {
    formatted
  };

  let stack = crate::js::vm_error_format::format_stack_trace_limited(&vm.capture_stack());
  if !stack.is_empty() {
    message.push('\n');
    message.push_str(&stack);
  }

  let message = console_truncate_trace_message(message);
  let msg_s = scope.alloc_string(&message)?;
  scope.push_root(Value::String(msg_s))?;
  let msg = [Value::String(msg_s)];
  sink(ConsoleMessageLevel::Log, scope.heap_mut(), &msg);
  Ok(Value::Undefined)
}

fn console_group_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let sink = console_sink_from_callee_and_this(scope, callee, this)?;
  if let Some(sink) = sink {
    sink(ConsoleMessageLevel::Log, scope.heap_mut(), args);
  }

  if let Some(user_data) = vm.user_data_mut::<WindowRealmUserData>() {
    user_data.console_group_depth = user_data
      .console_group_depth
      .saturating_add(1)
      .min(MAX_CONSOLE_GROUP_DEPTH);
  }

  Ok(Value::Undefined)
}

fn console_group_end_native(
  vm: &mut Vm,
  _scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  _this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  if let Some(user_data) = vm.user_data_mut::<WindowRealmUserData>() {
    user_data.console_group_depth = user_data.console_group_depth.saturating_sub(1);
  }
  Ok(Value::Undefined)
}

fn console_clear_native(
  vm: &mut Vm,
  _scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  _this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  if let Some(user_data) = vm.user_data_mut::<WindowRealmUserData>() {
    user_data.console_group_depth = 0;
  }
  Ok(Value::Undefined)
}

fn console_sink_from_callee_and_this(
  scope: &mut Scope<'_>,
  callee: GcObject,
  this: Value,
) -> Result<Option<ConsoleSink>, VmError> {
  let slots = scope.heap().get_function_native_slots(callee)?;
  let console_obj = match this {
    Value::Object(obj) => obj,
    _ => match slots.get(CONSOLE_THIS_SLOT).copied().unwrap_or(Value::Undefined) {
      Value::Object(obj) => obj,
      _ => return Ok(None),
    },
  };
  let sink_key_s = match slots
    .get(CONSOLE_SINK_KEY_SLOT)
    .copied()
    .unwrap_or(Value::Undefined)
  {
    Value::String(s) => s,
    _ => return Ok(None),
  };

  let sink_id_key = PropertyKey::from_string(sink_key_s);
  let id = match scope
    .heap()
    .object_get_own_data_property_value(console_obj, &sink_id_key)?
  {
    Some(Value::Number(n)) => n as u64,
    _ => return Ok(None),
  };

  Ok(console_sinks().lock().get(&id).cloned())
}

fn console_truncate_label(mut label: String) -> String {
  if label.len() <= MAX_CONSOLE_LABEL_BYTES {
    return label;
  }
  let mut end = MAX_CONSOLE_LABEL_BYTES;
  while end > 0 && !label.is_char_boundary(end) {
    end -= 1;
  }
  label.truncate(end);
  label
}

fn console_label_from_args(scope: &mut Scope<'_>, args: &[Value], default: &str) -> String {
  if args.is_empty() {
    return default.to_string();
  }
  console_truncate_label(crate::js::vm_error_format::format_console_arguments_limited(
    scope.heap_mut(),
    &args[..1],
  ))
}

fn console_label_for_map_insert<T>(map: &HashMap<String, T>, label: String) -> String {
  if label == CONSOLE_LABEL_LIMIT_EXCEEDED || map.contains_key(&label) {
    return label;
  }
  if map.len() >= MAX_CONSOLE_DISTINCT_LABELS.saturating_sub(1) {
    return CONSOLE_LABEL_LIMIT_EXCEEDED.to_string();
  }
  label
}

fn console_label_for_map_lookup<T>(map: &HashMap<String, T>, label: String) -> String {
  if map.contains_key(&label) {
    return label;
  }
  if map.contains_key(CONSOLE_LABEL_LIMIT_EXCEEDED) {
    return CONSOLE_LABEL_LIMIT_EXCEEDED.to_string();
  }
  label
}

fn console_format_assert_data(scope: &mut Scope<'_>, data: &[Value]) -> String {
  crate::js::vm_error_format::format_console_arguments_limited(scope.heap_mut(), data)
}

fn console_assert_native(
  _vm: &mut Vm,
  scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let condition = args.get(0).copied().unwrap_or(Value::Undefined);
  if scope.heap().to_boolean(condition)? {
    return Ok(Value::Undefined);
  }

  let Some(sink) = console_sink_from_callee_and_this(scope, callee, this)? else {
    return Ok(Value::Undefined);
  };

  let formatted = console_format_assert_data(scope, args.get(1..).unwrap_or(&[]));
  let message = if formatted.is_empty() {
    "Assertion failed".to_string()
  } else {
    format!("Assertion failed: {formatted}")
  };

  let msg_s = scope.alloc_string(&message)?;
  scope.push_root(Value::String(msg_s))?;
  let msg = [Value::String(msg_s)];
  sink(ConsoleMessageLevel::Error, scope.heap_mut(), &msg);

  Ok(Value::Undefined)
}

fn console_count_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let sink = console_sink_from_callee_and_this(scope, callee, this)?;
  let label = console_label_from_args(scope, args, "default");

  let (label, count) = if let Some(user_data) = vm.user_data_mut::<WindowRealmUserData>() {
    let label = console_label_for_map_insert(&user_data.console_counts, label);
    if user_data.console_counts.len() >= MAX_CONSOLE_DISTINCT_LABELS
      && !user_data.console_counts.contains_key(&label)
    {
      (label, 0)
    } else {
      let entry = user_data.console_counts.entry(label.clone()).or_insert(0);
      *entry = entry.saturating_add(1);
      (label, *entry)
    }
  } else {
    (label, 0)
  };

  if let Some(sink) = sink {
    let msg = format!("{label}: {count}");
    let msg_s = scope.alloc_string(&msg)?;
    scope.push_root(Value::String(msg_s))?;
    let msg_v = [Value::String(msg_s)];
    sink(ConsoleMessageLevel::Log, scope.heap_mut(), &msg_v);
  }

  Ok(Value::Undefined)
}

fn console_count_reset_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let sink = console_sink_from_callee_and_this(scope, callee, this)?;
  let label = console_label_from_args(scope, args, "default");

  let Some(user_data) = vm.user_data_mut::<WindowRealmUserData>() else {
    return Ok(Value::Undefined);
  };

  let label = console_label_for_map_lookup(&user_data.console_counts, label);
  let existed = user_data.console_counts.remove(&label).is_some();
  if !existed {
    if let Some(sink) = sink {
      let msg = format!("Count for '{label}' does not exist");
      let msg_s = scope.alloc_string(&msg)?;
      scope.push_root(Value::String(msg_s))?;
      let msg_v = [Value::String(msg_s)];
      sink(ConsoleMessageLevel::Warn, scope.heap_mut(), &msg_v);
    }
  }

  Ok(Value::Undefined)
}

fn console_time_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let sink = console_sink_from_callee_and_this(scope, callee, this)?;
  let label = console_label_from_args(scope, args, "default");
  let start = crate::js::time::clock_now(scope).unwrap_or(Duration::ZERO);

  let Some(user_data) = vm.user_data_mut::<WindowRealmUserData>() else {
    return Ok(Value::Undefined);
  };

  let label = console_label_for_map_insert(&user_data.console_timers, label);
  if user_data.console_timers.contains_key(&label) {
    if let Some(sink) = sink {
      let msg = format!("Timer '{label}' already exists");
      let msg_s = scope.alloc_string(&msg)?;
      scope.push_root(Value::String(msg_s))?;
      let msg_v = [Value::String(msg_s)];
      sink(ConsoleMessageLevel::Warn, scope.heap_mut(), &msg_v);
    }
    return Ok(Value::Undefined);
  }

  // Safety cap: refuse to track new timer labels once the realm has too many distinct entries.
  if user_data.console_timers.len() >= MAX_CONSOLE_DISTINCT_LABELS
    && !user_data.console_timers.contains_key(&label)
  {
    return Ok(Value::Undefined);
  }

  user_data.console_timers.insert(label, start);
  Ok(Value::Undefined)
}

fn console_time_log_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let sink = console_sink_from_callee_and_this(scope, callee, this)?;
  let label = console_label_from_args(scope, args, "default");

  let Some(user_data) = vm.user_data_mut::<WindowRealmUserData>() else {
    return Ok(Value::Undefined);
  };

  let label = console_label_for_map_lookup(&user_data.console_timers, label);
  let Some(&start) = user_data.console_timers.get(&label) else {
    if let Some(sink) = sink {
      let msg = format!("Timer '{label}' does not exist");
      let msg_s = scope.alloc_string(&msg)?;
      scope.push_root(Value::String(msg_s))?;
      let msg_v = [Value::String(msg_s)];
      sink(ConsoleMessageLevel::Warn, scope.heap_mut(), &msg_v);
    }
    return Ok(Value::Undefined);
  };

  let end = crate::js::time::clock_now(scope).unwrap_or(Duration::ZERO);
  let delta = end.checked_sub(start).unwrap_or(Duration::from_secs(0));
  let ms = crate::js::time::duration_to_ms_f64(delta);
  if let Some(sink) = sink {
    let extra = args.get(1..).unwrap_or(&[]);
    let formatted_extra = if extra.is_empty() {
      String::new()
    } else {
      let max_extra = MAX_CONSOLE_TIME_LOG_ARGS.saturating_sub(1);
      let extra = &extra[..extra.len().min(max_extra)];
      crate::js::vm_error_format::format_console_arguments_limited(scope.heap_mut(), extra)
    };

    let message = if formatted_extra.is_empty() {
      format!("{label}: {:.3}ms", ms)
    } else {
      format!("{label}: {:.3}ms {formatted_extra}", ms)
    };
    let msg_s = scope.alloc_string(&message)?;
    scope.push_root(Value::String(msg_s))?;
    let msg_v = [Value::String(msg_s)];
    sink(ConsoleMessageLevel::Log, scope.heap_mut(), &msg_v);
  }

  Ok(Value::Undefined)
}

fn console_time_end_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let sink = console_sink_from_callee_and_this(scope, callee, this)?;
  let label = console_label_from_args(scope, args, "default");

  let Some(user_data) = vm.user_data_mut::<WindowRealmUserData>() else {
    return Ok(Value::Undefined);
  };

  let label = console_label_for_map_lookup(&user_data.console_timers, label);
  let Some(start) = user_data.console_timers.remove(&label) else {
    if let Some(sink) = sink {
      let msg = format!("Timer '{label}' does not exist");
      let msg_s = scope.alloc_string(&msg)?;
      scope.push_root(Value::String(msg_s))?;
      let msg_v = [Value::String(msg_s)];
      sink(ConsoleMessageLevel::Warn, scope.heap_mut(), &msg_v);
    }
    return Ok(Value::Undefined);
  };

  let end = crate::js::time::clock_now(scope).unwrap_or(Duration::ZERO);
  let delta = end.checked_sub(start).unwrap_or(Duration::from_secs(0));
  let ms = crate::js::time::duration_to_ms_f64(delta);
  if let Some(sink) = sink {
    let msg = format!("{label}: {:.3}ms", ms);
    let msg_s = scope.alloc_string(&msg)?;
    scope.push_root(Value::String(msg_s))?;
    let msg_v = [Value::String(msg_s)];
    sink(ConsoleMessageLevel::Log, scope.heap_mut(), &msg_v);
  }

  Ok(Value::Undefined)
}

