const REPORT_ERROR_SINK_ID_SLOT: usize = 0;

fn window_report_error_native(
  _vm: &mut Vm,
  scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  callee: GcObject,
  _this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  // `reportError` must not throw, so avoid `?` and ignore any formatting failures.
  let sink = (|| {
    let slots = scope.heap().get_function_native_slots(callee).ok()?;
    let id = match slots
      .get(REPORT_ERROR_SINK_ID_SLOT)
      .copied()
      .unwrap_or(Value::Undefined)
    {
      Value::Number(n) => n as u64,
      _ => return None,
    };
    console_sinks().lock().get(&id).cloned()
  })();

  if let Some(sink) = sink {
    sink(ConsoleMessageLevel::Error, scope.heap_mut(), args);
  }

  Ok(Value::Undefined)
}

fn window_btoa_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  _this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let input = args.get(0).copied().unwrap_or(Value::Undefined);
  let s = match input {
    Value::String(s) => s,
    other => scope.heap_mut().to_string(other)?,
  };
  let code_units = scope.heap().get_string(s)?.as_code_units();

  if code_units.len() > MAX_BASE64_INPUT_LEN {
    return Err(VmError::Throw(make_dom_exception(vm, scope,
      "InvalidCharacterError",
      "The string to be encoded is too large.",
    )?));
  }

  let mut bytes: Vec<u8> = Vec::new();
  bytes
    .try_reserve_exact(code_units.len())
    .map_err(|_| VmError::OutOfMemory)?;
  for &u in code_units {
    if u > 0xFF {
      return Err(VmError::Throw(make_dom_exception(vm, scope,
        "InvalidCharacterError",
        "The string to be encoded contains characters outside of the Latin1 range.",
      )?));
    }
    bytes.push(u as u8);
  }

  let expected_len = (bytes.len().saturating_add(2) / 3).saturating_mul(4);
  if expected_len > MAX_BASE64_OUTPUT_LEN {
    return Err(VmError::Throw(make_dom_exception(vm, scope,
      "InvalidCharacterError",
      "The string to be encoded is too large.",
    )?));
  }

  // HTML's "forgiving-base64 encode" uses the standard alphabet with padding and no line breaks.
  let encoded = general_purpose::STANDARD.encode(bytes);
  if encoded.len() > MAX_BASE64_OUTPUT_LEN {
    return Err(VmError::Throw(make_dom_exception(vm, scope,
      "InvalidCharacterError",
      "The string to be encoded is too large.",
    )?));
  }
  let out = scope.alloc_string(&encoded)?;
  Ok(Value::String(out))
}

fn window_atob_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  _this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let input = args.get(0).copied().unwrap_or(Value::Undefined);
  let s = match input {
    Value::String(s) => s,
    other => scope.heap_mut().to_string(other)?,
  };
  let code_units = scope.heap().get_string(s)?.as_code_units();

  if code_units.len() > MAX_BASE64_INPUT_LEN {
    return Err(VmError::Throw(make_dom_exception(vm, scope,
      "InvalidCharacterError",
      "The string to be decoded is too large.",
    )?));
  }

  // HTML's forgiving-base64 decode algorithm.
  let mut stripped: Vec<u8> = Vec::new();
  stripped
    .try_reserve_exact(code_units.len())
    .map_err(|_| VmError::OutOfMemory)?;

  for &unit in code_units {
    if is_html_ascii_whitespace_unit(unit) {
      continue;
    }
    if unit > 0xFF {
      return Err(VmError::Throw(make_dom_exception(vm, scope,
        "InvalidCharacterError",
        "The string to be decoded is not correctly encoded.",
      )?));
    }
    stripped.push(unit as u8);
  }

  // If length mod 4 is 0, remove up to two '=' from the end.
  if stripped.len() % 4 == 0 {
    let mut removed = 0usize;
    while removed < 2 && stripped.last() == Some(&b'=') {
      stripped.pop();
      removed += 1;
    }
  }

  // If length mod 4 is 1, fail.
  if stripped.len() % 4 == 1 {
    return Err(VmError::Throw(make_dom_exception(vm, scope,
      "InvalidCharacterError",
      "The string to be decoded is not correctly encoded.",
    )?));
  }

  // If it contains a non-base64 character, fail.
  if stripped
    .iter()
    .copied()
    .any(|b| !is_base64_alphabet_byte(b))
  {
    return Err(VmError::Throw(make_dom_exception(vm, scope,
      "InvalidCharacterError",
      "The string to be decoded is not correctly encoded.",
    )?));
  }

  // Pad with '=' until length mod 4 is 0.
  while stripped.len() % 4 != 0 {
    stripped.push(b'=');
  }

  let decoded = match general_purpose::STANDARD.decode(&stripped) {
    Ok(decoded) => decoded,
    Err(_) => {
      return Err(VmError::Throw(make_dom_exception(vm, scope,
        "InvalidCharacterError",
        "The string to be decoded is not correctly encoded.",
      )?));
    }
  };

  if decoded.len() > MAX_BASE64_OUTPUT_LEN {
    return Err(VmError::Throw(make_dom_exception(vm, scope,
      "InvalidCharacterError",
      "The string to be decoded is too large.",
    )?));
  }

  let mut units: Vec<u16> = Vec::new();
  units
    .try_reserve_exact(decoded.len())
    .map_err(|_| VmError::OutOfMemory)?;
  units.extend(decoded.iter().map(|&b| b as u16));
  let out = scope.alloc_string_from_u16_vec(units)?;
  Ok(Value::String(out))
}

pub(crate) fn make_dom_exception(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  name: &str,
  message: &str,
) -> Result<Value, VmError> {
  // Prefer creating a real `DOMException` instance so `err instanceof DOMException` works in WPT.
  //
  // Note: `init_window_globals` installs `DOMException` early, but this helper is also used in
  // fallback/test-only code paths. If we cannot recover the current realm's global object or
  // intrinsics, fall back to a plain object so we still throw *something*.
  let window_obj = vm
    .user_data::<WindowRealmUserData>()
    .and_then(|data| data.window_obj);
  if let (Some(window_obj), Some(intr)) = (window_obj, vm.intrinsics()) {
    let dom_exception = DomExceptionClassVmJs::install_for_global(vm, scope, window_obj, intr)?;
    return dom_exception.new_instance(scope, name, message);
  }

  make_dom_exception_fallback_object(scope, name, message)
}

fn make_dom_exception_fallback_object(
  scope: &mut Scope<'_>,
  name: &str,
  message: &str,
) -> Result<Value, VmError> {
  let obj = scope.alloc_object()?;
  scope.push_root(Value::Object(obj))?;

  let name_s = scope.alloc_string(name)?;
  scope.push_root(Value::String(name_s))?;
  let message_s = scope.alloc_string(message)?;
  scope.push_root(Value::String(message_s))?;

  let name_key = alloc_key(scope, "name")?;
  let message_key = alloc_key(scope, "message")?;
  let code_key = alloc_key(scope, "code")?;

  scope.define_property(
    obj,
    name_key,
    PropertyDescriptor {
      enumerable: false,
      configurable: true,
      kind: PropertyKind::Data {
        value: Value::String(name_s),
        writable: false,
      },
    },
  )?;
  scope.define_property(
    obj,
    message_key,
    PropertyDescriptor {
      enumerable: false,
      configurable: true,
      kind: PropertyKind::Data {
        value: Value::String(message_s),
        writable: false,
      },
    },
  )?;

  let code = legacy_code_for_dom_exception_name(name);
  scope.define_property(
    obj,
    code_key,
    PropertyDescriptor {
      enumerable: false,
      configurable: true,
      kind: PropertyKind::Data {
        value: Value::Number(code as f64),
        writable: false,
      },
    },
  )?;

  Ok(Value::Object(obj))
}

fn dom_exception_class_for_global(
  scope: &mut Scope<'_>,
  global: GcObject,
) -> Result<Option<DomExceptionClassVmJs>, VmError> {
  // Root `global` while allocating property keys: `alloc_key` can GC.
  let mut scope = scope.reborrow();
  scope.push_root(Value::Object(global))?;

  let dom_exception_key = alloc_key(&mut scope, "DOMException")?;
  let ctor = match scope
    .heap()
    .object_get_own_data_property_value(global, &dom_exception_key)?
  {
    Some(Value::Object(obj)) => obj,
    _ => return Ok(None),
  };
  scope.push_root(Value::Object(ctor))?;

  let prototype_key = alloc_key(&mut scope, "prototype")?;
  let prototype = match scope
    .heap()
    .object_get_own_data_property_value(ctor, &prototype_key)?
  {
    Some(Value::Object(obj)) => obj,
    _ => return Ok(None),
  };

  Ok(Some(DomExceptionClassVmJs {
    constructor: ctor,
    prototype,
  }))
}

fn make_dom_exception_for_global(
  scope: &mut Scope<'_>,
  global: GcObject,
  name: &str,
  message: &str,
) -> Result<Value, VmError> {
  if let Some(dom_exception) = dom_exception_class_for_global(scope, global)? {
    return dom_exception.new_instance(scope, name, message);
  }
  make_dom_exception_fallback_object(scope, name, message)
}

fn to_uint16_from_f64(mut n: f64) -> u16 {
  // WebIDL `ToUint16`:
  // - NaN, infinities, and ±0 all map to 0
  // - otherwise, truncate toward zero and take modulo 2^16.
  if !n.is_finite() || n.is_nan() {
    n = 0.0;
  }
  let n = n.trunc();
  // NOTE: `%` on floats matches JavaScript's remainder operator; we normalize to a positive modulo.
  let n = n % 65536.0;
  let n = if n < 0.0 { n + 65536.0 } else { n };
  n as u16
}

/// DOM Traversal: <https://dom.spec.whatwg.org/#concept-node-filter>.
///
/// This implements the shared "filter a node within a NodeIterator or TreeWalker" algorithm,
/// including:
/// - `is_active` re-entrancy guard (`InvalidStateError`)
/// - WebIDL "call a user object's operation" semantics for callback interfaces
/// - return value conversion to `unsigned short` (`ToUint16`)
pub(crate) fn traversal_filter_node(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  traverser_is_active: &Cell<bool>,
  what_to_show: u32,
  filter: Value,
  node: Value,
  node_type: u16,
) -> Result<u16, VmError> {
  // Spec step 1: prevent recursive invocations.
  if traverser_is_active.get() {
    return Err(VmError::Throw(make_dom_exception(
      vm,
      scope,
      "InvalidStateError",
      "",
    )?));
  }

  // Spec step 2/3: apply the whatToShow bitmask before invoking the callback.
  let n = node_type.saturating_sub(1) as u32;
  if n >= 32 || (what_to_show & (1u32 << n)) == 0 {
    return Ok(3); // NodeFilter.FILTER_SKIP
  }

  // Spec step 4: null filter short-circuit.
  if matches!(filter, Value::Null | Value::Undefined) {
    return Ok(1); // NodeFilter.FILTER_ACCEPT
  }

  // Root callback + node while we allocate property keys and invoke user code.
  let mut scope = scope.reborrow();
  scope.push_root(filter)?;
  scope.push_root(node)?;

  // Spec step 5+: mark active for the duration of the callback conversion/invocation.
  traverser_is_active.set(true);
  struct TraversalActiveGuard<'a> {
    flag: &'a Cell<bool>,
  }
  impl Drop for TraversalActiveGuard<'_> {
    fn drop(&mut self) {
      self.flag.set(false);
    }
  }
  let _active_guard = TraversalActiveGuard {
    flag: traverser_is_active,
  };

  // Spec step 6: call a user object's operation.
  //
  // WebIDL callback interface rules:
  // - If `filter` is callable, call it directly with `this = undefined`.
  // - Otherwise, call `filter.acceptNode(node)` with `this = filter`.
  let return_value = if scope.heap().is_callable(filter)? {
    vm.call_with_host_and_hooks(host, &mut scope, hooks, filter, Value::Undefined, &[node])?
  } else if let Value::Object(filter_obj) = filter {
    let accept_node_key = alloc_key(&mut scope, "acceptNode")?;
    let accept_node =
      vm.get_with_host_and_hooks(host, &mut scope, hooks, filter_obj, accept_node_key)?;
    if !scope.heap().is_callable(accept_node)? {
      return Err(VmError::TypeError(
        "NodeFilter callback has no callable acceptNode",
      ));
    }
    vm.call_with_host_and_hooks(host, &mut scope, hooks, accept_node, filter, &[node])?
  } else {
    return Err(VmError::TypeError(
      "NodeFilter callback is not callable and not an object",
    ));
  };

  // WebIDL return type conversion: `unsigned short`.
  scope.push_root(return_value)?;
  let n = scope.to_number(vm, host, hooks, return_value)?;
  Ok(to_uint16_from_f64(n))
}

fn sanitize_scroll_coord(n: f64) -> f32 {
  if n.is_nan() {
    return 0.0;
  }
  if n == f64::INFINITY {
    return f32::MAX;
  }
  if n == f64::NEG_INFINITY {
    return f32::MIN;
  }
  let min = f32::MIN as f64;
  let max = f32::MAX as f64;
  n.clamp(min, max) as f32
}

const DEFAULT_SCROLL_LINE_HEIGHT_PX: f64 = 40.0;

fn sanitize_scroll_multiplier(n: f64) -> f64 {
  if n.is_finite() { n } else { 0.0 }
}

fn parse_scroll_offsets_from_options_object(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  options_obj: GcObject,
) -> Result<(f32, f32), VmError> {
  // Root `options_obj` while allocating property keys: `alloc_key` can trigger GC.
  let mut scope = scope.reborrow();
  scope.push_root(Value::Object(options_obj))?;

  let left_key = alloc_key(&mut scope, "left")?;
  let top_key = alloc_key(&mut scope, "top")?;

  let left_value = vm.get(&mut scope, options_obj, left_key)?;
  let top_value = vm.get(&mut scope, options_obj, top_key)?;

  let left = sanitize_scroll_coord(scope.to_number(vm, host, hooks, left_value)?);
  let top = sanitize_scroll_coord(scope.to_number(vm, host, hooks, top_value)?);

  Ok((left, top))
}

fn parse_scroll_offsets_from_args(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  args: &[Value],
) -> Result<(f32, f32), VmError> {
  let first = args.get(0).copied().unwrap_or(Value::Undefined);
  if let Value::Object(obj) = first {
    return parse_scroll_offsets_from_options_object(vm, scope, host, hooks, obj);
  }

  let x = sanitize_scroll_coord(scope.to_number(vm, host, hooks, first)?);
  let y_value = args.get(1).copied().unwrap_or(Value::Undefined);
  let y = sanitize_scroll_coord(scope.to_number(vm, host, hooks, y_value)?);
  Ok((x, y))
}

fn window_scroll_x_get_native(
  _vm: &mut Vm,
  _scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  _this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  if let Some(document) = host.as_any_mut().downcast_mut::<BrowserDocumentDom2>() {
    let offset = document.viewport_scroll_offset();
    return Ok(Value::Number(if offset.x.is_finite() {
      offset.x as f64
    } else {
      0.0
    }));
  }
  Ok(Value::Number(0.0))
}

fn window_scroll_y_get_native(
  _vm: &mut Vm,
  _scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  _this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  if let Some(document) = host.as_any_mut().downcast_mut::<BrowserDocumentDom2>() {
    let offset = document.viewport_scroll_offset();
    return Ok(Value::Number(if offset.y.is_finite() {
      offset.y as f64
    } else {
      0.0
    }));
  }
  Ok(Value::Number(0.0))
}

fn viewport_height_for_scroll_by_pages(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
) -> Result<f64, VmError> {
  if let Some(document) = host.as_any_mut().downcast_mut::<BrowserDocumentDom2>() {
    if let Some((_w, h)) = document.options().viewport {
      return Ok(h as f64);
    }
  }

  let Some(window_obj) = vm
    .user_data::<WindowRealmUserData>()
    .and_then(|data| data.window_obj)
  else {
    return Ok(0.0);
  };

  // Root the window object while allocating the property key: `alloc_key` can trigger GC.
  let mut scope = scope.reborrow();
  scope.push_root(Value::Object(window_obj))?;
  let key = alloc_key(&mut scope, "innerHeight")?;
  let raw = vm.get(&mut scope, window_obj, key)?;
  let n = scope.to_number(vm, host, hooks, raw)?;
  Ok(sanitize_scroll_multiplier(n))
}

fn window_scroll_to_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  _this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let (x, y) = parse_scroll_offsets_from_args(vm, scope, host, hooks, args)?;

  let Some(document) = host.as_any_mut().downcast_mut::<BrowserDocumentDom2>() else {
    return Ok(Value::Undefined);
  };

  let desired = crate::geometry::Point::new(x, y);
  let Ok(clamped) = document.clamp_viewport_scroll_offset(desired) else {
    return Ok(Value::Undefined);
  };
  document.set_scroll(clamped.x, clamped.y);
  Ok(Value::Undefined)
}

fn window_scroll_by_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  _this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let (dx, dy) = parse_scroll_offsets_from_args(vm, scope, host, hooks, args)?;

  let Some(document) = host.as_any_mut().downcast_mut::<BrowserDocumentDom2>() else {
    return Ok(Value::Undefined);
  };
  let current = document.viewport_scroll_offset();
  let desired = crate::geometry::Point::new(
    sanitize_scroll_coord(current.x as f64 + dx as f64),
    sanitize_scroll_coord(current.y as f64 + dy as f64),
  );
  let Ok(clamped) = document.clamp_viewport_scroll_offset(desired) else {
    return Ok(Value::Undefined);
  };
  document.set_scroll(clamped.x, clamped.y);
  Ok(Value::Undefined)
}

fn window_scroll_by_lines_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  _this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let lines_raw =
    scope.to_number(vm, host, hooks, args.get(0).copied().unwrap_or(Value::Undefined))?;
  let lines = sanitize_scroll_multiplier(lines_raw);
  let delta_y = sanitize_scroll_multiplier(lines * DEFAULT_SCROLL_LINE_HEIGHT_PX);
  let args = [Value::Number(0.0), Value::Number(delta_y)];
  window_scroll_by_native(vm, scope, host, hooks, _callee, _this, &args)
}

fn window_scroll_by_pages_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  _this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let pages_raw =
    scope.to_number(vm, host, hooks, args.get(0).copied().unwrap_or(Value::Undefined))?;
  let pages = sanitize_scroll_multiplier(pages_raw);
  let viewport_h = viewport_height_for_scroll_by_pages(vm, scope, host, hooks)?;
  let delta_y = sanitize_scroll_multiplier(pages * viewport_h);
  let args = [Value::Number(0.0), Value::Number(delta_y)];
  window_scroll_by_native(vm, scope, host, hooks, _callee, _this, &args)
}
fn serialized_origin_for_document_url(url: &str) -> String {
  let Ok(url) = Url::parse(url) else {
    return "null".to_string();
  };
  match url.scheme() {
    "http" | "https" => url.origin().ascii_serialization(),
    // FastRender treats trusted `chrome://` documents as having a tuple origin so internal pages
    // can safely use same-document navigation APIs like `history.pushState` without collapsing all
    // `chrome://*` pages into the opaque "null" origin bucket. See
    // `docs/renderer_chrome_schemes.md`.
    "chrome" => {
      let Some(host) = url.host_str() else {
        return "null".to_string();
      };
      let host = host.to_ascii_lowercase();
      let host = if host.contains(':') && !host.starts_with('[') {
        format!("[{host}]")
      } else {
        host
      };
      match url.port() {
        Some(port) => format!("chrome://{host}:{port}"),
        None => format!("chrome://{host}"),
      }
    }
    _ => "null".to_string(),
  }
}

pub(crate) fn is_secure_context_for_document_url(url: &str) -> bool {
  let Ok(url) = Url::parse(url) else {
    return false;
  };
  match url.scheme() {
    "https" => true,
    "http" => matches!(url.host_str(), Some("localhost" | "127.0.0.1" | "::1")),
    _ => false,
  }
}

fn is_base64_alphabet_byte(b: u8) -> bool {
  matches!(b, b'A'..=b'Z' | b'a'..=b'z' | b'0'..=b'9' | b'+' | b'/')
}

fn is_html_ascii_whitespace_unit(unit: u16) -> bool {
  matches!(unit, 0x09 | 0x0A | 0x0C | 0x0D | 0x20)
}

fn location_href_get_native(
  _vm: &mut Vm,
  scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(location_obj) = this else {
    return Ok(Value::Undefined);
  };
  let key = alloc_key(scope, LOCATION_URL_KEY)?;
  Ok(
    scope
      .heap()
      .object_get_own_data_property_value(location_obj, &key)?
      .unwrap_or(Value::Undefined),
  )
}

fn location_to_string_native(
  _vm: &mut Vm,
  scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  // `Location#toString` is defined to return the same value as `location.href`.
  //
  // Real browsers use a real Location prototype; FastRender models `location` as a plain object,
  // so keep the canonical URL in a private data property (`__fastrender_location_url`).
  let Value::Object(location_obj) = this else {
    return Ok(Value::Undefined);
  };
  let key = alloc_key(scope, LOCATION_URL_KEY)?;
  Ok(
    scope
      .heap()
      .object_get_own_data_property_value(location_obj, &key)?
      .unwrap_or(Value::Undefined),
  )
}

fn location_to_primitive_native(
  _vm: &mut Vm,
  scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  // `Location[@@toPrimitive]` should stringify to the current `href`.
  //
  // Ignore the hint argument: returning the URL string for all hints keeps common operations like
  // `location + ''` and `String(location)` aligned with browser expectations.
  let Value::Object(location_obj) = this else {
    return Ok(Value::Undefined);
  };
  let key = alloc_key(scope, LOCATION_URL_KEY)?;
  Ok(
    scope
      .heap()
      .object_get_own_data_property_value(location_obj, &key)?
      .unwrap_or(Value::Undefined),
  )
}

fn window_location_get_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  callee: GcObject,
  this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  let slots = scope.heap().get_function_native_slots(callee)?;
  let location_value = slots
    .get(LOCATION_ACCESSOR_LOCATION_OBJ_SLOT)
    .copied()
    .unwrap_or(Value::Undefined);

  let Value::Object(receiver_obj) = this else {
    return Ok(location_value);
  };

  // `document.location` must be `null` for windowless documents (e.g. those created via
  // `document.implementation.createHTMLDocument()`). Guard the shared accessor so inheriting
  // `document.location` from the host document cannot accidentally expose `window.location`.
  let allow = vm
    .user_data_mut::<WindowRealmUserData>()
    .map(|data| data.window_obj == Some(receiver_obj) || data.document_obj == Some(receiver_obj))
    .unwrap_or(true);
  if !allow {
    return Ok(Value::Null);
  }

  Ok(location_value)
}

const MAX_PENDING_HASHCHANGE_EVENTS: usize = 1024;

#[derive(Clone, Debug)]
struct QueuedHashChangeEvent {
  old_url: String,
  new_url: String,
}

fn queue_hashchange_event_task(
  vm: &mut Vm,
  hooks: &mut dyn VmHostHooks,
  old_url: String,
  new_url: String,
) {
  if let Some(event_loop) = event_loop_mut_from_hooks::<crate::api::BrowserTabHost>(hooks) {
    queue_hashchange_event_task_for_event_loop(event_loop, old_url, new_url);
    return;
  }
  if let Some(event_loop) = event_loop_mut_from_hooks::<WindowHostState>(hooks) {
    queue_hashchange_event_task_for_event_loop(event_loop, old_url, new_url);
    return;
  }

  // When no HTML event loop is installed (e.g. `WindowRealm` direct usage), still deliver
  // `hashchange` asynchronously by queueing it into the realm's user data. The queue is drained by
  // `WindowRealm::perform_microtask_checkpoint`.
  let Some(data) = vm.user_data_mut::<WindowRealmUserData>() else {
    return;
  };

  // Keep the queue bounded: if the limit is exceeded, drop the oldest events so the realm can't
  // grow unbounded via `location.hash` loops.
  while data.pending_hashchange_events.len() >= MAX_PENDING_HASHCHANGE_EVENTS {
    data.pending_hashchange_events.pop_front();
  }
  data
    .pending_hashchange_events
    .push_back(QueuedHashChangeEvent { old_url, new_url });
}

fn queue_hashchange_event_task_for_event_loop<Host: WindowRealmHost + 'static>(
  event_loop: &mut EventLoop<Host>,
  old_url: String,
  new_url: String,
) {
  let _ = event_loop.queue_task(TaskSource::DOMManipulation, move |host, event_loop| {
    dispatch_hashchange_event_task(host, event_loop, old_url, new_url)
  });
}

fn dispatch_hashchange_event(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  vm_host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  global_obj: GcObject,
  old_url: &str,
  new_url: &str,
) -> Result<(), VmError> {
  let document_obj = match vm
    .user_data::<WindowRealmUserData>()
    .and_then(|data| data.document_obj)
  {
    Some(obj) => obj,
    None => return Ok(()),
  };

  let dispatch_event = {
    scope.push_root(Value::Object(document_obj))?;
    let key = alloc_key(scope, EVENT_TARGET_DISPATCH_EVENT_KEY)?;
    scope
      .heap()
      .object_get_own_data_property_value(document_obj, &key)?
      .unwrap_or(Value::Undefined)
  };
  let dispatch_event = if matches!(dispatch_event, Value::Object(_))
    && scope.heap().is_callable(dispatch_event).unwrap_or(false)
  {
    dispatch_event
  } else {
    return Ok(());
  };

  let event_proto = {
    scope.push_root(Value::Object(document_obj))?;
    let key = alloc_key(scope, HASH_CHANGE_EVENT_PROTOTYPE_KEY)?;
    let proto = scope
      .heap()
      .object_get_own_data_property_value(document_obj, &key)?
      .and_then(|v| match v {
        Value::Object(obj) => Some(obj),
        _ => None,
      });
    if proto.is_some() {
      proto
    } else {
      let key = alloc_key(scope, EVENT_PROTOTYPE_KEY)?;
      scope
        .heap()
        .object_get_own_data_property_value(document_obj, &key)?
        .and_then(|v| match v {
          Value::Object(obj) => Some(obj),
          _ => None,
        })
    }
  };

  let event_obj = scope.alloc_object()?;
  scope.push_root(Value::Object(event_obj))?;
  if let Some(proto) = event_proto {
    scope.heap_mut().object_set_prototype(event_obj, Some(proto))?;
  }

  let type_key = alloc_key(scope, "type")?;
  let type_s = scope.alloc_string("hashchange")?;
  scope.push_root(Value::String(type_s))?;
  scope.define_property(event_obj, type_key, data_desc(Value::String(type_s)))?;

  let bubbles_key = alloc_key(scope, "bubbles")?;
  scope.define_property(event_obj, bubbles_key, data_desc(Value::Bool(false)))?;
  let cancelable_key = alloc_key(scope, "cancelable")?;
  scope.define_property(event_obj, cancelable_key, data_desc(Value::Bool(false)))?;
  let composed_key = alloc_key(scope, "composed")?;
  scope.define_property(event_obj, composed_key, data_desc(Value::Bool(false)))?;

  define_event_default_properties(scope, event_obj)?;

  let old_url_key = alloc_key(scope, "oldURL")?;
  let old_url_s = scope.alloc_string(old_url)?;
  scope.push_root(Value::String(old_url_s))?;
  scope.define_property(
    event_obj,
    old_url_key,
    read_only_data_desc(Value::String(old_url_s)),
  )?;
  let new_url_key = alloc_key(scope, "newURL")?;
  let new_url_s = scope.alloc_string(new_url)?;
  scope.push_root(Value::String(new_url_s))?;
  scope.define_property(
    event_obj,
    new_url_key,
    read_only_data_desc(Value::String(new_url_s)),
  )?;

  brand_event_object(scope, event_obj, BrandedEventKind::HashChangeEvent)?;

  vm.call_with_host_and_hooks(
    vm_host,
    scope,
    hooks,
    dispatch_event,
    Value::Object(global_obj),
    &[Value::Object(event_obj)],
  )?;
  Ok(())
}

fn dispatch_hashchange_event_task<Host: WindowRealmHost + 'static>(
  host: &mut Host,
  event_loop: &mut EventLoop<Host>,
  old_url: String,
  new_url: String,
) -> crate::error::Result<()> {
  let mut hooks = VmJsEventLoopHooks::<Host>::new_with_host(host)?;
  hooks.set_event_loop(event_loop);

  let (vm_host, window_realm) = host.vm_host_and_window_realm()?;
  let realm_id = window_realm.realm_id;
  let result = window_realm.with_vm_budget(|rt| {
    let (vm, realm, heap) = rt.vm_realm_and_heap_mut();
    let mut scope = heap.scope();
    let mut vm = vm
      .execution_context_guard(vm_js::ExecutionContext {
        realm: realm_id,
        script_or_module: None,
      })?;

    dispatch_hashchange_event(
      &mut vm,
      &mut scope,
      vm_host,
      &mut hooks,
      realm.global_object(),
      &old_url,
      &new_url,
    )
  });

  if let Some(err) = hooks.finish(window_realm.heap_mut()) {
    return Err(err);
  }

  match result {
    Ok(()) => Ok(()),
    Err(err) => Err(crate::js::vm_error_format::vm_error_to_error(
      window_realm.heap_mut(),
      err,
    )),
  }
}

fn request_location_navigation(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  location_obj: Option<GcObject>,
  url_value: Value,
  replace: bool,
) -> Result<Value, VmError> {
  let (base_url, current_document_url, window_obj, privileged_chrome_realm) = {
    let Some(data) = vm.user_data::<WindowRealmUserData>() else {
      return Err(VmError::InvariantViolation("window realm missing user data"));
    };
    // Match `document.baseURI`: fall back to the document URL when no explicit base URL is set.
    (
      data
        .base_url
        .clone()
        .unwrap_or_else(|| data.document_url.clone()),
      data.document_url.clone(),
      data.window_obj,
      data.privileged_chrome_realm,
    )
  };

  let url_value = match url_value {
    Value::String(s) => s,
    other => scope.heap_mut().to_string(other)?,
  };
  scope.push_root(Value::String(url_value))?;
  let url_input = scope.heap().get_string(url_value)?.to_utf8_lossy();

  let resolved = crate::js::url_resolve::resolve_url(&url_input, Some(base_url.as_str()))
    .map_err(|err| throw_type_error(vm, scope, host, hooks, &err.to_string()))?;

  let parsed = Url::parse(&resolved)
    .map_err(|err| throw_type_error(vm, scope, host, hooks, &err.to_string()))?;
  // Defense-in-depth: chrome:// documents must never be able to navigate to arbitrary network
  // schemes via `window.location` (even if the embedder forgets to set
  // `WindowRealm::set_privileged_chrome_realm(true)`).
  let privileged_chrome_realm = privileged_chrome_realm
    || Url::parse(&current_document_url)
      .ok()
      .is_some_and(|url| url.scheme() == "chrome");
  let scheme = parsed.scheme();
  let scheme_allowed = if privileged_chrome_realm {
    // Privileged chrome realms should never be able to navigate to untrusted content via
    // `window.location`. Restrict them to internal-only schemes.
    //
    // We allow `about:` to keep internal flows like `about:blank` usable.
    matches!(scheme, "chrome" | "about")
  } else {
    // Normal realms follow the existing navigation allowlist. Notably, they must not be able to
    // navigate into `chrome:` from web content.
    matches!(scheme, "http" | "https" | "file" | "data" | "about")
  };
  if !scheme_allowed {
    let message = if privileged_chrome_realm {
      format!("Navigation to {scheme}: URLs is not allowed from a privileged chrome realm")
    } else {
      format!("Navigation to {scheme}: URLs is not supported")
    };
    return Err(throw_type_error(vm, scope, host, hooks, &message));
  }

  // Same-document fragment navigation fast path.
  //
  // Assigning `location.href = "#fragment"` (or `location = "#fragment"`) should update the current
  // URL, push/replace a session history entry, and fire `hashchange` asynchronously. It must not
  // perform a full navigation (no pending navigation request, and no VM interruption).
  if let Ok(current_parsed) = Url::parse(&current_document_url) {
    let mut current_no_fragment = current_parsed;
    current_no_fragment.set_fragment(None);
    let mut target_no_fragment = parsed.clone();
    target_no_fragment.set_fragment(None);
    if current_no_fragment == target_no_fragment {
      if current_document_url == resolved {
        return Ok(Value::Undefined);
      }

      let resolved_s = scope.alloc_string(&resolved)?;
      scope.push_root(Value::String(resolved_s))?;

      {
        // Root objects while allocating property keys: `alloc_key` can trigger GC.
        let mut scope = scope.reborrow();
        if let Some(location_obj) = location_obj {
          scope.push_root(Value::Object(location_obj))?;
          let location_url_key = alloc_key(&mut scope, LOCATION_URL_KEY)?;
          scope.define_property(
            location_obj,
            location_url_key,
            data_desc(Value::String(resolved_s)),
          )?;
        }
      }

      let (history_state, session_history_len) = {
        let heap = scope.heap_mut();
        let Some(data) = vm.user_data_mut::<WindowRealmUserData>() else {
          return Err(VmError::InvariantViolation("window realm missing user data"));
        };
        if data.session_history.entries.is_empty() {
          return Err(VmError::InvariantViolation(
            "window realm missing session history state",
          ));
        }
        if data.session_history.index >= data.session_history.entries.len() {
          return Err(VmError::InvariantViolation(
            "window realm session history index out of bounds",
          ));
        }

        let state = heap
          .get_root(data.session_history.entries[data.session_history.index].state_root)
          .unwrap_or(Value::Null);

        let old_doc_url = std::mem::replace(&mut data.document_url, resolved.clone());
        let update_base =
          data.base_url.is_none() || data.base_url.as_deref() == Some(old_doc_url.as_str());
        if update_base {
          data.base_url = Some(resolved.clone());
          data
            .module_loader
            .borrow_mut()
            .set_document_url(data.base_url.clone());
        }

        let state_root = heap.add_root(state)?;
        if replace {
          let entry = &mut data.session_history.entries[data.session_history.index];
          entry.url = data.document_url.clone();
          let old_root = std::mem::replace(&mut entry.state_root, state_root);
          heap.remove_root(old_root);
        } else {
          let forward_start = data.session_history.index + 1;
          if forward_start < data.session_history.entries.len() {
            for entry in data.session_history.entries.drain(forward_start..) {
              heap.remove_root(entry.state_root);
            }
          }
          data
            .session_history
            .entries
            .try_reserve(1)
            .map_err(|_| VmError::OutOfMemory)?;
          data.session_history.entries.push(SessionHistoryEntry {
            url: data.document_url.clone(),
            state_root,
          });
          data.session_history.index = data.session_history.entries.len() - 1;
        }

        (state, data.session_history.entries.len())
      };

      if let Some(window_obj) = window_obj {
        let history_obj = {
          // Root the receiver while allocating the property key: `alloc_key` can trigger GC.
          let mut scope = scope.reborrow();
          scope.push_root(Value::Object(window_obj))?;
          let key = alloc_key(&mut scope, "history")?;
          scope
            .heap()
            .object_get_own_data_property_value(window_obj, &key)?
            .and_then(|v| match v {
              Value::Object(obj) => Some(obj),
              _ => None,
            })
        };

        if let Some(history_obj) = history_obj {
          // Root the receiver while allocating the property key: `alloc_key` can trigger GC.
          let mut scope = scope.reborrow();
          scope.push_root(Value::Object(history_obj))?;
          scope.push_root(history_state)?;

          let state_key = alloc_key(&mut scope, "state")?;
          scope.define_property(history_obj, state_key, read_only_data_desc(history_state))?;
          let length_key = alloc_key(&mut scope, "length")?;
          scope.define_property(
            history_obj,
            length_key,
            read_only_data_desc(Value::Number(session_history_len as f64)),
          )?;
        }
      }

      // Fire `hashchange` asynchronously: queue a DOM manipulation task when an event loop is
      // available, otherwise fall back to queuing the event on the realm for dispatch during
      // `WindowRealm::perform_microtask_checkpoint`.
      queue_hashchange_event_task(vm, hooks, current_document_url, resolved);
      return Ok(Value::Undefined);
    }
  }

  if let Some(location_obj) = location_obj {
    // Keep the resolved URL on the location object so `location.href` immediately reflects the new
    // target.
    let key = alloc_key(scope, LOCATION_URL_KEY)?;
    let resolved_s = scope.alloc_string(&resolved)?;
    scope.push_root(Value::String(resolved_s))?;
    scope.define_property(location_obj, key, data_desc(Value::String(resolved_s)))?;
  }

  {
    let Some(data) = vm.user_data_mut::<WindowRealmUserData>() else {
      return Err(VmError::InvariantViolation(
        "window realm missing user data",
      ));
    };
    data.pending_navigation = Some(LocationNavigationRequest {
      url: resolved,
      replace,
    });
  }

  // Abort the currently running script so the embedding can commit navigation synchronously (e.g.
  // cancel streaming HTML parsing and replace the document).
  vm.interrupt_handle().interrupt();
  // `InterruptHandle` is only observed at `Vm::tick()` boundaries; force a tick now so the
  // termination propagates out of this native call immediately.
  vm.tick()?;
  Ok(Value::Undefined)
}

fn window_location_set_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  if let Value::Object(receiver_obj) = this {
    let allow = vm
      .user_data_mut::<WindowRealmUserData>()
      .map(|data| data.window_obj == Some(receiver_obj) || data.document_obj == Some(receiver_obj))
      .unwrap_or(true);
    if !allow {
      // Prevent `document.location = ...` on owned documents from triggering navigation.
      return Ok(Value::Undefined);
    }
  }

  let slots = scope.heap().get_function_native_slots(callee)?;
  let location_obj = slots
    .get(LOCATION_ACCESSOR_LOCATION_OBJ_SLOT)
    .copied()
    .and_then(|value| {
      let Value::Object(obj) = value else {
        return None;
      };
      Some(obj)
    });
  let url_value = args.get(0).copied().unwrap_or(Value::Undefined);
  request_location_navigation(vm, scope, host, hooks, location_obj, url_value, false)
}

fn location_href_set_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let location_obj = location_require_this(scope, this)?;
  let url_value = args.get(0).copied().unwrap_or(Value::Undefined);
  request_location_navigation(vm, scope, host, hooks, Some(location_obj), url_value, false)
}

