fn location_reload_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  location_require_this(scope, this)?;

  let current_url = {
    let Some(data) = vm.user_data::<WindowRealmUserData>() else {
      return Err(VmError::InvariantViolation("window realm missing user data"));
    };
    data.document_url.clone()
  };

  {
    let Some(data) = vm.user_data_mut::<WindowRealmUserData>() else {
      return Err(VmError::InvariantViolation("window realm missing user data"));
    };
    data.pending_navigation = Some(LocationNavigationRequest {
      url: current_url,
      replace: true,
    });
  }

  vm.interrupt_handle().interrupt();
  vm.tick()?;
  Ok(Value::Undefined)
}

fn location_pathname_set_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let location_obj = location_require_this(scope, this)?;

  let pathname_value = args.get(0).copied().unwrap_or(Value::Undefined);
  let pathname_value = match pathname_value {
    Value::String(s) => s,
    other => scope.heap_mut().to_string(other)?,
  };
  scope.push_root(Value::String(pathname_value))?;
  let mut pathname = scope
    .heap()
    .get_string(pathname_value)?
    .to_utf8_lossy();
  if !pathname.is_empty() && !pathname.starts_with('/') {
    pathname = format!("/{pathname}");
  }

  let Some(mut url) = parse_location_url(scope, location_obj)? else {
    return Ok(Value::Undefined);
  };

  // The WHATWG URL parser treats `?`/`#` as query/fragment delimiters when parsing a path input.
  // `url::Url::set_path` percent-encodes these code points instead, so split them ourselves to
  // preserve delimiter semantics (mirrors `WebUrl::set_search`).
  let (path_and_query, fragment) = match pathname.split_once('#') {
    Some((before, fragment)) => (before, Some(fragment)),
    None => (pathname.as_str(), None),
  };
  let (path, query) = match path_and_query.split_once('?') {
    Some((path, query)) => (path, Some(query)),
    None => (path_and_query, None),
  };

  url.set_path(path);
  if let Some(query) = query {
    url.set_query(Some(query));
  }
  if let Some(fragment) = fragment {
    url.set_fragment(Some(fragment));
  }
  let new_href = url.to_string();
  let new_href_s = scope.alloc_string(&new_href)?;
  request_location_navigation(
    vm,
    scope,
    host,
    hooks,
    Some(location_obj),
    Value::String(new_href_s),
    false,
  )
}

fn location_search_set_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let location_obj = location_require_this(scope, this)?;

  let search_value = args.get(0).copied().unwrap_or(Value::Undefined);
  let search_value = match search_value {
    Value::String(s) => s,
    other => scope.heap_mut().to_string(other)?,
  };
  scope.push_root(Value::String(search_value))?;

  let Some(mut url) = parse_location_url(scope, location_obj)? else {
    return Ok(Value::Undefined);
  };

  let search = scope.heap().get_string(search_value)?.to_utf8_lossy();
  if search.is_empty() {
    url.set_query(None);
  } else {
    let input = search.strip_prefix('?').unwrap_or(search.as_ref());
    // In query state, `#` starts the fragment. `url::Url::set_query` percent-encodes `#`, so split
    // it ourselves to preserve delimiter semantics (matches `WebUrl::set_search`).
    let (query, fragment) = match input.split_once('#') {
      Some((query, fragment)) => (query, Some(fragment)),
      None => (input, None),
    };
    url.set_query(Some(query));
    if let Some(fragment) = fragment {
      url.set_fragment(Some(fragment));
    }
  }
  let new_href = url.to_string();
  let new_href_s = scope.alloc_string(&new_href)?;
  request_location_navigation(
    vm,
    scope,
    host,
    hooks,
    Some(location_obj),
    Value::String(new_href_s),
    false,
  )
}

fn location_hash_set_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let location_obj = location_require_this(scope, this)?;

  let hash_value = args.get(0).copied().unwrap_or(Value::Undefined);
  let hash_value = match hash_value {
    Value::String(s) => s,
    other => scope.heap_mut().to_string(other)?,
  };
  scope.push_root(Value::String(hash_value))?;
  let mut hash = scope.heap().get_string(hash_value)?.to_utf8_lossy();
  if !hash.is_empty() && !hash.starts_with('#') {
    hash = format!("#{hash}");
  }

  let Some(mut url) = parse_location_url(scope, location_obj)? else {
    return Ok(Value::Undefined);
  };
  if hash.is_empty() {
    url.set_fragment(None);
  } else {
    url.set_fragment(Some(&hash[1..]));
  }
  let new_href = url.to_string();
  let new_href_s = scope.alloc_string(&new_href)?;
  request_location_navigation(
    vm,
    scope,
    host,
    hooks,
    Some(location_obj),
    Value::String(new_href_s),
    false,
  )
}

fn location_protocol_set_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let location_obj = location_require_this(scope, this)?;

  let protocol_value = args.get(0).copied().unwrap_or(Value::Undefined);
  let protocol_value = match protocol_value {
    Value::String(s) => s,
    other => scope.heap_mut().to_string(other)?,
  };
  scope.push_root(Value::String(protocol_value))?;
  let mut scheme = scope
    .heap()
    .get_string(protocol_value)?
    .to_utf8_lossy()
    .trim_end_matches(':')
    .to_string();
  scheme.make_ascii_lowercase();

  // Match `request_location_navigation` supported schemes. For invalid/unsupported schemes, behave
  // browser-like and no-op instead of throwing.
  let (current_document_url, privileged_chrome_realm) = {
    let Some(data) = vm.user_data::<WindowRealmUserData>() else {
      return Err(VmError::InvariantViolation("window realm missing user data"));
    };
    (data.document_url.clone(), data.privileged_chrome_realm)
  };
  let chrome_scheme_document = Url::parse(&current_document_url)
    .ok()
    .is_some_and(|url| url.scheme() == "chrome");
  let privileged_chrome_realm = privileged_chrome_realm || chrome_scheme_document;
  let scheme_allowed = if privileged_chrome_realm {
    matches!(scheme.as_str(), "chrome" | "about")
  } else {
    matches!(scheme.as_str(), "http" | "https" | "file" | "data" | "about")
  };
  if !scheme_allowed {
    return Ok(Value::Undefined);
  }

  let Some(mut url) = parse_location_url(scope, location_obj)? else {
    return Ok(Value::Undefined);
  };
  if url.set_scheme(&scheme).is_err() {
    return Ok(Value::Undefined);
  }

  let new_href = url.to_string();
  let new_href_s = scope.alloc_string(&new_href)?;
  request_location_navigation(
    vm,
    scope,
    host,
    hooks,
    Some(location_obj),
    Value::String(new_href_s),
    false,
  )
}

fn location_host_set_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let location_obj = location_require_this(scope, this)?;

  let host_value = args.get(0).copied().unwrap_or(Value::Undefined);
  let host_value = match host_value {
    Value::String(s) => s,
    other => scope.heap_mut().to_string(other)?,
  };
  scope.push_root(Value::String(host_value))?;
  let host_input = scope.heap().get_string(host_value)?.to_utf8_lossy();

  let Some(mut url) = parse_location_url(scope, location_obj)? else {
    return Ok(Value::Undefined);
  };

  // Parse "hostname" or "hostname:port", with best-effort support for bracketed IPv6 hosts.
  //
  // Note: rust-url expects bracketed IPv6 (e.g. `"[::1]"`) for `Url::set_host`.
  let (host_part, port_part) = if host_input.starts_with('[') {
    let Some(end) = host_input.find(']') else {
      return Ok(Value::Undefined);
    };
    // Keep the brackets for `Url::set_host`.
    let host = &host_input[..end + 1];
    let after = &host_input[end + 1..];
    let port = if after.is_empty() {
      None
    } else if let Some(port) = after.strip_prefix(':') {
      Some(port)
    } else {
      // Trailing garbage after the closing bracket is invalid.
      return Ok(Value::Undefined);
    };
    (host, port)
  } else if let Some(colon) = host_input.rfind(':') {
    let (left, right_with_colon) = host_input.split_at(colon);
    let right = &right_with_colon[1..];
    // Only treat the last ':' as a port separator when the left side does not contain ':' (so we
    // don't misparse unbracketed IPv6).
    if !left.contains(':') && (right.is_empty() || right.chars().all(|c| c.is_ascii_digit())) {
      (left, Some(right))
    } else {
      (host_input.as_str(), None)
    }
  } else {
    (host_input.as_str(), None)
  };

  if host_part.is_empty() {
    return Ok(Value::Undefined);
  }
  if url.set_host(Some(host_part)).is_err() {
    return Ok(Value::Undefined);
  }

  // Setting `location.host` updates both hostname and port. When no port is provided, clear the
  // explicit port.
  let port_value = match port_part {
    None => None,
    Some("") => None,
    Some(port_str) => match port_str.parse::<u32>() {
      Ok(port) if port <= u16::MAX as u32 => Some(port as u16),
      _ => return Ok(Value::Undefined),
    },
  };
  if url.set_port(port_value).is_err() {
    return Ok(Value::Undefined);
  }

  let new_href = url.to_string();
  let new_href_s = scope.alloc_string(&new_href)?;
  request_location_navigation(
    vm,
    scope,
    host,
    hooks,
    Some(location_obj),
    Value::String(new_href_s),
    false,
  )
}

fn location_hostname_set_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let location_obj = location_require_this(scope, this)?;

  let hostname_value = args.get(0).copied().unwrap_or(Value::Undefined);
  let hostname_value = match hostname_value {
    Value::String(s) => s,
    other => scope.heap_mut().to_string(other)?,
  };
  scope.push_root(Value::String(hostname_value))?;
  let hostname_input = scope.heap().get_string(hostname_value)?.to_utf8_lossy();

  let Some(mut url) = parse_location_url(scope, location_obj)? else {
    return Ok(Value::Undefined);
  };

  // Best-effort: accept bracketed IPv6 (`[::1]`). rust-url expects the brackets for `set_host`.
  let hostname = hostname_input.as_str();

  if hostname.is_empty() {
    return Ok(Value::Undefined);
  }
  if url.set_host(Some(hostname)).is_err() {
    return Ok(Value::Undefined);
  }

  let new_href = url.to_string();
  let new_href_s = scope.alloc_string(&new_href)?;
  request_location_navigation(
    vm,
    scope,
    host,
    hooks,
    Some(location_obj),
    Value::String(new_href_s),
    false,
  )
}

fn location_port_set_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let location_obj = location_require_this(scope, this)?;

  let port_value = args.get(0).copied().unwrap_or(Value::Undefined);
  let port_value = match port_value {
    Value::String(s) => s,
    other => scope.heap_mut().to_string(other)?,
  };
  scope.push_root(Value::String(port_value))?;
  let port_input = scope.heap().get_string(port_value)?.to_utf8_lossy();

  let Some(mut url) = parse_location_url(scope, location_obj)? else {
    return Ok(Value::Undefined);
  };

  let port = if port_input.is_empty() {
    None
  } else if port_input.chars().all(|c| c.is_ascii_digit()) {
    match port_input.parse::<u32>() {
      Ok(port) if port <= u16::MAX as u32 => Some(port as u16),
      _ => return Ok(Value::Undefined),
    }
  } else {
    return Ok(Value::Undefined);
  };

  if url.set_port(port).is_err() {
    return Ok(Value::Undefined);
  }

  let new_href = url.to_string();
  let new_href_s = scope.alloc_string(&new_href)?;
  request_location_navigation(
    vm,
    scope,
    host,
    hooks,
    Some(location_obj),
    Value::String(new_href_s),
    false,
  )
}

fn throw_data_clone_error(vm: &mut Vm, scope: &mut Scope<'_>) -> Result<VmError, VmError> {
  Ok(VmError::Throw(make_dom_exception(vm, scope,
    "DataCloneError",
    "",
  )?))
}

fn history_state_is_uncloneable_dom_object(
  scope: &mut Scope<'_>,
  obj: GcObject,
) -> Result<bool, VmError> {
  // Treat DOM/platform wrapper objects as uncloneable. This is a subset of what the HTML structured
  // clone algorithm rejects, but is sufficient for `history.pushState` / `history.replaceState`:
  // Node wrappers, Document wrappers, and host-backed helper objects like DOMStringMap.

  // Fast path: any host slots indicate a host/platform object (e.g. DOMStringMap, TextEncoder).
  if scope.heap().object_host_slots(obj)?.is_some() {
    return Ok(true);
  }

  // DOM wrappers created by `window_realm` use internal, non-enumerable properties as brands.
  let node_id_key = alloc_key(scope, NODE_ID_KEY)?;
  if scope
    .heap()
    .object_get_own_data_property_value(obj, &node_id_key)?
    .is_some()
  {
    return Ok(true);
  }
  let wrapper_document_key = alloc_key(scope, WRAPPER_DOCUMENT_KEY)?;
  if scope
    .heap()
    .object_get_own_data_property_value(obj, &wrapper_document_key)?
    .is_some()
  {
    return Ok(true);
  }
  let document_window_key = alloc_key(scope, DOCUMENT_WINDOW_KEY)?;
  if scope
    .heap()
    .object_get_own_data_property_value(obj, &document_window_key)?
    .is_some()
  {
    return Ok(true);
  }

  Ok(false)
}

fn history_state_structured_clone(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  value: Value,
) -> Result<Value, VmError> {
  // Root the input value so the source graph stays live for the duration of the clone.
  scope.push_root(value)?;

  let mut seen: HashMap<GcObject, Value> = HashMap::new();
  history_state_structured_clone_inner(vm, scope, host, hooks, value, &mut seen)
}

fn history_state_structured_clone_inner(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  value: Value,
  seen: &mut HashMap<GcObject, Value>,
) -> Result<Value, VmError> {
  match value {
    Value::Undefined
    | Value::Null
    | Value::Bool(_)
    | Value::Number(_)
    | Value::BigInt(_)
    | Value::String(_) => Ok(value),
    Value::Symbol(_) => Err(throw_data_clone_error(vm, scope)?),
    Value::Object(obj) => {
      if let Some(cloned) = seen.get(&obj).copied() {
        return Ok(cloned);
      }

      // Uncloneable types (subset).
      if scope.heap().is_callable(value)? {
        return Err(throw_data_clone_error(vm, scope)?);
      }
      if scope.heap().is_promise_object(obj) {
        return Err(throw_data_clone_error(vm, scope)?);
      }
      if history_state_is_uncloneable_dom_object(scope, obj)? {
        return Err(throw_data_clone_error(vm, scope)?);
      }

      let intr = vm
        .intrinsics()
        .ok_or(VmError::InvariantViolation("structured clone requires intrinsics"))?;

      // ArrayBuffer.
      if scope.heap().is_array_buffer_object(obj) {
        let bytes: Vec<u8> = scope.heap().array_buffer_data(obj)?.to_vec();
        let cloned_buf = scope.alloc_array_buffer_from_u8_vec(bytes)?;
        scope.push_root(Value::Object(cloned_buf))?;
        scope
          .heap_mut()
          .object_set_prototype(cloned_buf, Some(intr.array_buffer_prototype()))?;
        let out = Value::Object(cloned_buf);
        seen.insert(obj, out);
        return Ok(out);
      }

      // Uint8Array (minimal): clone visible bytes into a new backing ArrayBuffer.
      if scope.heap().is_uint8_array_object(obj) {
        let bytes: Vec<u8> = {
          let data = scope.heap().uint8_array_data(obj)?;
          data.to_vec()
        };
        let len = bytes.len();
        let cloned_buf = scope.alloc_array_buffer_from_u8_vec(bytes)?;
        scope.push_root(Value::Object(cloned_buf))?;
        scope
          .heap_mut()
          .object_set_prototype(cloned_buf, Some(intr.array_buffer_prototype()))?;

        let cloned_view = scope.alloc_uint8_array(cloned_buf, 0, len)?;
        scope.push_root(Value::Object(cloned_view))?;
        scope
          .heap_mut()
          .object_set_prototype(cloned_view, Some(intr.uint8_array_prototype()))?;

        let out = Value::Object(cloned_view);
        seen.insert(obj, out);
        return Ok(out);
      }

      // Date objects are branded by an internal `[[DateValue]]` slot in `vm-js`.
      let date_value = scope.heap().date_value(obj)?;

      // Allocate the clone now and insert into `seen` before cloning properties so cyclic graphs are
      // supported.
      let (cloned_obj, is_array) = if scope.heap().object_is_array(obj)? {
        // Preserve Array `length` (including holes) by reading the non-enumerable own data
        // property directly (avoids getter invocation).
        let len_key = alloc_key(scope, "length")?;
        let len = match scope.heap().object_get_own_data_property_value(obj, &len_key)? {
          Some(Value::Number(n)) if n.is_finite() && n >= 0.0 => n as usize,
          _ => 0,
        };
        let arr = scope.alloc_array(len)?;
        scope.push_root(Value::Object(arr))?;
        scope
          .heap_mut()
          .object_set_prototype(arr, Some(intr.array_prototype()))?;
        (arr, true)
      } else if let Some(time) = date_value {
        let date = scope.alloc_date(time)?;
        scope.push_root(Value::Object(date))?;
        scope
          .heap_mut()
          .object_set_prototype(date, Some(intr.date_prototype()))?;
        (date, false)
      } else {
        let cloned = scope.alloc_object()?;
        scope.push_root(Value::Object(cloned))?;
        scope
          .heap_mut()
          .object_set_prototype(cloned, Some(intr.object_prototype()))?;
        (cloned, false)
      };

      let out = Value::Object(cloned_obj);
      seen.insert(obj, out);

      // Copy own enumerable string-keyed properties.
      //
      // Note: This intentionally ignores non-enumerable and symbol keys. This covers the common
      // subset used by History state in the wild.
      let keys = scope.heap().own_property_keys(obj)?;
      for key in keys {
        let PropertyKey::String(_) = key else {
          continue;
        };
        let Some(desc) = scope.heap().object_get_own_property(obj, &key)? else {
          continue;
        };
        if !desc.enumerable {
          continue;
        }

        // Obtain the source value. For accessors, invoke `Get` so we clone the observed value.
        let src_value = match desc.kind {
          PropertyKind::Data { value, .. } => value,
          PropertyKind::Accessor { .. } => vm.get_with_host_and_hooks(host, scope, hooks, obj, key)?,
        };

        let cloned_value = history_state_structured_clone_inner(vm, scope, host, hooks, src_value, seen)?;

        let new_desc = match desc.kind {
          PropertyKind::Data { writable, .. } => PropertyDescriptor {
            enumerable: true,
            configurable: desc.configurable,
            kind: PropertyKind::Data {
              value: cloned_value,
              writable,
            },
          },
          PropertyKind::Accessor { .. } => PropertyDescriptor {
            enumerable: true,
            configurable: desc.configurable,
            kind: PropertyKind::Data {
              value: cloned_value,
              writable: true,
            },
          },
        };

        // Root the receiver while defining properties: `define_property` can allocate.
        {
          let mut scope = scope.reborrow();
          scope.push_root(Value::Object(cloned_obj))?;
          scope.define_property(cloned_obj, key, new_desc)?;
        }
      }

      // Silence unused variable warning; `is_array` is only used for clarity when reading.
      let _ = is_array;
      Ok(out)
    }
  }
}

fn history_scroll_restoration_get_native(
  _vm: &mut Vm,
  scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(history_obj) = this else {
    return Err(VmError::TypeError("Illegal invocation"));
  };
  // Root the receiver while allocating strings.
  scope.push_root(Value::Object(history_obj))?;

  let slots = host_slots_for_object(scope, history_obj)?
    .filter(|slots| slots.a == WINDOW_REALM_HISTORY_HOST_TAG)
    .ok_or(VmError::TypeError("Illegal invocation"))?;

  let value = match slots.b {
    HISTORY_SCROLL_RESTORATION_AUTO => "auto",
    HISTORY_SCROLL_RESTORATION_MANUAL => "manual",
    // Defensive fallback: treat unknown values as the default "auto".
    _ => "auto",
  };
  Ok(Value::String(scope.alloc_string(value)?))
}

fn history_scroll_restoration_set_native(
  _vm: &mut Vm,
  scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(history_obj) = this else {
    return Err(VmError::TypeError("Illegal invocation"));
  };
  // Root the receiver while allocating strings.
  scope.push_root(Value::Object(history_obj))?;

  let slots = host_slots_for_object(scope, history_obj)?
    .filter(|slots| slots.a == WINDOW_REALM_HISTORY_HOST_TAG)
    .ok_or(VmError::TypeError("Illegal invocation"))?;

  // WebIDL enum conversion: ToString + validate exact matches.
  let raw_value = args.get(0).copied().unwrap_or(Value::Undefined);
  let value_s = match raw_value {
    Value::String(s) => s,
    other => scope.heap_mut().to_string(other)?,
  };
  scope.push_root(Value::String(value_s))?;
  let value = scope.heap().get_string(value_s)?.to_utf8_lossy();

  let mode = match value.as_str() {
    "auto" => HISTORY_SCROLL_RESTORATION_AUTO,
    "manual" => HISTORY_SCROLL_RESTORATION_MANUAL,
    _ => {
      return Err(VmError::TypeError(
        "history.scrollRestoration must be either \"auto\" or \"manual\"",
      ))
    }
  };

  scope.heap_mut().object_set_host_slots(
    history_obj,
    HostSlots {
      a: slots.a,
      b: mode,
    },
  )?;
  Ok(Value::Undefined)
}

fn history_state_change_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let slots = scope.heap().get_function_native_slots(callee)?;
  let history_obj = match slots
    .get(HISTORY_OBJ_SLOT)
    .copied()
    .unwrap_or(Value::Undefined)
  {
    Value::Object(obj) => obj,
    _ => return Ok(Value::Undefined),
  };
  history_require_this(this, history_obj)?;
  let location_obj = match slots
    .get(HISTORY_LOCATION_OBJ_SLOT)
    .copied()
    .unwrap_or(Value::Undefined)
  {
    Value::Object(obj) => obj,
    _ => return Ok(Value::Undefined),
  };
  let document_obj = match slots
    .get(HISTORY_DOCUMENT_OBJ_SLOT)
    .copied()
    .unwrap_or(Value::Undefined)
  {
    Value::Object(obj) => obj,
    _ => return Ok(Value::Undefined),
  };
  let _ = document_obj;
  let replace = matches!(
    slots
      .get(HISTORY_REPLACE_SLOT)
      .copied()
      .unwrap_or(Value::Undefined),
    Value::Bool(true)
  );

  // Store `history.state`. Browsers treat a missing/undefined state argument as `null`.
  let state_value = match args.get(0).copied().unwrap_or(Value::Undefined) {
    Value::Undefined => Value::Null,
    other => other,
  };
  let cloned_state_value = history_state_structured_clone(vm, scope, host, hooks, state_value)?;

  // The optional URL argument is resolved against the document base URL (`document.baseURI`).
  // This differs from `document.URL` when a `<base href>` element (or embedder override) is present.
  let url_value = args.get(2).copied().unwrap_or(Value::Undefined);
  let url_provided = !matches!(url_value, Value::Undefined | Value::Null);
  if url_provided {
    let (base_url, current_document_url) = {
      let Some(data) = vm.user_data::<WindowRealmUserData>() else {
        return Err(VmError::InvariantViolation("window realm missing user data"));
      };
      // Match `document.baseURI`: fall back to the document URL when no explicit base URL is set.
      (
        data
          .base_url
          .clone()
          .unwrap_or_else(|| data.document_url.clone()),
        data.document_url.clone(),
      )
    };

    let url_value = match url_value {
      Value::String(s) => s,
      other => scope.heap_mut().to_string(other)?,
    };
    scope.push_root(Value::String(url_value))?;
    let url_input = scope.heap().get_string(url_value)?.to_utf8_lossy();

    let resolved = match crate::js::url_resolve::resolve_url(&url_input, Some(base_url.as_str())) {
        Ok(resolved) => resolved,
        Err(err) => {
          return Err(VmError::Throw(make_dom_exception(vm, scope,
            "SecurityError",
            &err.to_string(),
          )?));
        }
      };
    let parsed = match Url::parse(&resolved) {
      Ok(parsed) => parsed,
      Err(err) => {
        return Err(VmError::Throw(make_dom_exception(vm, scope,
          "SecurityError",
          &err.to_string(),
        )?));
      }
    };

    match parsed.scheme() {
      "http" | "https" | "file" | "data" | "about" | "chrome" => {}
      other => {
        return Err(VmError::Throw(make_dom_exception(vm, scope,
          "SecurityError",
          &format!("history state updates to {other}: URLs are not supported"),
        )?));
      }
    }

    // Enforce same-origin URL updates so callers can't desync `location.origin` (currently a fixed
    // data property computed at realm init).
    //
    // For opaque origins (serialized as "null") we also require the scheme to remain stable since
    // multiple schemes share the same serialized origin.
    let current = Url::parse(&current_document_url)
      .map_err(|err| throw_type_error(vm, scope, host, hooks, &err.to_string()))?;
    let current_origin = serialized_origin_for_document_url(&current_document_url);
    let new_origin = serialized_origin_for_document_url(parsed.as_str());
    if current_origin != new_origin
      || (current_origin == "null" && current.scheme() != parsed.scheme())
    {
      return Err(VmError::Throw(make_dom_exception(vm, scope,
        "SecurityError",
        "history state updates may not change origin",
      )?));
    }

    // Keep the resolved URL on the location object so scripts observe updated components.
    let resolved_s = scope.alloc_string(&resolved)?;
    scope.push_root(Value::String(resolved_s))?;

    {
      // Root objects while allocating property keys: `alloc_key` can trigger GC.
      let mut scope = scope.reborrow();
      scope.push_root(Value::Object(location_obj))?;

      let location_url_key = alloc_key(&mut scope, LOCATION_URL_KEY)?;
      scope.define_property(
        location_obj,
        location_url_key,
        data_desc(Value::String(resolved_s)),
      )?;
    }

    {
      let Some(data) = vm.user_data_mut::<WindowRealmUserData>() else {
        return Err(VmError::InvariantViolation(
          "window realm missing user data",
        ));
      };
      let old_doc_url = std::mem::replace(&mut data.document_url, resolved.clone());
      let update_base =
        data.base_url.is_none() || data.base_url.as_deref() == Some(old_doc_url.as_str());
      if update_base {
        data.base_url = Some(resolved);
        data
          .module_loader
          .borrow_mut()
          .set_document_url(data.base_url.clone());
      }
    }
  }

  // Update the per-realm session history after URL validation so failures do not partially apply.
  //
  // This stores the entry state value as a persistent root so `history.back/forward/go` can restore
  // it later.
  let history_len = {
    let Some(data) = vm.user_data_mut::<WindowRealmUserData>() else {
      return Err(VmError::InvariantViolation(
        "window realm missing user data",
      ));
    };
    // Defensively initialize the session history if `init_window_globals` did not.
    if data.session_history.entries.is_empty() {
      data
        .session_history
        .entries
        .try_reserve(1)
        .map_err(|_| VmError::OutOfMemory)?;
      let root = scope.heap_mut().add_root(Value::Null)?;
      data.session_history.entries.push(SessionHistoryEntry {
        url: data.document_url.clone(),
        state_root: root,
      });
      data.session_history.index = 0;
    }

    let url = data.document_url.clone();
    let idx = data.session_history.index;
    if replace {
      if let Some(entry) = data.session_history.entries.get_mut(idx) {
        entry.url = url;
        scope.heap_mut().set_root(entry.state_root, cloned_state_value);
      }
    } else {
      // Discard any forward history entries.
      let truncate_from = idx.saturating_add(1);
      if truncate_from < data.session_history.entries.len() {
        for entry in data.session_history.entries.drain(truncate_from..) {
          scope.heap_mut().remove_root(entry.state_root);
        }
      }
      data
        .session_history
        .entries
        .try_reserve(1)
        .map_err(|_| VmError::OutOfMemory)?;
      let state_root = scope.heap_mut().add_root(cloned_state_value)?;
      data
        .session_history
        .entries
        .push(SessionHistoryEntry { url, state_root });
      data.session_history.index = data.session_history.entries.len().saturating_sub(1);
    }

    data.session_history.entries.len()
  };

  // Update `history.state`/`history.length` after URL/session history updates so failures do not
  // partially apply.
  {
    // Root the receiver while allocating property keys: `alloc_key` can trigger GC.
    let mut scope = scope.reborrow();
    scope.push_root(Value::Object(history_obj))?;
    scope.push_root(cloned_state_value)?;

    let state_key = alloc_key(&mut scope, "state")?;
    scope.define_property(
      history_obj,
      state_key,
      read_only_data_desc(cloned_state_value),
    )?;
    // Keep `history.length` in sync with the per-realm session history.
    let length_key = alloc_key(&mut scope, "length")?;
    scope.define_property(
      history_obj,
      length_key,
      read_only_data_desc(Value::Number(history_len as f64)),
    )?;
  }

  Ok(Value::Undefined)
}

#[derive(Debug, Clone)]
struct HistoryTraversalOutcome {
  old_url: String,
  new_url: String,
  state: Value,
}

fn history_traverse_delta(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  history_obj: GcObject,
  location_obj: GcObject,
  _document_obj: GcObject,
  delta: isize,
) -> Result<Option<HistoryTraversalOutcome>, VmError> {
  if delta == 0 {
    return Ok(None);
  }

  let (old_url, new_url, state_value, history_len) = {
    let Some(data) = vm.user_data_mut::<WindowRealmUserData>() else {
      return Err(VmError::InvariantViolation(
        "window realm missing user data",
      ));
    };

    let entries_len = data.session_history.entries.len();
    let Some(current_entry) = data.session_history.entries.get(data.session_history.index) else {
      return Ok(None);
    };

    let target = (data.session_history.index as isize).saturating_add(delta);
    if target < 0 || target as usize >= entries_len {
      return Ok(None);
    }
    let target = target as usize;
    if target == data.session_history.index {
      return Ok(None);
    }

    let old_url = current_entry.url.clone();
    let new_entry = data
      .session_history
      .entries
      .get(target)
      .cloned()
      .ok_or_else(|| VmError::InvariantViolation("session history target out of bounds"))?;
    data.session_history.index = target;

    let old_doc_url = data.document_url.clone();
    data.document_url = new_entry.url.clone();

    let update_base =
      data.base_url.is_none() || data.base_url.as_deref() == Some(old_doc_url.as_str());
    if update_base {
      data.base_url = Some(new_entry.url.clone());
      data
        .module_loader
        .borrow_mut()
        .set_document_url(data.base_url.clone());
    }

    let state_value = scope
      .heap()
      .get_root(new_entry.state_root)
      .unwrap_or(Value::Null);
    (old_url, new_entry.url, state_value, entries_len)
  };

  // Update `location.href` and the History facade (`history.state`/`history.length`).
  //
  // `document.URL` is implemented as a getter that mirrors `location.href`.
  let new_url_s = scope.alloc_string(&new_url)?;
  scope.push_root(Value::String(new_url_s))?;
  {
    // Root objects while allocating property keys: `alloc_key` can trigger GC.
    let mut scope = scope.reborrow();
    scope.push_root(Value::Object(location_obj))?;
    scope.push_root(Value::Object(history_obj))?;
    scope.push_root(state_value)?;

    let location_url_key = alloc_key(&mut scope, LOCATION_URL_KEY)?;
    scope.define_property(
      location_obj,
      location_url_key,
      data_desc(Value::String(new_url_s)),
    )?;

    let state_key = alloc_key(&mut scope, "state")?;
    scope.define_property(history_obj, state_key, read_only_data_desc(state_value))?;

    let length_key = alloc_key(&mut scope, "length")?;
    scope.define_property(
      history_obj,
      length_key,
      read_only_data_desc(Value::Number(history_len as f64)),
    )?;
  }

  Ok(Some(HistoryTraversalOutcome {
    old_url,
    new_url,
    state: state_value,
  }))
}

fn make_history_event_object(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  vm_host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  window_obj: GcObject,
  preferred_ctor_name: &str,
  type_name: &'static str,
  init_obj: GcObject,
) -> Result<(GcObject, bool), VmError> {
  let type_s = scope.alloc_string(type_name)?;
  scope.push_root(Value::String(type_s))?;

  // Root `window`/`init_obj` while allocating keys: `alloc_key` can trigger GC.
  scope.push_root(Value::Object(window_obj))?;
  scope.push_root(Value::Object(init_obj))?;

  let preferred_ctor_key = alloc_key(scope, preferred_ctor_name)?;
  let preferred_ctor =
    vm.get_with_host_and_hooks(vm_host, scope, hooks, window_obj, preferred_ctor_key)?;
  scope.push_root(preferred_ctor)?;

  let (event_value, needs_payload_define) = if scope
    .heap()
    .is_constructor(preferred_ctor)
    .unwrap_or(false)
  {
    (
      vm.construct_with_host_and_hooks(
        vm_host,
        scope,
        hooks,
        preferred_ctor,
        &[Value::String(type_s), Value::Object(init_obj)],
        preferred_ctor,
      )?,
      false,
    )
  } else {
    let event_ctor_key = alloc_key(scope, "Event")?;
    let event_ctor =
      vm.get_with_host_and_hooks(vm_host, scope, hooks, window_obj, event_ctor_key)?;
    scope.push_root(event_ctor)?;
    (
      vm.construct_with_host_and_hooks(
        vm_host,
        scope,
        hooks,
        event_ctor,
        &[Value::String(type_s), Value::Object(init_obj)],
        event_ctor,
      )?,
      true,
    )
  };

  let Value::Object(event_obj) = event_value else {
    return Err(VmError::Unimplemented(
      "PopStateEvent/HashChangeEvent/Event constructor returned non-object",
    ));
  };
  Ok((event_obj, needs_payload_define))
}

fn dispatch_history_traversal_events(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  vm_host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  window_obj: GcObject,
  traversal: &HistoryTraversalOutcome,
) -> Result<(), VmError> {
  let old_fragment = traversal.old_url.split_once('#').map(|(_, frag)| frag);
  let new_fragment = traversal.new_url.split_once('#').map(|(_, frag)| frag);
  let hash_changed = old_fragment != new_fragment;

  {
    let init_obj = scope.alloc_object()?;
    scope.push_root(Value::Object(init_obj))?;
    scope.push_root(traversal.state)?;
    let state_key = alloc_key(scope, "state")?;
    scope.define_property(init_obj, state_key, data_desc(traversal.state))?;

    let (event_obj, needs_payload_define) = make_history_event_object(
      vm,
      scope,
      vm_host,
      hooks,
      window_obj,
      "PopStateEvent",
      "popstate",
      init_obj,
    )?;
    scope.push_root(Value::Object(event_obj))?;
    if needs_payload_define {
      scope.define_property(event_obj, state_key, read_only_data_desc(traversal.state))?;
    }

    let dispatch_key = alloc_key(scope, "dispatchEvent")?;
    let dispatch = vm.get_with_host_and_hooks(vm_host, scope, hooks, window_obj, dispatch_key)?;
    let _ = vm.call_with_host_and_hooks(
      vm_host,
      scope,
      hooks,
      dispatch,
      Value::Object(window_obj),
      &[Value::Object(event_obj)],
    )?;
  }

  if hash_changed {
    let init_obj = scope.alloc_object()?;
    scope.push_root(Value::Object(init_obj))?;
    let old_url_s = scope.alloc_string(&traversal.old_url)?;
    scope.push_root(Value::String(old_url_s))?;
    let new_url_s = scope.alloc_string(&traversal.new_url)?;
    scope.push_root(Value::String(new_url_s))?;

    let old_url_key = alloc_key(scope, "oldURL")?;
    scope.define_property(init_obj, old_url_key, data_desc(Value::String(old_url_s)))?;
    let new_url_key = alloc_key(scope, "newURL")?;
    scope.define_property(init_obj, new_url_key, data_desc(Value::String(new_url_s)))?;

    let (event_obj, needs_payload_define) = make_history_event_object(
      vm,
      scope,
      vm_host,
      hooks,
      window_obj,
      "HashChangeEvent",
      "hashchange",
      init_obj,
    )?;
    scope.push_root(Value::Object(event_obj))?;
    if needs_payload_define {
      scope.define_property(
        event_obj,
        old_url_key,
        read_only_data_desc(Value::String(old_url_s)),
      )?;
      scope.define_property(
        event_obj,
        new_url_key,
        read_only_data_desc(Value::String(new_url_s)),
      )?;
    }

    let dispatch_key = alloc_key(scope, "dispatchEvent")?;
    let dispatch = vm.get_with_host_and_hooks(vm_host, scope, hooks, window_obj, dispatch_key)?;
    let _ = vm.call_with_host_and_hooks(
      vm_host,
      scope,
      hooks,
      dispatch,
      Value::Object(window_obj),
      &[Value::Object(event_obj)],
    )?;
  }

  Ok(())
}

fn queue_history_traversal_task<Host: WindowRealmHost + 'static>(
  event_loop: &mut EventLoop<Host>,
  delta: isize,
  window_obj: GcObject,
  history_obj: GcObject,
  location_obj: GcObject,
  document_obj: GcObject,
) -> bool {
  event_loop
    .queue_task(TaskSource::DOMManipulation, move |host, event_loop| {
      let mut hooks = VmJsEventLoopHooks::<Host>::new_with_host(host)?;
      hooks.set_event_loop(event_loop);
      let (vm_host, window_realm) = host.vm_host_and_window_realm()?;
      window_realm.reset_interrupt();
      let budget = window_realm.vm_budget_now();
      let (vm, heap) = window_realm.vm_and_heap_mut();

      let result: crate::error::Result<()> = (|| {
        let mut vm = vm.push_budget(budget);
        vm.tick()
          .map_err(|err| crate::js::window_timers::vm_error_to_event_loop_error(heap, err))?;

        let traversal_and_dispatch: Result<(), VmError> = (|| {
          let mut scope = heap.scope();

          let traversal = history_traverse_delta(
            &mut vm,
            &mut scope,
            history_obj,
            location_obj,
            document_obj,
            delta,
          )?;
          if let Some(traversal) = traversal.as_ref() {
            dispatch_history_traversal_events(
              &mut vm,
              &mut scope,
              vm_host,
              &mut hooks,
              window_obj,
              traversal,
            )?;
          }
          Ok(())
        })();

        traversal_and_dispatch
          .map_err(|err| crate::js::window_timers::vm_error_to_event_loop_error(heap, err))
      })();

      let finish_err = hooks.finish(heap);
      if let Some(err) = finish_err {
        return Err(err);
      }

      result
    })
    .is_ok()
}

fn schedule_history_traversal(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  vm_host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  window_obj: GcObject,
  history_obj: GcObject,
  location_obj: GcObject,
  document_obj: GcObject,
  delta: isize,
) -> Result<(), VmError> {
  if delta == 0 {
    return Ok(());
  }

  // Queue a DOM manipulation task when an HTML event loop is available.
  let queued =
    if let Some(event_loop) = event_loop_mut_from_hooks::<crate::api::BrowserTabHost>(hooks) {
      queue_history_traversal_task::<crate::api::BrowserTabHost>(
        event_loop,
        delta,
        window_obj,
        history_obj,
        location_obj,
        document_obj,
      )
    } else if let Some(event_loop) = event_loop_mut_from_hooks::<WindowHostState>(hooks) {
      queue_history_traversal_task::<WindowHostState>(
        event_loop,
        delta,
        window_obj,
        history_obj,
        location_obj,
        document_obj,
      )
    } else {
      false
    };

  if queued {
    return Ok(());
  }

  // Best-effort fallback when no event loop is available.
  if let Some(traversal) =
    history_traverse_delta(vm, scope, history_obj, location_obj, document_obj, delta)?
  {
    dispatch_history_traversal_events(vm, scope, vm_host, hooks, window_obj, &traversal)?;
  }

  Ok(())
}

fn history_back_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  vm_host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  callee: GcObject,
  this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  let slots = scope.heap().get_function_native_slots(callee)?;
  let window_obj = match slots
    .get(HISTORY_TRAVERSE_WINDOW_OBJ_SLOT)
    .copied()
    .unwrap_or(Value::Undefined)
  {
    Value::Object(obj) => obj,
    _ => return Ok(Value::Undefined),
  };
  let history_obj = match slots
    .get(HISTORY_TRAVERSE_HISTORY_OBJ_SLOT)
    .copied()
    .unwrap_or(Value::Undefined)
  {
    Value::Object(obj) => obj,
    _ => return Ok(Value::Undefined),
  };
  history_require_this(this, history_obj)?;
  let location_obj = match slots
    .get(HISTORY_TRAVERSE_LOCATION_OBJ_SLOT)
    .copied()
    .unwrap_or(Value::Undefined)
  {
    Value::Object(obj) => obj,
    _ => return Ok(Value::Undefined),
  };
  let document_obj = match slots
    .get(HISTORY_TRAVERSE_DOCUMENT_OBJ_SLOT)
    .copied()
    .unwrap_or(Value::Undefined)
  {
    Value::Object(obj) => obj,
    _ => return Ok(Value::Undefined),
  };

  schedule_history_traversal(
    vm,
    scope,
    vm_host,
    hooks,
    window_obj,
    history_obj,
    location_obj,
    document_obj,
    -1,
  )?;
  Ok(Value::Undefined)
}

fn history_forward_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  vm_host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  callee: GcObject,
  this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  let slots = scope.heap().get_function_native_slots(callee)?;
  let window_obj = match slots
    .get(HISTORY_TRAVERSE_WINDOW_OBJ_SLOT)
    .copied()
    .unwrap_or(Value::Undefined)
  {
    Value::Object(obj) => obj,
    _ => return Ok(Value::Undefined),
  };
  let history_obj = match slots
    .get(HISTORY_TRAVERSE_HISTORY_OBJ_SLOT)
    .copied()
    .unwrap_or(Value::Undefined)
  {
    Value::Object(obj) => obj,
    _ => return Ok(Value::Undefined),
  };
  history_require_this(this, history_obj)?;
  let location_obj = match slots
    .get(HISTORY_TRAVERSE_LOCATION_OBJ_SLOT)
    .copied()
    .unwrap_or(Value::Undefined)
  {
    Value::Object(obj) => obj,
    _ => return Ok(Value::Undefined),
  };
  let document_obj = match slots
    .get(HISTORY_TRAVERSE_DOCUMENT_OBJ_SLOT)
    .copied()
    .unwrap_or(Value::Undefined)
  {
    Value::Object(obj) => obj,
    _ => return Ok(Value::Undefined),
  };

  schedule_history_traversal(
    vm,
    scope,
    vm_host,
    hooks,
    window_obj,
    history_obj,
    location_obj,
    document_obj,
    1,
  )?;
  Ok(Value::Undefined)
}

fn history_go_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  vm_host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let (window_obj, history_obj, location_obj, document_obj) = {
    let slots = scope.heap().get_function_native_slots(callee)?;
    let window_obj = match slots
      .get(HISTORY_TRAVERSE_WINDOW_OBJ_SLOT)
      .copied()
      .unwrap_or(Value::Undefined)
    {
      Value::Object(obj) => obj,
      _ => return Ok(Value::Undefined),
    };
    let history_obj = match slots
      .get(HISTORY_TRAVERSE_HISTORY_OBJ_SLOT)
      .copied()
      .unwrap_or(Value::Undefined)
    {
      Value::Object(obj) => obj,
      _ => return Ok(Value::Undefined),
    };
    let location_obj = match slots
      .get(HISTORY_TRAVERSE_LOCATION_OBJ_SLOT)
      .copied()
      .unwrap_or(Value::Undefined)
    {
      Value::Object(obj) => obj,
      _ => return Ok(Value::Undefined),
    };
    let document_obj = match slots
      .get(HISTORY_TRAVERSE_DOCUMENT_OBJ_SLOT)
      .copied()
      .unwrap_or(Value::Undefined)
    {
      Value::Object(obj) => obj,
      _ => return Ok(Value::Undefined),
    };
    (window_obj, history_obj, location_obj, document_obj)
  };

  history_require_this(this, history_obj)?;

  let delta_value = args.get(0).copied().unwrap_or(Value::Undefined);
  let mut delta = scope.heap_mut().to_number(delta_value)?;
  if delta.is_nan() {
    delta = 0.0;
  }
  // `ToIntegerOrInfinity` rounds toward zero; keep infinities so they clamp below.
  let delta = delta.trunc();
  let delta = if delta >= isize::MAX as f64 {
    isize::MAX
  } else if delta <= isize::MIN as f64 {
    isize::MIN
  } else {
    delta as isize
  };

  if delta == 0 {
    let current_url = {
      let Some(data) = vm.user_data::<WindowRealmUserData>() else {
        return Err(VmError::InvariantViolation("window realm missing user data"));
      };
      data.document_url.clone()
    };
    {
      let Some(data) = vm.user_data_mut::<WindowRealmUserData>() else {
        return Err(VmError::InvariantViolation("window realm missing user data"));
      };
      data.pending_navigation = Some(LocationNavigationRequest {
        url: current_url,
        replace: true,
      });
    }

    vm.interrupt_handle().interrupt();
    vm.tick()?;
    return Ok(Value::Undefined);
  }

  schedule_history_traversal(
    vm,
    scope,
    vm_host,
    hooks,
    window_obj,
    history_obj,
    location_obj,
    document_obj,
    delta,
  )?;
  Ok(Value::Undefined)
}

fn parse_location_url(
  scope: &mut Scope<'_>,
  location_obj: GcObject,
) -> Result<Option<Url>, VmError> {
  let key = alloc_key(scope, LOCATION_URL_KEY)?;
  let value = scope
    .heap()
    .object_get_own_data_property_value(location_obj, &key)?
    .unwrap_or(Value::Undefined);
  let Value::String(s) = value else {
    return Ok(None);
  };
  let href = scope.heap().get_string(s)?.to_utf8_lossy();
  Ok(Url::parse(&href).ok())
}

fn location_protocol_get_native(
  _vm: &mut Vm,
  scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(location_obj) = this else {
    return Ok(Value::Undefined);
  };
  let Some(url) = parse_location_url(scope, location_obj)? else {
    return Ok(Value::String(scope.alloc_string("")?));
  };
  let protocol = format!("{}:", url.scheme());
  Ok(Value::String(scope.alloc_string(&protocol)?))
}

fn location_host_get_native(
  _vm: &mut Vm,
  scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(location_obj) = this else {
    return Ok(Value::Undefined);
  };
  let Some(url) = parse_location_url(scope, location_obj)? else {
    return Ok(Value::String(scope.alloc_string("")?));
  };
  let host = url.host_str().unwrap_or("");
  let port = url.port();
  let mut out = String::new();
  out.push_str(host);
  if let Some(port) = port {
    use std::fmt::Write as _;
    out.push(':');
    let _ = write!(&mut out, "{port}");
  }
  Ok(Value::String(scope.alloc_string(&out)?))
}

