fn sync_cached_select_options_for_select_ancestor(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  document_obj: GcObject,
  dom: &dom2::Document,
  node_id: NodeId,
) -> Result<(), VmError> {
  // `HTMLSelectElement.options` is derived from the select element's descendant `<option>` nodes,
  // so we need to sync whenever any descendant subtree mutates (e.g. when inserting into an
  // `<optgroup>`). Walk ancestors (including `node_id` itself) and update any cached options
  // collections for select elements we encounter.
  let mut cur = Some(node_id);
  let mut remaining = dom.nodes_len().saturating_add(1);
  while let Some(id) = cur {
    if remaining == 0 {
      break;
    }
    remaining -= 1;
    if id.index() >= dom.nodes_len() {
      break;
    }

    let is_select = match &dom.node(id).kind {
      NodeKind::Element {
        tag_name,
        namespace,
        ..
      } if tag_name.eq_ignore_ascii_case("select")
        && (namespace.is_empty() || namespace == crate::dom::HTML_NAMESPACE) =>
      {
        true
      }
      _ => false,
    };
    if is_select {
      sync_cached_select_options_for_node_id(vm, scope, document_obj, dom, id)?;
    }
    cur = dom.parent_node(id);
  }

  Ok(())
}

fn document_window_from_document(
  scope: &mut Scope<'_>,
  document_obj: GcObject,
) -> Result<Option<GcObject>, VmError> {
  scope.push_root(Value::Object(document_obj))?;
  let key = alloc_key(scope, DOCUMENT_WINDOW_KEY)?;
  Ok(
    scope
      .heap()
      .object_get_own_data_property_value(document_obj, &key)?
      .and_then(|v| match v {
        Value::Object(obj) => Some(obj),
        _ => None,
      }),
  )
}

fn queue_mutation_observer_microtask(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  document_obj: GcObject,
) -> Result<(), VmError> {
  if !hooks_have_event_loop(hooks) {
    return Ok(());
  }

  let global = match document_window_from_document(scope, document_obj)? {
    Some(global) => global,
    None => {
      let Some(data) = vm.user_data_mut::<WindowRealmUserData>() else {
        return Ok(());
      };
      let Some(global) = data.window_obj else {
        return Ok(());
      };
      global
    }
  };

  // Find the internal queueMicrotask implementation (preferred) or fall back to the user-visible
  // `queueMicrotask` binding.
  let queue_microtask = {
    scope.push_root(Value::Object(global))?;
    let key = alloc_key(scope, INTERNAL_QUEUE_MICROTASK_KEY)?;
    scope
      .heap()
      .object_get_own_data_property_value(global, &key)?
      .or_else(|| {
        let key = alloc_key(scope, "queueMicrotask").ok()?;
        scope
          .heap()
          .object_get_own_data_property_value(global, &key)
          .ok()
          .flatten()
      })
      .unwrap_or(Value::Undefined)
  };

  if !matches!(queue_microtask, Value::Object(_)) || !scope.heap().is_callable(queue_microtask)? {
    return Ok(());
  }

  let notify = {
    scope.push_root(Value::Object(document_obj))?;
    let notify_key = alloc_key(scope, MUTATION_OBSERVER_NOTIFY_KEY)?;
    let existing = scope
      .heap()
      .object_get_own_data_property_value(document_obj, &notify_key)?
      .unwrap_or(Value::Undefined);
    if matches!(existing, Value::Object(_)) && scope.heap().is_callable(existing)? {
      existing
    } else {
      // Some `Document` wrapper objects can be created without going through `init_window_globals`
      // (e.g. registered secondary documents). Create the notify shim lazily so mutation observer
      // microtasks can still be queued.
      let notify_call_id = vm.register_native_call(mutation_observer_notify_native)?;
      let notify_name = scope.alloc_string("notify mutation observers")?;
      scope.push_root(Value::String(notify_name))?;
      let func = scope.alloc_native_function_with_slots(
        notify_call_id,
        None,
        notify_name,
        0,
        &[Value::Object(document_obj)],
      )?;
      if let Some(intrinsics) = vm.intrinsics() {
        scope
          .heap_mut()
          .object_set_prototype(func, Some(intrinsics.function_prototype()))?;
      }
      scope.push_root(Value::Object(func))?;
      scope.define_property(
        document_obj,
        notify_key,
        PropertyDescriptor {
          enumerable: false,
          configurable: false,
          kind: PropertyKind::Data {
            value: Value::Object(func),
            writable: false,
          },
        },
      )?;
      Value::Object(func)
    }
  };

  // This is an internal scheduling primitive; don't let failures (missing queueMicrotask binding,
  // full microtask queue, etc) perturb DOM mutations.
  let _ = vm.call_with_host_and_hooks(
    host,
    scope,
    hooks,
    queue_microtask,
    Value::Undefined,
    &[notify],
  );
  Ok(())
}

fn maybe_queue_mutation_observer_microtask(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  document_obj: GcObject,
  needs_microtask: bool,
) -> Result<(), VmError> {
  if needs_microtask {
    queue_mutation_observer_microtask(vm, scope, host, hooks, document_obj)?;
  }
  Ok(())
}

pub(crate) fn drain_pending_dataset_mutation_observer_microtasks(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
) -> Result<(), VmError> {
  // Without an EventLoop-backed `queueMicrotask` implementation, we cannot deliver mutation observer
  // callbacks. Avoid consuming `microtask_needs_queueing` so delivery can happen later once the
  // realm is wired into an event loop.
  if !hooks_have_event_loop(hooks) {
    return Ok(());
  }

  let (pending, owned_dom2_documents) = {
    let Some(data) = vm.user_data_mut::<WindowRealmUserData>() else {
      return Ok(());
    };

    let pending: Vec<WeakGcObject> = {
      let mut pending = data.pending_dataset_mutation_observer_microtasks.borrow_mut();
      if pending.is_empty() {
        return Ok(());
      }
      pending.drain().collect()
    };
    (pending, Rc::clone(&data.owned_dom2_documents))
  };

  for doc_key in pending {
    let Some(document_obj) = doc_key.upgrade(scope.heap()) else {
      continue;
    };
    let document_id = gc_object_id(document_obj);

    let needs_microtask = if is_host_document_id(vm, document_id) {
      mutate_dom_for_vm_host(host, |dom| (dom.take_mutation_observer_microtask_needed(), false))
    } else {
      // Avoid holding the `owned_dom2_documents` `RefCell` borrow while queueing microtasks (which can
      // re-enter JS and cause nested `dataset` accesses).
      let mut owned_dom2_documents = owned_dom2_documents.borrow_mut();
      owned_dom2_documents
        .get_mut(&document_id)
        .map(|dom| dom.take_mutation_observer_microtask_needed())
    };

    if let Some(needs_microtask) = needs_microtask {
      maybe_queue_mutation_observer_microtask(vm, scope, host, hooks, document_obj, needs_microtask)?;
    }
  }

  Ok(())
}

fn document_document_element_get_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(document_obj) = this else {
    return Ok(Value::Null);
  };

  let document_id = match dom_platform_mut(vm)
    .and_then(|platform| platform.require_document_handle(scope.heap(), Value::Object(document_obj)).ok())
  {
    Some(key) => key.document_id,
    None => return Ok(Value::Null),
  };

  let Some(dom_ptr) = dom_ptr_for_document_id_read(vm, host, document_id) else {
    return Ok(Value::Null);
  };
  // SAFETY: `dom_ptr` is valid for the duration of this native call.
  let dom = unsafe { dom_ptr.as_ref() };
  let Some(node_id) = dom.document_element() else {
    return Ok(Value::Null);
  };

  get_or_create_node_wrapper(vm, scope, document_obj, Some(dom), node_id)
}

