fn document_doctype_get_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(document_obj) = this else {
    return Ok(Value::Null);
  };

  let handle = match dom_platform_mut(vm) {
    Some(platform) => match platform.require_document_handle(scope.heap(), Value::Object(document_obj)) {
      Ok(handle) => handle,
      Err(_) => return Ok(Value::Null),
    },
    None => return Ok(Value::Null),
  };

  let Some(dom_ptr) = dom_ptr_for_document_id_read(vm, host, handle.document_id) else {
    return Ok(Value::Null);
  };
  // SAFETY: `dom_ptr` points at either the host document or a realm-owned document stored in VM
  // user data. Both outlive this native call.
  let dom = unsafe { dom_ptr.as_ref() };
  let Some(node_id) = dom.doctype_for(handle.node_id) else {
    return Ok(Value::Null);
  };

  get_or_create_node_wrapper(vm, scope, document_obj, Some(dom), node_id)
}
fn document_scrolling_element_get_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(document_obj) = this else {
    return Ok(Value::Null);
  };

  let handle = match dom_platform_mut(vm) {
    Some(platform) => match platform.require_document_handle(scope.heap(), Value::Object(document_obj)) {
      Ok(handle) => handle,
      Err(_) => return Ok(Value::Null),
    },
    None => return Ok(Value::Null),
  };

  let Some(dom_ptr) = dom_ptr_for_document_id_read(vm, host, handle.document_id) else {
    return Ok(Value::Null);
  };
  // SAFETY: `dom_ptr` points at either the host document or a realm-owned document stored in VM
  // user data. Both outlive this native call.
  let dom = unsafe { dom_ptr.as_ref() };

  let quirks_mode = match &dom.node(dom.root()).kind {
    NodeKind::Document { quirks_mode } => *quirks_mode,
    _ => QuirksMode::NoQuirks,
  };

  if quirks_mode == QuirksMode::Quirks {
    if let Some(node_id) = dom.body_for(handle.node_id) {
      return get_or_create_node_wrapper(vm, scope, document_obj, Some(dom), node_id);
    }
  }

  let Some(node_id) = dom.document_element_for(handle.node_id) else {
    return Ok(Value::Null);
  };

  get_or_create_node_wrapper(vm, scope, document_obj, Some(dom), node_id)
}

fn selection_range_count_get_native(
  _vm: &mut Vm,
  scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(selection_obj) = this else {
    return Ok(Value::Number(0.0));
  };

  // Root `selection_obj` while allocating property keys.
  scope.push_root(Value::Object(selection_obj))?;
  let range_key = alloc_key(scope, SELECTION_RANGE_KEY)?;
  let stored = match scope
    .heap()
    .object_get_own_data_property_value(selection_obj, &range_key)
  {
    Ok(Some(value)) => value,
    Ok(None) | Err(VmError::PropertyNotData) => Value::Undefined,
    Err(err) => return Err(err),
  };

  Ok(Value::Number(if matches!(stored, Value::Object(_)) {
    1.0
  } else {
    0.0
  }))
}

fn selection_to_string_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(selection_obj) = this else {
    return Ok(Value::String(scope.alloc_string("")?));
  };

  // Root `selection_obj` while allocating property keys.
  scope.push_root(Value::Object(selection_obj))?;
  let range_key = alloc_key(scope, SELECTION_RANGE_KEY)?;
  let stored = match scope
    .heap()
    .object_get_own_data_property_value(selection_obj, &range_key)
  {
    Ok(Some(value)) => value,
    Ok(None) | Err(VmError::PropertyNotData) => Value::Undefined,
    Err(err) => return Err(err),
  };
  let Value::Object(range_obj) = stored else {
    return Ok(Value::String(scope.alloc_string("")?));
  };

  // Root `range_obj` while allocating the method name.
  scope.push_root(Value::Object(range_obj))?;
  let to_string_key = alloc_key(scope, "toString")?;
  let to_string_func = vm.get_with_host_and_hooks(host, scope, hooks, range_obj, to_string_key)?;
  let result = vm.call_with_host_and_hooks(host, scope, hooks, to_string_func, stored, &[])?;
  match result {
    Value::String(_) => Ok(result),
    other => Ok(Value::String(scope.heap_mut().to_string(other)?)),
  }
}

fn selection_remove_all_ranges_native(
  _vm: &mut Vm,
  scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(selection_obj) = this else {
    return Ok(Value::Undefined);
  };

  // Root `selection_obj` while allocating property keys.
  scope.push_root(Value::Object(selection_obj))?;
  let range_key = alloc_key(scope, SELECTION_RANGE_KEY)?;
  scope.define_property(selection_obj, range_key, data_desc(Value::Undefined))?;
  Ok(Value::Undefined)
}

fn selection_add_range_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(selection_obj) = this else {
    return Ok(Value::Undefined);
  };

  let range_value = args.get(0).copied().unwrap_or(Value::Undefined);
  let Value::Object(range_obj) = range_value else {
    // WPT `dom/get_selection_stub.window.js` expects `addRange(null)` to be a no-op that does not
    // throw.
    return Ok(Value::Undefined);
  };

  // Root objects while allocating property keys / walking prototype chains.
  scope.push_root(Value::Object(selection_obj))?;
  scope.push_root(Value::Object(range_obj))?;

  // Treat non-Range values as no-ops to preserve curated stub stability.
  if !is_range_object(vm, scope, range_obj)? {
    return Ok(Value::Undefined);
  }

  let range_key = alloc_key(scope, SELECTION_RANGE_KEY)?;
  scope.define_property(selection_obj, range_key, data_desc(range_value))?;
  Ok(Value::Undefined)
}

fn selection_get_range_at_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(selection_obj) = this else {
    return Err(VmError::Throw(make_dom_exception(
      vm,
      scope,
      "IndexSizeError",
      "",
    )?));
  };

  // Root `selection_obj` while allocating property keys / coercing arguments.
  scope.push_root(Value::Object(selection_obj))?;

  let index_value = args.get(0).copied().unwrap_or(Value::Undefined);
  let mut idx = scope.heap_mut().to_number(index_value)?;
  if !idx.is_finite() || idx.is_nan() {
    idx = 0.0;
  }
  idx = idx.trunc();
  if idx != 0.0 {
    return Err(VmError::Throw(make_dom_exception(
      vm,
      scope,
      "IndexSizeError",
      "",
    )?));
  }

  let range_key = alloc_key(scope, SELECTION_RANGE_KEY)?;
  let stored = match scope
    .heap()
    .object_get_own_data_property_value(selection_obj, &range_key)
  {
    Ok(Some(value)) => value,
    Ok(None) | Err(VmError::PropertyNotData) => Value::Undefined,
    Err(err) => return Err(err),
  };

  match stored {
    Value::Object(_) => Ok(stored),
    _ => Err(VmError::Throw(make_dom_exception(
      vm,
      scope,
      "IndexSizeError",
      "",
    )?)),
  }
}

fn is_range_object(vm: &Vm, scope: &mut Scope<'_>, obj: GcObject) -> Result<bool, VmError> {
  let Some(user_data) = vm.user_data::<WindowRealmUserData>() else {
    return Ok(false);
  };
  let Some(window_obj) = user_data.window_obj else {
    return Ok(false);
  };

  // Root objects while allocating property keys.
  scope.push_root(Value::Object(window_obj))?;
  scope.push_root(Value::Object(obj))?;

  let range_key = alloc_key(scope, "Range")?;
  let range_ctor = match object_get_data_property_value(scope.heap(), window_obj, &range_key) {
    Ok(Some(Value::Object(ctor))) => ctor,
    Ok(_) | Err(VmError::PropertyNotData) => return Ok(false),
    Err(err) => return Err(err),
  };
  scope.push_root(Value::Object(range_ctor))?;

  let proto_key = alloc_key(scope, "prototype")?;
  let range_proto = match object_get_data_property_value(scope.heap(), range_ctor, &proto_key) {
    Ok(Some(Value::Object(proto))) => proto,
    Ok(_) | Err(VmError::PropertyNotData) => return Ok(false),
    Err(err) => return Err(err),
  };

  let mut cursor = scope.object_get_prototype(obj)?;
  while let Some(proto) = cursor {
    if proto == range_proto {
      return Ok(true);
    }
    cursor = scope.object_get_prototype(proto)?;
  }
  Ok(false)
}

fn get_or_create_selection_stub(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  document_obj: GcObject,
) -> Result<GcObject, VmError> {
  let selection_key = alloc_key(scope, DOCUMENT_SELECTION_KEY)?;
  if let Some(Value::Object(existing)) = scope
    .heap()
    .object_get_own_data_property_value(document_obj, &selection_key)?
  {
    return Ok(existing);
  }

  let intrinsics = vm.intrinsics();

  let selection_obj = scope.alloc_object()?;
  scope.push_root(Value::Object(selection_obj))?;
  if let Some(intrinsics) = intrinsics {
    scope
      .heap_mut()
      .object_set_prototype(selection_obj, Some(intrinsics.object_prototype()))?;
  }

  // selection.rangeCount (getter only)
  let range_count_get_call_id = vm.register_native_call(selection_range_count_get_native)?;
  let range_count_get_name = scope.alloc_string("get rangeCount")?;
  scope.push_root(Value::String(range_count_get_name))?;
  let range_count_get_func =
    scope.alloc_native_function(range_count_get_call_id, None, range_count_get_name, 0)?;
  if let Some(intrinsics) = intrinsics {
    scope.heap_mut().object_set_prototype(
      range_count_get_func,
      Some(intrinsics.function_prototype()),
    )?;
  }
  scope.push_root(Value::Object(range_count_get_func))?;
  let range_count_key = alloc_key(scope, "rangeCount")?;
  scope.define_property(
    selection_obj,
    range_count_key,
    PropertyDescriptor {
      enumerable: false,
      configurable: true,
      kind: PropertyKind::Accessor {
        get: Value::Object(range_count_get_func),
        set: Value::Undefined,
      },
    },
  )?;

  // selection.toString()
  let to_string_call_id = vm.register_native_call(selection_to_string_native)?;
  let to_string_name = scope.alloc_string("toString")?;
  scope.push_root(Value::String(to_string_name))?;
  let to_string_func = scope.alloc_native_function(to_string_call_id, None, to_string_name, 0)?;
  if let Some(intrinsics) = intrinsics {
    scope
      .heap_mut()
      .object_set_prototype(to_string_func, Some(intrinsics.function_prototype()))?;
  }
  scope.push_root(Value::Object(to_string_func))?;
  let to_string_key = alloc_key(scope, "toString")?;
  scope.define_property(
    selection_obj,
    to_string_key,
    data_desc(Value::Object(to_string_func)),
  )?;

  // selection.removeAllRanges()
  let remove_all_ranges_call_id = vm.register_native_call(selection_remove_all_ranges_native)?;
  let remove_all_ranges_name = scope.alloc_string("removeAllRanges")?;
  scope.push_root(Value::String(remove_all_ranges_name))?;
  let remove_all_ranges_func = scope.alloc_native_function(
    remove_all_ranges_call_id,
    None,
    remove_all_ranges_name,
    0,
  )?;
  if let Some(intrinsics) = intrinsics {
    scope.heap_mut().object_set_prototype(
      remove_all_ranges_func,
      Some(intrinsics.function_prototype()),
    )?;
  }
  scope.push_root(Value::Object(remove_all_ranges_func))?;
  let remove_all_ranges_key = alloc_key(scope, "removeAllRanges")?;
  scope.define_property(
    selection_obj,
    remove_all_ranges_key,
    data_desc(Value::Object(remove_all_ranges_func)),
  )?;

  // selection.addRange(range)
  let add_range_call_id = vm.register_native_call(selection_add_range_native)?;
  let add_range_name = scope.alloc_string("addRange")?;
  scope.push_root(Value::String(add_range_name))?;
  let add_range_func = scope.alloc_native_function(add_range_call_id, None, add_range_name, 1)?;
  if let Some(intrinsics) = intrinsics {
    scope
      .heap_mut()
      .object_set_prototype(add_range_func, Some(intrinsics.function_prototype()))?;
  }
  scope.push_root(Value::Object(add_range_func))?;
  let add_range_key = alloc_key(scope, "addRange")?;
  scope.define_property(
    selection_obj,
    add_range_key,
    data_desc(Value::Object(add_range_func)),
  )?;

  // selection.getRangeAt(index)
  let get_range_at_call_id = vm.register_native_call(selection_get_range_at_native)?;
  let get_range_at_name = scope.alloc_string("getRangeAt")?;
  scope.push_root(Value::String(get_range_at_name))?;
  let get_range_at_func =
    scope.alloc_native_function(get_range_at_call_id, None, get_range_at_name, 1)?;
  if let Some(intrinsics) = intrinsics {
    scope.heap_mut().object_set_prototype(
      get_range_at_func,
      Some(intrinsics.function_prototype()),
    )?;
  }
  scope.push_root(Value::Object(get_range_at_func))?;
  let get_range_at_key = alloc_key(scope, "getRangeAt")?;
  scope.define_property(
    selection_obj,
    get_range_at_key,
    data_desc(Value::Object(get_range_at_func)),
  )?;

  scope.define_property(
    document_obj,
    selection_key,
    PropertyDescriptor {
      enumerable: false,
      configurable: false,
      kind: PropertyKind::Data {
        value: Value::Object(selection_obj),
        writable: false,
      },
    },
  )?;

  Ok(selection_obj)
}

fn get_selection_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  let canonical_document_obj = vm
    .user_data::<WindowRealmUserData>()
    .and_then(|data| data.document_obj);

  let mut document_obj = None;
  if let Value::Object(receiver) = this {
    let is_document = dom_platform_mut(vm)
      .and_then(|platform| {
        platform
          .require_document_id(scope.heap(), Value::Object(receiver))
          .ok()
      })
      .is_some();
    if is_document {
      document_obj = Some(receiver);
    }
  }

  let Some(document_obj) = document_obj.or(canonical_document_obj) else {
    return Ok(Value::Null);
  };

  let selection_obj = get_or_create_selection_stub(vm, scope, document_obj)?;
  Ok(Value::Object(selection_obj))
}

fn document_get_element_by_id_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(document_obj) = this else {
    return Err(VmError::TypeError("Illegal invocation"));
  };

  // Brand check: `Document.prototype.getElementById` must only be callable on real Document
  // wrappers, not arbitrary DOM-backed nodes (e.g. Elements) that happen to have a source id.
  let handle = {
    let platform = dom_platform_mut(vm).ok_or(VmError::TypeError("Illegal invocation"))?;
    platform.require_document_handle(scope.heap(), Value::Object(document_obj))?
  };
  let dom_ptr = dom_ptr_for_document_id_read(vm, host, handle.document_id)
    .ok_or(VmError::TypeError("Illegal invocation"))?;
  // SAFETY: `dom_ptr` points at either the host document or a realm-owned document stored in VM
  // user data. Both outlive this native call.
  let dom = unsafe { dom_ptr.as_ref() };

  let query_value = args.get(0).copied().unwrap_or(Value::Undefined);
  let query_value = scope.heap_mut().to_string(query_value)?;
  let query = scope
    .heap()
    .get_string(query_value)
    .map(|s| s.to_utf8_lossy())
    .unwrap_or_default();

  let Some(node_id) = dom.get_element_by_id_from(handle.node_id, &query) else {
    return Ok(Value::Null);
  };
  get_or_create_node_wrapper(vm, scope, document_obj, Some(dom), node_id)
}

fn document_get_elements_by_tag_name_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(document_obj) = this else {
    return Err(VmError::TypeError("Illegal invocation"));
  };

  // Brand check.
  {
    let platform = dom_platform_mut(vm).ok_or(VmError::TypeError("Illegal invocation"))?;
    let _ = platform.require_document_handle(scope.heap(), Value::Object(document_obj))?;
  }

  let qualified_name_value = args.get(0).copied().unwrap_or(Value::Undefined);
  let qualified_name_s = scope.heap_mut().to_string(qualified_name_value)?;
  scope.push_root(Value::String(qualified_name_s))?;

  let proto_key = alloc_key(scope, HTML_COLLECTION_PROTOTYPE_KEY)?;
  let proto = match object_get_data_property_value(scope.heap(), document_obj, &proto_key)? {
    Some(Value::Object(obj)) => obj,
    _ => return Err(VmError::InvariantViolation("missing HTMLCollection prototype")),
  };

  let collection = alloc_live_collection_object(
    vm,
    scope,
    host,
    document_obj,
    document_obj,
    proto,
    LiveCollectionQueryKind::TagName,
    Value::String(qualified_name_s),
    Value::Undefined,
  )?;
  Ok(Value::Object(collection))
}

