fn document_get_elements_by_name_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(document_obj) = this else {
    return Err(VmError::TypeError("Illegal invocation"));
  };

  {
    let platform = dom_platform_mut(vm).ok_or(VmError::TypeError("Illegal invocation"))?;
    let _ = platform.require_document_handle(scope.heap(), Value::Object(document_obj))?;
  }

  let name_value = args.get(0).copied().unwrap_or(Value::Undefined);
  let name_s = match name_value {
    Value::String(s) => s,
    other => scope.heap_mut().to_string(other)?,
  };
  scope.push_root(Value::String(name_s))?;

  let list_obj = scope.alloc_object()?;
  scope.push_root(Value::Object(list_obj))?;
  scope.push_root(Value::Object(document_obj))?;

  // Use the realm's NodeList prototype so `instanceof NodeList` works.
  let proto = node_list_prototype_from_document(scope, document_obj)?;
  scope.heap_mut().object_set_prototype(list_obj, Some(proto))?;

  // Keep the document wrapper alive even if the caller only holds the NodeList object.
  let root_key = alloc_key(scope, NODE_LIST_ROOT_KEY)?;
  scope.define_property(
    list_obj,
    root_key,
    PropertyDescriptor {
      enumerable: false,
      configurable: false,
      kind: PropertyKind::Data {
        value: Value::Object(document_obj),
        writable: false,
      },
    },
  )?;

  let kind_key = alloc_key(scope, NODE_LIST_QUERY_KIND_KEY)?;
  let kind_s = scope.alloc_string("name")?;
  scope.push_root(Value::String(kind_s))?;
  scope.define_property(
    list_obj,
    kind_key,
    PropertyDescriptor {
      enumerable: false,
      configurable: false,
      kind: PropertyKind::Data {
        value: Value::String(kind_s),
        writable: false,
      },
    },
  )?;

  let name_key = alloc_key(scope, NODE_LIST_QUERY_NAME_KEY)?;
  scope.define_property(
    list_obj,
    name_key,
    PropertyDescriptor {
      enumerable: false,
      configurable: false,
      kind: PropertyKind::Data {
        value: Value::String(name_s),
        writable: false,
      },
    },
  )?;

  sync_node_list_query_if_needed(vm, scope, host, list_obj)?;

  Ok(Value::Object(list_obj))
}

fn document_fragment_get_element_by_id_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(wrapper_obj) = this else {
    return Err(VmError::TypeError("Illegal invocation"));
  };

  let fragment_handle = {
    let platform = dom_platform_mut(vm).ok_or(VmError::TypeError("Illegal invocation"))?;
    platform.require_document_fragment_handle(scope.heap(), Value::Object(wrapper_obj))?
  };
  let dom_ptr = dom_ptr_for_document_id_read(vm, host, fragment_handle.document_id)
    .ok_or(VmError::TypeError("Illegal invocation"))?;
  // SAFETY: `dom_ptr` points at either the host document or a realm-owned document stored in VM
  // user data. Both outlive this native call.
  let dom = unsafe { dom_ptr.as_ref() };

  let query_value = args.get(0).copied().unwrap_or(Value::Undefined);
  let query_value = scope.heap_mut().to_string(query_value)?;
  let query = scope
    .heap()
    .get_string(query_value)
    .map(|s| s.to_utf8_lossy())
    .unwrap_or_default();

  let Some(found) = dom.get_element_by_id_from(fragment_handle.node_id, &query) else {
    return Ok(Value::Null);
  };

  let document_obj = node_wrapper_document_obj(scope, wrapper_obj, fragment_handle.node_id)?;
  get_or_create_node_wrapper(vm, scope, document_obj, Some(dom), found)
}

fn document_query_selector_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(document_obj) = this else {
    return Err(VmError::TypeError("Illegal invocation"));
  };

  let handle = {
    let platform = dom_platform_mut(vm).ok_or(VmError::TypeError("Illegal invocation"))?;
    platform.require_document_handle(scope.heap(), Value::Object(document_obj))?
  };

  let selector_value = args.get(0).copied().unwrap_or(Value::Undefined);
  let selector_value = scope.heap_mut().to_string(selector_value)?;
  let selector = scope
    .heap()
    .get_string(selector_value)
    .map(|s| s.to_utf8_lossy())
    .unwrap_or_default();

  let result = if is_host_document_id(vm, handle.document_id) {
    mutate_dom_for_vm_host(host, |dom| (dom.query_selector(&selector, Some(handle.node_id)), false))
      .ok_or(VmError::TypeError("Illegal invocation"))?
  } else {
    let Some(mut dom_ptr) = dom_ptr_for_document_id_mut(vm, host, handle.document_id) else {
      return Err(VmError::TypeError("Illegal invocation"));
    };
    // SAFETY: `dom_ptr` points at a realm-owned document stored in VM user data. We have exclusive
    // access for the duration of this native call.
    let dom = unsafe { dom_ptr.as_mut() };
    dom.query_selector(&selector, Some(handle.node_id))
  };

  match result {
    Ok(Some(node_id)) => {
      let dom_ptr = dom_ptr_for_document_id_read(vm, host, handle.document_id)
        .ok_or(VmError::TypeError("Illegal invocation"))?;
      // SAFETY: `dom_ptr` points at either the host document or a realm-owned document stored in VM
      // user data. Both outlive this native call.
      let dom = unsafe { dom_ptr.as_ref() };
      get_or_create_node_wrapper(vm, scope, document_obj, Some(dom), node_id)
    }
    Ok(None) => Ok(Value::Null),
    Err(err) => {
      let (name, message) = match err {
        crate::web::dom::DomException::SyntaxError { message } => ("SyntaxError", message),
        crate::web::dom::DomException::NoModificationAllowedError { message } => {
          ("NoModificationAllowedError", message)
        }
        crate::web::dom::DomException::NotSupportedError { message } => {
          ("NotSupportedError", message)
        }
        crate::web::dom::DomException::InvalidStateError { message } => {
          ("InvalidStateError", message)
        }
      };
      Err(VmError::Throw(make_dom_exception(vm, scope, name, &message)?))
    }
  }
}

