fn document_element_from_point_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(document_obj) = this else {
    return Err(VmError::TypeError("Illegal invocation"));
  };

  {
    let platform = dom_platform_mut(vm).ok_or(VmError::TypeError("Illegal invocation"))?;
    let _ = platform.require_document_id(scope.heap(), Value::Object(document_obj))?;
  };

  let x = scope
    .heap_mut()
    .to_number(args.get(0).copied().unwrap_or(Value::Undefined))?;
  let y = scope
    .heap_mut()
    .to_number(args.get(1).copied().unwrap_or(Value::Undefined))?;
  if !x.is_finite() || !y.is_finite() {
    return Ok(Value::Null);
  }

  let Some(document) = host.as_any_mut().downcast_mut::<BrowserDocumentDom2>() else {
    // Safe no-op fallback for non-renderer-backed hosts.
    return Ok(Value::Null);
  };

  let hit = match document.element_from_point(x as f32, y as f32) {
    Ok(hit) => hit,
    Err(_) => return Ok(Value::Null),
  };
  let Some(mut node_id) = hit else {
    return Ok(Value::Null);
  };

  // Ensure we return an element wrapper. If hit testing returns a non-element (unexpected), walk up
  // to the first element ancestor.
  loop {
    match &document.dom().node(node_id).kind {
      NodeKind::Element { .. } => break,
      _ => match document.dom().parent_node(node_id) {
        Some(parent) => node_id = parent,
        None => return Ok(Value::Null),
      },
    }
  }

  get_or_create_node_wrapper(vm, scope, document_obj, Some(document.dom()), node_id)
}

fn document_elements_from_point_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(document_obj) = this else {
    return Err(VmError::TypeError("Illegal invocation"));
  };

  {
    let platform = dom_platform_mut(vm).ok_or(VmError::TypeError("Illegal invocation"))?;
    let _ = platform.require_document_id(scope.heap(), Value::Object(document_obj))?;
  };

  let x = scope
    .heap_mut()
    .to_number(args.get(0).copied().unwrap_or(Value::Undefined))?;
  let y = scope
    .heap_mut()
    .to_number(args.get(1).copied().unwrap_or(Value::Undefined))?;

  let mut ids: Vec<NodeId> = Vec::new();
  let dom: Option<&dom2::Document>;
  if x.is_finite() && y.is_finite() {
    if let Some(document) = host.as_any_mut().downcast_mut::<BrowserDocumentDom2>() {
      match document.elements_from_point(x as f32, y as f32) {
        Ok(found) => {
          ids = found;
          dom = Some(document.dom());
        }
        Err(_) => {
          dom = Some(document.dom());
        }
      }
    } else {
      dom = dom_from_vm_host(host);
    }
  } else {
    dom = dom_from_vm_host(host);
  }

  let array = scope.alloc_array(0)?;
  scope.push_root(Value::Object(array))?;
  if let Some(intrinsics) = vm.intrinsics() {
    scope
      .heap_mut()
      .object_set_prototype(array, Some(intrinsics.array_prototype()))?;
  }

  // Only BrowserDocumentDom2 can currently produce hit-tested results. For other hosts, return an
  // empty array.
  let Some(dom) = dom else {
    let length_key = alloc_key(scope, "length")?;
    scope.define_property(
      array,
      length_key,
      PropertyDescriptor {
        enumerable: false,
        configurable: false,
        kind: PropertyKind::Data {
          value: Value::Number(0.0),
          writable: true,
        },
      },
    )?;
    return Ok(Value::Object(array));
  };

  let mut written: usize = 0;
  for node_id in ids.into_iter() {
    let key = alloc_key(scope, &written.to_string())?;
    let wrapper = get_or_create_node_wrapper(vm, scope, document_obj, Some(dom), node_id)?;
    scope.define_property(array, key, data_desc(wrapper))?;
    written = written.saturating_add(1);
  }

  let length_key = alloc_key(scope, "length")?;
  scope.define_property(
    array,
    length_key,
    PropertyDescriptor {
      enumerable: false,
      configurable: false,
      kind: PropertyKind::Data {
        value: Value::Number(written as f64),
        writable: true,
      },
    },
  )?;

  Ok(Value::Object(array))
}

fn element_query_selector_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(wrapper_obj) = this else {
    return Err(VmError::TypeError(
      "Element.querySelector must be called on a node object",
    ));
  };

  let node_id_key = alloc_key(scope, NODE_ID_KEY)?;
  let node_index = match scope
    .heap()
    .object_get_own_data_property_value(wrapper_obj, &node_id_key)?
  {
    Some(Value::Number(n)) if n.is_finite() && n >= 0.0 => n as usize,
    _ => {
      return Err(VmError::TypeError(
        "Element.querySelector must be called on a node object",
      ));
    }
  };

  let document_obj_key = alloc_key(scope, WRAPPER_DOCUMENT_KEY)?;
  let document_obj = match scope
    .heap()
    .object_get_own_data_property_value(wrapper_obj, &document_obj_key)?
  {
    Some(Value::Object(obj)) => obj,
    _ => {
      return Err(VmError::TypeError(
        "Element.querySelector requires a DOM-backed element",
      ));
    }
  };

  let node_id = {
    let dom = dom_from_vm_host(host).ok_or(VmError::TypeError(
      "Element.querySelector requires a DOM-backed element",
    ))?;
    match dom.node_id_from_index(node_index) {
      Ok(id) => id,
      Err(_) => {
        return Err(VmError::TypeError(
          "Element.querySelector must be called on a node object",
        ));
      }
    }
  };

  let selector_value = args.get(0).copied().unwrap_or(Value::Undefined);
  let selector_value = scope.heap_mut().to_string(selector_value)?;
  let selector = scope
    .heap()
    .get_string(selector_value)
    .map(|s| s.to_utf8_lossy())
    .unwrap_or_default();

  let result = mutate_dom_for_vm_host(host, |dom| (dom.query_selector(&selector, Some(node_id)), false))
    .ok_or(VmError::TypeError(
      "Element.querySelector requires a DOM-backed element",
    ))?;
  let dom = dom_from_vm_host(host).ok_or(VmError::TypeError(
    "Element.querySelector requires a DOM-backed element",
  ))?;

  match result {
    Ok(Some(found)) => get_or_create_node_wrapper(vm, scope, document_obj, Some(dom), found),
    Ok(None) => Ok(Value::Null),
    Err(err) => {
      let (name, message) = match err {
        crate::web::dom::DomException::SyntaxError { message } => ("SyntaxError", message),
        crate::web::dom::DomException::NoModificationAllowedError { message } => {
          ("NoModificationAllowedError", message)
        }
        crate::web::dom::DomException::NotSupportedError { message } => {
          ("NotSupportedError", message)
        }
        crate::web::dom::DomException::InvalidStateError { message } => {
          ("InvalidStateError", message)
        }
      };
      Err(VmError::Throw(make_dom_exception(vm, scope, name, &message)?))
    }
  }
}

