fn dom_rect_to_json_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(obj) = this else {
    return Err(VmError::TypeError(
      "DOMRectReadOnly.toJSON must be called on an object",
    ));
  };

  let x = dom_rect_get_number_or_zero(vm, scope, host, hooks, obj, "x")?;
  let y = dom_rect_get_number_or_zero(vm, scope, host, hooks, obj, "y")?;
  let width = dom_rect_get_number_or_zero(vm, scope, host, hooks, obj, "width")?;
  let height = dom_rect_get_number_or_zero(vm, scope, host, hooks, obj, "height")?;
  let left = x;
  let top = y;
  let right = x + width;
  let bottom = y + height;

  let out = scope.alloc_object()?;
  scope.push_root(Value::Object(out))?;

  let mut define = |scope: &mut Scope<'_>, name: &str, value: f64| -> Result<(), VmError> {
    let key = alloc_key(scope, name)?;
    scope.define_property(
      out,
      key,
      PropertyDescriptor {
        enumerable: true,
        configurable: true,
        kind: PropertyKind::Data {
          value: Value::Number(value),
          writable: true,
        },
      },
    )
  };

  // Root `out` while allocating property keys.
  let mut scope = scope.reborrow();
  scope.push_root(Value::Object(out))?;
  define(&mut scope, "x", x)?;
  define(&mut scope, "y", y)?;
  define(&mut scope, "width", width)?;
  define(&mut scope, "height", height)?;
  define(&mut scope, "top", top)?;
  define(&mut scope, "right", right)?;
  define(&mut scope, "bottom", bottom)?;
  define(&mut scope, "left", left)?;

  Ok(Value::Object(out))
}

