fn dom_rect_from_rect_slots(scope: &Scope<'_>, callee: GcObject) -> Result<(GcObject, bool), VmError> {
  let slots = scope.heap().get_function_native_slots(callee)?;
  let ctor = slots
    .get(DOM_RECT_FROM_RECT_CTOR_SLOT)
    .copied()
    .unwrap_or(Value::Undefined);
  let read_only = slots
    .get(DOM_RECT_FROM_RECT_READ_ONLY_SLOT)
    .copied()
    .unwrap_or(Value::Bool(false));
  let Value::Object(ctor_obj) = ctor else {
    return Err(VmError::InvariantViolation(
      "DOMRect.fromRect missing constructor slot",
    ));
  };
  let read_only = matches!(read_only, Value::Bool(true));
  Ok((ctor_obj, read_only))
}

fn dom_rect_init_get_number_or_zero(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  init: GcObject,
  name: &str,
) -> Result<f64, VmError> {
  // Root `init` while allocating the property key: string allocation can trigger GC.
  let mut scope = scope.reborrow();
  scope.push_root(Value::Object(init))?;
  let key = alloc_key(&mut scope, name)?;
  let value = vm.get_with_host_and_hooks(host, &mut scope, hooks, init, key)?;
  dom_rect_value_to_number_or_zero(vm, &mut scope, host, hooks, value)
}

fn dom_rect_from_rect_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  callee: GcObject,
  _this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let (ctor, read_only) = dom_rect_from_rect_slots(scope, callee)?;
  let init = args.get(0).copied().unwrap_or(Value::Undefined);

  let (x, y, width, height) = if matches!(init, Value::Undefined | Value::Null) {
    (0.0, 0.0, 0.0, 0.0)
  } else {
    // Spec: convert `other` to a `DOMRectInit` dictionary, which uses `ToObject` + `Get` for each
    // member. This allows inherited properties, accessors, and boxed primitives.
    let init_obj = scope.to_object(vm, host, hooks, init)?;
    (
      dom_rect_init_get_number_or_zero(vm, scope, host, hooks, init_obj, "x")?,
      dom_rect_init_get_number_or_zero(vm, scope, host, hooks, init_obj, "y")?,
      dom_rect_init_get_number_or_zero(vm, scope, host, hooks, init_obj, "width")?,
      dom_rect_init_get_number_or_zero(vm, scope, host, hooks, init_obj, "height")?,
    )
  };

  dom_rect_create_instance(scope, ctor, read_only, x, y, width, height)
}

fn element_get_bounding_client_rect_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(wrapper_obj) = this else {
    return Err(VmError::TypeError("Illegal invocation"));
  };

  let handle = element_handle_from_wrapper_obj(
    vm,
    scope,
    wrapper_obj,
    "Illegal invocation",
  )?;

  let rect = if is_host_document_id(vm, handle.document_id) {
    if let Some(document) = host.as_any_mut().downcast_mut::<BrowserDocumentDom2>() {
      document
        .geometry_context()
        .ok()
        .and_then(|ctx| ctx.border_box_in_viewport(handle.node_id))
        .unwrap_or(Rect::ZERO)
    } else {
      Rect::ZERO
    }
  } else {
    Rect::ZERO
  };

  let global = match document_window_from_document(scope, handle.document_obj)? {
    Some(global) => global,
    None => vm
      .user_data::<WindowRealmUserData>()
      .and_then(|data| data.window_obj)
      .ok_or(VmError::TypeError("Illegal invocation"))?,
  };

  let rect_obj = crate::js::window_dom_rect::alloc_dom_rect_from_global(
    scope,
    global,
    rect.x() as f64,
    rect.y() as f64,
    rect.width() as f64,
    rect.height() as f64,
  )?;
  Ok(Value::Object(rect_obj))
}

fn element_wrapper_node_index(scope: &mut Scope<'_>, obj: GcObject) -> Result<Option<usize>, VmError> {
  let node_id_key = alloc_key(scope, NODE_ID_KEY)?;
  Ok(
    match scope
      .heap()
      .object_get_own_data_property_value(obj, &node_id_key)?
    {
      Some(Value::Number(n)) if n.is_finite() && n >= 0.0 => Some(n as usize),
      _ => None,
    },
  )
}

fn finite_f64_to_f32_or_zero(n: f64) -> f32 {
  if !n.is_finite() {
    return 0.0;
  }
  let min = f32::MIN as f64;
  let max = f32::MAX as f64;
  n.clamp(min, max) as f32
}

fn layout_metric_f32_to_f64_or_zero(n: f32) -> f64 {
  if n.is_finite() { n as f64 } else { 0.0 }
}

fn layout_metric_nonneg_f32_to_f64_or_zero(n: f32) -> f64 {
  if n.is_finite() { n.max(0.0) as f64 } else { 0.0 }
}

fn find_fragment_node_for_box_id<'a>(
  fragment_tree: &'a crate::tree::fragment_tree::FragmentTree,
  box_id: usize,
) -> Option<(&'a crate::tree::fragment_tree::FragmentNode, bool)> {
  struct Frame<'a> {
    node: &'a crate::tree::fragment_tree::FragmentNode,
    has_fixed_cb_ancestor: bool,
  }

  let mut stack: Vec<Frame<'_>> = Vec::new();
  for root in fragment_tree.additional_fragments.iter().rev() {
    stack.push(Frame {
      node: root,
      has_fixed_cb_ancestor: false,
    });
  }
  stack.push(Frame {
    node: &fragment_tree.root,
    has_fixed_cb_ancestor: false,
  });

  while let Some(frame) = stack.pop() {
    if frame.node.box_id() == Some(box_id) {
      return Some((frame.node, frame.has_fixed_cb_ancestor));
    }
    let establishes_fixed_cb = frame
      .node
      .style
      .as_deref()
      .is_some_and(|style| style.establishes_fixed_containing_block());
    let has_fixed_cb_ancestor_for_children = frame.has_fixed_cb_ancestor || establishes_fixed_cb;
    for child in frame.node.children.iter().rev() {
      stack.push(Frame {
        node: child,
        has_fixed_cb_ancestor: has_fixed_cb_ancestor_for_children,
      });
    }
  }

  None
}

fn element_scroll_container_metrics_for_box_id(
  prepared: &crate::api::PreparedDocument,
  box_id: usize,
) -> Option<(f32, f32, f32, f32)> {
  let (node, has_fixed_cb_ancestor) = find_fragment_node_for_box_id(prepared.fragment_tree(), box_id)?;
  let style = node.style.as_deref()?;
  let (client_w, client_h) = crate::scroll::client_width_height_for_fragment(node, style);
  let bounds = crate::scroll::scroll_bounds_for_fragment(
    node,
    crate::geometry::Point::ZERO,
    node.bounds.size,
    prepared.layout_viewport(),
    false,
    has_fixed_cb_ancestor,
  );
  let scroll_w = client_w + bounds.max_x;
  let scroll_h = client_h + bounds.max_y;
  Some((client_w, client_h, scroll_w, scroll_h))
}

fn element_offset_width_get_native(
  _vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(obj) = this else {
    return Ok(Value::Number(0.0));
  };
  let Some(document) = host.as_any_mut().downcast_mut::<BrowserDocumentDom2>() else {
    return Ok(Value::Number(0.0));
  };
  let Some(node_index) = element_wrapper_node_index(scope, obj)? else {
    return Ok(Value::Number(0.0));
  };
  let node_id = match document.dom().node_id_from_index(node_index) {
    Ok(id) => id,
    Err(_) => return Ok(Value::Number(0.0)),
  };
  let rect = match document.border_box_rect_page(node_id) {
    Ok(Some(rect)) => rect,
    _ => return Ok(Value::Number(0.0)),
  };
  Ok(Value::Number(layout_metric_nonneg_f32_to_f64_or_zero(rect.width())))
}

