fn document_create_element_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(document_obj) = this else {
    return Err(VmError::TypeError(
      "document.createElement must be called on a document object",
    ));
  };

  let document_id = ensure_document_handle_for_object(
    vm,
    scope,
    document_obj,
    "document.createElement must be called on a document object",
  )?;

  let tag_value = args.get(0).copied().unwrap_or(Value::Undefined);
  let tag_value = scope.heap_mut().to_string(tag_value)?;
  let tag_name = scope
    .heap()
    .get_string(tag_value)
    .map(|s| s.to_utf8_lossy())
    .unwrap_or_default();

  if let Err(err) = dom2::validate_element_qualified_name(tag_name.as_ref()) {
    return Err(VmError::Throw(make_dom_exception(vm, scope, err.code(), "")?));
  }

  let node_id = if let Some(mut dom_ptr) = owned_dom_ptr_for_document_id_mut(vm, document_id) {
    // SAFETY: `dom_ptr` points at a realm-owned `dom2::Document` and is valid for the duration of
    // this native call.
    let dom_mut = unsafe { dom_ptr.as_mut() };
    // DOM: createElement() uses the HTML namespace only for HTML documents; XML documents default to
    // the null namespace.
    let namespace = if dom_mut.is_html_document() { "" } else { dom2::NULL_NAMESPACE };
    dom_mut.create_element(&tag_name, namespace)
  } else {
    // Creating a detached node must not invalidate rendering for host-backed documents.
    mutate_dom_for_vm_host(host, |dom| {
      let namespace = if dom.is_html_document() { "" } else { dom2::NULL_NAMESPACE };
      (dom.create_element(&tag_name, namespace), false)
    })
    .ok_or(VmError::TypeError(
      "document.createElement requires a DOM-backed document",
    ))?
  };

  let dom = dom_ptr_for_document_id_read(vm, host, document_id)
    .map(|ptr| unsafe { ptr.as_ref() })
    .ok_or(VmError::TypeError(
      "document.createElement requires a DOM-backed document",
    ))?;
  get_or_create_node_wrapper(vm, scope, document_obj, Some(dom), node_id)
}

fn value_to_rust_utf16_string(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  value: Value,
) -> Result<String, VmError> {
  let value_s = match value {
    Value::String(s) => s,
    other => scope.heap_mut().to_string(other)?,
  };
  let units = scope.heap().get_string(value_s)?.as_code_units();
  match String::from_utf16(units) {
    Ok(s) => Ok(s),
    Err(_) => Err(VmError::Throw(make_dom_exception(vm, scope,
      "InvalidCharacterError",
      "Invalid UTF-16 string.",
    )?)),
  }
}

fn document_create_element_ns_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(document_obj) = this else {
    return Err(VmError::TypeError(
      "document.createElementNS must be called on a document object",
    ));
  };

  let document_id = dom_platform_mut(vm)
    .ok_or(VmError::TypeError(
      "document.createElementNS must be called on a document object",
    ))?
    .require_document_handle(scope.heap(), Value::Object(document_obj))
    .map_err(|_| VmError::TypeError("document.createElementNS must be called on a document object"))?
    .document_id;

  let namespace_value = args.get(0).copied().unwrap_or(Value::Undefined);
  let namespace: Option<String> = match namespace_value {
    Value::Null | Value::Undefined => None,
    other => {
      let ns = value_to_rust_utf16_string(vm, scope, other)?;
      (!ns.is_empty()).then_some(ns)
    }
  };

  let qualified_name_value = args.get(1).copied().unwrap_or(Value::Undefined);
  let qualified_name = value_to_rust_utf16_string(vm, scope, qualified_name_value)?;

  let dom2::ParsedQualifiedName { prefix, mut local_name } =
    match dom2::validate_and_extract_element(namespace.as_deref(), &qualified_name) {
      Ok(v) => v,
      Err(err) => return Err(VmError::Throw(make_dom_exception(vm, scope, err.code(), "")?)),
    };

  let node_id = if let Some(mut dom_ptr) = owned_dom_ptr_for_document_id_mut(vm, document_id) {
    // SAFETY: `dom_ptr` points at a realm-owned `dom2::Document` and is valid for the duration of
    // this native call.
    let dom_mut = unsafe { dom_ptr.as_mut() };
    // DOM: HTML namespace elements have an ASCII-lowercased localName in HTML documents.
    if dom_mut.is_html_document() && namespace.as_deref() == Some(crate::dom::HTML_NAMESPACE) {
      local_name = local_name.to_ascii_lowercase();
    }
    let ns_for_dom2 = namespace.as_deref().unwrap_or(dom2::NULL_NAMESPACE);
    dom_mut.create_element_ns(&local_name, ns_for_dom2, prefix.as_deref())
  } else {
    // Creating a detached node must not invalidate rendering for host-backed documents.
    mutate_dom_for_vm_host(host, move |dom| {
      // DOM: HTML namespace elements have an ASCII-lowercased localName in HTML documents.
      if dom.is_html_document() && namespace.as_deref() == Some(crate::dom::HTML_NAMESPACE) {
        local_name = local_name.to_ascii_lowercase();
      }
      let ns_for_dom2 = namespace.as_deref().unwrap_or(dom2::NULL_NAMESPACE);
      (
        dom.create_element_ns(&local_name, ns_for_dom2, prefix.as_deref()),
        false,
      )
    })
    .ok_or(VmError::TypeError(
      "document.createElementNS requires a DOM-backed document",
    ))?
  };

  let dom = dom_ptr_for_document_id_read(vm, host, document_id)
    .map(|ptr| unsafe { ptr.as_ref() })
    .ok_or(VmError::TypeError(
      "document.createElementNS requires a DOM-backed document",
    ))?;
  get_or_create_node_wrapper(vm, scope, document_obj, Some(dom), node_id)
}

fn document_create_attribute_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(document_obj) = this else {
    return Err(VmError::TypeError(
      "document.createAttribute must be called on a document object",
    ));
  };

  let name_value = args.get(0).copied().unwrap_or(Value::Undefined);
  let mut local_name = value_to_rust_utf16_string(vm, scope, name_value)?;
  if let Err(err) = dom2::validate_attribute_local_name(&local_name) {
    return Err(VmError::Throw(make_dom_exception(vm, scope, err.code(), "")?));
  }

  let is_html_document = dom_platform_mut(vm)
    .and_then(|platform| platform.require_document_handle(scope.heap(), Value::Object(document_obj)).ok())
    .and_then(|handle| dom_ptr_for_document_id_read(vm, host, handle.document_id))
    .map(|dom_ptr| unsafe { dom_ptr.as_ref() }.is_html_document())
    .unwrap_or(true);

  // HTML documents lowercase attribute local names.
  if is_html_document {
    local_name = local_name.to_ascii_lowercase();
  }

  // Construct a branded Attr object (`instanceof Attr` / `instanceof Node`).
  scope.push_root(Value::Object(document_obj))?;
  let attr_proto_key = alloc_key(scope, ATTR_PROTOTYPE_KEY)?;
  let attr_proto = scope
    .heap()
    .object_get_own_data_property_value(document_obj, &attr_proto_key)?
    .and_then(|v| match v {
      Value::Object(o) => Some(o),
      _ => None,
    });
  let attr_obj = scope.alloc_object_with_prototype(attr_proto)?;
  scope.push_root(Value::Object(attr_obj))?;
  scope.heap_mut().object_set_host_slots(
    attr_obj,
    HostSlots {
      a: 0,
      b: HOST_OBJECT_ATTR,
    },
  )?;

  // Basic Attr shape: name/localName/prefix/namespaceURI/value.
  let name = local_name.clone();

  let name_key = alloc_key(scope, "name")?;
  let local_name_key = alloc_key(scope, "localName")?;
  let prefix_key = alloc_key(scope, "prefix")?;
  let namespace_uri_key = alloc_key(scope, "namespaceURI")?;
  let value_key = alloc_key(scope, "value")?;
  let owner_element_key = alloc_key(scope, "ownerElement")?;
  let specified_key = alloc_key(scope, "specified")?;

  let name_s = scope.alloc_string(&name)?;
  scope.push_root(Value::String(name_s))?;
  let local_name_s = scope.alloc_string(&local_name)?;
  scope.push_root(Value::String(local_name_s))?;
  let empty_s = scope.alloc_string("")?;
  scope.push_root(Value::String(empty_s))?;

  scope.define_property(attr_obj, name_key, read_only_data_desc(Value::String(name_s)))?;
  scope.define_property(
    attr_obj,
    local_name_key,
    read_only_data_desc(Value::String(local_name_s)),
  )?;
  scope.define_property(attr_obj, prefix_key, read_only_data_desc(Value::Null))?;
  scope.define_property(attr_obj, namespace_uri_key, read_only_data_desc(Value::Null))?;
  scope.define_property(
    attr_obj,
    value_key,
    data_desc(Value::String(empty_s)),
  )?;
  scope.define_property(
    attr_obj,
    owner_element_key,
    read_only_data_desc(Value::Null),
  )?;
  scope.define_property(
    attr_obj,
    specified_key,
    read_only_data_desc(Value::Bool(true)),
  )?;

  Ok(Value::Object(attr_obj))
}

fn document_create_attribute_ns_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(document_obj) = this else {
    return Err(VmError::TypeError(
      "document.createAttributeNS must be called on a document object",
    ));
  };

  let namespace_value = args.get(0).copied().unwrap_or(Value::Undefined);
  let namespace: Option<String> = match namespace_value {
    Value::Null | Value::Undefined => None,
    other => {
      let ns = value_to_rust_utf16_string(vm, scope, other)?;
      (!ns.is_empty()).then_some(ns)
    }
  };

  let qualified_name_value = args.get(1).copied().unwrap_or(Value::Undefined);
  let qualified_name = value_to_rust_utf16_string(vm, scope, qualified_name_value)?;

  let dom2::ParsedQualifiedName { prefix, mut local_name } =
    match dom2::validate_and_extract_attribute(namespace.as_deref(), &qualified_name) {
      Ok(v) => v,
      Err(err) => return Err(VmError::Throw(make_dom_exception(vm, scope, err.code(), "")?)),
    };

  // HTML documents lowercase attribute local names when the namespace is null.
  let is_html_document = dom_platform_mut(vm)
    .and_then(|platform| platform.require_document_handle(scope.heap(), Value::Object(document_obj)).ok())
    .and_then(|handle| dom_ptr_for_document_id_read(vm, host, handle.document_id))
    .map(|dom_ptr| unsafe { dom_ptr.as_ref() }.is_html_document())
    .unwrap_or(true);
  if is_html_document && namespace.is_none() {
    local_name = local_name.to_ascii_lowercase();
  }

  // Construct a branded Attr object (`instanceof Attr` / `instanceof Node`).
  scope.push_root(Value::Object(document_obj))?;
  let attr_proto_key = alloc_key(scope, ATTR_PROTOTYPE_KEY)?;
  let attr_proto = scope
    .heap()
    .object_get_own_data_property_value(document_obj, &attr_proto_key)?
    .and_then(|v| match v {
      Value::Object(o) => Some(o),
      _ => None,
    });
  let attr_obj = scope.alloc_object_with_prototype(attr_proto)?;
  scope.push_root(Value::Object(attr_obj))?;
  scope.heap_mut().object_set_host_slots(
    attr_obj,
    HostSlots {
      a: 0,
      b: HOST_OBJECT_ATTR,
    },
  )?;

  let name = match prefix.as_deref() {
    Some(prefix) => format!("{prefix}:{local_name}"),
    None => local_name.clone(),
  };

  let name_key = alloc_key(scope, "name")?;
  let local_name_key = alloc_key(scope, "localName")?;
  let prefix_key = alloc_key(scope, "prefix")?;
  let namespace_uri_key = alloc_key(scope, "namespaceURI")?;
  let value_key = alloc_key(scope, "value")?;
  let owner_element_key = alloc_key(scope, "ownerElement")?;
  let specified_key = alloc_key(scope, "specified")?;

  let name_s = scope.alloc_string(&name)?;
  scope.push_root(Value::String(name_s))?;
  let local_name_s = scope.alloc_string(&local_name)?;
  scope.push_root(Value::String(local_name_s))?;
  let empty_s = scope.alloc_string("")?;
  scope.push_root(Value::String(empty_s))?;

  scope.define_property(attr_obj, name_key, read_only_data_desc(Value::String(name_s)))?;
  scope.define_property(
    attr_obj,
    local_name_key,
    read_only_data_desc(Value::String(local_name_s)),
  )?;
  match prefix.as_deref() {
    Some(prefix) => {
      let prefix_s = scope.alloc_string(prefix)?;
      scope.push_root(Value::String(prefix_s))?;
      scope.define_property(
        attr_obj,
        prefix_key,
        read_only_data_desc(Value::String(prefix_s)),
      )?;
    }
    None => {
      scope.define_property(attr_obj, prefix_key, read_only_data_desc(Value::Null))?;
    }
  }
  match namespace.as_deref() {
    Some(ns) => {
      let ns_s = scope.alloc_string(ns)?;
      scope.push_root(Value::String(ns_s))?;
      scope.define_property(
        attr_obj,
        namespace_uri_key,
        read_only_data_desc(Value::String(ns_s)),
      )?;
    }
    None => {
      scope.define_property(attr_obj, namespace_uri_key, read_only_data_desc(Value::Null))?;
    }
  }
  scope.define_property(
    attr_obj,
    value_key,
    data_desc(Value::String(empty_s)),
  )?;
  scope.define_property(
    attr_obj,
    owner_element_key,
    read_only_data_desc(Value::Null),
  )?;
  scope.define_property(
    attr_obj,
    specified_key,
    read_only_data_desc(Value::Bool(true)),
  )?;

  Ok(Value::Object(attr_obj))
}

fn document_create_text_node_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(document_obj) = this else {
    return Err(VmError::TypeError(
      "document.createTextNode must be called on a document object",
    ));
  };

  let document_id = ensure_document_handle_for_object(
    vm,
    scope,
    document_obj,
    "document.createTextNode must be called on a document object",
  )?;

  let data_value = args.get(0).copied().unwrap_or(Value::Undefined);
  let data_value = scope.heap_mut().to_string(data_value)?;
  let data = scope
    .heap()
    .get_string(data_value)
    .map(|s| s.to_utf8_lossy())
    .unwrap_or_default();

  let node_id = if let Some(mut dom_ptr) = owned_dom_ptr_for_document_id_mut(vm, document_id) {
    // SAFETY: `dom_ptr` points at a realm-owned `dom2::Document` and is valid for the duration of
    // this native call.
    unsafe { dom_ptr.as_mut() }.create_text(&data)
  } else {
    // Creating a detached node must not invalidate rendering for host-backed documents.
    mutate_dom_for_vm_host(host, |dom| (dom.create_text(&data), false)).ok_or(VmError::TypeError(
      "document.createTextNode requires a DOM-backed document",
    ))?
  };

  let dom = dom_ptr_for_document_id_read(vm, host, document_id)
    .map(|ptr| unsafe { ptr.as_ref() })
    .ok_or(VmError::TypeError(
      "document.createTextNode requires a DOM-backed document",
    ))?;
  get_or_create_node_wrapper(vm, scope, document_obj, Some(dom), node_id)
}

fn document_create_cdata_section_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(document_obj) = this else {
    return Err(VmError::TypeError(
      "document.createCDATASection must be called on a document object",
    ));
  };

  let document_id = ensure_document_handle_for_object(
    vm,
    scope,
    document_obj,
    "document.createCDATASection must be called on a document object",
  )?;

  let data_value = args.get(0).copied().unwrap_or(Value::Undefined);
  let data_value = scope.heap_mut().to_string(data_value)?;
  let data = scope
    .heap()
    .get_string(data_value)
    .map(|s| s.to_utf8_lossy())
    .unwrap_or_default();

  // https://dom.spec.whatwg.org/#dom-document-createcdatasection
  //
  // - Only XML documents can create CDATASection nodes.
  // - The data must not contain the CDATA section end delimiter.
  let mut dom_ptr =
    dom_ptr_for_document_id_mut(vm, host, document_id).ok_or(VmError::TypeError(
      "document.createCDATASection requires a DOM-backed document",
    ))?;
  // SAFETY: `dom_ptr` is valid for the duration of this native call.
  let dom_mut = unsafe { dom_ptr.as_mut() };
  if dom_mut.is_html_document() {
    return Err(VmError::Throw(make_dom_exception(
      vm,
      scope,
      "NotSupportedError",
      "",
    )?));
  }
  if data.contains("]]>") {
    return Err(VmError::Throw(make_dom_exception(
      vm,
      scope,
      "InvalidCharacterError",
      "",
    )?));
  }

  // `dom2` does not currently distinguish between Text and CDATASection nodes; treat CDATASection
  // as a Text node for DOM operations.
  let node_id = dom_mut.create_text(&data);
  let dom = unsafe { dom_ptr.as_ref() };
  get_or_create_node_wrapper(vm, scope, document_obj, Some(dom), node_id)
}

