fn node_remove_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(wrapper_obj) = this else {
    return Err(VmError::TypeError(
      "Node.remove must be called on a node object",
    ));
  };

  let handle = dom_platform_mut(vm)
    .ok_or(VmError::TypeError("Node.remove must be called on a node object"))?
    .require_node_handle(scope.heap(), Value::Object(wrapper_obj))
    .map_err(|_| VmError::TypeError("Node.remove must be called on a node object"))?;

  let document_id = handle.document_id;
  let node_id = handle.node_id;

  let document_obj = node_wrapper_document_obj(scope, wrapper_obj, node_id)
    .map_err(|_| VmError::TypeError("Node.remove must be called on a node object"))?;
  let run_side_effects =
    should_run_dom_side_effects_for_document(vm, scope, document_id, document_obj)?;

  let Some(mut dom_ptr) = dom_ptr_for_document_id_mut(vm, host, document_id) else {
    return Ok(Value::Undefined);
  };

  // ShadowRoot is never a tree child in the DOM Standard. Even though `dom2` stores it as a child
  // of its host element for internal traversal, JS `ShadowRoot` nodes must not be removable.
  //
  // Spec-wise `ShadowRoot.parentNode` is always `null`, so `ShadowRoot.remove()` is a no-op.
  {
    // SAFETY: `dom_ptr` is valid for the duration of this native call.
    let dom = unsafe { dom_ptr.as_ref() };
    if matches!(&dom.node(node_id).kind, NodeKind::ShadowRoot { .. }) {
      return Ok(Value::Undefined);
    }
  }

  let needs_microtask = {
    // SAFETY: `dom_ptr` is valid for the duration of this native call.
    let dom = unsafe { dom_ptr.as_mut() };

    let Some(parent) = dom.parent_node(node_id) else {
      return Ok(Value::Undefined);
    };

    if let Err(err) = dom.remove_child(parent, node_id) {
      return Err(VmError::Throw(make_dom_exception(vm, scope, err.code(), "")?));
    }

    // Keep cached `childNodes` live NodeLists updated.
    sync_cached_child_nodes_for_node_id(vm, scope, document_obj, dom, parent)?;
    sync_cached_children_for_node_id(vm, scope, document_obj, dom, parent)?;
    sync_cached_select_options_for_select_ancestor(vm, scope, document_obj, dom, parent)?;
    dom.take_mutation_observer_microtask_needed()
  };

  if run_side_effects {
    maybe_queue_mutation_observer_microtask(vm, scope, host, hooks, document_obj, needs_microtask)?;
  }

  Ok(Value::Undefined)
}

fn convert_nodes_into_node(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  callee: GcObject,
  document_obj: GcObject,
  document_id: DocumentId,
  nodes: &[Value],
  error_message: &'static str,
) -> Result<Value, VmError> {
  // Require DOM-backed node wrappers for Node-vs-string detection.
  if dom_platform_mut(vm).is_none() {
    return Err(VmError::TypeError(error_message));
  }

  // Root the document wrapper while allocating keys / node wrappers: string allocation can trigger GC.
  scope.push_root(Value::Object(document_obj))?;

  let mut dom_ptr = dom_ptr_for_document_id_mut(vm, host, document_id).ok_or(VmError::TypeError(
    "operation requires a DOM-backed document",
  ))?;

  let mut converted: Vec<Value> = Vec::with_capacity(nodes.len());
  for &value in nodes {
    if let Value::Object(obj) = value {
      let is_node = dom_platform_mut(vm)
        .and_then(|platform| platform.require_node_handle(scope.heap(), Value::Object(obj)).ok())
        .is_some();
      if is_node {
        converted.push(Value::Object(obj));
        continue;
      }
    }

    let s = scope.heap_mut().to_string(value)?;
    let data = scope
      .heap()
      .get_string(s)
      .map(|s| s.to_utf8_lossy())
      .unwrap_or_default();
    let node_id = unsafe { dom_ptr.as_mut() }.create_text(&data);
    let dom = unsafe { dom_ptr.as_ref() };
    let text_value = get_or_create_node_wrapper(vm, scope, document_obj, Some(dom), node_id)?;
    if let Value::Object(obj) = text_value {
      scope.push_root(Value::Object(obj))?;
    }
    converted.push(text_value);
  }

  if converted.len() == 1 {
    return Ok(converted[0]);
  }

  let fragment_id = unsafe { dom_ptr.as_mut() }.create_document_fragment();
  let dom = unsafe { dom_ptr.as_ref() };
  let fragment_value = get_or_create_node_wrapper(vm, scope, document_obj, Some(dom), fragment_id)?;
  let Value::Object(fragment_obj) = fragment_value else {
    return Ok(fragment_value);
  };
  scope.push_root(Value::Object(fragment_obj))?;

  for node_value in converted {
    let _ = node_append_child_native(
      vm,
      scope,
      host,
      hooks,
      callee,
      Value::Object(fragment_obj),
      &[node_value],
    )?;
  }

  Ok(Value::Object(fragment_obj))
}

fn parent_node_append_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(wrapper_obj) = this else {
    return Err(VmError::TypeError(
      "ParentNode.append must be called on a node object",
    ));
  };

  let handle = node_handle_from_wrapper_obj(
    vm,
    scope,
    wrapper_obj,
    "ParentNode.append must be called on a node object",
  )?;

  let node_value = convert_nodes_into_node(
    vm,
    scope,
    host,
    hooks,
    callee,
    handle.document_obj,
    handle.document_id,
    args,
    "ParentNode.append must be called on a node object",
  )?;
  if let Value::Object(obj) = node_value {
    scope.push_root(Value::Object(obj))?;
  }

  let _ = node_append_child_native(
    vm,
    scope,
    host,
    hooks,
    callee,
    Value::Object(wrapper_obj),
    &[node_value],
  )?;
  Ok(Value::Undefined)
}

fn parent_node_prepend_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(wrapper_obj) = this else {
    return Err(VmError::TypeError(
      "ParentNode.prepend must be called on a node object",
    ));
  };

  let handle = node_handle_from_wrapper_obj(
    vm,
    scope,
    wrapper_obj,
    "ParentNode.prepend must be called on a node object",
  )?;

  let node_value = convert_nodes_into_node(
    vm,
    scope,
    host,
    hooks,
    callee,
    handle.document_obj,
    handle.document_id,
    args,
    "ParentNode.prepend must be called on a node object",
  )?;
  if let Value::Object(obj) = node_value {
    scope.push_root(Value::Object(obj))?;
  }

  let dom_ptr = dom_ptr_for_document_id_read(vm, host, handle.document_id).ok_or(
    VmError::TypeError("ParentNode.prepend must be called on a DOM-backed node"),
  )?;
  let dom = unsafe { dom_ptr.as_ref() };
  let reference_id = node_first_child_for_traversal(dom, handle.node_id);
  let reference_value = match reference_id {
    Some(id) => {
      let v = get_or_create_node_wrapper(vm, scope, handle.document_obj, Some(dom), id)?;
      if let Value::Object(obj) = v {
        scope.push_root(Value::Object(obj))?;
      }
      v
    }
    None => Value::Null,
  };

  let _ = node_insert_before_native(
    vm,
    scope,
    host,
    hooks,
    callee,
    Value::Object(wrapper_obj),
    &[node_value, reference_value],
  )?;

  Ok(Value::Undefined)
}

fn parent_node_replace_children_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(wrapper_obj) = this else {
    return Err(VmError::TypeError(
      "ParentNode.replaceChildren must be called on a node object",
    ));
  };

  let handle = node_handle_from_wrapper_obj(
    vm,
    scope,
    wrapper_obj,
    "ParentNode.replaceChildren must be called on a node object",
  )?;

  // Spec: convert nodes into a node first (can move nodes out of `this`).
  let node_value = convert_nodes_into_node(
    vm,
    scope,
    host,
    hooks,
    callee,
    handle.document_obj,
    handle.document_id,
    args,
    "ParentNode.replaceChildren must be called on a node object",
  )?;
  if let Value::Object(obj) = node_value {
    scope.push_root(Value::Object(obj))?;
  }

  // Collect the light DOM children (skip internal ShadowRoot nodes).
  let dom_ptr = dom_ptr_for_document_id_read(vm, host, handle.document_id).ok_or(
    VmError::TypeError("ParentNode.replaceChildren must be called on a DOM-backed node"),
  )?;
  let dom = unsafe { dom_ptr.as_ref() };
  let mut to_remove: Vec<NodeId> = Vec::new();
  let mut child = node_first_child_for_traversal(dom, handle.node_id);
  while let Some(child_id) = child {
    to_remove.push(child_id);
    child = node_next_sibling_for_traversal(dom, child_id);
  }

  for child_id in to_remove {
    let v = get_or_create_node_wrapper(vm, scope, handle.document_obj, Some(dom), child_id)?;
    if let Value::Object(obj) = v {
      scope.push_root(Value::Object(obj))?;
    }
    let _ = node_remove_child_native(
      vm,
      scope,
      host,
      hooks,
      callee,
      Value::Object(wrapper_obj),
      &[v],
    )?;
  }

  let _ = node_append_child_native(
    vm,
    scope,
    host,
    hooks,
    callee,
    Value::Object(wrapper_obj),
    &[node_value],
  )?;

  Ok(Value::Undefined)
}

fn nodes_in_same_dom_as(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  dom_ptr: NonNull<dom2::Document>,
  nodes: &[Value],
) -> Result<HashSet<NodeId>, VmError> {
  if dom_platform_mut(vm).is_none() {
    return Ok(HashSet::new());
  }
  let mut ids: HashSet<NodeId> = HashSet::new();
  for &value in nodes {
    let Value::Object(obj) = value else {
      continue;
    };
    let Some(handle) = dom_platform_mut(vm)
      .and_then(|platform| platform.require_node_handle(scope.heap(), Value::Object(obj)).ok())
    else {
      continue;
    };
    let Some(node_dom_ptr) = dom_ptr_for_document_id_read(vm, host, handle.document_id) else {
      continue;
    };
    if node_dom_ptr == dom_ptr {
      ids.insert(handle.node_id);
    }
  }
  Ok(ids)
}

fn child_node_before_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(wrapper_obj) = this else {
    return Err(VmError::TypeError(
      "ChildNode.before must be called on a node object",
    ));
  };

  let handle = node_handle_from_wrapper_obj(
    vm,
    scope,
    wrapper_obj,
    "ChildNode.before must be called on a node object",
  )?;

  let dom_ptr = dom_ptr_for_document_id_read(vm, host, handle.document_id).ok_or(
    VmError::TypeError("ChildNode.before must be called on a DOM-backed node"),
  )?;
  let dom = unsafe { dom_ptr.as_ref() };
  let Some(parent_id) = node_parent_node_for_traversal(dom, handle.node_id) else {
    return Ok(Value::Undefined);
  };

  let excluded = nodes_in_same_dom_as(vm, scope, host, dom_ptr, args)?;

  let mut viable_prev = node_previous_sibling_for_traversal(dom, handle.node_id);
  while let Some(prev_id) = viable_prev {
    if excluded.contains(&prev_id) {
      viable_prev = node_previous_sibling_for_traversal(dom, prev_id);
    } else {
      break;
    }
  }

  let node_value = convert_nodes_into_node(
    vm,
    scope,
    host,
    hooks,
    callee,
    handle.document_obj,
    handle.document_id,
    args,
    "ChildNode.before must be called on a node object",
  )?;
  if let Value::Object(obj) = node_value {
    scope.push_root(Value::Object(obj))?;
  }

  // Recompute reference after conversion.
  let dom_ptr = dom_ptr_for_document_id_read(vm, host, handle.document_id).ok_or(
    VmError::TypeError("ChildNode.before must be called on a DOM-backed node"),
  )?;
  let dom = unsafe { dom_ptr.as_ref() };
  let reference_id = match viable_prev {
    None => node_first_child_for_traversal(dom, parent_id),
    Some(prev) => node_next_sibling_for_traversal(dom, prev),
  };

  let parent_value = get_or_create_node_wrapper(vm, scope, handle.document_obj, Some(dom), parent_id)?;
  let Value::Object(parent_obj) = parent_value else {
    return Ok(Value::Undefined);
  };
  scope.push_root(Value::Object(parent_obj))?;

  let reference_value = match reference_id {
    Some(id) => {
      let v = get_or_create_node_wrapper(vm, scope, handle.document_obj, Some(dom), id)?;
      if let Value::Object(obj) = v {
        scope.push_root(Value::Object(obj))?;
      }
      v
    }
    None => Value::Null,
  };

  let _ = node_insert_before_native(
    vm,
    scope,
    host,
    hooks,
    callee,
    Value::Object(parent_obj),
    &[node_value, reference_value],
  )?;
  Ok(Value::Undefined)
}

fn child_node_after_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(wrapper_obj) = this else {
    return Err(VmError::TypeError(
      "ChildNode.after must be called on a node object",
    ));
  };

  let handle = node_handle_from_wrapper_obj(
    vm,
    scope,
    wrapper_obj,
    "ChildNode.after must be called on a node object",
  )?;

  let dom_ptr = dom_ptr_for_document_id_read(vm, host, handle.document_id).ok_or(
    VmError::TypeError("ChildNode.after must be called on a DOM-backed node"),
  )?;
  let dom = unsafe { dom_ptr.as_ref() };
  let Some(parent_id) = node_parent_node_for_traversal(dom, handle.node_id) else {
    return Ok(Value::Undefined);
  };

  let excluded = nodes_in_same_dom_as(vm, scope, host, dom_ptr, args)?;

  let mut viable_next = node_next_sibling_for_traversal(dom, handle.node_id);
  while let Some(next_id) = viable_next {
    if excluded.contains(&next_id) {
      viable_next = node_next_sibling_for_traversal(dom, next_id);
    } else {
      break;
    }
  }

  let node_value = convert_nodes_into_node(
    vm,
    scope,
    host,
    hooks,
    callee,
    handle.document_obj,
    handle.document_id,
    args,
    "ChildNode.after must be called on a node object",
  )?;
  if let Value::Object(obj) = node_value {
    scope.push_root(Value::Object(obj))?;
  }

  let dom_ptr = dom_ptr_for_document_id_read(vm, host, handle.document_id).ok_or(
    VmError::TypeError("ChildNode.after must be called on a DOM-backed node"),
  )?;
  let dom = unsafe { dom_ptr.as_ref() };

  let parent_value = get_or_create_node_wrapper(vm, scope, handle.document_obj, Some(dom), parent_id)?;
  let Value::Object(parent_obj) = parent_value else {
    return Ok(Value::Undefined);
  };
  scope.push_root(Value::Object(parent_obj))?;

  let reference_value = match viable_next {
    Some(id) => {
      let v = get_or_create_node_wrapper(vm, scope, handle.document_obj, Some(dom), id)?;
      if let Value::Object(obj) = v {
        scope.push_root(Value::Object(obj))?;
      }
      v
    }
    None => Value::Null,
  };

  let _ = node_insert_before_native(
    vm,
    scope,
    host,
    hooks,
    callee,
    Value::Object(parent_obj),
    &[node_value, reference_value],
  )?;
  Ok(Value::Undefined)
}

fn child_node_replace_with_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(wrapper_obj) = this else {
    return Err(VmError::TypeError(
      "ChildNode.replaceWith must be called on a node object",
    ));
  };

  let handle = node_handle_from_wrapper_obj(
    vm,
    scope,
    wrapper_obj,
    "ChildNode.replaceWith must be called on a node object",
  )?;

  let dom_ptr = dom_ptr_for_document_id_read(vm, host, handle.document_id).ok_or(
    VmError::TypeError("ChildNode.replaceWith must be called on a DOM-backed node"),
  )?;
  let dom = unsafe { dom_ptr.as_ref() };
  let Some(parent_id) = node_parent_node_for_traversal(dom, handle.node_id) else {
    return Ok(Value::Undefined);
  };

  let excluded = nodes_in_same_dom_as(vm, scope, host, dom_ptr, args)?;

  let mut viable_next = node_next_sibling_for_traversal(dom, handle.node_id);
  while let Some(next_id) = viable_next {
    if excluded.contains(&next_id) {
      viable_next = node_next_sibling_for_traversal(dom, next_id);
    } else {
      break;
    }
  }

  let node_value = convert_nodes_into_node(
    vm,
    scope,
    host,
    hooks,
    callee,
    handle.document_obj,
    handle.document_id,
    args,
    "ChildNode.replaceWith must be called on a node object",
  )?;
  if let Value::Object(obj) = node_value {
    scope.push_root(Value::Object(obj))?;
  }

  let dom_ptr = dom_ptr_for_document_id_read(vm, host, handle.document_id).ok_or(
    VmError::TypeError("ChildNode.replaceWith must be called on a DOM-backed node"),
  )?;
  let dom = unsafe { dom_ptr.as_ref() };

  let parent_value = get_or_create_node_wrapper(vm, scope, handle.document_obj, Some(dom), parent_id)?;
  let Value::Object(parent_obj) = parent_value else {
    return Ok(Value::Undefined);
  };
  scope.push_root(Value::Object(parent_obj))?;

  let current_parent = node_parent_node_for_traversal(dom, handle.node_id);
  if current_parent == Some(parent_id) {
    let _ = node_replace_child_native(
      vm,
      scope,
      host,
      hooks,
      callee,
      Value::Object(parent_obj),
      &[node_value, Value::Object(wrapper_obj)],
    )?;
    return Ok(Value::Undefined);
  }

  let reference_value = match viable_next {
    Some(id) => {
      let v = get_or_create_node_wrapper(vm, scope, handle.document_obj, Some(dom), id)?;
      if let Value::Object(obj) = v {
        scope.push_root(Value::Object(obj))?;
      }
      v
    }
    None => Value::Null,
  };

  let _ = node_insert_before_native(
    vm,
    scope,
    host,
    hooks,
    callee,
    Value::Object(parent_obj),
    &[node_value, reference_value],
  )?;
  Ok(Value::Undefined)
}

fn node_text_content_get_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(wrapper_obj) = this else {
    return Err(VmError::TypeError(
      "Node.textContent must be called on a node object",
    ));
  };

  let handle = dom_platform_mut(vm)
    .ok_or(VmError::TypeError(
      "Node.textContent must be called on a node object",
    ))?
    .require_node_handle(scope.heap(), Value::Object(wrapper_obj))
    .map_err(|_| VmError::TypeError("Node.textContent must be called on a node object"))?;

  let node_id = handle.node_id;

  let Some(dom_ptr) = dom_ptr_for_document_id_read(vm, host, handle.document_id) else {
    return Err(VmError::TypeError(
      "Node.textContent requires a DOM-backed document",
    ));
  };
  // SAFETY: `dom_ptr` is valid for the duration of this native call.
  let dom = unsafe { dom_ptr.as_ref() };
  match crate::js::dom2_bindings::text_content_get_from_dom(dom, node_id) {
    None => Ok(Value::Null),
    Some(text) => Ok(Value::String(scope.alloc_string(&text)?)),
  }
}

fn node_text_content_set_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(wrapper_obj) = this else {
    return Err(VmError::TypeError(
      "Node.textContent must be called on a node object",
    ));
  };

  let value_value = args.get(0).copied().unwrap_or(Value::Undefined);
  let value = match value_value {
    // `textContent` is `DOMString?`; `null` and `undefined` act as the empty string.
    Value::Null | Value::Undefined => String::new(),
    other => {
      let s = scope.heap_mut().to_string(other)?;
      scope
        .heap()
        .get_string(s)
        .map(|s| s.to_utf8_lossy())
        .unwrap_or_default()
    }
  };

  let handle = dom_platform_mut(vm)
    .ok_or(VmError::TypeError(
      "Node.textContent must be called on a node object",
    ))?
    .require_node_handle(scope.heap(), Value::Object(wrapper_obj))
    .map_err(|_| VmError::TypeError("Node.textContent must be called on a node object"))?;

  let document_id = handle.document_id;
  let node_id = handle.node_id;

  let document_obj = node_wrapper_document_obj(scope, wrapper_obj, node_id)
    .map_err(|_| VmError::TypeError("Node.textContent requires a DOM-backed document"))?;

  let run_side_effects =
    should_run_dom_side_effects_for_document(vm, scope, document_id, document_obj)?;

  let is_host_document = is_host_document_id(vm, document_id);

  // Avoid `dom_mut()` on `BrowserDocumentDom2` so mutations can be classified for incremental
  // invalidation.
  let mut dom_ptr = if is_host_document {
    dom_ptr_for_event_registry(host).ok_or(VmError::TypeError(
      "Node.textContent requires a DOM-backed document",
    ))?
  } else {
    dom_ptr_for_document_id_mut(vm, host, document_id).ok_or(VmError::TypeError(
      "Node.textContent requires a DOM-backed document",
    ))?
  };

  #[derive(Clone, Copy)]
  struct TextContentEffects {
    did_replace_children: bool,
    maybe_script_children_changed: Option<NodeId>,
  }

  let TextContentEffects {
    did_replace_children,
    maybe_script_children_changed,
  } = if is_host_document {
    let result: Result<TextContentEffects, dom2::DomError> = mutate_dom_for_vm_host(host, |dom| {
      match crate::js::dom2_bindings::text_content_set_from_dom(dom, node_id, &value) {
        Ok(result) => {
          let maybe_script = if result.render_affecting {
            // `textContent` updates should trigger script "children changed" steps when they affect
            // either:
            // - a `<script>` element's own children (ReplaceChildren), or
            // - a text node that is a child of a `<script>` element.
            if matches!(&dom.node(node_id).kind, NodeKind::Text { .. }) {
              dom
                .node(node_id)
                .parent
                .filter(|&parent| is_html_script_element(dom, parent))
            } else {
              is_html_script_element(dom, node_id).then_some(node_id)
            }
          } else {
            None
          };

          (
            Ok(TextContentEffects {
              did_replace_children: result.did_replace_children,
              maybe_script_children_changed: maybe_script,
            }),
            result.render_affecting,
          )
        }
        Err(err) => (Err(err), false),
      }
    })
    .ok_or(VmError::TypeError(
      "Node.textContent requires a DOM-backed document",
    ))?;

    match result {
      Ok(v) => v,
      Err(err) => return Err(VmError::Throw(make_dom_exception(vm, scope, err.code(), "")?)),
    }
  } else {
    // SAFETY: `dom_ptr` is valid for the duration of this native call.
    let dom = unsafe { dom_ptr.as_mut() };
    match crate::js::dom2_bindings::text_content_set_from_dom(dom, node_id, &value) {
      Ok(result) => TextContentEffects {
        did_replace_children: result.did_replace_children,
        // Side effects (scripts, microtasks) are only driven for the host document.
        maybe_script_children_changed: None,
      },
      Err(err) => return Err(VmError::Throw(make_dom_exception(vm, scope, err.code(), "")?)),
    }
  };

  if did_replace_children {
    // SAFETY: `dom_ptr` is valid for the duration of this native call.
    let dom = unsafe { dom_ptr.as_ref() };
    sync_cached_child_nodes_for_wrapper(vm, scope, document_obj, dom, wrapper_obj, node_id)?;
    sync_cached_children_for_wrapper(vm, scope, document_obj, dom, wrapper_obj, node_id)?;
    sync_cached_select_options_for_select_ancestor(vm, scope, document_obj, dom, node_id)?;
  }

  if run_side_effects {
    if let Some(script) = maybe_script_children_changed {
      run_dynamic_script_children_changed_steps(
        vm,
        scope,
        host,
        hooks,
        document_obj,
        dom_ptr,
        script,
      )?;
    }
  }

  let needs_microtask = unsafe { dom_ptr.as_mut() }.take_mutation_observer_microtask_needed();
  if run_side_effects {
    maybe_queue_mutation_observer_microtask(vm, scope, host, hooks, document_obj, needs_microtask)?;
  }

  Ok(Value::Undefined)
}

fn text_data_get_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(text_obj) = this else {
    return Err(VmError::TypeError("Illegal invocation"));
  };

  let platform = dom_platform_mut(vm).ok_or(VmError::TypeError("Illegal invocation"))?;
  let node_key = platform.require_text_handle(scope.heap(), Value::Object(text_obj))?;
  let dom_ptr = dom_ptr_for_document_id_read(vm, host, node_key.document_id)
    .ok_or(VmError::TypeError("Illegal invocation"))?;
  // SAFETY: `dom_ptr` is valid for the duration of this native call.
  let dom = unsafe { dom_ptr.as_ref() };

  let data = dom
    .text_data(node_key.node_id)
    .map_err(|_| VmError::TypeError("Illegal invocation"))?;
  Ok(Value::String(scope.alloc_string(data)?))
}

fn text_data_set_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(text_obj) = this else {
    return Err(VmError::TypeError("Illegal invocation"));
  };

  let platform = dom_platform_mut(vm).ok_or(VmError::TypeError("Illegal invocation"))?;
  let node_key = platform.require_text_handle(scope.heap(), Value::Object(text_obj))?;
  let document_obj = node_wrapper_document_obj(scope, text_obj, node_key.node_id)?;

  let new_value = args.get(0).copied().unwrap_or(Value::Undefined);
  let new_value = scope.heap_mut().to_string(new_value)?;
  let new_value = scope
    .heap()
    .get_string(new_value)
    .map(|s| s.to_utf8_lossy())
    .unwrap_or_default();

  let mut dom_ptr = if is_host_document_id(vm, node_key.document_id) {
    dom_ptr_for_event_registry(host).ok_or(VmError::TypeError("Illegal invocation"))?
  } else {
    dom_ptr_for_document_id_mut(vm, host, node_key.document_id).ok_or(VmError::TypeError("Illegal invocation"))?
  };

  let maybe_script_parent = if is_host_document_id(vm, node_key.document_id) {
    let (_changed, maybe_script_parent) =
      mutate_dom_for_vm_host(host, |dom| match dom.set_text_data(node_key.node_id, &new_value) {
        Ok(changed) => {
          let maybe_script_parent = changed
            .then(|| dom.node(node_key.node_id).parent)
            .flatten()
            .filter(|&parent| is_html_script_element(dom, parent));
          (Ok((changed, maybe_script_parent)), changed)
        }
        Err(err) => {
          let exc = match make_dom_exception(vm, scope, err.code(), "") {
            Ok(v) => VmError::Throw(v),
            Err(e) => e,
          };
          (Err(exc), false)
        }
      })
      .ok_or(VmError::TypeError("Illegal invocation"))??;
    maybe_script_parent
  } else {
    // SAFETY: `dom_ptr` is valid for the duration of this native call.
    let dom = unsafe { dom_ptr.as_mut() };
    if let Err(err) = dom.set_text_data(node_key.node_id, &new_value) {
      let exc = make_dom_exception(vm, scope, err.code(), "")?;
      return Err(VmError::Throw(exc));
    }
    None
  };

  if let Some(parent) = maybe_script_parent {
    run_dynamic_script_children_changed_steps(
      vm,
      scope,
      host,
      hooks,
      document_obj,
      dom_ptr,
      parent,
    )?;
  }

  let needs_microtask = unsafe { dom_ptr.as_mut() }.take_mutation_observer_microtask_needed();
  maybe_queue_mutation_observer_microtask(vm, scope, host, hooks, document_obj, needs_microtask)?;

  Ok(Value::Undefined)
}

fn text_split_text_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(text_obj) = this else {
    return Err(VmError::TypeError("Illegal invocation"));
  };

  let platform = dom_platform_mut(vm).ok_or(VmError::TypeError("Illegal invocation"))?;
  let node_key = platform.require_text_handle(scope.heap(), Value::Object(text_obj))?;
  let document_obj = node_wrapper_document_obj(scope, text_obj, node_key.node_id)?;

  // WebIDL `unsigned long` argument.
  let offset_value = args.get(0).copied().unwrap_or(Value::Undefined);
  let offset = webidl_to_uint32(vm, scope, host, hooks, offset_value)? as usize;

  let mut dom_ptr = if is_host_document_id(vm, node_key.document_id) {
    dom_ptr_for_event_registry(host).ok_or(VmError::TypeError("Illegal invocation"))?
  } else {
    dom_ptr_for_document_id_mut(vm, host, node_key.document_id).ok_or(VmError::TypeError("Illegal invocation"))?
  };

  let (new_text_id, parent_id, maybe_script_parent) = if is_host_document_id(vm, node_key.document_id)
  {
    mutate_dom_for_vm_host(host, |dom| {
      let parent_id = dom.parent_node(node_key.node_id);
      match dom.split_text(node_key.node_id, offset) {
        Ok(new_text_id) => {
          let maybe_script_parent =
            parent_id.filter(|&parent| is_html_script_element(dom, parent));
          (Ok((new_text_id, parent_id, maybe_script_parent)), parent_id.is_some())
        }
        Err(err) => {
          let exc = match make_dom_exception(vm, scope, err.code(), "") {
            Ok(v) => VmError::Throw(v),
            Err(e) => e,
          };
          (Err(exc), false)
        }
      }
    })
    .ok_or(VmError::TypeError("Illegal invocation"))??
  } else {
    // SAFETY: `dom_ptr` is valid for the duration of this native call.
    let dom = unsafe { dom_ptr.as_mut() };
    let parent_id = dom.parent_node(node_key.node_id);
    let new_text_id = match dom.split_text(node_key.node_id, offset) {
      Ok(id) => id,
      Err(err) => return Err(VmError::Throw(make_dom_exception(vm, scope, err.code(), "")?)),
    };
    (new_text_id, parent_id, None)
  };

  // SAFETY: `dom_ptr` is valid for the duration of this native call.
  let dom = unsafe { dom_ptr.as_ref() };

  // Keep cached `childNodes` / `children` live lists updated for the parent.
  if let Some(parent_id) = parent_id {
    sync_cached_child_nodes_for_node_id(vm, scope, document_obj, dom, parent_id)?;
    sync_cached_children_for_node_id(vm, scope, document_obj, dom, parent_id)?;
    sync_cached_select_options_for_select_ancestor(vm, scope, document_obj, dom, parent_id)?;
  }

  if let Some(script_parent) = maybe_script_parent {
    run_dynamic_script_children_changed_steps(
      vm,
      scope,
      host,
      hooks,
      document_obj,
      dom_ptr,
      script_parent,
    )?;
  }

  let needs_microtask = unsafe { dom_ptr.as_mut() }.take_mutation_observer_microtask_needed();
  maybe_queue_mutation_observer_microtask(vm, scope, host, hooks, document_obj, needs_microtask)?;

  get_or_create_node_wrapper(vm, scope, document_obj, Some(dom), new_text_id)
}

fn comment_data_get_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(comment_obj) = this else {
    return Err(VmError::TypeError("Illegal invocation"));
  };

  let comment_id = dom_platform_mut(vm)
    .ok_or(VmError::TypeError("Illegal invocation"))?
    .require_comment_id(scope.heap(), Value::Object(comment_obj))?;
  let dom = dom_from_vm_host(host).ok_or(VmError::TypeError("Illegal invocation"))?;

  let data = dom
    .comment_data(comment_id)
    .map_err(|_| VmError::TypeError("Illegal invocation"))?;
  Ok(Value::String(scope.alloc_string(data)?))
}

fn comment_data_set_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(comment_obj) = this else {
    return Err(VmError::TypeError("Illegal invocation"));
  };

  let Some(document_obj) = vm
    .user_data::<WindowRealmUserData>()
    .and_then(|data| data.document_obj)
  else {
    return Ok(Value::Undefined);
  };

  let comment_id = dom_platform_mut(vm)
    .ok_or(VmError::TypeError("Illegal invocation"))?
    .require_comment_id(scope.heap(), Value::Object(comment_obj))?;

  let new_value = args.get(0).copied().unwrap_or(Value::Undefined);
  let new_value = scope.heap_mut().to_string(new_value)?;
  let new_value = scope
    .heap()
    .get_string(new_value)
    .map(|s| s.to_utf8_lossy())
    .unwrap_or_default();

  // Comments are ignored by renderer DOM snapshots. Also, `dom2::Document::set_comment_data` does
  // not currently emit structured mutation logs (it only queues MutationObserver records).
  //
  // Reporting `changed=true` to `BrowserDocumentDom2` would therefore trigger the conservative
  // fallback path ("changed but no mutation log" => full invalidation). Avoid that by reporting
  // `changed=false` to the host invalidation layer.
  let needs_microtask =
    mutate_dom_for_vm_host(host, |dom| match dom.set_comment_data(comment_id, &new_value) {
      Ok(_changed) => {
        let needs = dom.take_mutation_observer_microtask_needed();
        (Ok(needs), false)
      }
    Err(err) => {
      let exc = match make_dom_exception(vm, scope, err.code(), "") {
        Ok(v) => VmError::Throw(v),
        Err(e) => e,
      };
      (Err(exc), false)
    }
    })
    .ok_or(VmError::TypeError("Illegal invocation"))??;

  maybe_queue_mutation_observer_microtask(vm, scope, host, hooks, document_obj, needs_microtask)?;
  Ok(Value::Undefined)
}

