fn element_scroll_parent_get_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(wrapper_obj) = this else {
    return Ok(Value::Null);
  };

  let document_obj_key = alloc_key(scope, WRAPPER_DOCUMENT_KEY)?;
  let document_obj = match scope
    .heap()
    .object_get_own_data_property_value(wrapper_obj, &document_obj_key)?
  {
    Some(Value::Object(obj)) => obj,
    _ => return Ok(Value::Null),
  };

  let node_id_key = alloc_key(scope, NODE_ID_KEY)?;
  let node_index = match scope
    .heap()
    .object_get_own_data_property_value(wrapper_obj, &node_id_key)?
  {
    Some(Value::Number(n)) if n.is_finite() && n >= 0.0 => n as usize,
    _ => return Ok(Value::Null),
  };

  let Some(document) = host.as_any_mut().downcast_mut::<BrowserDocumentDom2>() else {
    return Ok(Value::Null);
  };

  let node_id = match document.dom().node_id_from_index(node_index) {
    Ok(id) => id,
    Err(_) => return Ok(Value::Null),
  };

  let Some(scroll_parent) = document.element_scroll_parent(node_id) else {
    return Ok(Value::Null);
  };

  get_or_create_node_wrapper(vm, scope, document_obj, Some(document.dom()), scroll_parent)
}

fn native_slot_string(scope: &Scope<'_>, callee: GcObject) -> Result<String, VmError> {
  let slots = scope.heap().get_function_native_slots(callee)?;
  let slot = slots.get(0).copied().unwrap_or(Value::Undefined);
  let Value::String(s) = slot else {
    return Err(VmError::InvariantViolation(
      "expected native slot string argument",
    ));
  };
  Ok(scope.heap().get_string(s)?.to_utf8_lossy())
}

fn dom_node_id_from_obj(
  scope: &mut Scope<'_>,
  dom: &dom2::Document,
  obj: GcObject,
) -> Result<Option<NodeId>, VmError> {
  let node_id_key = alloc_key(scope, NODE_ID_KEY)?;
  let node_index = match scope
    .heap()
    .object_get_own_data_property_value(obj, &node_id_key)?
  {
    Some(Value::Number(n)) if n.is_finite() && n >= 0.0 => n as usize,
    _ => return Ok(None),
  };

  let node_id = match dom.node_id_from_index(node_index) {
    Ok(id) => id,
    Err(_) => return Ok(None),
  };

  Ok(Some(node_id))
}

fn element_reflected_string_get_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  callee: GcObject,
  this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(obj) = this else {
    return Ok(Value::Undefined);
  };

  let attr = native_slot_string(scope, callee)?;
  let Some(handle) = element_handle_from_wrapper_obj_opt(vm, scope, obj) else {
    return Ok(Value::Undefined);
  };
  let Some(dom_ptr) = dom_ptr_for_document_id_read(vm, host, handle.document_id) else {
    return Ok(Value::Undefined);
  };
  // SAFETY: `dom_ptr` is valid for the duration of this native call.
  let dom = unsafe { dom_ptr.as_ref() };
  let value = dom
    .get_attribute(handle.node_id, &attr)
    .ok()
    .flatten()
    .unwrap_or("");
  Ok(Value::String(scope.alloc_string(value)?))
}

fn html_media_element_can_play_type_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(obj) = this else {
    return Err(VmError::TypeError(ILLEGAL_INVOCATION_ERROR));
  };
  let platform =
    dom_platform_mut(vm).ok_or(VmError::TypeError(ILLEGAL_INVOCATION_ERROR))?;
  let _ = platform.require_html_media_element_handle(scope.heap(), Value::Object(obj))?;

  let type_value = args.get(0).copied().unwrap_or(Value::Undefined);
  let type_s = match type_value {
    Value::String(s) => s,
    other => scope.heap_mut().to_string(other)?,
  };
  let type_str = scope
    .heap()
    .get_string(type_s)
    .map(|s| s.to_utf8_lossy())
    .unwrap_or_default();

  let result = crate::html::media::can_play_type(&type_str);
  Ok(Value::String(scope.alloc_string(result.as_str())?))
}

fn element_reflected_string_set_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(obj) = this else {
    return Ok(Value::Undefined);
  };

  let Some(handle) = element_handle_from_wrapper_obj_opt(vm, scope, obj) else {
    return Ok(Value::Undefined);
  };

  let attr = native_slot_string(scope, callee)?;
  if !is_host_document_id(vm, handle.document_id) {
    let Some(mut dom_ptr) = dom_ptr_for_document_id_mut(vm, host, handle.document_id) else {
      return Ok(Value::Undefined);
    };
    // SAFETY: `dom_ptr` points at the `dom2::Document` backing this element, and we have exclusive
    // access for the duration of this native call.
    let dom = unsafe { dom_ptr.as_mut() };
    let new_value = args.get(0).copied().unwrap_or(Value::Undefined);
    let new_value = scope.heap_mut().to_string(new_value)?;
    let new_value = scope
      .heap()
      .get_string(new_value)
      .map(|s| s.to_utf8_lossy())
      .unwrap_or_default();

    if let Err(err) = dom.set_attribute(handle.node_id, &attr, &new_value) {
      return Err(VmError::Throw(make_dom_exception(vm, scope, err.code(), "")?));
    }
    // Owned documents: skip dynamic script steps + MutationObserver microtask scheduling.
    let _ = dom.take_mutation_observer_microtask_needed();
    return Ok(Value::Undefined);
  }

  let Some(mut dom_ptr) = dom_ptr_for_document_id_mut(vm, host, handle.document_id) else {
    return Ok(Value::Undefined);
  };

  let new_value = args.get(0).copied().unwrap_or(Value::Undefined);
  let new_value = scope.heap_mut().to_string(new_value)?;
  let new_value = scope
    .heap()
    .get_string(new_value)
    .map(|s| s.to_utf8_lossy())
    .unwrap_or_default();

  if let Err(err) = unsafe { dom_ptr.as_mut() }.set_attribute(handle.node_id, &attr, &new_value) {
    return Err(VmError::Throw(make_dom_exception(vm, scope, err.code(), "")?));
  }
  let should_run_src_attribute_changed_steps =
    attr.eq_ignore_ascii_case("src") && is_html_script_element(unsafe { dom_ptr.as_ref() }, handle.node_id);

  if should_run_src_attribute_changed_steps {
    run_dynamic_script_src_attribute_changed_steps(
      vm,
      scope,
      host,
      hooks,
      handle.document_obj,
      dom_ptr,
      handle.node_id,
    )?;
  }
  let needs_microtask = unsafe { dom_ptr.as_mut() }.take_mutation_observer_microtask_needed();
  maybe_queue_mutation_observer_microtask(
    vm,
    scope,
    host,
    hooks,
    handle.document_obj,
    needs_microtask,
  )?;

  Ok(Value::Undefined)
}

fn element_reflected_bool_get_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  callee: GcObject,
  this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(obj) = this else {
    return Ok(Value::Undefined);
  };

  let attr = native_slot_string(scope, callee)?;
  let Some(handle) = element_handle_from_wrapper_obj_opt(vm, scope, obj) else {
    return Ok(Value::Undefined);
  };
  let Some(dom_ptr) = dom_ptr_for_document_id_read(vm, host, handle.document_id) else {
    return Ok(Value::Undefined);
  };
  // SAFETY: `dom_ptr` is valid for the duration of this native call.
  let dom = unsafe { dom_ptr.as_ref() };
  if attr == "async" && is_html_script_element(dom, handle.node_id) {
    let force_async = dom.node(handle.node_id).script_force_async;
    let async_attr = dom.has_attribute(handle.node_id, "async").unwrap_or(false);
    return Ok(Value::Bool(force_async || async_attr));
  }
  Ok(Value::Bool(
    dom.has_attribute(handle.node_id, &attr).unwrap_or(false),
  ))
}

fn element_reflected_bool_set_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(obj) = this else {
    return Ok(Value::Undefined);
  };

  let Some(handle) = element_handle_from_wrapper_obj_opt(vm, scope, obj) else {
    return Ok(Value::Undefined);
  };

  let attr = native_slot_string(scope, callee)?;
  let Some(mut dom_ptr) = dom_ptr_for_document_id_mut(vm, host, handle.document_id) else {
    return Ok(Value::Undefined);
  };
  // SAFETY: `dom_ptr` points at the `dom2::Document` backing this element, and we have exclusive
  // access for the duration of this native call.
  let dom = unsafe { dom_ptr.as_mut() };

  let present_value = args.get(0).copied().unwrap_or(Value::Undefined);
  let present = scope.heap().to_boolean(present_value)?;

  if attr == "async" && is_html_script_element(dom, handle.node_id) {
    // HTMLScriptElement.async setter:
    // - If value is true: ensure the `async` content attribute is present.
    // - If value is false: set the element's "force async" flag to false and remove the `async`
    //   content attribute.
    //
    // Note: adding the `async` content attribute clears the "force async" flag via dom2's attribute
    // mutation hooks, so we only need to explicitly clear it for the `false` path here.
    if !present {
      if let Err(err) = dom.set_script_force_async(handle.node_id, false) {
        return Err(VmError::Throw(make_dom_exception(vm, scope, err.code(), "")?));
      }
    }
    if let Err(err) = dom.set_bool_attribute(handle.node_id, "async", present) {
      return Err(VmError::Throw(make_dom_exception(vm, scope, err.code(), "")?));
    }
    return Ok(Value::Undefined);
  }
  if let Err(err) = dom.set_bool_attribute(handle.node_id, &attr, present) {
    return Err(VmError::Throw(make_dom_exception(vm, scope, err.code(), "")?));
  }

  if !is_host_document_id(vm, handle.document_id) {
    // Owned documents: skip MutationObserver microtask scheduling.
    let _ = dom.take_mutation_observer_microtask_needed();
    return Ok(Value::Undefined);
  }
  let needs_microtask = dom.take_mutation_observer_microtask_needed();
  maybe_queue_mutation_observer_microtask(vm, scope, host, hooks, handle.document_obj, needs_microtask)?;

  Ok(Value::Undefined)
}

fn html_media_element_current_src_get_native(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  let Value::Object(obj) = this else {
    return Ok(Value::Undefined);
  };

  let Some(handle) = element_handle_from_wrapper_obj_opt(vm, scope, obj) else {
    return Ok(Value::Undefined);
  };
  let Some(dom_ptr) = dom_ptr_for_document_id_read(vm, host, handle.document_id) else {
    return Ok(Value::Undefined);
  };
  // SAFETY: `dom_ptr` is valid for the duration of this native call.
  let dom = unsafe { dom_ptr.as_ref() };

  // Identify the media element type so we can prefer matching <source type="video/*"> or
  // <source type="audio/*"> candidates.
  let preferred_prefix = match &dom.node(handle.node_id).kind {
    NodeKind::Element {
      tag_name,
      namespace,
      ..
    } if (namespace.is_empty() || namespace == crate::dom::HTML_NAMESPACE)
      && tag_name.eq_ignore_ascii_case("video") =>
    {
      "video/"
    }
    NodeKind::Element {
      tag_name,
      namespace,
      ..
    } if (namespace.is_empty() || namespace == crate::dom::HTML_NAMESPACE)
      && tag_name.eq_ignore_ascii_case("audio") =>
    {
      "audio/"
    }
    _ => {
      // Should be unreachable: wrappers only install `currentSrc` on <video>/<audio>, but keep
      // the getter total and side-effect free.
      return Ok(Value::String(scope.alloc_string("")?));
    }
  };

  fn src_is_unusable(candidate: &str) -> bool {
    let trimmed = crate::js::trim_ascii_whitespace(candidate);
    if trimmed.is_empty() || trimmed.starts_with('#') {
      return true;
    }
    const ABOUT_BLANK: &str = "about:blank";
    if trimmed
      .get(..ABOUT_BLANK.len())
      .is_some_and(|head| head.eq_ignore_ascii_case(ABOUT_BLANK))
    {
      return matches!(
        trimmed.as_bytes().get(ABOUT_BLANK.len()),
        None | Some(b'#') | Some(b'?')
      );
    }
    false
  }

  fn src_from_source_children(
    dom: &dom2::Document,
    element: NodeId,
    preferred_prefix: &str,
  ) -> Option<String> {
    let mut first_any: Option<String> = None;
    for &child in &dom.node(element).children {
      let NodeKind::Element {
        tag_name,
        namespace,
        ..
      } = &dom.node(child).kind
      else {
        continue;
      };
      let is_html = namespace.is_empty() || namespace == crate::dom::HTML_NAMESPACE;
      if !is_html || !tag_name.eq_ignore_ascii_case("source") {
        continue;
      }

      let Some(src_attr) = dom.get_attribute(child, "src").ok().flatten() else {
        continue;
      };
      let src_trimmed = crate::js::trim_ascii_whitespace(src_attr);
      if src_trimmed.is_empty() {
        continue;
      }

      if first_any.is_none() {
        first_any = Some(src_trimmed.to_string());
      }

      if let Some(type_attr) = dom.get_attribute(child, "type").ok().flatten() {
        let type_trimmed = crate::js::trim_ascii_whitespace(type_attr);
        if type_trimmed
          .get(..preferred_prefix.len())
          .is_some_and(|prefix| prefix.eq_ignore_ascii_case(preferred_prefix))
        {
          return Some(src_trimmed.to_string());
        }
      }
    }
    first_any
  }

  let candidate = {
    let src = dom
      .get_attribute(handle.node_id, "src")
      .ok()
      .flatten()
      .map(crate::js::trim_ascii_whitespace)
      .unwrap_or("");
    if !src_is_unusable(src) {
      src.to_string()
    } else {
      src_from_source_children(dom, handle.node_id, preferred_prefix).unwrap_or_default()
    }
  };

  // Post-process the chosen candidate: trim and apply the same unusable checks browsers use for
  // `currentSrc` (empty / fragment-only / about:blank).
  let candidate = crate::js::trim_ascii_whitespace(&candidate);
  if src_is_unusable(candidate) {
    return Ok(Value::String(scope.alloc_string("")?));
  }

  let base_url = vm.user_data::<WindowRealmUserData>().map(|data| {
    data
      .base_url
      .as_deref()
      .unwrap_or_else(|| data.document_url.as_str())
  });

  let resolved = match crate::js::url_resolve::resolve_url(candidate, base_url) {
    Ok(url) => url,
    Err(_) => String::new(),
  };

  Ok(Value::String(scope.alloc_string(&resolved)?))
}

