  #[test]
  fn media_element_state_registry_sweeps_on_gc() -> Result<(), VmError> {
    let mut realm = WindowRealm::new(WindowRealmConfig::new("https://example.com/"))?;
    let (vm, _realm_ref, heap) = realm.vm_realm_and_heap_mut();

    let document_obj = vm
      .user_data::<WindowRealmUserData>()
      .and_then(|data| data.document_obj())
      .expect("expected cached document object");

    let document_id = {
      let data = vm
        .user_data_mut::<WindowRealmUserData>()
        .expect("expected WindowRealmUserData");
      let platform = data
        .dom_platform
        .as_mut()
        .expect("expected dom platform to be installed");
      platform
        .require_document_handle(heap, Value::Object(document_obj))?
        .document_id
    };

    let mut host = DocumentHostState::new(dom2::Document::new(QuirksMode::NoQuirks));

    const PER_CYCLE: usize = 128;
    for _cycle in 0..2 {
      let base_len = vm
        .user_data::<WindowRealmUserData>()
        .expect("expected WindowRealmUserData")
        .media_element_state_registry_len();
      let mut roots: Vec<RootId> = Vec::with_capacity(PER_CYCLE);
      {
        let data = vm
          .user_data_mut::<WindowRealmUserData>()
          .expect("expected WindowRealmUserData");
        let platform = data
          .dom_platform
          .as_mut()
          .expect("expected dom platform to be installed");
        let registry = &mut data.media_element_state_registry;

        let mut scope = heap.scope();
        for _ in 0..PER_CYCLE {
          let node_id = host
            .dom_mut()
            .create_element("video", crate::dom::HTML_NAMESPACE);
          let wrapper = platform.get_or_create_wrapper_for_document_id(
            &mut scope,
            document_id,
            node_id,
            DomInterface::HTMLElement,
          )?;
          roots.push(scope.heap_mut().add_root(Value::Object(wrapper))?);
          registry.get_or_create(DomNodeKey::new(document_id, node_id));
        }
      }

      let after_insert = vm
        .user_data::<WindowRealmUserData>()
        .expect("expected WindowRealmUserData")
        .media_element_state_registry_len();
      assert_eq!(after_insert, base_len + PER_CYCLE);

      for root in roots {
        heap.remove_root(root);
      }
      let prev_gc_runs = heap.gc_runs();
      heap.collect_garbage();
      assert!(
        heap.gc_runs() > prev_gc_runs,
        "expected explicit GC to increment gc run counter"
      );

      let data = vm
        .user_data_mut::<WindowRealmUserData>()
        .expect("expected WindowRealmUserData");
      data.sweep_media_element_state_registry_if_needed(heap, &mut host);
      let after_sweep = data.media_element_state_registry_len();
      assert!(after_sweep < after_insert);
      assert!(after_sweep <= base_len);
    }
    Ok(())
  }

  #[test]
  fn webidl_backend_installs_collection_interface_bindings() -> Result<(), VmError> {
    let mut realm = new_realm(
      WindowRealmConfig::new("https://example.com/")
        .with_dom_bindings_backend(DomBindingsBackend::WebIdl),
    )?;
    let ok = realm.exec_script(
      r#"(() => {
        if (typeof NodeList !== 'function') return false;
        if (typeof HTMLCollection !== 'function') return false;
        if (typeof DOMTokenList !== 'function') return false;
        if (typeof NodeList.prototype.item !== 'function') return false;
        if (typeof HTMLCollection.prototype.item !== 'function') return false;
        if (typeof DOMTokenList.prototype.item !== 'function') return false;
        return true;
      })()"#,
    )?;
    assert_eq!(ok, Value::Bool(true));
    Ok(())
  }

  #[test]
  fn range_detach_is_legacy_noop() -> Result<(), VmError> {
    let mut host = new_host_document_state();
    let mut realm = new_realm(WindowRealmConfig::new("https://example.com/"))?;
    let ok = exec_script_with_dom_host(
      &mut realm,
      &mut host,
      r#"(() => {
        const range = document.createRange();
        const before = [
          range.startContainer.nodeType,
          range.startOffset,
          range.endContainer.nodeType,
          range.endOffset,
          range.collapsed,
        ];
        const ret = range.detach();
        const after = [
          range.startContainer.nodeType,
          range.startOffset,
          range.endContainer.nodeType,
          range.endOffset,
          range.collapsed,
        ];
        if (ret !== undefined) return false;
        for (let i = 0; i < before.length; i++) {
          if (before[i] !== after[i]) return false;
        }
        return true;
      })()"#,
    )?;
    assert_eq!(ok, Value::Bool(true));
    Ok(())
  }

  #[test]
  fn traversal_interface_objects_exist_and_are_illegal_constructors() -> Result<(), VmError> {
    let mut realm = new_realm(WindowRealmConfig::new("https://example.com/"))?;
    let result = realm.exec_script(
      r#"(() => {
        function check(name) {
          const ctor = globalThis[name];
          if (typeof ctor !== 'function') return name + ':typeof';
          if (!ctor.prototype || typeof ctor.prototype !== 'object') return name + ':prototype';
          if (ctor.prototype.constructor !== ctor) return name + ':ctorlink';
          if (!(Object.create(ctor.prototype) instanceof ctor)) return name + ':instanceof';

          let ok = false;
          try { ctor(); } catch (e) {
            ok = e && e.name === 'TypeError' && String(e.message).includes('Illegal constructor');
          }
          if (!ok) return name + ':call';

          ok = false;
          try { new ctor(); } catch (e) {
            ok = e && e.name === 'TypeError' && String(e.message).includes('Illegal constructor');
          }
          if (!ok) return name + ':new';
          return null;
        }
        return check('NodeIterator') || check('TreeWalker') || 'ok';
      })()"#,
    )?;
    assert_eq!(get_string(realm.heap(), result), "ok");
    Ok(())
  }

