  #[test]
  fn realm_document_registry_sweeps_after_gc() -> Result<(), VmError> {
    let mut window = new_realm(WindowRealmConfig::new("https://example.com/"))?;
    let mut host = VmJsHostContext::default();
    let (vm, _realm, heap) = window.vm_realm_and_heap_mut();

    let extra_doc_obj = {
      let mut scope = heap.scope();
      let extra_doc_obj = scope.alloc_object()?;
      scope.push_root(Value::Object(extra_doc_obj))?;

      vm
        .user_data_mut::<WindowRealmUserData>()
        .expect("missing WindowRealmUserData")
        .register_realm_document(extra_doc_obj, dom2::Document::new(QuirksMode::NoQuirks));

      assert_eq!(
        vm.user_data_mut::<WindowRealmUserData>()
          .expect("missing WindowRealmUserData")
          .realm_document_registry
          .documents
          .len(),
        1
      );

      let (_dom_ptr, is_fallback) =
        resolve_document_dom_ptr_for_events(vm, &mut scope, &mut host, extra_doc_obj)?;
      assert!(!is_fallback);

      extra_doc_obj
    };

    heap.collect_garbage();
    assert!(!heap.is_valid_object(extra_doc_obj));

    assert_eq!(
      vm.user_data_mut::<WindowRealmUserData>()
        .expect("missing WindowRealmUserData")
        .realm_document_registry
        .documents
        .len(),
      1
    );

    let err = {
      let mut scope = heap.scope();
      resolve_document_dom_ptr_for_events(vm, &mut scope, &mut host, extra_doc_obj).unwrap_err()
    };
    assert!(matches!(err, VmError::TypeError("Illegal invocation")));

    assert_eq!(
      vm.user_data_mut::<WindowRealmUserData>()
        .expect("missing WindowRealmUserData")
        .realm_document_registry
        .documents
        .len(),
      0
    );

    Ok(())
  }

  #[test]
  fn html_element_global_attributes_reflect_and_brand_check() -> Result<(), VmError> {
    use crate::api::RenderOptions;

    let mut document = BrowserDocumentDom2::from_html(
      "<!doctype html><html><head></head><body></body></html>",
      RenderOptions::default(),
    )
    .expect("BrowserDocumentDom2::from_html should succeed");

    let mut realm = new_realm(WindowRealmConfig::new("https://example.com/"))?;
    let value = exec_script_with_dom_host(
      &mut realm,
      &mut document,
      "(() => {\n\
         const el = document.createElement('div');\n\
         el.title = 'x';\n\
         if (el.getAttribute('title') !== 'x') return false;\n\
         el.lang = 'en';\n\
         if (el.getAttribute('lang') !== 'en') return false;\n\
         el.dir = 'rtl';\n\
         if (el.getAttribute('dir') !== 'rtl') return false;\n\
         el.hidden = true;\n\
         if (!el.hasAttribute('hidden')) return false;\n\
         el.hidden = false;\n\
         if (el.hasAttribute('hidden')) return false;\n\
\n\
         const desc = Object.getOwnPropertyDescriptor(HTMLElement.prototype, 'title');\n\
         if (!desc || typeof desc.get !== 'function') return false;\n\
         try {\n\
           desc.get.call(document);\n\
           return false;\n\
         } catch (e) {\n\
           if (!(e instanceof TypeError)) return false;\n\
           if (e.message !== 'Illegal invocation') return false;\n\
         }\n\
         return true;\n\
      })()",
    )?;
    assert_eq!(value, Value::Bool(true));
    Ok(())
  }

  #[test]
  fn html_element_instanceof_uses_dom_platform_prototypes() -> Result<(), VmError> {
    use crate::api::RenderOptions;

    let mut document = BrowserDocumentDom2::from_html(
      "<!doctype html><html><body>\n\
        <input id=\"i\">\n\
        <div id=\"d\"></div>\n\
        <video id=\"v\"></video>\n\
        <audio id=\"a\"></audio>\n\
        <svg id=\"s\"></svg>\n\
      </body></html>",
      RenderOptions::default(),
    )
    .expect("document");

    let mut realm = new_realm(WindowRealmConfig::new("https://example.com/"))?;
    let value = exec_script_with_dom_host(
      &mut realm,
      &mut document,
      "(() => {\n\
        const input = document.getElementById('i');\n\
        const div = document.getElementById('d');\n\
        const video = document.getElementById('v');\n\
        const audio = document.getElementById('a');\n\
        const svg = document.getElementById('s');\n\
\n\
        if (typeof HTMLElement !== 'function') return false;\n\
        if (typeof HTMLMediaElement !== 'function') return false;\n\
        if (typeof HTMLVideoElement !== 'function') return false;\n\
        if (typeof HTMLAudioElement !== 'function') return false;\n\
        if (typeof HTMLInputElement !== 'function') return false;\n\
        if (typeof HTMLDivElement !== 'function') return false;\n\
\n\
        if (!(input instanceof HTMLInputElement)) return false;\n\
        if (!(input instanceof HTMLElement)) return false;\n\
        if (!(div instanceof HTMLDivElement)) return false;\n\
        if (!(div instanceof HTMLElement)) return false;\n\
        if (!(video instanceof HTMLVideoElement)) return false;\n\
        if (!(video instanceof HTMLMediaElement)) return false;\n\
        if (!(video instanceof HTMLElement)) return false;\n\
        if (!(audio instanceof HTMLAudioElement)) return false;\n\
        if (!(audio instanceof HTMLMediaElement)) return false;\n\
        if (!(audio instanceof HTMLElement)) return false;\n\
        if (svg instanceof HTMLElement) return false;\n\
        if (!(svg instanceof Element)) return false;\n\
\n\
        if (HTMLElement.prototype === Element.prototype) return false;\n\
        if (Object.getPrototypeOf(HTMLElement.prototype) !== Element.prototype) return false;\n\
        if (Object.getPrototypeOf(HTMLMediaElement.prototype) !== HTMLElement.prototype) return false;\n\
        if (Object.getPrototypeOf(HTMLVideoElement.prototype) !== HTMLMediaElement.prototype) return false;\n\
        if (Object.getPrototypeOf(HTMLAudioElement.prototype) !== HTMLMediaElement.prototype) return false;\n\
        if (Object.getPrototypeOf(HTMLInputElement.prototype) !== HTMLElement.prototype) return false;\n\
\n\
        if (Object.getPrototypeOf(HTMLMediaElement) !== HTMLElement) return false;\n\
        if (Object.getPrototypeOf(HTMLVideoElement) !== HTMLMediaElement) return false;\n\
        if (Object.getPrototypeOf(HTMLAudioElement) !== HTMLMediaElement) return false;\n\
        return true;\n\
      })()",
    )?;
    assert_eq!(value, Value::Bool(true));
    Ok(())
  }

