  fn check_hooks_payload_native(
    _vm: &mut Vm,
    _scope: &mut Scope<'_>,
    _host: &mut dyn VmHost,
    hooks: &mut dyn VmHostHooks,
    _callee: GcObject,
    _this: Value,
    _args: &[Value],
  ) -> Result<Value, VmError> {
    let Some(any) = hooks.as_any_mut() else {
      return Err(VmError::TypeError("VmHostHooks::as_any_mut returned None"));
    };
    let Some(payload) = any.downcast_mut::<VmJsHostHooksPayload>() else {
      return Err(VmError::TypeError(
        "VmHostHooks::as_any_mut did not downcast to VmJsHostHooksPayload",
      ));
    };
    if payload.vm_host_mut().is_none() {
      return Err(VmError::TypeError(
        "VmJsHostHooksPayload did not contain a VmHost pointer",
      ));
    }
    Ok(Value::Undefined)
  }

  #[test]
  fn exec_script_with_name_exposes_vmjs_host_hooks_payload() -> Result<(), VmError> {
    let mut window = new_realm(WindowRealmConfig::new("https://example.com/"))?;

    {
      let (vm, realm, heap) = window.vm_realm_and_heap_mut();
      let mut scope = heap.scope();
      let global = realm.global_object();
      scope.push_root(Value::Object(global))?;

      let call_id = vm.register_native_call(check_hooks_payload_native)?;
      let name_s = scope.alloc_string("__check_hooks_payload")?;
      scope.push_root(Value::String(name_s))?;
      let func = scope.alloc_native_function(call_id, None, name_s, 0)?;
      scope.push_root(Value::Object(func))?;

      let key = alloc_key(&mut scope, "__check_hooks_payload")?;
      scope.define_property(global, key, data_desc(Value::Object(func)))?;
    }

    window.exec_script("__check_hooks_payload()")?;
    Ok(())
  }

  #[test]
  fn window_realm_standalone_exec_script_supports_webidl_event_target() -> Result<(), VmError> {
    let mut realm = new_realm(WindowRealmConfig::new("https://example.com/"))?;

    // Remove the handcrafted EventTarget binding so the WebIDL-generated installer defines it.
    realm.exec_script("delete globalThis.EventTarget;")?;
    {
      let (vm, realm_ref, heap) = realm.vm_realm_and_heap_mut();
      crate::js::bindings::install_event_target_bindings_vm_js(vm, heap, realm_ref)?;
    }

    let ran = realm.exec_script(
      r#"
        globalThis.__ran = 0;
        const t = new EventTarget();
        t.addEventListener('x', () => { globalThis.__ran += 1; });
        t.dispatchEvent(new Event('x'));
        globalThis.__ran;
      "#,
    )?;
    assert_eq!(ran, Value::Number(1.0));

    // FastRender-only extension: `new EventTarget(parent)` wires an explicit parent chain for
    // capture/bubble semantics.
    let order = realm.exec_script(
      r#"
        (() => {
          const parent = new EventTarget();
          const child = new EventTarget(parent);
          let log = '';
          parent.addEventListener('x', (e) => { log += 'c' + e.eventPhase; }, { capture: true });
          child.addEventListener('x', (e) => { log += 't' + e.eventPhase; });
          parent.addEventListener('x', (e) => { log += 'b' + e.eventPhase; });
          child.dispatchEvent({ type: 'x', bubbles: true });
          return log;
        })()
      "#,
    )?;
    assert_eq!(get_string(realm.heap(), order), "c1t2b3");

    // Brand-check: borrowing the prototype method onto a non-EventTarget should throw.
    assert!(realm
      .exec_script("EventTarget.prototype.addEventListener.call({}, 'x', () => {});")
      .is_err());

    Ok(())
  }

  #[test]
  fn webidl_dispatch_event_clears_cancel_bubble_after_dispatch() -> Result<(), VmError> {
    let mut realm = new_realm(WindowRealmConfig::new("https://example.com/"))?;

    // Remove the handcrafted EventTarget binding so the WebIDL-generated installer defines it.
    realm.exec_script("delete globalThis.EventTarget;")?;
    {
      let (vm, realm_ref, heap) = realm.vm_realm_and_heap_mut();
      crate::js::bindings::install_event_target_bindings_vm_js(vm, heap, realm_ref)?;
    }

    let ok = realm.exec_script(
      "(() => {\n\
        const et = new EventTarget();\n\
        const ev = new Event('x', { bubbles: true });\n\
        let during = false;\n\
        et.addEventListener('x', e => { e.stopPropagation(); during = e.cancelBubble; });\n\
        et.dispatchEvent(ev);\n\
        return during === true && ev.cancelBubble === false;\n\
      })()",
    )?;
    assert_eq!(ok, Value::Bool(true));
    Ok(())
  }

  #[test]
  fn webidl_dispatch_event_clears_stop_immediate_propagation_after_dispatch() -> Result<(), VmError> {
    let mut realm = new_realm(WindowRealmConfig::new("https://example.com/"))?;

    // Remove the handcrafted EventTarget binding so the WebIDL-generated installer defines it.
    realm.exec_script("delete globalThis.EventTarget;")?;
    {
      let (vm, realm_ref, heap) = realm.vm_realm_and_heap_mut();
      crate::js::bindings::install_event_target_bindings_vm_js(vm, heap, realm_ref)?;
    }

    let ok = realm.exec_script(
      "(() => {\n\
        const et = new EventTarget();\n\
        const ev = new Event('x', { bubbles: true });\n\
        let during_cancel = false;\n\
        let during_immediate = false;\n\
        et.addEventListener('x', e => {\n\
          e.stopImmediatePropagation();\n\
          during_cancel = e.cancelBubble;\n\
          during_immediate = e.__fastrender_event_stop_immediate;\n\
        });\n\
        et.dispatchEvent(ev);\n\
        return during_cancel === true &&\n\
          during_immediate === true &&\n\
          ev.cancelBubble === false &&\n\
          ev.__fastrender_event_stop_immediate === false;\n\
      })()",
    )?;
    assert_eq!(ok, Value::Bool(true));
    Ok(())
  }

  #[test]
  fn window_realm_microtask_checkpoint_supports_webidl_event_target() -> Result<(), VmError> {
    let mut realm = new_realm(WindowRealmConfig::new("https://example.com/"))?;

    realm.exec_script("delete globalThis.EventTarget;")?;
    {
      let (vm, realm_ref, heap) = realm.vm_realm_and_heap_mut();
      crate::js::bindings::install_event_target_bindings_vm_js(vm, heap, realm_ref)?;
    }

    realm.exec_script(
      r#"
        globalThis.__ran = 0;
        Promise.resolve().then(() => {
          const t = new EventTarget();
          t.addEventListener('x', () => { globalThis.__ran = 1; });
          t.dispatchEvent(new Event('x'));
        });
      "#,
    )?;
    assert_eq!(realm.exec_script("globalThis.__ran")?, Value::Number(0.0));

    realm.perform_microtask_checkpoint()?;
    assert_eq!(realm.exec_script("globalThis.__ran")?, Value::Number(1.0));

    Ok(())
  }

  #[test]
  fn window_realm_perform_microtask_checkpoint_runs_promise_jobs() -> Result<(), VmError> {
    let mut realm = new_realm(WindowRealmConfig::new("https://example.com/"))?;

    // `WindowRealm` does not install the full HTML event loop / `queueMicrotask` bindings by
    // default, but Promise jobs still enqueue microtasks into the VM-owned microtask queue.
    realm
      .exec_script("globalThis.__x = 0; Promise.resolve().then(() => { globalThis.__x = 1; });")?;
    assert_eq!(realm.exec_script("globalThis.__x")?, Value::Number(0.0));

    realm.perform_microtask_checkpoint()?;
    assert_eq!(realm.exec_script("globalThis.__x")?, Value::Number(1.0));
    Ok(())
  }

  #[test]
  fn window_realm_perform_microtask_checkpoint_treats_oom_as_hard_stop() -> Result<(), VmError> {
    use std::sync::atomic::{AtomicUsize, Ordering};
    use std::sync::Arc;
    use vm_js::{Job, JobKind, VmJobContext, WeakGcObject};

    struct JobCtx<'a> {
      heap: &'a mut Heap,
    }

    impl VmJobContext for JobCtx<'_> {
      fn call(
        &mut self,
        _host: &mut dyn VmHostHooks,
        _callee: Value,
        _this: Value,
        _args: &[Value],
      ) -> Result<Value, VmError> {
        Err(VmError::Unimplemented("JobCtx::call"))
      }

      fn construct(
        &mut self,
        _host: &mut dyn VmHostHooks,
        _callee: Value,
        _args: &[Value],
        _new_target: Value,
      ) -> Result<Value, VmError> {
        Err(VmError::Unimplemented("JobCtx::construct"))
      }

      fn add_root(&mut self, value: Value) -> Result<RootId, VmError> {
        self.heap.add_root(value)
      }

      fn remove_root(&mut self, id: RootId) {
        self.heap.remove_root(id);
      }
    }

    let mut realm = new_realm(WindowRealmConfig::new("https://example.com/"))?;

    let job2_runs = Arc::new(AtomicUsize::new(0));
    let job3_runs = Arc::new(AtomicUsize::new(0));
    let job_after_runs = Arc::new(AtomicUsize::new(0));

    // Create a GC object that's kept alive by a persistent root owned by a queued job.
    let obj = {
      let mut scope = realm.runtime.heap.scope();
      scope.alloc_object()?
    };
    let weak = WeakGcObject::from(obj);

    let job2_runs_clone = Arc::clone(&job2_runs);
    let mut job2 = Job::new(JobKind::Promise, move |_ctx, _hooks| {
      job2_runs_clone.fetch_add(1, Ordering::Relaxed);
      Ok(())
    })?;
    {
      let mut ctx = JobCtx {
        heap: &mut realm.runtime.heap,
      };
      job2.add_root(&mut ctx, Value::Object(obj))?;
    }

    let job3_runs_clone = Arc::clone(&job3_runs);
    let job3 = Job::new(JobKind::Promise, move |_ctx, _hooks| {
      job3_runs_clone.fetch_add(1, Ordering::Relaxed);
      Ok(())
    })?;

    let job_after_runs_clone = Arc::clone(&job_after_runs);
    let job_after = Job::new(JobKind::Promise, move |_ctx, _hooks| {
      job_after_runs_clone.fetch_add(1, Ordering::Relaxed);
      Ok(())
    })?;

    // The rooted job should keep the object alive.
    realm.runtime.heap.collect_garbage();
    assert_eq!(weak.upgrade(&realm.runtime.heap), Some(obj));

    // First job: enqueue additional jobs and then OOM. OOM should be treated as a hard stop and
    // trigger teardown of the remaining queue (including the jobs enqueued by this failing job).
    let oom_job = Job::new(JobKind::Promise, move |_ctx, hooks| {
      hooks.host_enqueue_promise_job(job2, None);
      hooks.host_enqueue_promise_job(job3, None);
      Err(VmError::OutOfMemory)
    })?;

    let realm_id = realm.realm_id;
    realm
      .runtime
      .vm
      .microtask_queue_mut()
      .enqueue_promise_job(oom_job, Some(realm_id));
    // Also enqueue a job behind the failing one to ensure we stop draining immediately.
    realm
      .runtime
      .vm
      .microtask_queue_mut()
      .enqueue_promise_job(job_after, Some(realm_id));

    let err = realm.perform_microtask_checkpoint().unwrap_err();
    assert!(
      matches!(err, VmError::OutOfMemory),
      "expected OOM hard stop, got {err:?}"
    );

    assert_eq!(job2_runs.load(Ordering::Relaxed), 0);
    assert_eq!(job3_runs.load(Ordering::Relaxed), 0);
    assert_eq!(job_after_runs.load(Ordering::Relaxed), 0);
    assert!(
      realm.runtime.vm.microtask_queue_mut().is_empty(),
      "expected microtask queue to be torn down on OOM"
    );

    // The teardown must remove persistent roots held by abandoned jobs.
    realm.runtime.heap.collect_garbage();
    assert_eq!(weak.upgrade(&realm.runtime.heap), None);

    // The checkpoint reentrancy flag should be reset even on hard-stop errors.
    assert!(realm.runtime.vm.microtask_queue_mut().begin_checkpoint());
    realm.runtime.vm.microtask_queue_mut().end_checkpoint();
    Ok(())
  }

  #[test]
  fn window_realm_exec_script_and_microtask_checkpoint_delegate_to_webidl_exotic_get() -> Result<(), VmError> {
    struct ExoticHost {
      foo_gets: usize,
    }

    impl WebIdlBindingsHost for ExoticHost {
      fn call_operation(
        &mut self,
        _vm: &mut Vm,
        _scope: &mut Scope<'_>,
        _receiver: Option<Value>,
        _interface: &'static str,
        _operation: &'static str,
        _overload: usize,
        _args: &[Value],
      ) -> Result<Value, VmError> {
        Err(VmError::Unimplemented("operation dispatch not used by this test"))
      }

      fn call_constructor(
        &mut self,
        _vm: &mut Vm,
        _scope: &mut Scope<'_>,
        _interface: &'static str,
        _overload: usize,
        _args: &[Value],
        _new_target: Value,
      ) -> Result<Value, VmError> {
        Err(VmError::Unimplemented("constructor dispatch not used by this test"))
      }

      fn exotic_get(
        &mut self,
        scope: &mut Scope<'_>,
        _obj: GcObject,
        key: PropertyKey,
        _receiver: Value,
      ) -> Result<Option<Value>, VmError> {
        let PropertyKey::String(s) = key else {
          return Ok(None);
        };
        if scope.heap().get_string(s)?.to_utf8_lossy() != "foo" {
          return Ok(None);
        }
        self.foo_gets += 1;
        Ok(Some(Value::String(scope.alloc_string("webidl")?)))
      }
    }

    let mut realm = new_realm(WindowRealmConfig::new("https://example.com/"))?;
    let mut host = ExoticHost { foo_gets: 0 };

    realm.with_webidl_bindings_host(&mut host, |realm| -> Result<(), VmError> {
      let direct = realm.exec_script("({}).foo")?;
      assert_eq!(get_string(realm.heap(), direct), "webidl");

      // Ensure `perform_microtask_checkpoint` uses the same exotic dispatch pipeline as
      // `exec_script_with_name` so Promise jobs can delegate to WebIDL hosts too.
      realm.exec_script(
        "globalThis.__out = 'pending'; Promise.resolve().then(() => { __out = ({}).foo; });",
      )?;
      realm.perform_microtask_checkpoint()?;
      let out = realm.exec_script("__out")?;
      assert_eq!(get_string(realm.heap(), out), "webidl");
      Ok(())
    })?;

    assert!(
      host.foo_gets >= 2,
      "expected WebIDL exotic_get to run for both direct eval and microtask callback"
    );
    Ok(())
  }

  #[test]
  fn history_scroll_restoration_exists_and_validates() -> Result<(), VmError> {
    let mut realm = new_realm(WindowRealmConfig::new("https://example.com/"))?;

    assert_eq!(
      realm.exec_script("'scrollRestoration' in history")?,
      Value::Bool(true)
    );

    let initial = realm.exec_script("history.scrollRestoration")?;
    assert_eq!(get_string(realm.heap(), initial), "auto");

    realm.exec_script("history.scrollRestoration = 'manual'")?;
    let manual = realm.exec_script("history.scrollRestoration")?;
    assert_eq!(get_string(realm.heap(), manual), "manual");

    let throws_on_bogus = realm.exec_script(
      "(() => { try { history.scrollRestoration = 'bogus'; return false; } catch (e) { return e instanceof TypeError; } })()",
    )?;
    assert_eq!(throws_on_bogus, Value::Bool(true));

    let throws_on_number = realm.exec_script(
      "(() => { try { history.scrollRestoration = 123; return false; } catch (e) { return e instanceof TypeError; } })()",
    )?;
    assert_eq!(throws_on_number, Value::Bool(true));

    // Invalid assignments should not clobber the previous value.
    let after_invalid = realm.exec_script("history.scrollRestoration")?;
    assert_eq!(get_string(realm.heap(), after_invalid), "manual");

    Ok(())
  }

  #[test]
  fn history_traversal_queues_task_and_dispatches_events() -> crate::error::Result<()> {
    let mut host = make_host(
      dom2::Document::new(QuirksMode::NoQuirks),
      "https://example.com/",
    )?;

    host.exec_script(
      "globalThis.__events = [];\n\
       onpopstate = (e) => { __events.push(['popstate', e.state]); };\n\
       onhashchange = (e) => { __events.push(['hashchange', e.oldURL, e.newURL]); };\n\
       history.pushState(1, '', '#one');\n\
       history.pushState(2, '', '#two');\n\
       globalThis.__len_after_push = history.length;\n\
       globalThis.__url_after_push = location.href;\n\
       globalThis.__state_after_push = history.state;\n\
       history.back();\n\
       globalThis.__url_after_back_call = location.href;\n\
       globalThis.__state_after_back_call = history.state;\n\
       globalThis.__events_len_after_back_call = __events.length;\n",
    )?;

    assert_eq!(host.exec_script("__len_after_push")?, Value::Number(3.0));
    let url_after_push = host.exec_script("__url_after_push")?;
    assert_eq!(
      get_string(host.host().window().heap(), url_after_push),
      "https://example.com/#two"
    );
    assert_eq!(host.exec_script("__state_after_push")?, Value::Number(2.0));
    // `history.back()` queues a task; it should not apply synchronously.
    let url_after_back_call = host.exec_script("__url_after_back_call")?;
    assert_eq!(
      get_string(host.host().window().heap(), url_after_back_call),
      "https://example.com/#two"
    );
    assert_eq!(
      host.exec_script("__state_after_back_call")?,
      Value::Number(2.0)
    );
    assert_eq!(
      host.exec_script("__events_len_after_back_call")?,
      Value::Number(0.0)
    );

    host.run_until_idle(RunLimits::unbounded())?;

    let href_after_back = host.exec_script("location.href")?;
    assert_eq!(
      get_string(host.host().window().heap(), href_after_back),
      "https://example.com/#one"
    );
    assert_eq!(host.exec_script("history.state")?, Value::Number(1.0));
    let document_url_after_back = host.exec_script("document.URL")?;
    assert_eq!(
      get_string(host.host().window().heap(), document_url_after_back),
      "https://example.com/#one"
    );
    let events_after_back = host.exec_script("JSON.stringify(__events)")?;
    assert_eq!(
      get_string(host.host().window().heap(), events_after_back),
      "[[\"popstate\",1],[\"hashchange\",\"https://example.com/#two\",\"https://example.com/#one\"]]"
    );

    // `history.forward()` should also be async + fire the same events.
    host.exec_script(
      "__events = [];\n\
       history.forward();\n\
       globalThis.__url_after_forward_call = location.href;\n\
       globalThis.__events_len_after_forward_call = __events.length;\n",
    )?;
    let url_after_forward_call = host.exec_script("__url_after_forward_call")?;
    assert_eq!(
      get_string(host.host().window().heap(), url_after_forward_call),
      "https://example.com/#one"
    );
    assert_eq!(
      host.exec_script("__events_len_after_forward_call")?,
      Value::Number(0.0)
    );
    host.run_until_idle(RunLimits::unbounded())?;
    let href_after_forward = host.exec_script("location.href")?;
    assert_eq!(
      get_string(host.host().window().heap(), href_after_forward),
      "https://example.com/#two"
    );
    assert_eq!(host.exec_script("history.state")?, Value::Number(2.0));
    let events_after_forward = host.exec_script("JSON.stringify(__events)")?;
    assert_eq!(
      get_string(host.host().window().heap(), events_after_forward),
      "[[\"popstate\",2],[\"hashchange\",\"https://example.com/#one\",\"https://example.com/#two\"]]"
    );

    // `history.go(-1)` should behave like `history.back()`.
    host.exec_script(
      "__events = [];\n\
       history.go(-1);\n\
       globalThis.__url_after_go_call = location.href;\n\
       globalThis.__events_len_after_go_call = __events.length;\n",
    )?;
    let url_after_go_call = host.exec_script("__url_after_go_call")?;
    assert_eq!(
      get_string(host.host().window().heap(), url_after_go_call),
      "https://example.com/#two"
    );
    assert_eq!(
      host.exec_script("__events_len_after_go_call")?,
      Value::Number(0.0)
    );
    host.run_until_idle(RunLimits::unbounded())?;
    let href_after_go = host.exec_script("location.href")?;
    assert_eq!(
      get_string(host.host().window().heap(), href_after_go),
      "https://example.com/#one"
    );
    assert_eq!(host.exec_script("history.state")?, Value::Number(1.0));
    let events_after_go = host.exec_script("JSON.stringify(__events)")?;
    assert_eq!(
      get_string(host.host().window().heap(), events_after_go),
      "[[\"popstate\",1],[\"hashchange\",\"https://example.com/#two\",\"https://example.com/#one\"]]"
    );

    Ok(())
  }

  #[test]
  fn element_dataset_resolves_extra_document_by_wrapper_document_identity() -> Result<(), VmError> {
    let mut realm = new_realm(WindowRealmConfig::new("https://example.com/"))?;

    // Active host document.
    let mut host = DocumentHostState::new(dom2::Document::new(QuirksMode::NoQuirks));
    let node1 = {
      let dom = host.dom_mut();
      let root = dom.root();
      let el = dom.create_element("div", "");
      dom
        .append_child(root, el)
        .expect("append child into host document");
      el
    };

    // Create a second JS-owned `Document` object with its own `dom2::Document` backing.
    let (doc2_dom_ptr, node2_id) = {
      let (vm, realm_ref, heap) = realm.vm_realm_and_heap_mut();
      let mut scope = heap.scope();
      let global = realm_ref.global_object();
      scope.push_root(Value::Object(global))?;

      let doc2_obj = scope.alloc_object()?;
      scope.push_root(Value::Object(doc2_obj))?;

      let (doc2_dom_ptr, node2_id) = {
        let Some(data) = vm.user_data_mut::<WindowRealmUserData>() else {
          return Err(VmError::InvariantViolation(
            "WindowRealm is missing required VM user data",
          ));
        };
        let Some(platform) = data.dom_platform.as_mut() else {
          return Err(VmError::InvariantViolation(
            "WindowRealm is missing required DomPlatform for dataset multi-document test",
          ));
        };

        scope.heap_mut().object_set_prototype(
          doc2_obj,
          Some(platform.prototype_for(DomInterface::Document)),
        )?;

        // Register a unique document id so wrapper caching is document-aware. Document IDs are
        // derived from the JS Document wrapper identity.
        let doc2_id = gc_object_id(doc2_obj);
        let doc2_key = WeakGcObject::from(doc2_obj);
        platform.register_wrapper(
          scope.heap(),
          doc2_obj,
          doc2_key,
          NodeId::from_index(0),
          DomInterface::Document,
        );

        let mut dom2 = dom2::Document::new(QuirksMode::NoQuirks);
        let root = dom2.root();
        let node2_id = dom2.create_element("div", "");
        dom2
          .append_child(root, node2_id)
          .expect("append child into extra document");

        // Store in the realm registry keyed by `DocumentId` so dataset exotic hooks can resolve it
        // by wrapper identity.
        let mut dom2_box = Box::new(dom2);
        let dom2_ptr = NonNull::from(dom2_box.as_mut());
        data
          .owned_dom2_documents
          .borrow_mut()
          .insert(doc2_id, dom2_box);
        (dom2_ptr, node2_id)
      };

      assert_eq!(
        node1.index(),
        node2_id.index(),
        "test requires NodeId index collision across documents"
      );

      // SAFETY: `doc2_dom_ptr` points at the boxed `dom2::Document` owned by `WindowRealmUserData`.
      let doc2_dom = unsafe { doc2_dom_ptr.as_ref() };
      let node2_obj =
        match get_or_create_node_wrapper(vm, &mut scope, doc2_obj, Some(doc2_dom), node2_id)? {
          Value::Object(obj) => obj,
          _ => {
            return Err(VmError::InvariantViolation(
              "expected get_or_create_node_wrapper to return an object",
            ))
          }
        };
      scope.push_root(Value::Object(node2_obj))?;

      let node2_key = alloc_key(&mut scope, "__node2")?;
      scope.define_property(global, node2_key, data_desc(Value::Object(node2_obj)))?;

      (doc2_dom_ptr, node2_id)
    };

    exec_script_with_dom_host(&mut realm, &mut host, "__node2.dataset.foo = '1';")?;

    // Regression test: without document identity, dataset mutations would target the host document's
    // node with the same index.
    assert_eq!(
      host
        .dom()
        .get_attribute(node1, "data-foo")
        .expect("host get_attribute"),
      None
    );

    let value = unsafe { doc2_dom_ptr.as_ref() }
      .get_attribute(node2_id, "data-foo")
      .expect("extra get_attribute");
    assert_eq!(value, Some("1"));

    Ok(())
  }

  #[test]
  fn window_env_shims_exist_and_match_media_evaluates() -> Result<(), VmError> {
    let media = MediaContext::screen(800.0, 600.0).with_device_pixel_ratio(2.0);
    let mut realm =
      new_realm(WindowRealmConfig::new("https://example.com/").with_media_context(media))?;

    let dpr = realm.exec_script("devicePixelRatio")?;
    assert!(matches!(dpr, Value::Number(v) if (v - 2.0).abs() < f64::EPSILON));

    let ua = realm.exec_script("navigator.userAgent")?;
    assert_eq!(get_string(realm.heap(), ua), FASTRENDER_USER_AGENT);
    let platform = realm.exec_script("navigator.platform")?;
    assert_eq!(get_string(realm.heap(), platform), "Win32");

    assert_eq!(
      realm.exec_script("matchMedia('(min-width: 700px)').matches")?,
      Value::Bool(true)
    );
    assert_eq!(
      realm.exec_script("matchMedia('(min-resolution: 2dppx)').matches")?,
      Value::Bool(true)
    );
    assert_eq!(
      realm.exec_script("matchMedia('(max-resolution: 1.5dppx)').matches")?,
      Value::Bool(false)
    );

    // Listener APIs are allowed to be stubs, but they must exist and be callable.
    assert_eq!(
      realm.exec_script("{ const m = matchMedia('(min-width: 1px)'); m.addListener(()=>{}); m.removeListener(()=>{}); true }")?,
      Value::Bool(true)
    );

    Ok(())
  }

  #[test]
  fn node_compare_document_position_reports_tree_order_and_shadow_disconnection() -> Result<(), VmError>
  {
    let renderer_dom = crate::dom::parse_html(
      "<!doctype html><html><body><div id=a><span id=b></span></div><p id=c></p></body></html>",
    )
    .unwrap();
    let mut host = crate::js::HostDocumentState::from_renderer_dom(&renderer_dom);
    let mut realm = new_realm(WindowRealmConfig::new("https://example.com/"))?;

    let result = exec_script_with_dom_host(
      &mut realm,
      &mut host,
      r#"(() => {
        if (typeof Node.prototype.compareDocumentPosition !== 'function') return 'missing_method';
        const a = document.getElementById('a');
        const b = document.getElementById('b');
        const c = document.getElementById('c');
        const PRECEDING = Node.DOCUMENT_POSITION_PRECEDING;
        const FOLLOWING = Node.DOCUMENT_POSITION_FOLLOWING;
        const CONTAINS = Node.DOCUMENT_POSITION_CONTAINS;
        const CONTAINED_BY = Node.DOCUMENT_POSITION_CONTAINED_BY;

        const r1 = a.compareDocumentPosition(b);
        if (r1 !== (FOLLOWING | CONTAINS)) return 'a_vs_b:' + r1;
        const r2 = b.compareDocumentPosition(a);
        if (r2 !== (PRECEDING | CONTAINED_BY)) return 'b_vs_a:' + r2;
        const r3 = b.compareDocumentPosition(c);
        if (r3 !== FOLLOWING) return 'b_vs_c:' + r3;
        const r4 = c.compareDocumentPosition(b);
        if (r4 !== PRECEDING) return 'c_vs_b:' + r4;
        const r5 = a.compareDocumentPosition(a);
        if (r5 !== 0) return 'a_vs_a:' + r5;

        // Shadow trees are separate from the light DOM tree for compareDocumentPosition.
        const host = document.createElement('div');
        document.body.appendChild(host);
        const sr = host.attachShadow({ mode: 'open' });
        sr.innerHTML = '<span id=shadow>shadow</span>';
        const shadow = sr.querySelector('#shadow');
        const res = host.compareDocumentPosition(shadow);
        if (!(res & Node.DOCUMENT_POSITION_DISCONNECTED)) return 'shadow_missing_disconnected:' + res;
        if (!(res & Node.DOCUMENT_POSITION_IMPLEMENTATION_SPECIFIC)) return 'shadow_missing_impl:' + res;
        if (res & Node.DOCUMENT_POSITION_CONTAINS) return 'shadow_contains:' + res;
        if (res & Node.DOCUMENT_POSITION_CONTAINED_BY) return 'shadow_contained_by:' + res;
        if (!(res & (PRECEDING | FOLLOWING))) return 'shadow_missing_order:' + res;

        const rev = shadow.compareDocumentPosition(host);
        if (!(rev & Node.DOCUMENT_POSITION_DISCONNECTED)) return 'shadow_rev_missing_disconnected:' + rev;
        if (!(rev & Node.DOCUMENT_POSITION_IMPLEMENTATION_SPECIFIC)) return 'shadow_rev_missing_impl:' + rev;
        // The implementation-specific ordering bit must be symmetric.
        if ((res & PRECEDING) && !(rev & FOLLOWING)) return 'shadow_rev_order';
        if ((res & FOLLOWING) && !(rev & PRECEDING)) return 'shadow_rev_order';

        return 'ok';
      })()"#,
    )?;
    assert_eq!(get_string(realm.heap(), result), "ok");
    Ok(())
  }

  #[test]
  fn node_compare_document_position_reports_tree_order_and_shadow_disconnection_webidl(
  ) -> Result<(), VmError> {
    let renderer_dom = crate::dom::parse_html(
      "<!doctype html><html><body><div id=a><span id=b></span></div><p id=c></p></body></html>",
    )
    .unwrap();
    let document = crate::js::HostDocumentState::from_renderer_dom(&renderer_dom);
    let window = new_realm(
      WindowRealmConfig::new("https://example.com/")
        .with_dom_bindings_backend(DomBindingsBackend::WebIdl),
    )?;
    let mut host = WebIdlTestHost::new(document, window);

    let result = host.exec_script(
      r#"(() => {
        if (typeof Node.prototype.compareDocumentPosition !== 'function') return 'missing_method';
        const a = document.getElementById('a');
        const b = document.getElementById('b');
        const c = document.getElementById('c');
        const PRECEDING = Node.DOCUMENT_POSITION_PRECEDING;
        const FOLLOWING = Node.DOCUMENT_POSITION_FOLLOWING;
        const CONTAINS = Node.DOCUMENT_POSITION_CONTAINS;
        const CONTAINED_BY = Node.DOCUMENT_POSITION_CONTAINED_BY;

        const r1 = a.compareDocumentPosition(b);
        if (r1 !== (FOLLOWING | CONTAINS)) return 'a_vs_b:' + r1;
        const r2 = b.compareDocumentPosition(a);
        if (r2 !== (PRECEDING | CONTAINED_BY)) return 'b_vs_a:' + r2;
        const r3 = b.compareDocumentPosition(c);
        if (r3 !== FOLLOWING) return 'b_vs_c:' + r3;
        const r4 = c.compareDocumentPosition(b);
        if (r4 !== PRECEDING) return 'c_vs_b:' + r4;

        const host = document.createElement('div');
        document.body.appendChild(host);
        const sr = host.attachShadow({ mode: 'open' });
        sr.innerHTML = '<span id=shadow>shadow</span>';
        const shadow = sr.querySelector('#shadow');
        const res = host.compareDocumentPosition(shadow);
        if (!(res & Node.DOCUMENT_POSITION_DISCONNECTED)) return 'shadow_missing_disconnected:' + res;
        if (!(res & Node.DOCUMENT_POSITION_IMPLEMENTATION_SPECIFIC)) return 'shadow_missing_impl:' + res;
        if (res & Node.DOCUMENT_POSITION_CONTAINS) return 'shadow_contains:' + res;
        if (res & Node.DOCUMENT_POSITION_CONTAINED_BY) return 'shadow_contained_by:' + res;
        if (!(res & (PRECEDING | FOLLOWING))) return 'shadow_missing_order:' + res;
        return 'ok';
      })()"#,
    )?;

    assert_eq!(get_string(host.window.heap(), result), "ok");
    Ok(())
  }

