  #[test]
  fn window_storage_exists_and_round_trips() -> Result<(), VmError> {
    crate::js::web_storage::reset_default_web_storage_hub_for_tests();
    let mut realm = new_realm(WindowRealmConfig::new("https://example.com/"))?;

    assert_eq!(realm.exec_script("typeof Storage === 'function'")?, Value::Bool(true));
    assert_eq!(
      realm.exec_script("typeof Storage.prototype.getItem === 'function'")?,
      Value::Bool(true)
    );
    assert_eq!(
      realm.exec_script("localStorage.getItem === Storage.prototype.getItem")?,
      Value::Bool(true)
    );
    assert_eq!(
      realm.exec_script("localStorage instanceof Storage && sessionStorage instanceof Storage")?,
      Value::Bool(true)
    );
    let tag = realm.exec_script("Object.prototype.toString.call(localStorage)")?;
    assert_eq!(get_string(realm.heap(), tag), "[object Storage]");
    assert_eq!(
      realm.exec_script("localStorage.hasOwnProperty('getItem')")?,
      Value::Bool(false)
    );
    assert_eq!(
      realm.exec_script("typeof localStorage.getItem === 'function'")?,
      Value::Bool(true)
    );
    assert_eq!(
      realm.exec_script("localStorage.hasOwnProperty('length')")?,
      Value::Bool(false)
    );
    let illegal_invocation_name = realm.exec_script(
      "(() => {\n\
        try { Storage.prototype.getItem.call({}, 'x'); return 'no error'; }\n\
        catch (e) { return e && e.name; }\n\
      })()",
    )?;
    assert_eq!(get_string(realm.heap(), illegal_invocation_name), "TypeError");
    let illegal_invocation_message = realm.exec_script(
      "(() => {\n\
        try { Storage.prototype.getItem.call({}, 'x'); return 'no error'; }\n\
        catch (e) { return e && e.message; }\n\
      })()",
    )?;
    assert_eq!(
      get_string(realm.heap(), illegal_invocation_message),
      ILLEGAL_INVOCATION_ERROR
    );

    let set_item_illegal_name = realm.exec_script(
      "(() => {\n\
        try { Storage.prototype.setItem.call({}, 'a', '1'); return 'no error'; }\n\
        catch (e) { return e && e.name; }\n\
      })()",
    )?;
    assert_eq!(get_string(realm.heap(), set_item_illegal_name), "TypeError");
    let set_item_illegal_message = realm.exec_script(
      "(() => {\n\
        try { Storage.prototype.setItem.call({}, 'a', '1'); return 'no error'; }\n\
        catch (e) { return e && e.message; }\n\
      })()",
    )?;
    assert_eq!(
      get_string(realm.heap(), set_item_illegal_message),
      ILLEGAL_INVOCATION_ERROR
    );

    let remove_item_illegal_name = realm.exec_script(
      "(() => {\n\
        try { Storage.prototype.removeItem.call({}, 'a'); return 'no error'; }\n\
        catch (e) { return e && e.name; }\n\
      })()",
    )?;
    assert_eq!(get_string(realm.heap(), remove_item_illegal_name), "TypeError");
    let remove_item_illegal_message = realm.exec_script(
      "(() => {\n\
        try { Storage.prototype.removeItem.call({}, 'a'); return 'no error'; }\n\
        catch (e) { return e && e.message; }\n\
      })()",
    )?;
    assert_eq!(
      get_string(realm.heap(), remove_item_illegal_message),
      ILLEGAL_INVOCATION_ERROR
    );

    let clear_illegal_name = realm.exec_script(
      "(() => {\n\
        try { Storage.prototype.clear.call({}); return 'no error'; }\n\
        catch (e) { return e && e.name; }\n\
      })()",
    )?;
    assert_eq!(get_string(realm.heap(), clear_illegal_name), "TypeError");
    let clear_illegal_message = realm.exec_script(
      "(() => {\n\
        try { Storage.prototype.clear.call({}); return 'no error'; }\n\
        catch (e) { return e && e.message; }\n\
      })()",
    )?;
    assert_eq!(
      get_string(realm.heap(), clear_illegal_message),
      ILLEGAL_INVOCATION_ERROR
    );
    assert_eq!(
      realm.exec_script(
        "(() => {\n\
          try {\n\
            const obs = new MutationObserver(() => {});\n\
            Storage.prototype.getItem.call(obs, 'a');\n\
            return false;\n\
          } catch (e) {\n\
            return e && e.name === 'TypeError' && String(e.message).includes('Illegal invocation');\n\
          }\n\
        })()",
      )?,
      Value::Bool(true)
    );

    let ctor_error = realm.exec_script(
      "(() => {\n\
        try { Storage(); return 'no error'; }\n\
        catch (e) { return e && e.name; }\n\
      })()",
    )?;
    assert_eq!(get_string(realm.heap(), ctor_error), "TypeError");

    let new_error = realm.exec_script(
      "(() => {\n\
        try { new Storage(); return 'no error'; }\n\
        catch (e) { return e && e.name; }\n\
      })()",
    )?;
    assert_eq!(get_string(realm.heap(), new_error), "TypeError");

    assert_eq!(
      realm.exec_script("Storage.prototype.getItem.call(localStorage, 'missing')")?,
      Value::Null
    );
    assert_eq!(
      realm.exec_script("localStorage.getItem('missing')")?,
      Value::Null
    );

    realm.exec_script("localStorage.setItem('a', 1)")?;
    let a = realm.exec_script("localStorage.getItem('a')")?;
    assert_eq!(get_string(realm.heap(), a), "1");
    assert!(matches!(
      realm.exec_script("localStorage.length")?,
      Value::Number(n) if n == 1.0
    ));

    realm.exec_script("localStorage.setItem('b', '2')")?;
    assert!(matches!(
      realm.exec_script("localStorage.length")?,
      Value::Number(n) if n == 2.0
    ));

    let key0 = realm.exec_script("localStorage.key(0)")?;
    assert_eq!(get_string(realm.heap(), key0), "a");
    let key1 = realm.exec_script("localStorage.key(1)")?;
    assert_eq!(get_string(realm.heap(), key1), "b");
    assert_eq!(realm.exec_script("localStorage.key(2)")?, Value::Null);

    realm.exec_script("localStorage.removeItem('a')")?;
    assert_eq!(realm.exec_script("localStorage.getItem('a')")?, Value::Null);
    assert!(matches!(
      realm.exec_script("localStorage.length")?,
      Value::Number(n) if n == 1.0
    ));

    realm.exec_script("localStorage.clear()")?;
    assert!(matches!(
      realm.exec_script("localStorage.length")?,
      Value::Number(n) if n == 0.0
    ));

    // sessionStorage should be isolated from localStorage.
    realm.exec_script("sessionStorage.setItem('x', 's'); localStorage.setItem('x', 'l');")?;
    let s = realm.exec_script("sessionStorage.getItem('x')")?;
    assert_eq!(get_string(realm.heap(), s), "s");
    let l = realm.exec_script("localStorage.getItem('x')")?;
    assert_eq!(get_string(realm.heap(), l), "l");

    crate::js::web_storage::reset_default_web_storage_hub_for_tests();
    Ok(())
  }

  #[test]
  fn window_storage_key_properties_enumerate_like_browsers() -> Result<(), VmError> {
    crate::js::web_storage::reset_default_web_storage_hub_for_tests();
    let mut realm = new_realm(WindowRealmConfig::new("https://example.com/"))?;

    realm.exec_script("localStorage.setItem('a','1'); localStorage.setItem('b','2');")?;
    let keys = realm.exec_script("JSON.stringify(Object.keys(localStorage))")?;
    assert_eq!(get_string(realm.heap(), keys), "[\"a\",\"b\"]");
    let names = realm.exec_script("JSON.stringify(Object.getOwnPropertyNames(localStorage))")?;
    assert_eq!(get_string(realm.heap(), names), "[\"a\",\"b\"]");
    let for_in = realm.exec_script(
      "(() => { const out = []; for (const k in localStorage) out.push(k); return JSON.stringify(out); })()",
    )?;
    assert_eq!(get_string(realm.heap(), for_in), "[\"a\",\"b\"]");
    assert_eq!(realm.exec_script("'a' in localStorage")?, Value::Bool(true));
    assert_eq!(realm.exec_script("'missing' in localStorage")?, Value::Bool(false));

    // Updating an existing key must not change enumeration order.
    realm.exec_script("localStorage.setItem('a','3')")?;
    let keys = realm.exec_script("JSON.stringify(Object.keys(localStorage))")?;
    assert_eq!(get_string(realm.heap(), keys), "[\"a\",\"b\"]");
    let names = realm.exec_script("JSON.stringify(Object.getOwnPropertyNames(localStorage))")?;
    assert_eq!(get_string(realm.heap(), names), "[\"a\",\"b\"]");

    // Removing + reinserting must move the key to the end.
    realm.exec_script("localStorage.removeItem('a'); localStorage.setItem('a','4');")?;
    let keys = realm.exec_script("JSON.stringify(Object.keys(localStorage))")?;
    assert_eq!(get_string(realm.heap(), keys), "[\"b\",\"a\"]");
    let names = realm.exec_script("JSON.stringify(Object.getOwnPropertyNames(localStorage))")?;
    assert_eq!(get_string(realm.heap(), names), "[\"b\",\"a\"]");
    let for_in = realm.exec_script(
      "(() => { const out = []; for (const k in localStorage) out.push(k); return JSON.stringify(out); })()",
    )?;
    assert_eq!(get_string(realm.heap(), for_in), "[\"b\",\"a\"]");

    // Stored keys must not shadow prototype properties.
    realm.exec_script("localStorage.setItem('getItem','x')")?;
    assert_eq!(
      realm.exec_script("localStorage.getItem === Storage.prototype.getItem")?,
      Value::Bool(true)
    );
    assert_eq!(
      realm.exec_script("Object.keys(localStorage).includes('getItem')")?,
      Value::Bool(false)
    );
    assert_eq!(
      realm.exec_script("Object.getOwnPropertyNames(localStorage).includes('getItem')")?,
      Value::Bool(false)
    );
    let stored = realm.exec_script("localStorage.getItem('getItem')")?;
    assert_eq!(get_string(realm.heap(), stored), "x");

    crate::js::web_storage::reset_default_web_storage_hub_for_tests();
    Ok(())
  }

