  #[test]
  fn dom_implementation_create_document_creates_xml_document() -> Result<(), VmError> {
    let mut host = new_host_document_state();
    let mut realm = new_realm(WindowRealmConfig::new("https://example.com/"))?;

    let result = exec_script_with_dom_host(
      &mut realm,
      &mut host,
      r#"(() => {
        const dt = document.implementation.createDocumentType("qorflesnorf", "abcde", "x\"'y");
        const xmlDoc = document.implementation.createDocument(null, null, dt);
        if (xmlDoc === document) throw new Error("expected createDocument to create a new Document");
        if (xmlDoc.contentType !== "application/xml") throw new Error(`expected application/xml, got ${xmlDoc.contentType}`);
        if (xmlDoc.doctype !== dt) throw new Error("expected doctype to be adopted into the new document");
        const pi = xmlDoc.createProcessingInstruction("whippoorwill", "chirp chirp chirp");
        const comment = xmlDoc.createComment("hello");
        if (pi.nodeValue !== "chirp chirp chirp") throw new Error(`expected PI nodeValue, got ${pi.nodeValue}`);
        if (comment.nodeValue !== "hello") throw new Error(`expected comment nodeValue, got ${comment.nodeValue}`);
        pi.nodeValue = "x";
        comment.nodeValue = "y";
        if (pi.nodeValue !== "x") throw new Error(`expected PI nodeValue after set, got ${pi.nodeValue}`);
        if (comment.nodeValue !== "y") throw new Error(`expected comment nodeValue after set, got ${comment.nodeValue}`);
        xmlDoc.appendChild(pi);
        xmlDoc.appendChild(comment);
        return true;
      })()"#,
    )?;

    assert_eq!(result, Value::Bool(true));
    Ok(())
  }

  #[test]
  fn document_constructor_creates_windowless_xml_document() -> Result<(), VmError> {
    let mut host = new_host_document_state();
    let mut realm = new_realm(WindowRealmConfig::new("https://example.com/"))?;

    let result = exec_script_with_dom_host(
      &mut realm,
      &mut host,
      r#"(() => {
        const d = new Document();
        if (d === document) throw new Error("expected new Document() to create a new Document");
        if (d.defaultView !== null) throw new Error("expected new Document().defaultView to be null");
        if (d.URL !== "about:blank") throw new Error(`expected about:blank URL, got ${d.URL}`);
        if (d.contentType !== "application/xml") throw new Error(`expected application/xml, got ${d.contentType}`);

        // createCDATASection is only supported for XML documents.
        const cdata = d.createCDATASection("1234");
        if (cdata.nodeValue !== "1234") throw new Error(`expected CDATA nodeValue, got ${cdata.nodeValue}`);

        // Invalid CDATA payload should throw.
        try {
          d.createCDATASection("]]>");
          throw new Error("expected InvalidCharacterError for ]]> payload");
        } catch (e) {
          if (e.name !== "InvalidCharacterError") throw e;
        }

        // HTML documents must reject createCDATASection.
        try {
          document.createCDATASection("x");
          throw new Error("expected NotSupportedError from HTML document");
        } catch (e) {
          if (e.name !== "NotSupportedError") throw e;
        }

        // Appending across documents should adopt the node (used by Range WPT harness).
        document.body.appendChild(cdata);
        if (cdata.ownerDocument !== document) throw new Error("expected adopted ownerDocument");
        return true;
      })()"#,
    )?;

    assert_eq!(result, Value::Bool(true));
    Ok(())
  }

  #[test]
  fn range_end_offset_updates_after_cross_document_adopt_of_detached_container() -> Result<(), VmError> {
    let mut host = new_host_document_state();
    let mut realm = new_realm(WindowRealmConfig::new("https://example.com/"))?;

    let result = exec_script_with_dom_host(
      &mut realm,
      &mut host,
      r#"(() => {
        const range = document.createRange();
        const container = document.createElement("container");
        const child = document.createElement("child");
        container.appendChild(child);
        range.setStart(container, 0);
        range.setEnd(container, 1);

        const other = document.implementation.createDocument(null, null);
        other.appendChild(container);

        // Remove the only child after adoption; live range updates should still collapse the range.
        container.removeChild(child);

        return range.endOffset;
      })()"#,
    )?;

    assert_eq!(result, Value::Number(0.0));
    Ok(())
  }

