  #[test]
  fn event_constructors_require_new_and_expose_phase_constants() -> Result<(), VmError> {
    let mut realm = new_realm(WindowRealmConfig::new("https://example.com/"))?;

    let err = realm.exec_script("Event('x')");
    let err = err.expect_err("expected Event('x') to throw");
    match err {
      VmError::TypeError(msg) => assert_eq!(msg, "Event constructor cannot be invoked without 'new'"),
      other => {
        let obj = unwrap_thrown_object(other);
        let (vm, heap) = realm.vm_and_heap_mut();
        let mut scope = heap.scope();
        scope.push_root(Value::Object(obj))?;
        let name = get_prop(vm, &mut scope, obj, "name")?;
        assert_eq!(get_string(scope.heap(), name), "TypeError");
        let message = get_prop(vm, &mut scope, obj, "message")?;
        assert_eq!(
          get_string(scope.heap(), message),
          "Event constructor cannot be invoked without 'new'"
        );
      }
    }

    assert!(matches!(realm.exec_script("new Event('x')")?, Value::Object(_)));

    let err = realm.exec_script("CustomEvent('x')");
    let err = err.expect_err("expected CustomEvent('x') to throw");
    match err {
      VmError::TypeError(msg) => {
        assert_eq!(msg, "CustomEvent constructor cannot be invoked without 'new'")
      }
      other => {
        let obj = unwrap_thrown_object(other);
        let (vm, heap) = realm.vm_and_heap_mut();
        let mut scope = heap.scope();
        scope.push_root(Value::Object(obj))?;
        let name = get_prop(vm, &mut scope, obj, "name")?;
        assert_eq!(get_string(scope.heap(), name), "TypeError");
        let message = get_prop(vm, &mut scope, obj, "message")?;
        assert_eq!(
          get_string(scope.heap(), message),
          "CustomEvent constructor cannot be invoked without 'new'"
        );
      }
    }

    assert!(matches!(
      realm.exec_script("new CustomEvent('x')")?,
      Value::Object(_)
    ));

    let err = realm.exec_script("ErrorEvent('error')");
    let err = err.expect_err("expected ErrorEvent('error') to throw");
    match err {
      VmError::TypeError(msg) => {
        assert_eq!(msg, "ErrorEvent constructor cannot be invoked without 'new'")
      }
      other => {
        let obj = unwrap_thrown_object(other);
        let (vm, heap) = realm.vm_and_heap_mut();
        let mut scope = heap.scope();
        scope.push_root(Value::Object(obj))?;
        let name = get_prop(vm, &mut scope, obj, "name")?;
        assert_eq!(get_string(scope.heap(), name), "TypeError");
        let message = get_prop(vm, &mut scope, obj, "message")?;
        assert_eq!(
          get_string(scope.heap(), message),
          "ErrorEvent constructor cannot be invoked without 'new'"
        );
      }
    }

    let err = realm.exec_script("BeforeUnloadEvent('beforeunload')");
    let err = err.expect_err("expected BeforeUnloadEvent('beforeunload') to throw");
    match err {
      VmError::TypeError(msg) => {
        assert_eq!(msg, "BeforeUnloadEvent constructor cannot be invoked without 'new'")
      }
      other => {
        let obj = unwrap_thrown_object(other);
        let (vm, heap) = realm.vm_and_heap_mut();
        let mut scope = heap.scope();
        scope.push_root(Value::Object(obj))?;
        let name = get_prop(vm, &mut scope, obj, "name")?;
        assert_eq!(get_string(scope.heap(), name), "TypeError");
        let message = get_prop(vm, &mut scope, obj, "message")?;
        assert_eq!(
          get_string(scope.heap(), message),
          "BeforeUnloadEvent constructor cannot be invoked without 'new'"
        );
      }
    }

    let err = realm.exec_script("PageTransitionEvent('pagehide')");
    let err = err.expect_err("expected PageTransitionEvent('pagehide') to throw");
    match err {
      VmError::TypeError(msg) => {
        assert_eq!(msg, "PageTransitionEvent constructor cannot be invoked without 'new'")
      }
      other => {
        let obj = unwrap_thrown_object(other);
        let (vm, heap) = realm.vm_and_heap_mut();
        let mut scope = heap.scope();
        scope.push_root(Value::Object(obj))?;
        let name = get_prop(vm, &mut scope, obj, "name")?;
        assert_eq!(get_string(scope.heap(), name), "TypeError");
        let message = get_prop(vm, &mut scope, obj, "message")?;
        assert_eq!(
          get_string(scope.heap(), message),
          "PageTransitionEvent constructor cannot be invoked without 'new'"
        );
      }
    }

    // DOM constants should be present and numeric.
    assert_eq!(realm.exec_script("Event.NONE")?, Value::Number(0.0));
    assert_eq!(realm.exec_script("Event.CAPTURING_PHASE")?, Value::Number(1.0));
    assert_eq!(realm.exec_script("Event.AT_TARGET")?, Value::Number(2.0));
    assert_eq!(realm.exec_script("Event.BUBBLING_PHASE")?, Value::Number(3.0));

    // Constants are mirrored onto the interface prototype in browsers / WebIDL.
    assert_eq!(realm.exec_script("Event.prototype.CAPTURING_PHASE")?, Value::Number(1.0));

    // Constants are non-writable and non-configurable.
    assert_eq!(
      realm.exec_script(
        "(() => {\n\
          let threw = false;\n\
          try {\n\
            (function () { 'use strict'; Event.CAPTURING_PHASE = 9; })();\n\
          } catch (e) {\n\
            threw = true;\n\
          }\n\
          return threw || Event.CAPTURING_PHASE === 1;\n\
        })()",
      )?,
      Value::Bool(true)
    );
    assert_eq!(realm.exec_script("delete Event.CAPTURING_PHASE")?, Value::Bool(false));
    Ok(())
  }

  #[test]
  fn domless_window_and_document_event_targets_dispatch_via_fallback_registry(
  ) -> Result<(), VmError> {
    let mut realm = WindowRealm::new(WindowRealmConfig::new("https://example.com/"))?;

    let order = realm.exec_script(
      "(() => {\n\
        let log = '';\n\
        const push = (s) => { log = log === '' ? s : log + ',' + s; };\n\
        window.addEventListener('x', () => push('w-c'), true);\n\
        window.addEventListener('x', () => push('w-b'));\n\
        document.addEventListener('x', () => push('d-c'), { capture: true });\n\
        document.addEventListener('x', () => push('d-b'));\n\
\n\
        document.dispatchEvent(new Event('x'));\n\
        const first = log;\n\
        log = '';\n\
        document.dispatchEvent(new Event('x', { bubbles: true }));\n\
        const second = log;\n\
        return first + '|' + second;\n\
      })()",
    )?;
    assert_eq!(
      get_string(realm.heap(), order),
      "w-c,d-c,d-b|w-c,d-c,d-b,w-b"
    );
    Ok(())
  }

  #[test]
  fn window_inherits_event_target_and_dispatches_via_prototype_chain() -> Result<(), VmError> {
    let mut realm = WindowRealm::new(WindowRealmConfig::new("https://example.com/"))?;

    assert_eq!(realm.exec_script("window instanceof EventTarget")?, Value::Bool(true));

    // EventTarget methods should be inherited (not installed as own properties on the global).
    assert_eq!(
      realm.exec_script("Object.prototype.hasOwnProperty.call(window, 'addEventListener')")?,
      Value::Bool(false)
    );
    assert_eq!(
      realm.exec_script("Object.prototype.hasOwnProperty.call(window, 'dispatchEvent')")?,
      Value::Bool(false)
    );
    assert_eq!(
      realm.exec_script("EventTarget.prototype.isPrototypeOf(window)")?,
      Value::Bool(true)
    );

    let typeof_add = realm.exec_script("typeof window.addEventListener")?;
    assert_eq!(get_string(realm.heap(), typeof_add), "function");

    let fired = realm.exec_script(
      "(() => {\n\
        let count = 0;\n\
        window.addEventListener('x', () => { count++; });\n\
        window.dispatchEvent(new Event('x'));\n\
        return count;\n\
      })()",
    )?;
    assert_eq!(fired, Value::Number(1.0));

    Ok(())
  }

  #[test]
  fn event_target_constructor_dispatches_via_shared_event_system() -> Result<(), VmError> {
    let mut realm = WindowRealm::new(WindowRealmConfig::new("https://example.com/"))?;

    let called = realm.exec_script(
      "(() => {\n\
        const t = new EventTarget();\n\
        let count = 0;\n\
        t.addEventListener('x', () => { count++; });\n\
        t.dispatchEvent(new Event('x'));\n\
        return count;\n\
      })()",
    )?;
    assert_eq!(called, Value::Number(1.0));

    let removed = realm.exec_script(
      "(() => {\n\
        const t = new EventTarget();\n\
        let count = 0;\n\
        const cb = () => { count++; };\n\
        t.addEventListener('x', cb);\n\
        t.removeEventListener('x', cb);\n\
        t.dispatchEvent(new Event('x'));\n\
        return count;\n\
      })()",
    )?;
    assert_eq!(removed, Value::Number(0.0));
    Ok(())
  }

  #[test]
  fn event_target_add_event_listener_options_union_treats_number_as_capture_bool() -> Result<(), VmError>
  {
    let mut realm = WindowRealm::new(WindowRealmConfig::new("https://example.com/"))?;

    let order = realm.exec_script(
      "(() => {\n\
        const t = new EventTarget();\n\
        let log = '';\n\
        const push = (s) => { log = log === '' ? s : log + ',' + s; };\n\
        // If `1` is treated as the legacy boolean `capture` argument, this listener must run\n\
        // before the bubble listener even though it is registered second.\n\
        t.addEventListener('x', () => push('b'));\n\
        t.addEventListener('x', () => push('c'), 1);\n\
        t.dispatchEvent(new Event('x'));\n\
        return log;\n\
      })()",
    )?;

    assert_eq!(get_string(realm.heap(), order), "c,b");
    Ok(())
  }

