  #[test]
  fn host_dom_event_dispatch_synthesizes_drag_events() -> Result<(), VmError> {
    let renderer_dom =
      crate::dom::parse_html("<!doctype html><html><body><div id=target></div></body></html>")
        .unwrap();
    let mut host = crate::js::HostDocumentState::from_renderer_dom(&renderer_dom);

    let mut realm = new_realm(WindowRealmConfig::new("https://example.com/"))?;
    exec_script_with_dom_host(
      &mut realm,
      &mut host,
      "globalThis.__log = [];\n\
       globalThis.__dt = { foo: 123 };\n\
       globalThis.__create = (() => {\n\
         try {\n\
           const e = document.createEvent('DragEvent');\n\
           const ok1 = (e instanceof DragEvent);\n\
           const ok2 = ('dataTransfer' in e);\n\
           const ok3 = (e.dataTransfer === null);\n\
           const ok4 = (typeof e.initMouseEvent === 'function');\n\
           let ok5 = false;\n\
           try {\n\
             e.initMouseEvent('dragstart', true, true, globalThis, 0, 0, 0, 0, 0, false, false, false, false, 0, null);\n\
             ok5 = true;\n\
           } catch (e) {}\n\
           return [ok1, ok2, ok3, ok4, ok5].join('|');\n\
         } catch (e) {\n\
           return 'throw';\n\
         }\n\
       })();\n\
       const target = document.getElementById('target');\n\
       function cap(e) {\n\
         __log.push([\n\
           e.type,\n\
           (e instanceof DragEvent),\n\
           (e instanceof MouseEvent),\n\
           (e.dataTransfer === __dt),\n\
           (e.dataTransfer === null),\n\
           String(e.dataTransfer ? e.dataTransfer.foo : null),\n\
         ].join('|'));\n\
       }\n\
       target.addEventListener('dragstart', cap);\n\
       target.addEventListener('dragover', cap);\n\
       target.addEventListener('drop', cap);\n\
       target.addEventListener('dragend', cap);",
    )?;

    let data_transfer = realm.exec_script("__dt")?;

    struct DummyHost;
    impl WindowRealmHost for DummyHost {
      fn vm_host_and_window_realm(
        &mut self,
      ) -> crate::error::Result<(&mut dyn VmHost, &mut WindowRealm)> {
        unreachable!("DummyHost is only used as a type parameter for VmJsEventLoopHooks");
      }
    }

    let mut realm_slot = Some(realm);
    let mut vm_host_ctx = ();
    let mut vm_host_slot: Option<NonNull<dyn VmHost>> =
      Some(NonNull::from(&mut vm_host_ctx as &mut dyn VmHost));
    let mut webidl_bindings_host_slot: Option<NonNull<dyn WebIdlBindingsHost>> = None;
    let mut invoker = WindowRealmDomEventListenerInvoker::<DummyHost>::new(
      &mut realm_slot,
      &mut vm_host_slot,
      &mut webidl_bindings_host_slot,
    );

    let target = host.dom().get_element_by_id("target").expect("missing #target");

    let mut dragstart = web_events::Event::new(
      "dragstart",
      web_events::EventInit {
        bubbles: true,
        cancelable: true,
        composed: false,
      },
    );
    dragstart.is_trusted = true;
    dragstart.mouse = Some(web_events::MouseEvent {
      client_x: 1.0,
      client_y: 2.0,
      button: 0,
      buttons: 1,
      detail: 0,
      ctrl_key: false,
      shift_key: false,
      alt_key: false,
      meta_key: false,
      related_target: None,
    });
    dragstart.drag_data_transfer = Some(data_transfer);
    web_events::dispatch_event(
      web_events::EventTargetId::Node(target).normalize(),
      &mut dragstart,
      host.dom(),
      host.dom().events(),
      &mut invoker,
    )
    .expect("dragstart dispatch should succeed");

    let mut dragover = web_events::Event::new(
      "dragover",
      web_events::EventInit {
        bubbles: true,
        cancelable: true,
        composed: false,
      },
    );
    dragover.is_trusted = true;
    dragover.mouse = dragstart.mouse;
    web_events::dispatch_event(
      web_events::EventTargetId::Node(target).normalize(),
      &mut dragover,
      host.dom(),
      host.dom().events(),
      &mut invoker,
    )
    .expect("dragover dispatch should succeed");

    let mut drop = web_events::Event::new(
      "drop",
      web_events::EventInit {
        bubbles: true,
        cancelable: true,
        composed: false,
      },
    );
    drop.is_trusted = true;
    drop.mouse = dragstart.mouse;
    drop.drag_data_transfer = Some(data_transfer);
    web_events::dispatch_event(
      web_events::EventTargetId::Node(target).normalize(),
      &mut drop,
      host.dom(),
      host.dom().events(),
      &mut invoker,
    )
    .expect("drop dispatch should succeed");

    let mut dragend = web_events::Event::new(
      "dragend",
      web_events::EventInit {
        bubbles: true,
        cancelable: true,
        composed: false,
      },
    );
    dragend.is_trusted = true;
    dragend.mouse = dragstart.mouse;
    web_events::dispatch_event(
      web_events::EventTargetId::Node(target).normalize(),
      &mut dragend,
      host.dom(),
      host.dom().events(),
      &mut invoker,
    )
    .expect("dragend dispatch should succeed");

    let realm = realm_slot.as_mut().expect("expected realm slot");
    let create_v = realm.exec_script("__create")?;
    let create_s = get_string(realm.heap(), create_v);
    assert_eq!(create_s, "true|true|true|true|true");
    let ok = realm.exec_script(
      "(() => {\n\
         return __log.length === 4 &&\n\
           __log[0] === 'dragstart|true|true|true|false|123' &&\n\
           __log[1] === 'dragover|true|true|false|true|null' &&\n\
           __log[2] === 'drop|true|true|true|false|123' &&\n\
           __log[3] === 'dragend|true|true|false|true|null';\n\
       })()",
    )?;
    assert_eq!(ok, Value::Bool(true));
    Ok(())
  }

  #[test]
  fn host_click_event_exposes_mouse_coordinates_buttons_and_modifiers() -> Result<(), VmError> {
    let renderer_dom =
      crate::dom::parse_html("<!doctype html><html><body><button id=t></button></body></html>")
        .unwrap();
    let mut host = crate::js::HostDocumentState::from_renderer_dom(&renderer_dom);
    let click_target = host
      .dom()
      .get_element_by_id("t")
      .expect("expected #t in DOM");

    let mut realm = new_realm(WindowRealmConfig::new("https://example.com/"))?;
    exec_script_with_dom_host(
      &mut realm,
      &mut host,
      "globalThis.__is_mouse = null;\n\
       globalThis.__cx = null;\n\
       globalThis.__cy = null;\n\
       globalThis.__button = null;\n\
       globalThis.__buttons = null;\n\
       globalThis.__ctrl = null;\n\
       globalThis.__shift = null;\n\
       globalThis.__alt = null;\n\
       globalThis.__meta = null;\n\
       globalThis.__view_ok = null;\n\
       document.getElementById('t').addEventListener('click', (e) => {\n\
         globalThis.__is_mouse = (e instanceof MouseEvent);\n\
         globalThis.__cx = e.clientX;\n\
         globalThis.__cy = e.clientY;\n\
         globalThis.__button = e.button;\n\
         globalThis.__buttons = e.buttons;\n\
         globalThis.__ctrl = e.ctrlKey;\n\
         globalThis.__shift = e.shiftKey;\n\
         globalThis.__alt = e.altKey;\n\
         globalThis.__meta = e.metaKey;\n\
         globalThis.__view_ok = (e.view === globalThis);\n\
       });",
    )?;

    struct DummyHost;
    impl WindowRealmHost for DummyHost {
      fn vm_host_and_window_realm(
        &mut self,
      ) -> crate::error::Result<(&mut dyn VmHost, &mut WindowRealm)> {
        unreachable!("DummyHost is only used as a type parameter for VmJsEventLoopHooks");
      }
    }

    let mut realm_slot = Some(realm);
    let mut vm_host_ctx = ();
    let mut vm_host_slot: Option<NonNull<dyn VmHost>> =
      Some(NonNull::from(&mut vm_host_ctx as &mut dyn VmHost));
    let mut webidl_bindings_host_slot: Option<NonNull<dyn WebIdlBindingsHost>> = None;
    let mut invoker = WindowRealmDomEventListenerInvoker::<DummyHost>::new(
      &mut realm_slot,
      &mut vm_host_slot,
      &mut webidl_bindings_host_slot,
    );

    let mut event = web_events::Event::new(
      "click",
      web_events::EventInit {
        bubbles: true,
        cancelable: true,
        composed: false,
      },
    );
    event.is_trusted = true;
    event.mouse = Some(web_events::MouseEvent {
      client_x: 12.5,
      client_y: 34.0,
      button: 0,
      buttons: 1,
      detail: 0,
      ctrl_key: true,
      shift_key: false,
      alt_key: true,
      meta_key: false,
      related_target: None,
    });

    web_events::dispatch_event(
      web_events::EventTargetId::Node(click_target).normalize(),
      &mut event,
      host.dom(),
      host.dom().events(),
      &mut invoker,
    )
    .expect("expected host click dispatch to succeed");

    let realm = realm_slot.as_mut().expect("expected realm slot");
    assert_eq!(realm.exec_script("globalThis.__is_mouse")?, Value::Bool(true));
    assert!(matches!(
      realm.exec_script("globalThis.__cx")?,
      Value::Number(v) if (v - 12.5).abs() < f64::EPSILON
    ));
    assert!(matches!(
      realm.exec_script("globalThis.__cy")?,
      Value::Number(v) if (v - 34.0).abs() < f64::EPSILON
    ));
    assert_eq!(realm.exec_script("globalThis.__button")?, Value::Number(0.0));
    assert_eq!(realm.exec_script("globalThis.__buttons")?, Value::Number(1.0));
    assert_eq!(realm.exec_script("globalThis.__ctrl")?, Value::Bool(true));
    assert_eq!(realm.exec_script("globalThis.__shift")?, Value::Bool(false));
    assert_eq!(realm.exec_script("globalThis.__alt")?, Value::Bool(true));
    assert_eq!(realm.exec_script("globalThis.__meta")?, Value::Bool(false));
    assert_eq!(realm.exec_script("globalThis.__view_ok")?, Value::Bool(true));

    Ok(())
  }

  #[test]
  fn dom_event_once_listeners_are_removed_after_first_dispatch() -> Result<(), VmError> {
    let renderer_dom = crate::dom::parse_html("<!doctype html><html></html>").unwrap();
    let mut host = crate::js::HostDocumentState::from_renderer_dom(&renderer_dom);

    let mut realm = new_realm(WindowRealmConfig::new("https://example.com/"))?;

    exec_script_with_dom_host(
      &mut realm,
      &mut host,
      "globalThis.__count = 0;\n\
       document.addEventListener('x', () => { __count++; }, { once: true });\n\
       globalThis.__ev = new Event('x');",
    )?;

    for _ in 0..2 {
      let realm_id = realm.realm_id;
      let (vm, realm_ref, heap) = realm.vm_realm_and_heap_mut();
      let mut scope = heap.scope();
      let mut vm = vm
        .execution_context_guard(vm_js::ExecutionContext {
          realm: realm_id,
          script_or_module: None,
        })?;
      let global = realm_ref.global_object();
      let document_obj = match get_prop(&mut vm, &mut scope, global, "document")? {
        Value::Object(obj) => obj,
        other => panic!("expected document object, got {other:?}"),
      };
      let event_obj = match get_prop(&mut vm, &mut scope, global, "__ev")? {
        Value::Object(obj) => obj,
        other => panic!("expected Event object, got {other:?}"),
      };
      let document_listener_roots =
        super::get_or_create_event_listener_roots(&mut scope, document_obj)?;
      let dom_ptr = NonNull::from(host.dom_mut());
      let mut vm_host = ();
      let mut hooks = NoopHostHooks::default();
      let mut invoker = super::VmJsDomEventInvoker {
        vm: &mut *vm,
        scope: &mut scope,
        vm_host: (&mut vm_host as &mut dyn VmHost) as *mut dyn VmHost,
        hooks: &mut hooks,
        window_obj: global,
        document_obj,
        event_obj,
        dom_ptr,
        document_listener_roots,
        opaque_target_obj: None,
        registry: host.dom().events() as *const _,
      };

      let mut event = web_events::Event::new(
        "x",
        web_events::EventInit {
          bubbles: false,
          cancelable: false,
          composed: false,
        },
      );
      web_events::dispatch_event(
        web_events::EventTargetId::Document,
        &mut event,
        host.dom(),
        host.dom().events(),
        &mut invoker,
      )
      .expect("dispatch_event should succeed");
    }

    assert_eq!(realm.exec_script("__count")?, Value::Number(1.0));
    Ok(())
  }

