  #[test]
  fn dom_wrapper_add_remove_event_listener_callback_argument_conversion_is_spec_compliant(
  ) -> Result<(), VmError> {
    let renderer_dom = crate::dom::parse_html("<!doctype html><html></html>").unwrap();
    let mut host = crate::js::HostDocumentState::from_renderer_dom(&renderer_dom);

    let mut realm = new_realm(WindowRealmConfig::new("https://example.com/"))?;

    let add_type_error = exec_script_with_dom_host(
      &mut realm,
      &mut host,
      "(() => {\n\
        const el = document.createElement('div');\n\
        try {\n\
          el.addEventListener('x', 1);\n\
          return 'no';\n\
        } catch (e) {\n\
          return e.name;\n\
        }\n\
      })()",
    )?;
    assert_eq!(get_string(realm.heap(), add_type_error), "TypeError");

    let remove_type_error = exec_script_with_dom_host(
      &mut realm,
      &mut host,
      "(() => {\n\
        const el = document.createElement('div');\n\
        try {\n\
          el.removeEventListener('x', 1);\n\
          return 'no';\n\
        } catch (e) {\n\
          return e.name;\n\
        }\n\
      })()",
    )?;
    assert_eq!(get_string(realm.heap(), remove_type_error), "TypeError");

    let add_null_is_noop = exec_script_with_dom_host(
      &mut realm,
      &mut host,
      "(() => {\n\
        const el = document.createElement('div');\n\
        try {\n\
          el.addEventListener('x', null);\n\
          return 'ok';\n\
        } catch (e) {\n\
          return e.name;\n\
        }\n\
      })()",
    )?;
    assert_eq!(get_string(realm.heap(), add_null_is_noop), "ok");

    let remove_null_is_noop = exec_script_with_dom_host(
      &mut realm,
      &mut host,
      "(() => {\n\
        const el = document.createElement('div');\n\
        try {\n\
          el.removeEventListener('x', null);\n\
          return 'ok';\n\
        } catch (e) {\n\
          return e.name;\n\
        }\n\
      })()",
    )?;
    assert_eq!(get_string(realm.heap(), remove_null_is_noop), "ok");

    let add_undefined_is_noop = exec_script_with_dom_host(
      &mut realm,
      &mut host,
      "(() => {\n\
        const el = document.createElement('div');\n\
        try {\n\
          el.addEventListener('x', undefined);\n\
          return 'ok';\n\
        } catch (e) {\n\
          return e.name;\n\
        }\n\
      })()",
    )?;
    assert_eq!(get_string(realm.heap(), add_undefined_is_noop), "ok");

    let remove_undefined_is_noop = exec_script_with_dom_host(
      &mut realm,
      &mut host,
      "(() => {\n\
        const el = document.createElement('div');\n\
        try {\n\
          el.removeEventListener('x', undefined);\n\
          return 'ok';\n\
        } catch (e) {\n\
          return e.name;\n\
        }\n\
      })()",
    )?;
    assert_eq!(get_string(realm.heap(), remove_undefined_is_noop), "ok");

    Ok(())
  }

