  #[test]
  fn dom_shim_host_slots_tags_do_not_collide_with_small_b_values() -> Result<(), VmError> {
    // Regression test: DOM shim kind tags used to be small integers stored in `HostSlots.b`, which
    // could collide with unrelated shims that also store small state values in `HostSlots.b` (for
    // example, TextDecoder flags/encoding ids).
    //
    // Construct forged host-slots objects with small `b` values that used to be used as DOM shim
    // tags:
    // - `b == 4`: previous DOMStringMap/dataset tag.
    // - `b == 3`: previous DOMTokenList/classList tag.
    //
    // Ensure the DOM shim exotic hooks do **not** claim these objects; instead, dispatch should fall
    // through to the WebIDL exotic hooks.
    let dom = crate::dom2::parse_html(
      "<!doctype html><html><body><div id=target class=\"a b\" data-foo=\"bar\"></div></body></html>",
    )
    .expect("parse html");
    let target = dom.get_element_by_id("target").expect("missing #target");
    let mut host = crate::js::HostDocumentState::new(dom);
    let mut realm = new_realm(WindowRealmConfig::new("https://example.com/"))?;

    let (forged_dataset_obj, forged_token_list_obj) = {
      let (vm, realm_ref, heap) = realm.vm_realm_and_heap_mut();
      let mut scope = heap.scope();
      let global = realm_ref.global_object();
      scope.push_root(Value::Object(global))?;

      // Point the forged object at the real `window.document` wrapper so that if the dataset shim
      // ever mis-routes based on a small `HostSlots.b` value, it would *actually* return a dataset
      // value (and thus prevent WebIDL exotic dispatch). This makes the test sensitive to the
      // collision bug rather than merely exercising the "fall through" path.
      let document_obj = {
        let document_v = get_prop(vm, &mut scope, global, "document")?;
        let Value::Object(document_obj) = document_v else {
          panic!("expected window.document to be an object");
        };
        scope.push_root(Value::Object(document_obj))?;
        document_obj
      };

      let wrapper_document_key = alloc_key(&mut scope, WRAPPER_DOCUMENT_KEY)?;

      let dataset_obj = scope.alloc_object()?;
      scope.push_root(Value::Object(dataset_obj))?;
      scope.heap_mut().object_set_host_slots(
        dataset_obj,
        HostSlots {
          a: target.index() as u64,
          b: 4,
        },
      )?;

      scope.define_property(
        dataset_obj,
        wrapper_document_key,
        data_desc(Value::Object(document_obj)),
      )?;

      let dataset_key = alloc_key(&mut scope, "forgedDataset")?;
      scope.define_property(global, dataset_key, data_desc(Value::Object(dataset_obj)))?;

      let token_list_obj = scope.alloc_object()?;
      scope.push_root(Value::Object(token_list_obj))?;
      scope.heap_mut().object_set_host_slots(
        token_list_obj,
        HostSlots {
          a: target.index() as u64,
          b: 3,
        },
      )?;

      scope.define_property(
        token_list_obj,
        wrapper_document_key,
        data_desc(Value::Object(document_obj)),
      )?;

      let token_list_key = alloc_key(&mut scope, "forgedTokenList")?;
      scope.define_property(global, token_list_key, data_desc(Value::Object(token_list_obj)))?;

      (dataset_obj, token_list_obj)
    };

    struct ExoticHost {
      forged_dataset_obj: GcObject,
      forged_token_list_obj: GcObject,
      dataset_gets: usize,
      token_list_gets: usize,
    }

    impl WebIdlBindingsHost for ExoticHost {
      fn call_operation(
        &mut self,
        _vm: &mut Vm,
        _scope: &mut Scope<'_>,
        _receiver: Option<Value>,
        _interface: &'static str,
        _operation: &'static str,
        _overload: usize,
        _args: &[Value],
      ) -> Result<Value, VmError> {
        Err(VmError::Unimplemented("operation dispatch not used by this test"))
      }

      fn call_constructor(
        &mut self,
        _vm: &mut Vm,
        _scope: &mut Scope<'_>,
        _interface: &'static str,
        _overload: usize,
        _args: &[Value],
        _new_target: Value,
      ) -> Result<Value, VmError> {
        Err(VmError::Unimplemented("constructor dispatch not used by this test"))
      }

      fn exotic_get(
        &mut self,
        scope: &mut Scope<'_>,
        obj: GcObject,
        key: PropertyKey,
        _receiver: Value,
      ) -> Result<Option<Value>, VmError> {
        let PropertyKey::String(s) = key else {
          return Ok(None);
        };
        let key = scope.heap().get_string(s)?.to_utf8_lossy();

        if obj == self.forged_dataset_obj {
          if key != "foo" {
            return Ok(None);
          }
          self.dataset_gets += 1;
          return Ok(Some(Value::String(scope.alloc_string("webidl_dataset")?)));
        }

        if obj == self.forged_token_list_obj {
          if key != "0" {
            return Ok(None);
          }
          self.token_list_gets += 1;
          return Ok(Some(Value::String(
            scope.alloc_string("webidl_token_list")?,
          )));
        }

        Ok(None)
      }
    }

    let mut webidl_host = ExoticHost {
      forged_dataset_obj,
      forged_token_list_obj,
      dataset_gets: 0,
      token_list_gets: 0,
    };

    let dataset_ctx = realm.dataset_exotic_context();
    let mut hooks =
      DomShimHostHooks::new(&mut host, dataset_ctx, realm.js_execution_options().webidl_limits);
    hooks.set_webidl_bindings_host(&mut webidl_host);

    let dataset_value =
      realm.exec_script_with_host_and_hooks(&mut host, &mut hooks, "forgedDataset.foo")?;
    assert_eq!(get_string(realm.heap(), dataset_value), "webidl_dataset");
    assert_eq!(webidl_host.dataset_gets, 1);

    let token_list_value =
      realm.exec_script_with_host_and_hooks(&mut host, &mut hooks, "forgedTokenList[0]")?;
    assert_eq!(get_string(realm.heap(), token_list_value), "webidl_token_list");
    assert_eq!(webidl_host.token_list_gets, 1);

    Ok(())
  }

  #[test]
  fn element_dataset_shim_mutates_dom2_document() -> Result<(), VmError> {
    let renderer_dom = crate::dom::parse_html(
      "<!doctype html><html><body><div id=target data-foo-bar=\"baz\"></div></body></html>",
    )
    .unwrap();
    let mut host = crate::js::HostDocumentState::from_renderer_dom(&renderer_dom);

    let mut realm = new_realm(WindowRealmConfig::new("https://example.com/"))?;

    let ok = exec_script_with_dom_host(
      &mut realm,
      &mut host,
      "(() => {\n\
        const el = document.getElementById('target');\n\
        if (!el) return false;\n\
        if (el.dataset.fooBar !== 'baz') return false;\n\
        el.dataset.fooBar = 'qux';\n\
        if (el.getAttribute('data-foo-bar') !== 'qux') return false;\n\
        if (el.dataset.fooBar !== 'qux') return false;\n\
        delete el.dataset.fooBar;\n\
        if (el.getAttribute('data-foo-bar') !== null) return false;\n\
        // Invalid property names should not throw and should not create attributes.\n\
        try { el.dataset.Foo = 'x'; } catch (e) { return false; }\n\
        try { el.dataset['foo-bar'] = 'y'; } catch (e) { return false; }\n\
        return el.getAttribute('data-foo') === null;\n\
      })()",
    )?;
    assert_eq!(ok, Value::Bool(true));

    let target = host
      .dom()
      .get_element_by_id("target")
      .expect("missing #target");
    assert_eq!(
      host.dom().get_attribute(target, "data-foo-bar").unwrap(),
      None
    );
    Ok(())
  }

  #[test]
  fn element_reflected_attributes_mutate_dom2_document() -> Result<(), VmError> {
    let renderer_dom = crate::dom::parse_html("<!doctype html><html><body></body></html>").unwrap();
    let mut host = crate::js::HostDocumentState::from_renderer_dom(&renderer_dom);

    let mut realm = new_realm(WindowRealmConfig::new("https://example.com/"))?;

    let ok = exec_script_with_dom_host(
      &mut realm,
      &mut host,
      "(() => {\n\
        const script = document.createElement('script');\n\
        script.id = 's';\n\
        script.src = 'https://example.com/app.js';\n\
        script.type = 'module';\n\
        script.charset = 'utf-8';\n\
        script.crossOrigin = 'anonymous';\n\
        script.async = true;\n\
        script.defer = true;\n\
        document.body.appendChild(script);\n\
        return script.src === 'https://example.com/app.js'\n\
          && script.type === 'module'\n\
          && script.charset === 'utf-8'\n\
          && script.crossOrigin === 'anonymous'\n\
          && script.async === true\n\
          && script.defer === true;\n\
      })()",
    )?;
    assert_eq!(ok, Value::Bool(true));

    let script = host.dom().get_element_by_id("s").expect("missing #s");
    assert_eq!(
      host.dom().get_attribute(script, "src").unwrap(),
      Some("https://example.com/app.js")
    );
    assert_eq!(
      host.dom().get_attribute(script, "type").unwrap(),
      Some("module")
    );
    assert_eq!(
      host.dom().get_attribute(script, "charset").unwrap(),
      Some("utf-8")
    );
    assert_eq!(
      host.dom().get_attribute(script, "crossorigin").unwrap(),
      Some("anonymous")
    );
    assert_eq!(host.dom().has_attribute(script, "async").unwrap(), true);
    assert_eq!(host.dom().has_attribute(script, "defer").unwrap(), true);

    Ok(())
  }

  #[test]
  fn html_script_element_async_reflects_force_async_slot() -> Result<(), VmError> {
    let renderer_dom = crate::dom::parse_html("<!doctype html><html><body></body></html>").unwrap();
    let mut host = crate::js::HostDocumentState::from_renderer_dom(&renderer_dom);

    let mut realm = new_realm(WindowRealmConfig::new("https://example.com/"))?;

    let ok = exec_script_with_dom_host(
      &mut realm,
      &mut host,
      "(() => {\n\
        const s = document.createElement('script');\n\
        if (!(s.async === true && s.getAttribute('async') === null)) return false;\n\
        s.async = false;\n\
        if (!(s.async === false && s.getAttribute('async') === null)) return false;\n\
        s.async = true;\n\
        if (!(s.async === true && s.getAttribute('async') === '')) return false;\n\
        const t = document.createElement('script');\n\
        if (!(t.async === true && t.getAttribute('async') === null)) return false;\n\
        t.setAttribute('async', '');\n\
        t.removeAttribute('async');\n\
        return t.async === false && t.getAttribute('async') === null;\n\
      })()",
    )?;
    assert_eq!(ok, Value::Bool(true));
    Ok(())
  }

