  #[test]
  fn shadow_root_inner_html_round_trips_and_does_not_affect_host_light_dom() -> Result<(), VmError> {
    let renderer_dom =
      crate::dom::parse_html("<!doctype html><html><body></body></html>").unwrap();
    let mut host = crate::js::HostDocumentState::from_renderer_dom(&renderer_dom);
    let mut realm = new_realm(WindowRealmConfig::new("https://example.com/"))?;

    let result = exec_script_with_dom_host(
      &mut realm,
      &mut host,
      "(() => {\n\
        const host = document.createElement('div');\n\
        host.innerHTML = '<i id=\"light\">light</i>';\n\
        const sr = host.attachShadow({ mode: 'open' });\n\
        sr.innerHTML = '<span id=a>hi</span>';\n\
        if (!sr.innerHTML.includes('<span id=\"a\">hi</span>')) return 'open_roundtrip:' + sr.innerHTML;\n\
        if (host.shadowRoot !== sr) return 'open_shadowRoot_identity';\n\
        if (host.innerHTML !== '<i id=\"light\">light</i>') return 'open_host:' + host.innerHTML;\n\
\n\
        sr.innerHTML = '';\n\
        if (sr.innerHTML !== '') return 'open_clear:' + sr.innerHTML;\n\
        if (host.innerHTML !== '<i id=\"light\">light</i>') return 'open_host_after:' + host.innerHTML;\n\
\n\
        const host2 = document.createElement('div');\n\
        host2.appendChild(document.createTextNode('light'));\n\
        const sr2 = host2.attachShadow({ mode: 'closed' });\n\
        if (host2.shadowRoot !== null) return 'closed_shadowRoot_exposed';\n\
        sr2.innerHTML = '<span id=a>hi</span>';\n\
        if (!sr2.innerHTML.includes('<span id=\"a\">hi</span>')) return 'closed_roundtrip:' + sr2.innerHTML;\n\
        sr2.innerHTML = '';\n\
        if (sr2.innerHTML !== '') return 'closed_clear:' + sr2.innerHTML;\n\
        if (host2.textContent !== 'light') return 'closed_host_text:' + host2.textContent;\n\
        return 'ok';\n\
      })()",
    )?;

    assert_eq!(get_string(realm.heap(), result), "ok");
    Ok(())
  }

  #[test]
  fn shadow_root_inner_html_round_trips_and_does_not_affect_host_light_dom_webidl(
  ) -> Result<(), VmError> {
    let renderer_dom =
      crate::dom::parse_html("<!doctype html><html><body></body></html>").unwrap();
    let document = crate::js::HostDocumentState::from_renderer_dom(&renderer_dom);
    let window = new_realm(
      WindowRealmConfig::new("https://example.com/")
        .with_dom_bindings_backend(DomBindingsBackend::WebIdl),
    )?;
    let mut host = WebIdlTestHost::new(document, window);

    let result = host.exec_script(
      r#"(() => {
        const host = document.createElement('div');
        host.innerHTML = '<i id="light">light</i>';
        const sr = host.attachShadow({ mode: 'open' });
        sr.innerHTML = '<span id=a>hi</span>';
        if (!sr.innerHTML.includes('<span id="a">hi</span>')) return 'open_roundtrip:' + sr.innerHTML;
        if (host.shadowRoot !== sr) return 'open_shadowRoot_identity';
        if (host.innerHTML !== '<i id="light">light</i>') return 'open_host:' + host.innerHTML;

        sr.innerHTML = '';
        if (sr.innerHTML !== '') return 'open_clear:' + sr.innerHTML;
        if (host.innerHTML !== '<i id="light">light</i>') return 'open_host_after:' + host.innerHTML;

        const host2 = document.createElement('div');
        host2.appendChild(document.createTextNode('light'));
        const sr2 = host2.attachShadow({ mode: 'closed' });
        if (host2.shadowRoot !== null) return 'closed_shadowRoot_exposed';
        sr2.innerHTML = '<span id=a>hi</span>';
        if (!sr2.innerHTML.includes('<span id="a">hi</span>')) return 'closed_roundtrip:' + sr2.innerHTML;
        sr2.innerHTML = '';
        if (sr2.innerHTML !== '') return 'closed_clear:' + sr2.innerHTML;
        if (host2.textContent !== 'light') return 'closed_host_text:' + host2.textContent;
        return 'ok';
      })()"#,
    )?;

    assert_eq!(get_string(host.window.heap(), result), "ok");
    Ok(())
  }

  #[test]
  fn node_text_content_set_queues_mutation_records_and_keeps_live_node_lists_in_sync(
  ) -> Result<(), VmError> {
    let renderer_dom =
      crate::dom::parse_html("<!doctype html><html><body><div id=root></div></body></html>")
        .unwrap();
    let mut host = crate::js::HostDocumentState::from_renderer_dom(&renderer_dom);
    let mut realm = new_realm(WindowRealmConfig::new("https://example.com/"))?;

    let ok = exec_script_with_dom_host(
      &mut realm,
      &mut host,
      "(() => {\n\
        const root = document.getElementById('root');\n\
        root.appendChild(document.createElement('span'));\n\
        root.appendChild(document.createElement('b'));\n\
        root.appendChild(document.createTextNode('c'));\n\
\n\
        const cachedChildNodes = root.childNodes;\n\
        const cachedChildren = root.children;\n\
        if (cachedChildNodes.length !== 3) return 'pre_nodes:' + cachedChildNodes.length;\n\
        if (cachedChildren.length !== 2) return 'pre_children:' + cachedChildren.length;\n\
\n\
        const obs = new MutationObserver(() => {});\n\
        obs.observe(root, { childList: true });\n\
        root.textContent = 'X';\n\
        const records = obs.takeRecords();\n\
\n\
        let removed = 0;\n\
        let added = 0;\n\
        for (let i = 0; i < records.length; i++) {\n\
          removed += records[i].removedNodes.length;\n\
          added += records[i].addedNodes.length;\n\
        }\n\
        if (records.length !== 4) return 'records:' + records.length;\n\
        if (removed !== 3) return 'removed:' + removed;\n\
        if (added !== 1) return 'added:' + added;\n\
        if (cachedChildNodes.length !== 1) return 'post_nodes:' + cachedChildNodes.length;\n\
        if (cachedChildren.length !== 0) return 'post_children:' + cachedChildren.length;\n\
\n\
        const c = document.createComment('old');\n\
        const obs2 = new MutationObserver(() => {});\n\
        obs2.observe(c, { characterData: true, characterDataOldValue: true });\n\
        c.textContent = 'new';\n\
        const r2 = obs2.takeRecords();\n\
        if (r2.length !== 1) return 'c_records:' + r2.length;\n\
        if (r2[0].type !== 'characterData') return 'c_type:' + r2[0].type;\n\
        if (r2[0].oldValue !== 'old') return 'c_old:' + r2[0].oldValue;\n\
\n\
        return 'ok';\n\
      })()",
    )?;
    assert_eq!(get_string(realm.heap(), ok), "ok");

    Ok(())
  }

  #[test]
  fn detached_document_node_text_content_and_element_attribute_accessors_use_detached_dom(
  ) -> Result<(), VmError> {
    let renderer_dom = crate::dom::parse_html(
      "<!doctype html><html><body><div id=host>HOST</div></body></html>",
    )
    .unwrap();
    let mut host = crate::js::HostDocumentState::from_renderer_dom(&renderer_dom);

    let mut realm = new_realm(WindowRealmConfig::new("https://example.com/"))?;

    {
      let (vm, realm_state, heap) = realm.vm_realm_and_heap_mut();
      let mut scope = heap.scope();
      let global = realm_state.global_object();

      let mut detached_dom = dom2::Document::new_with_scripting(QuirksMode::NoQuirks, false);
      let root = detached_dom.create_element("root", "");
      let text = detached_dom.create_text("DETACHED");
      detached_dom.append_child(root, text).unwrap();
      detached_dom.set_attribute(root, "data-x", "y").unwrap();
      detached_dom.append_child(detached_dom.root(), root).unwrap();

      let detached_document_obj = scope.alloc_object()?;
      scope.push_root(Value::Object(detached_document_obj))?;

      // Treat this wrapper object as the canonical `NodeId(0)` for the detached document.
      let node_id_key = alloc_key(&mut scope, NODE_ID_KEY)?;
      scope.define_property(detached_document_obj, node_id_key, data_desc(Value::Number(0.0)))?;

      // Mirror the internal `__fastrender_wrapper_document` backreference used by host documents.
      let wrapper_document_key = alloc_key(&mut scope, WRAPPER_DOCUMENT_KEY)?;
      scope.define_property(
        detached_document_obj,
        wrapper_document_key,
        PropertyDescriptor {
          enumerable: false,
          configurable: false,
          kind: PropertyKind::Data {
            value: Value::Object(detached_document_obj),
            writable: false,
          },
        },
      )?;

      // Copy Node.textContent accessor function objects from the host document so wrappers in the
      // detached document can reuse them.
      let host_document_obj = vm
        .user_data::<WindowRealmUserData>()
        .and_then(|data| data.document_obj)
        .expect("missing host document object");
      for internal_key in [NODE_TEXT_CONTENT_GET_KEY, NODE_TEXT_CONTENT_SET_KEY] {
        let key = alloc_key(&mut scope, internal_key)?;
        let value = scope
          .heap()
          .object_get_own_data_property_value(host_document_obj, &key)?
          .unwrap_or(Value::Undefined);
        let Value::Object(func) = value else {
          panic!("missing {internal_key} function on host document");
        };
        scope.define_property(
          detached_document_obj,
          key,
          data_desc(Value::Object(func)),
        )?;
      }

      // Register the detached DOM so document-aware accessors resolve the correct `dom2::Document`
      // instead of falling back to the host document.
      let detached_document_id = gc_object_id(detached_document_obj);
      let detached_dom_ptr = {
        let data = vm
          .user_data_mut::<WindowRealmUserData>()
          .expect("expected WindowRealmUserData");
        let mut boxed = Box::new(detached_dom);
        let dom_ptr = NonNull::from(boxed.as_mut());
        data
          .owned_dom2_documents
          .borrow_mut()
          .insert(detached_document_id, boxed);
        dom_ptr
      };

      // SAFETY: `detached_dom_ptr` points at the boxed `dom2::Document` owned by `WindowRealmUserData`.
      let detached_dom_ref = unsafe { detached_dom_ptr.as_ref() };
      let detached_root_wrapper = match get_or_create_node_wrapper(
        vm,
        &mut scope,
        detached_document_obj,
        Some(detached_dom_ref),
        root,
      )? {
        Value::Object(obj) => obj,
        _ => {
          return Err(VmError::InvariantViolation(
            "expected get_or_create_node_wrapper to return an object",
          ))
        }
      };
      scope.push_root(Value::Object(detached_root_wrapper))?;

      let detached_key = alloc_key(&mut scope, "detachedRoot")?;
      scope.define_property(
        global,
        detached_key,
        data_desc(Value::Object(detached_root_wrapper)),
      )?;
    }

    let result = exec_script_with_dom_host(
      &mut realm,
      &mut host,
      "(() => {\n\
        const hostEl = document.getElementById('host');\n\
        if (hostEl.textContent !== 'HOST') return 'host1:' + hostEl.textContent;\n\
        if (detachedRoot.textContent !== 'DETACHED') return 'text1:' + detachedRoot.textContent;\n\
        if (detachedRoot.getAttribute('data-x') !== 'y') return 'attr1:' + detachedRoot.getAttribute('data-x');\n\
        detachedRoot.textContent = 'CHANGED';\n\
        if (detachedRoot.textContent !== 'CHANGED') return 'text2:' + detachedRoot.textContent;\n\
        if (hostEl.textContent !== 'HOST') return 'host2:' + hostEl.textContent;\n\
        detachedRoot.setAttribute('data-x', 'z');\n\
        if (detachedRoot.getAttribute('data-x') !== 'z') return 'attr2:' + detachedRoot.getAttribute('data-x');\n\
        detachedRoot.removeAttribute('data-x');\n\
        if (detachedRoot.getAttribute('data-x') !== null) return 'attr3:' + detachedRoot.getAttribute('data-x');\n\
        return 'ok';\n\
      })()",
    )?;
    assert_eq!(get_string(realm.heap(), result), "ok");
    Ok(())
  }

  #[test]
  fn node_iterator_pre_remove_steps_run_for_inner_html() -> Result<(), VmError> {
    // Spec: https://dom.spec.whatwg.org/#nodeiterator-pre-removing-steps
    //
    // Ensure `Element.innerHTML = ""` removes nodes via DOM remove steps so active NodeIterators
    // update their reference/pointer state.
    let renderer_dom = crate::dom::parse_html(
      "<!doctype html><html><body><div id=root><div id=a><div id=a1></div></div><div id=b></div></div></body></html>",
    )
    .unwrap();
    let mut host = crate::js::HostDocumentState::from_renderer_dom(&renderer_dom);

    let mut realm = new_realm(WindowRealmConfig::new("https://example.com/"))?;

    let result = exec_script_with_dom_host(
      &mut realm,
      &mut host,
      "(() => {\n\
        const root = document.getElementById('root');\n\
        const a = document.getElementById('a');\n\
        const a1 = document.getElementById('a1');\n\
        const b = document.getElementById('b');\n\
\n\
        // whatToShow=1 == NodeFilter.SHOW_ELEMENT.\n\
        const it = document.createNodeIterator(root, 1);\n\
        if (it.nextNode() !== root) return 'step1';\n\
        if (it.nextNode() !== a) return 'step2';\n\
        if (it.nextNode() !== a1) return 'step3';\n\
        if (it.referenceNode !== a1) return 'ref_before';\n\
        if (it.pointerBeforeReferenceNode !== false) return 'ptr_before';\n\
\n\
        a.innerHTML = '';\n\
        if (it.referenceNode !== a) return 'ref_after';\n\
        if (it.pointerBeforeReferenceNode !== false) return 'ptr_after';\n\
\n\
        const next = it.nextNode();\n\
        if (next !== b) return 'next:' + (next && next.id);\n\
        return 'ok';\n\
      })()",
    )?;
    assert_eq!(get_string(realm.heap(), result), "ok");
    Ok(())
  }

