  #[test]
  fn console_standard_methods_exist_and_behave() -> Result<(), VmError> {
    let _lock = console_sink_test_lock()
      .lock()
      .expect("console sink test mutex should not be poisoned");
    let url = "https://example.com/path";
    let captured: Arc<Mutex<Vec<(ConsoleMessageLevel, String)>>> = Arc::new(Mutex::new(Vec::new()));
    let captured_for_sink = captured.clone();

    let sink: ConsoleSink = Arc::new(move |level, heap, args| {
      let message = crate::js::vm_error_format::format_console_arguments_limited(heap, args);
      captured_for_sink.lock().push((level, message));
    });

    let clock = Arc::new(VirtualClock::new());
    let clock_for_config: Arc<dyn Clock> = clock.clone();

    let mut config = WindowRealmConfig::new(url).with_clock(clock_for_config);
    config.console_sink = Some(sink);
    let mut realm = new_realm(config)?;

    assert_eq!(
      realm.exec_script(
        "typeof console.assert === 'function' && \
         typeof console.count === 'function' && \
         typeof console.countReset === 'function' && \
         typeof console.time === 'function' && \
         typeof console.timeLog === 'function' && \
         typeof console.timeEnd === 'function' && \
         typeof console.dir === 'function' && \
         typeof console.dirxml === 'function' && \
         typeof console.table === 'function'"
      )?,
      Value::Bool(true)
    );

    captured.lock().clear();
    realm.exec_script("console.assert(true, 'x')")?;
    assert!(captured.lock().is_empty());

    realm.exec_script("console.assert(false, 'x=%d', 1)")?;
    assert_eq!(
      &*captured.lock(),
      &[(ConsoleMessageLevel::Error, "Assertion failed: x=1".to_string())]
    );

    captured.lock().clear();
    realm.exec_script("const a = console.assert; a(false, 'x=%d', 1)")?;
    assert_eq!(
      &*captured.lock(),
      &[(ConsoleMessageLevel::Error, "Assertion failed: x=1".to_string())]
    );

    captured.lock().clear();
    realm.exec_script(
      "console.count(); console.count(); console.count('x'); console.count('x'); console.count();"
    )?;
    assert_eq!(
      &*captured.lock(),
      &[
        (ConsoleMessageLevel::Log, "default: 1".to_string()),
        (ConsoleMessageLevel::Log, "default: 2".to_string()),
        (ConsoleMessageLevel::Log, "x: 1".to_string()),
        (ConsoleMessageLevel::Log, "x: 2".to_string()),
        (ConsoleMessageLevel::Log, "default: 3".to_string()),
      ]
    );

    // Methods must work even when extracted from the console object.
    captured.lock().clear();
    realm.exec_script("const c = console.count; c();")?;
    assert_eq!(
      &*captured.lock(),
      &[(ConsoleMessageLevel::Log, "default: 4".to_string())]
    );

    // `console.countReset` resets existing counters (and warns when missing).
    captured.lock().clear();
    realm.exec_script("console.countReset('x'); console.count('x');")?;
    assert_eq!(
      &*captured.lock(),
      &[(ConsoleMessageLevel::Log, "x: 1".to_string())]
    );

    captured.lock().clear();
    realm.exec_script("console.countReset(); console.count();")?;
    assert_eq!(
      &*captured.lock(),
      &[(ConsoleMessageLevel::Log, "default: 1".to_string())]
    );

    captured.lock().clear();
    realm.exec_script("console.countReset('missing')")?;
    assert_eq!(
      &*captured.lock(),
      &[(
        ConsoleMessageLevel::Warn,
        "Count for 'missing' does not exist".to_string()
      )]
    );

    // `console.time`/`console.timeEnd` must follow the same monotonic clock as `performance.now()`.
    captured.lock().clear();
    clock.set_now(Duration::from_millis(0));
    realm.exec_script("console.time('t')")?;
    assert!(captured.lock().is_empty());

    clock.set_now(Duration::from_nanos(1_234_567_890)); // 1234.56789ms
    realm.exec_script("console.timeLog('t', 'extra', 1)")?;
    clock.set_now(Duration::from_millis(2000));
    realm.exec_script("console.timeEnd('t')")?;
    assert_eq!(
      &*captured.lock(),
      &[
        (ConsoleMessageLevel::Log, "t: 1234.568ms extra 1".to_string()),
        (ConsoleMessageLevel::Log, "t: 2000.000ms".to_string()),
      ]
    );

    captured.lock().clear();
    realm.exec_script("console.time('dup'); console.time('dup');")?;
    assert_eq!(
      &*captured.lock(),
      &[(ConsoleMessageLevel::Warn, "Timer 'dup' already exists".to_string())]
    );

    captured.lock().clear();
    realm.exec_script("console.timeEnd('missing')")?;
    assert_eq!(
      &*captured.lock(),
      &[(ConsoleMessageLevel::Warn, "Timer 'missing' does not exist".to_string())]
    );

    captured.lock().clear();
    realm.exec_script("console.timeLog('missing')")?;
    assert_eq!(
      &*captured.lock(),
      &[(ConsoleMessageLevel::Warn, "Timer 'missing' does not exist".to_string())]
    );

    captured.lock().clear();
    let ok = realm.exec_script(
      "try { console.dir({}); console.dirxml({}); console.table({}); true } catch (e) { false }",
    )?;
    assert_eq!(ok, Value::Bool(true));
    let calls = captured.lock().clone();
    assert!(
      calls.len() >= 3
        && calls
          .iter()
          .all(|(level, _)| *level == ConsoleMessageLevel::Log),
      "expected console.dir/dirxml/table to emit log messages, got {calls:?}"
    );

    Ok(())
  }

  #[test]
  fn console_sink_can_be_swapped_and_cleared_without_leaking() -> Result<(), VmError> {
    let _lock = console_sink_test_lock()
      .lock()
      .expect("console sink test mutex should not be poisoned");
    let initial_len = console_sinks().lock().len();

    let captured_a: Arc<Mutex<Vec<String>>> = Arc::new(Mutex::new(Vec::new()));
    let captured_b: Arc<Mutex<Vec<String>>> = Arc::new(Mutex::new(Vec::new()));

    let sink_a_captured = Arc::clone(&captured_a);
    let sink_a: ConsoleSink = Arc::new(move |_level, heap, args| {
      let msg = match args.get(0).copied().unwrap_or(Value::Undefined) {
        Value::String(s) => heap
          .get_string(s)
          .expect("string handle should be valid")
          .to_utf8_lossy(),
        _ => "<non-string>".to_string(),
      };
      sink_a_captured.lock().push(msg);
    });

    let sink_b_captured = Arc::clone(&captured_b);
    let sink_b: ConsoleSink = Arc::new(move |_level, heap, args| {
      let msg = match args.get(0).copied().unwrap_or(Value::Undefined) {
        Value::String(s) => heap
          .get_string(s)
          .expect("string handle should be valid")
          .to_utf8_lossy(),
        _ => "<non-string>".to_string(),
      };
      sink_b_captured.lock().push(msg);
    });

    let mut config = WindowRealmConfig::new("https://example.com/");
    config.console_sink = Some(Arc::clone(&sink_a));
    let mut realm = new_realm(config)?;
    assert_eq!(
      console_sinks().lock().len(),
      initial_len + 1,
      "expected realm construction to register its console sink"
    );

    realm.exec_script("console.log('a')")?;
    assert_eq!(&*captured_a.lock(), &["a".to_string()]);
    assert!(captured_b.lock().is_empty());

    realm.set_console_sink(Some(Arc::clone(&sink_b)))?;
    assert_eq!(
      console_sinks().lock().len(),
      initial_len + 1,
      "expected sink swap to unregister the old sink"
    );

    realm.exec_script("console.log('b')")?;
    assert_eq!(&*captured_a.lock(), &["a".to_string()]);
    assert_eq!(&*captured_b.lock(), &["b".to_string()]);

    realm.set_console_sink(None)?;
    assert_eq!(
      console_sinks().lock().len(),
      initial_len,
      "expected sink clear to unregister the active sink"
    );

    realm.exec_script("console.log('c')")?;
    assert_eq!(&*captured_a.lock(), &["a".to_string()]);
    assert_eq!(&*captured_b.lock(), &["b".to_string()]);

    drop(realm);
    assert_eq!(
      console_sinks().lock().len(),
      initial_len,
      "expected realm drop to not leak console sinks"
    );
    Ok(())
  }

  #[test]
