  #[test]
  fn external_interrupt_flag_interrupts_window_realm_and_is_not_reset() -> Result<(), VmError> {
    struct RestoreFlag {
      flag: Arc<AtomicBool>,
      prev: bool,
    }

    impl Drop for RestoreFlag {
      fn drop(&mut self) {
        self.flag.store(self.prev, Ordering::Relaxed);
      }
    }

    let mut realm = new_realm(WindowRealmConfig::new("https://example.com/"))?;

    let flag = crate::render_control::interrupt_flag();
    let _guard = RestoreFlag {
      prev: flag.swap(true, Ordering::Relaxed),
      flag: Arc::clone(&flag),
    };

    let err = realm.exec_script("1 + 2").unwrap_err();
    match err {
      VmError::Termination(term) => assert_eq!(term.reason, vm_js::TerminationReason::Interrupted),
      other => panic!("expected interrupted termination, got {other:?}"),
    }

    realm.reset_interrupt();
    assert!(flag.load(Ordering::Relaxed));

    let err = realm.exec_script("1 + 2").unwrap_err();
    match err {
      VmError::Termination(term) => assert_eq!(term.reason, vm_js::TerminationReason::Interrupted),
      other => panic!("expected interrupted termination, got {other:?}"),
    }

    Ok(())
  }

  #[test]
  fn location_href_fragment_navigation_updates_url_history_and_emits_hashchange(
  ) -> crate::error::Result<()> {
    let mut host = make_host(
      dom2::Document::new(QuirksMode::NoQuirks),
      "https://example.com/",
    )?;

    host.exec_script(
      "globalThis.__events = [];\n\
       globalThis.__is_hashchange_event = null;\n\
       window.addEventListener('hashchange', (e) => {\n\
         __events.push(e.oldURL + '|' + e.newURL);\n\
         __is_hashchange_event = (typeof HashChangeEvent === 'function') && (e instanceof HashChangeEvent);\n\
       });\n\
       location.href = '#a';\n\
       globalThis.__sync_len = __events.length;\n\
       globalThis.__href = location.href;\n\
       globalThis.__url = document.URL;\n\
       globalThis.__hist_len = history.length;",
    )?;

    assert_eq!(host.exec_script("__sync_len")?, Value::Number(0.0));
    assert_eq!(host.exec_script("__hist_len")?, Value::Number(2.0));
    assert!(host
      .host_mut()
      .window_realm()?
      .take_pending_navigation_request()
      .is_none());

    let href_v = host.exec_script("__href")?;
    let url_v = host.exec_script("__url")?;
    {
      let heap = host.host_mut().window_realm()?.heap();
      assert_eq!(get_string(heap, href_v), "https://example.com/#a");
      assert_eq!(get_string(heap, url_v), "https://example.com/#a");
    }

    host.run_until_idle(crate::js::RunLimits::unbounded())?;
    assert_eq!(host.exec_script("__events.length")?, Value::Number(1.0));
    assert_eq!(host.exec_script("__is_hashchange_event")?, Value::Bool(true));
    let event_v = host.exec_script("__events[0]")?;
    {
      let heap = host.host_mut().window_realm()?.heap();
      assert_eq!(
        get_string(heap, event_v),
        "https://example.com/|https://example.com/#a"
      );
    }

    Ok(())
  }

